{
  "name": "MCAT Pulse - Adaptive Study Scheduler",
  "description": "A highly interactive MCAT study planner featuring drag-and-drop task management, visual progress tracking, and AI-powered schedule adaptation.",
  "requestFramePermissions": []
}

export type MCATSection = 'Chem/Phys' | 'CARS' | 'Bio/Biochem' | 'Psych/Soc' | 'Practice Exam' | 'General';

export interface StudyTask {
  id: string;
  title: string;
  description: string;
  section: MCATSection;
  completed: boolean;
  dayIndex: number; // 0-6 for weekly view
}

export interface WeeklySchedule {
  tasks: StudyTask[];
  startDate: string;
}

export interface AIResponse {
  suggestion: string;
  suggestedTasks: StudyTask[];
}

import React from 'react';
import { MCATSection } from './types';

export const SECTION_COLORS: Record<MCATSection, string> = {
  'Chem/Phys': 'bg-blue-100 border-blue-300 text-blue-700',
  'CARS': 'bg-amber-100 border-amber-300 text-amber-700',
  'Bio/Biochem': 'bg-emerald-100 border-emerald-300 text-emerald-700',
  'Psych/Soc': 'bg-purple-100 border-purple-300 text-purple-700',
  'Practice Exam': 'bg-rose-100 border-rose-300 text-rose-700',
  'General': 'bg-slate-100 border-slate-300 text-slate-700',
};

export const DAYS_OF_WEEK = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];

export const INITIAL_TASKS: any[] = [
  { id: '1', title: 'Amino Acid Structures', description: 'Review all 20 side chains', section: 'Bio/Biochem', completed: false, dayIndex: 0 },
  { id: '2', title: 'Kinematics Practice', description: 'UWorld set 20 questions', section: 'Chem/Phys', completed: false, dayIndex: 0 },
  { id: '3', title: 'CARS Diagnostic', description: '3 passages under timed conditions', section: 'CARS', completed: true, dayIndex: 1 },
  { id: '4', title: 'Nervous System', description: 'Action potential & neurons', section: 'Bio/Biochem', completed: false, dayIndex: 2 },
  { id: '5', title: 'Social Stratification', description: 'Khan Academy videos', section: 'Psych/Soc', completed: false, dayIndex: 3 },
  { id: '6', title: 'Full Length #1', description: 'Simulated environment', section: 'Practice Exam', completed: false, dayIndex: 5 },
  { id: '7', title: 'Review FL #1', description: 'In-depth analysis of mistakes', section: 'General', completed: false, dayIndex: 6 },
];

import { GoogleGenAI, Type } from "@google/genai";
import { StudyTask, MCATSection } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export async function adaptSchedule(currentTasks: StudyTask[], userGoals: string): Promise<{ suggestion: string, updatedTasks: StudyTask[] }> {
  const model = 'gemini-3-flash-preview';

  const prompt = `
    You are an expert MCAT Study Coach. 
    Current Schedule: ${JSON.stringify(currentTasks)}
    User Input: ${userGoals}

    Tasks:
    - If the user is behind, move uncompleted tasks to future days.
    - If the user wants to focus on a subject, add new tasks for that subject.
    - Ensure a balanced workload (max 4 tasks per day).
    - Provide a supportive encouragement message.

    Return the response in JSON format.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          suggestion: { type: Type.STRING, description: "A message to the student" },
          updatedTasks: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                section: { type: Type.STRING },
                completed: { type: Type.BOOLEAN },
                dayIndex: { type: Type.NUMBER }
              },
              required: ["id", "title", "section", "completed", "dayIndex"]
            }
          }
        },
        required: ["suggestion", "updatedTasks"]
      }
    }
  });

  try {
    return JSON.parse(response.text);
  } catch (e) {
    console.error("Failed to parse AI response", e);
    return { suggestion: "I had trouble updating the schedule. Try again!", updatedTasks: currentTasks };
  }
}

import React from 'react';
import { StudyTask } from '../types';
import { SECTION_COLORS } from '../constants';

interface TaskCardProps {
  task: StudyTask;
  onToggle: (id: string) => void;
  onDragStart: (e: React.DragEvent, id: string) => void;
}

const TaskCard: React.FC<TaskCardProps> = ({ task, onToggle, onDragStart }) => {
  return (
    <div
      draggable
      onDragStart={(e) => onDragStart(e, task.id)}
      className={`p-3 mb-2 rounded-lg border shadow-sm transition-all cursor-grab active:cursor-grabbing hover:shadow-md ${
        SECTION_COLORS[task.section]
      } ${task.completed ? 'opacity-50 grayscale-[0.5]' : ''}`}
    >
      <div className="flex items-start gap-2">
        <input
          type="checkbox"
          checked={task.completed}
          onChange={() => onToggle(task.id)}
          className="mt-1 h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500 cursor-pointer"
        />
        <div className="flex-1 min-w-0">
          <h4 className={`font-semibold text-sm truncate ${task.completed ? 'line-through' : ''}`}>
            {task.title}
          </h4>
          <p className="text-xs mt-1 opacity-80 line-clamp-2">{task.description}</p>
        </div>
      </div>
      <div className="mt-2 text-[10px] font-bold uppercase tracking-wider opacity-60">
        {task.section}
      </div>
    </div>
  );
};

export default TaskCard;

import React, { useState } from 'react';
import { StudyTask } from '../types';
import TaskCard from './TaskCard';

interface DayColumnProps {
  dayName: string;
  dayIndex: number;
  tasks: StudyTask[];
  onToggleTask: (id: string) => void;
  onDropTask: (taskId: string, targetDay: number) => void;
  onDragStartTask: (e: React.DragEvent, id: string) => void;
}

const DayColumn: React.FC<DayColumnProps> = ({
  dayName,
  dayIndex,
  tasks,
  onToggleTask,
  onDropTask,
  onDragStartTask,
}) => {
  const [isOver, setIsOver] = useState(false);

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(true);
  };

  const handleDragLeave = () => {
    setIsOver(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(false);
    const taskId = e.dataTransfer.getData('taskId');
    onDropTask(taskId, dayIndex);
  };

  const isToday = new Date().getDay() === (dayIndex + 1) % 7;

  return (
    <div
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`flex flex-col min-h-[400px] w-full rounded-xl p-3 transition-colors ${
        isOver ? 'bg-blue-50 ring-2 ring-blue-400 ring-inset' : 'bg-slate-50'
      }`}
    >
      <div className="flex justify-between items-center mb-4">
        <h3 className={`font-bold text-sm ${isToday ? 'text-blue-600' : 'text-slate-600'}`}>
          {dayName} {isToday && '(Today)'}
        </h3>
        <span className="text-xs bg-white px-2 py-0.5 rounded-full border border-slate-200 text-slate-500 font-medium">
          {tasks.length}
        </span>
      </div>

      <div className="flex-1">
        {tasks.map((task) => (
          <TaskCard
            key={task.id}
            task={task}
            onToggle={onToggleTask}
            onDragStart={onDragStartTask}
          />
        ))}
        {tasks.length === 0 && (
          <div className="h-24 border-2 border-dashed border-slate-200 rounded-lg flex items-center justify-center text-slate-400 text-xs text-center p-4 italic">
            No tasks scheduled. Drag here to add.
          </div>
        )}
      </div>
    </div>
  );
};

export default DayColumn;

import React, { useState, useEffect, useCallback } from 'react';
import DayColumn from './components/DayColumn';
import { StudyTask, MCATSection } from './types';
import { DAYS_OF_WEEK, INITIAL_TASKS } from './constants';
import { adaptSchedule } from './services/geminiService';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(INITIAL_TASKS);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');

  // Persist to local storage
  useEffect(() => {
    const saved = localStorage.getItem('mcat-schedule');
    if (saved) {
      setTasks(JSON.parse(saved));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('mcat-schedule', JSON.stringify(tasks));
  }, [tasks]);

  const toggleTask = (id: string) => {
    setTasks((prev) =>
      prev.map((t) => (t.id === id ? { ...t, completed: !t.completed } : t))
    );
  };

  const handleDragStartTask = (e: React.DragEvent, id: string) => {
    e.dataTransfer.setData('taskId', id);
  };

  const moveTask = (taskId: string, targetDay: number) => {
    setTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, dayIndex: targetDay } : t))
    );
  };

  const handleAiUpdate = async () => {
    if (!userInput.trim() && tasks.every(t => !t.completed)) return;

    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput || "Adjust my schedule based on my progress.");
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      console.error(err);
      setAiMessage("Something went wrong with the AI coach. Please try again.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const progressPercentage = Math.round(
    (tasks.filter((t) => t.completed).length / tasks.length) * 100
  ) || 0;

  return (
    <div className="min-h-screen pb-20">
      {/* Header */}
      <header className="bg-white border-b sticky top-0 z-10 shadow-sm px-6 py-4">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
              <span className="text-blue-600">MCAT</span> Pulse
              <span className="bg-blue-100 text-blue-700 text-[10px] px-2 py-0.5 rounded-full uppercase tracking-tighter">Adaptive</span>
            </h1>
            <p className="text-slate-500 text-sm">Visualize your path to medical school.</p>
          </div>

          <div className="flex items-center gap-6">
            <div className="hidden sm:block">
              <div className="flex justify-between text-[10px] font-bold text-slate-400 uppercase mb-1">
                <span>Weekly Progress</span>
                <span>{progressPercentage}%</span>
              </div>
              <div className="w-48 h-2 bg-slate-100 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-blue-500 transition-all duration-500" 
                  style={{ width: `${progressPercentage}%` }}
                />
              </div>
            </div>

            <button
              onClick={() => {
                if (confirm('Are you sure you want to reset your schedule?')) {
                  setTasks(INITIAL_TASKS);
                  localStorage.removeItem('mcat-schedule');
                }
              }}
              className="text-xs text-rose-500 font-semibold hover:text-rose-600"
            >
              Reset Plan
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-[1600px] mx-auto p-6 space-y-8">
        {/* AI Control Panel */}
        <section className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
          <div className="flex flex-col md:flex-row gap-6 items-start">
            <div className="flex-1 w-full">
              <label className="block text-sm font-semibold text-slate-700 mb-2">
                Ask your AI Study Coach to adapt your schedule...
              </label>
              <div className="flex gap-2">
                <input
                  type="text"
                  value={userInput}
                  onChange={(e) => setUserInput(e.target.value)}
                  placeholder="e.g., 'I'm behind on CARS, reschedule my week' or 'Add more Physics practice'"
                  className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none"
                />
                <button
                  onClick={handleAiUpdate}
                  disabled={isAiLoading}
                  className="bg-slate-900 text-white px-6 py-2 rounded-xl text-sm font-medium hover:bg-slate-800 disabled:opacity-50 transition-colors flex items-center gap-2"
                >
                  {isAiLoading ? (
                    <>
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                      Thinking...
                    </>
                  ) : (
                    'Sync Schedule'
                  )}
                </button>
              </div>
            </div>

            {aiMessage && (
              <div className="flex-1 w-full bg-blue-50 border border-blue-100 rounded-xl p-4 relative animate-in fade-in slide-in-from-top-2">
                <div className="text-blue-800 text-sm leading-relaxed">
                  <span className="font-bold mr-2">Coach:</span>
                  {aiMessage}
                </div>
                <button 
                  onClick={() => setAiMessage(null)}
                  className="absolute top-2 right-2 text-blue-400 hover:text-blue-600"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>
            )}
          </div>
        </section>

        {/* Schedule Grid */}
        <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 xl:grid-cols-7 gap-4">
          {DAYS_OF_WEEK.map((day, index) => (
            <DayColumn
              key={day}
              dayName={day}
              dayIndex={index}
              tasks={tasks.filter((t) => t.dayIndex === index)}
              onToggleTask={toggleTask}
              onDragStartTask={handleDragStartTask}
              onDropTask={moveTask}
            />
          ))}
        </section>

        {/* Legend / Stats */}
        <section className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-4">
          {(['Chem/Phys', 'CARS', 'Bio/Biochem', 'Psych/Soc', 'Practice Exam', 'General'] as MCATSection[]).map(section => {
            const sectionTasks = tasks.filter(t => t.section === section);
            const comp = sectionTasks.filter(t => t.completed).length;
            return (
              <div key={section} className="bg-white p-3 rounded-xl border border-slate-100 flex flex-col items-center">
                <span className="text-[10px] font-bold text-slate-400 uppercase mb-1">{section}</span>
                <span className="text-xl font-bold text-slate-800">{comp}/{sectionTasks.length}</span>
              </div>
            )
          })}
        </section>
      </main>

      {/* Floating Action Button for Mobile Add? Just simplified for now. */}
      <footer className="fixed bottom-0 left-0 right-0 p-4 pointer-events-none flex justify-center">
        <div className="bg-white/80 backdrop-blur-md px-4 py-2 rounded-full border border-slate-200 shadow-xl pointer-events-auto text-xs text-slate-500 font-medium">
          Drag tasks to reschedule • Click checkbox to complete
        </div>
      </footer>
    </div>
  );
};

export default App;

