import React, { useState } from 'react';
import { StudyTask } from '../types';
import TaskCard from './TaskCard';
import { DAYS_OF_WEEK } from '../constants';

interface DayColumnProps {
  dayIndex: number;
  tasks: StudyTask[];
  onToggleTask: (id: string) => void;
  onDropTask: (taskId: string, targetDay: number) => void;
  onDragStartTask: (e: React.DragEvent, id: string) => void;
}

const DayColumn: React.FC<DayColumnProps> = ({
  dayIndex,
  tasks,
  onToggleTask,
  onDropTask,
  onDragStartTask,
}) => {
  const [isOver, setIsOver] = useState(false);
  const dayInfo = DAYS_OF_WEEK[dayIndex];
  const isToday = dayInfo.short === 'Wed' && dayInfo.date === '4'; // Mock today for visual consistency with screenshot

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(true);
  };

  const handleDragLeave = () => {
    setIsOver(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(false);
    const taskId = e.dataTransfer.getData('taskId');
    onDropTask(taskId, dayIndex);
  };

  return (
    <div
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`flex flex-col min-h-[500px] w-full max-w-[360px] rounded-[32px] border-2 p-6 transition-all ${
        isOver 
          ? 'bg-blue-50/50 border-blue-400 border-dashed' 
          : 'bg-[#f5f8ff] border-transparent'
      }`}
    >
      <div className="flex justify-between items-start mb-8">
        <div>
          <h3 className={`text-2xl font-extrabold tracking-tight ${isToday ? 'text-[#3b5bdb]' : 'text-slate-800'}`}>
            {dayInfo.short} {dayInfo.date} {isToday && '(Today)'}
          </h3>
          <p className="text-slate-400 font-semibold mt-1">
            {tasks.length} tasks
          </p>
        </div>

