import React, { useState, useEffect } from 'react';
import DayColumn from './components/DayColumn';
import EditTaskModal from './components/EditTaskModal';
import { StudyTask } from './types';
import { DAYS_OF_WEEK, INITIAL_TASKS } from './constants';
import { adaptSchedule } from './services/geminiService';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(INITIAL_TASKS);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');

  // Modal state
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('mcat-schedule');
    if (saved) {
      setTasks(JSON.parse(saved));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('mcat-schedule', JSON.stringify(tasks));
  }, [tasks]);

  const toggleTask = (id: string) => {
    setTasks((prev) =>
      prev.map((t) => (t.id === id ? { ...t, completed: !t.completed } : t))
    );
  };

  const handleDragStartTask = (e: React.DragEvent, id: string) => {
    e.dataTransfer.setData('taskId', id);
  };

  const moveTask = (taskId: string, targetDay: number) => {
    setTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, dayIndex: targetDay } : t))
    );
  };

  const handleEditTask = (task: StudyTask) => {
    setCurrentTaskToEdit(task);
    setIsModalOpen(true);
  };

  const handleAddTask = (dayIndex: number) => {
    setCurrentTaskToEdit({
      dayIndex,
      completed: false,
      description: '',
      section: 'Biology',
      duration: '1h',
      recurrence: 'None',
    });
    setIsModalOpen(true);
  };

  const saveTask = (task: StudyTask) => {
    if (task.id) {
      // Update existing
      setTasks(prev => prev.map(t => t.id === task.id ? task : t));
    } else {
      // Create new
      if (task.recurrence === 'Daily') {
        // Create 7 tasks, one for each day
        const newTasks: StudyTask[] = Array.from({ length: 7 }).map((_, i) => ({
          ...task,
          id: Math.random().toString(36).substr(2, 9),
          dayIndex: i,
          recurrence: 'Daily',
        }));
        setTasks(prev => [...prev, ...newTasks]);
      } else {
        const newTask = {
          ...task,
          id: Math.random().toString(36).substr(2, 9),
          recurrence: 'None',
        };
        setTasks(prev => [...prev, newTask]);
      }
    }
  };

  const deleteTask = (id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
  };

  const handleAiUpdate = async () => {
    if (!userInput.trim() && tasks.every(t => !t.completed)) return;
    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput || "Adjust my schedule based on my progress.");
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      console.error(err);
      setAiMessage("Something went wrong with the AI coach.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const completedCount = tasks.filter(t => t.completed).length;
  const totalCount = tasks.length || 1;
  const progressPercent = Math.round((completedCount / totalCount) * 100);

  return (
    <div className="min-h-screen bg-[#f8faff] pb-32">
      <header className="px-8 pt-8 max-w-[1800px] mx-auto flex flex-col sm:flex-row items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight flex items-center gap-2">
            <span className="text-[#3b5bdb]">MCAT</span> PULSE
          </h1>
          <p className="text-slate-400 font-bold text-sm tracking-wide mt-1 uppercase">DRAG & DROP STUDY PLANNER</p>
        </div>

        <div className="w-full sm:w-auto max-w-md bg-white rounded-3xl p-2 shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100 flex items-center gap-2">
          <input
            type="text"
            value={userInput}
            onChange={(e) => setUserInput(e.target.value)}
            placeholder="Ask AI to adjust your week..."
            className="flex-1 bg-transparent border-none px-4 py-2 font-semibold text-sm focus:ring-0 outline-none placeholder:text-slate-300"
          />
          <button
            onClick={handleAiUpdate}
            disabled={isAiLoading}
            className="bg-[#3b5bdb] text-white px-6 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-[#2f49b1] transition-all disabled:opacity-50 flex items-center gap-2"
          >
            {isAiLoading ? 'SYNCING...' : 'SYNC AI'}
          </button>
        </div>
      </header>

      {aiMessage && (
        <div className="max-w-2xl mx-auto mt-8 px-6">
           <div className="bg-[#3b5bdb] text-white rounded-3xl p-6 shadow-xl relative animate-in zoom-in-95 duration-300">
             <p className="font-bold leading-relaxed">{aiMessage}</p>
             <button onClick={() => setAiMessage(null)} className="absolute top-4 right-4 opacity-50 hover:opacity-100">
               <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
             </button>
           </div>
        </div>
      )}

      <main className="mt-12 overflow-x-auto pb-8">
        <div className="flex gap-6 px-8 min-w-max pb-4">
          {DAYS_OF_WEEK.map((_, index) => (
            <div key={index} className="w-[320px] shrink-0">
              <DayColumn
                dayIndex={index}
                tasks={tasks.filter((t) => t.dayIndex === index)}
                onToggleTask={toggleTask}
                onDragStartTask={handleDragStartTask}
                onDropTask={moveTask}
                onAddTask={handleAddTask}
                onEditTask={handleEditTask}
              />
            </div>
          ))}
        </div>
      </main>

      <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur-xl px-10 py-5 rounded-[40px] shadow-[0_20px_60px_rgba(0,0,0,0.1)] border border-white flex items-center gap-8 z-50">
        <div className="flex flex-col">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Mastery Level</span>
          <span className="text-xl font-black text-[#3b5bdb]">{progressPercent}%</span>
        </div>
        <div className="w-64 h-3 bg-slate-100 rounded-full overflow-hidden">
          <div 
            className="h-full bg-gradient-to-r from-blue-400 to-[#3b5bdb] transition-all duration-1000 ease-out"
            style={{ width: `${progressPercent}%` }}
          />
        </div>
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-2xl bg-[#3b5bdb] flex items-center justify-center text-white font-black text-xs">
            {completedCount}
          </div>
          <span className="text-xs font-bold text-slate-500">Tasks Finished</span>
        </div>
      </div>

      <EditTaskModal
        isOpen={isModalOpen}
        task={currentTaskToEdit}
        onClose={() => setIsModalOpen(false)}
        onSave={saveTask}
        onDelete={deleteTask}
      />
    </div>
  );
};

