            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
              <div className="lg:col-start-2">
                <DayColumn
                  date={currentRangeDays[5]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[5]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              </div>
              <div className="lg:col-start-3">
                <DayColumn
                  date={currentRangeDays[6]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[6]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              </div>
            </div>
          </div>
        ) : (
          <div className="flex justify-center pb-8">
            <DayColumn
              date={currentRangeDays[0]}
              tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[0]))}
              onToggleTask={toggleTask}
              onDragStartTask={handleDragStartTask}
              onDropTask={moveTask}
              onAddTask={handleAddTask}
              onEditTask={handleEditTask}
              isFocused
            />
          </div>
        )}
      </main>

      {/* Progress Footer */}
      <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur-xl px-10 py-5 rounded-[40px] shadow-[0_20px_60px_rgba(0,0,0,0.1)] border border-white flex items-center gap-8 z-50">
        <div className="flex flex-col">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Mastery</span>
          <span className="text-xl font-black text-[#3b5bdb]">{progressPercent}%</span>
