import React, { useState } from 'react';
import { StudyTask } from '../types';
import TaskCard from './TaskCard';
import { formatDateKey } from '../constants';

interface DayColumnProps {
  date: Date;
  tasks: StudyTask[];
  onToggleTask: (id: string) => void;
  onDropTask: (taskId: string, targetDate: string) => void;
  onDragStartTask: (e: React.DragEvent, id: string) => void;
  onAddTask: (date: string) => void;
  onEditTask: (task: StudyTask) => void;
  isFocused?: boolean;
}

const DayColumn: React.FC<DayColumnProps> = ({
  date,
  tasks,
  onToggleTask,
  onDropTask,
  onDragStartTask,
  onAddTask,
  onEditTask,
  isFocused = false
}) => {
  const [isOver, setIsOver] = useState(false);
  const dateKey = formatDateKey(date);
  const isToday = dateKey === formatDateKey(new Date());

  // Standard getDay(): 0=Sun, 1=Mon, 2=Tue, 3=Wed, 4=Thu, 5=Fri, 6=Sat
  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const dayName = dayNames[date.getDay()];
  const dayNum = date.getDate();

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(true);
  };

  const handleDragLeave = () => {
    setIsOver(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(false);
    const taskId = e.dataTransfer.getData('taskId');
    onDropTask(taskId, dateKey);
  };

  return (
    <div
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`flex flex-col rounded-[32px] border-2 p-7 transition-all h-full ${
        isFocused ? 'min-h-[600px] w-full max-w-[500px]' : 'min-h-[450px] w-full'
      } ${
        isOver 
          ? 'bg-blue-50/50 border-blue-400 border-dashed' 
          : isToday
            ? 'bg-white border-[#3b5bdb]/30 shadow-[0_15px_40px_rgba(59,91,219,0.08)] ring-1 ring-[#3b5bdb]/5'
            : 'bg-[#f5f8ff] border-transparent'
      }`}
    >
      <div className="flex justify-between items-center mb-8">
        <div>
          <h3 className={`text-2xl font-black tracking-tight ${isToday ? 'text-[#3b5bdb]' : 'text-slate-800'}`}>
            {dayName} {dayNum} {isToday && <span className="text-[0.9em] ml-1">(Today)</span>}
          </h3>
          <p className="text-slate-400 font-semibold text-sm mt-0.5">
            {tasks.length} {tasks.length === 1 ? 'task' : 'tasks'}
          </p>
        </div>

        <button 
          onClick={() => onAddTask(dateKey)}
          className="w-11 h-11 rounded-2xl bg-white shadow-[0_8px_20px_rgba(0,0,0,0.06)] border border-slate-100 flex items-center justify-center text-slate-400 hover:text-[#3b5bdb] hover:border-[#3b5bdb]/20 transition-all active:scale-90"
        >
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
            <line x1="12" y1="5" x2="12" y2="19"></line>
            <line x1="5" y1="12" x2="19" y2="12"></line>
          </svg>
        </button>
      </div>

      <div className="flex-1 space-y-4">
        {tasks.map((task) => (
          <TaskCard
            key={task.id}
            task={task}
            onToggle={onToggleTask}
            onDragStart={onDragStartTask}
            onEdit={onEditTask}
          />
        ))}
        {tasks.length === 0 && (
          <div className="h-28 border-2 border-dashed border-slate-200/50 rounded-[28px] flex items-center justify-center text-slate-300 font-bold text-xs italic p-4 text-center">
            Rest day?
          </div>
        )}
      </div>
    </div>
  );
};

