import React, { useState, useEffect, useMemo } from 'react';
import DayColumn from './components/DayColumn';
import EditTaskModal from './components/EditTaskModal';
import { StudyTask, ViewType } from './types';
import { INITIAL_TASKS, formatDateKey, DAYS_SHORT, SECTION_STYLES } from './constants';
import { adaptSchedule } from './services/geminiService';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(INITIAL_TASKS);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');
  const [view, setView] = useState<ViewType>('weekly');
  const [baseDate, setBaseDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('mcat-schedule-v2');
    if (saved) {
      setTasks(JSON.parse(saved));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('mcat-schedule-v2', JSON.stringify(tasks));
  }, [tasks]);

  // Task Handlers
  const toggleTask = (id: string) => setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  const handleDragStartTask = (e: React.DragEvent, id: string) => e.dataTransfer.setData('taskId', id);
  const moveTask = (taskId: string, targetDate: string) => setTasks(prev => prev.map(t => t.id === taskId ? { ...t, date: targetDate } : t));
  const handleEditTask = (task: StudyTask) => { setCurrentTaskToEdit(task); setIsModalOpen(true); };
  const handleAddTask = (dateKey: string) => { setCurrentTaskToEdit({ date: dateKey, completed: false, description: '', section: 'Biology', duration: '1h', recurrence: 'None' }); setIsModalOpen(true); };
  const deleteTask = (id: string) => setTasks(prev => prev.filter(t => t.id !== id));

  const saveTask = (task: StudyTask) => {
    if (task.id) {
      setTasks(prev => prev.map(t => t.id === task.id ? task : t));
    } else {
      if (task.recurrence === 'Daily') {
        const newTasks: StudyTask[] = Array.from({ length: 7 }).map((_, i) => {
          const d = new Date(task.date);
          d.setDate(d.getDate() + i);
          return { ...task, id: Math.random().toString(36).substr(2, 9), date: formatDateKey(d) };
        });
        setTasks(prev => [...prev, ...newTasks]);
      } else {
        setTasks(prev => [...prev, { ...task, id: Math.random().toString(36).substr(2, 9) }]);
      }
    }
  };

  // Date Logic
  const navigate = (amount: number) => {
    const newDate = new Date(baseDate);
    if (view === 'daily') newDate.setDate(newDate.getDate() + amount);
    if (view === 'weekly') newDate.setDate(newDate.getDate() + (amount * 7));
    if (view === 'monthly') newDate.setMonth(newDate.getMonth() + amount);
    setBaseDate(newDate);
  };

  const currentRangeDays = useMemo(() => {
    if (view === 'daily') return [new Date(baseDate)];
    if (view === 'weekly') {
      const start = new Date(baseDate);
      const day = start.getDay();
      const shift = day === 0 ? 6 : day - 1;
      start.setDate(start.getDate() - shift); 
      return Array.from({ length: 7 }).map((_, i) => {
        const d = new Date(start);
        d.setDate(d.getDate() + i);
        return d;
      });
    }
    return [];
  }, [view, baseDate]);

  const monthGrid = useMemo(() => {
    if (view !== 'monthly') return [];
    const start = new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
    const end = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0);
    const startDay = start.getDay();
    const padding = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < padding; i++) {
      const d = new Date(start);
      d.setDate(d.getDate() - (padding - i));
      days.push({ date: d, currentMonth: false });
    }
    for (let i = 1; i <= end.getDate(); i++) {
      days.push({ date: new Date(baseDate.getFullYear(), baseDate.getMonth(), i), currentMonth: true });
    }
    const totalSlots = days.length > 35 ? 42 : 35;
    const remaining = totalSlots - days.length;
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(end);
      d.setDate(d.getDate() + i);
      days.push({ date: d, currentMonth: false });
    }
    return days;
  }, [view, baseDate]);

  const handleAiUpdate = async () => {
    if (!userInput.trim() && tasks.every(t => !t.completed)) return;
    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput || "Adjust my schedule based on my progress.");
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      setAiMessage("Something went wrong with the AI coach.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const progressPercent = Math.round((tasks.filter(t => t.completed).length / (tasks.length || 1)) * 100);

  return (
    <div className="min-h-screen bg-[#f8faff] pb-32">
      <header className="px-8 pt-8 max-w-[1800px] mx-auto flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="shrink-0">
          <h1 className="text-3xl font-black text-slate-900 tracking-tight flex items-center gap-2">
            <span className="text-[#3b5bdb]">MCAT</span> PULSE
          </h1>
          <p className="text-slate-400 font-bold text-sm tracking-wide mt-1 uppercase">SMART CALENDAR</p>
        </div>

        <div className="flex flex-wrap items-center justify-center gap-4 bg-white p-2 rounded-[28px] shadow-sm border border-slate-100">
           <div className="flex bg-slate-50 p-1 rounded-2xl">
             {(['daily', 'weekly', 'monthly'] as ViewType[]).map(v => (
               <button 
                 key={v}
                 onClick={() => setView(v)}
                 className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${view === v ? 'bg-white text-[#3b5bdb] shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
               >
                 {v}
               </button>
             ))}
           </div>
           <div className="h-6 w-px bg-slate-200" />
           <div className="flex items-center gap-2">
             <button onClick={() => navigate(-1)} className="p-2 hover:bg-slate-50 rounded-xl transition-colors"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M15 18l-6-6 6-6"/></svg></button>
             <button onClick={() => setBaseDate(new Date())} className="px-4 py-2 text-xs font-black text-[#3b5bdb] uppercase tracking-tighter hover:bg-slate-50 rounded-xl">Today</button>
             <button onClick={() => navigate(1)} className="p-2 hover:bg-slate-50 rounded-xl transition-colors"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M9 18l6-6-6-6"/></svg></button>
           </div>
        </div>

        <div className="w-full sm:w-auto max-w-md bg-white rounded-3xl p-2 shadow-sm border border-slate-100 flex items-center gap-2">
          <input
            type="text"
            value={userInput}
            onChange={(e) => setUserInput(e.target.value)}
            placeholder="Ask AI for changes..."
            className="flex-1 bg-transparent border-none px-4 py-2 font-semibold text-sm focus:ring-0 outline-none placeholder:text-slate-300"
          />
          <button
            onClick={handleAiUpdate}
            disabled={isAiLoading}
            className="bg-[#3b5bdb] text-white px-6 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-[#2f49b1] transition-all disabled:opacity-50"
          >
            {isAiLoading ? '...' : 'SYNC'}
          </button>
        </div>
      </header>

      {aiMessage && (
        <div className="max-w-2xl mx-auto mt-8 px-6 animate-in slide-in-from-top-4">
           <div className="bg-[#3b5bdb] text-white rounded-3xl p-6 shadow-xl relative">
             <p className="font-bold leading-relaxed">{aiMessage}</p>
             <button onClick={() => setAiMessage(null)} className="absolute top-4 right-4 opacity-50 hover:opacity-100"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
           </div>
        </div>
      )}

      <main className="mt-12 px-8 max-w-[1600px] mx-auto overflow-hidden">
        {view === 'monthly' ? (
          <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
            <div className="grid grid-cols-7 border-b border-slate-50">
              {DAYS_SHORT.map(d => <div key={d} className="py-4 text-center text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{d}</div>)}
            </div>
            <div className="grid grid-cols-7">
              {monthGrid.map(({ date, currentMonth }, i) => {
                const dateKey = formatDateKey(date);
                const dayTasks = tasks.filter(t => t.date === dateKey);
                const isSelected = dateKey === formatDateKey(baseDate);
                const isToday = dateKey === formatDateKey(new Date());
                return (
                  <div 
                    key={i} 
                    onClick={() => { setBaseDate(new Date(date)); setView('daily'); }}
                    className={`min-h-[140px] p-2 border-r border-b border-slate-50 cursor-pointer transition-all hover:bg-slate-50 group ${!currentMonth ? 'opacity-30' : ''} ${isSelected ? 'bg-blue-50/30' : ''}`}
                  >
                    <div className="flex justify-between items-center mb-1.5">
                      <span className={`text-[11px] font-black ${isToday ? 'bg-[#3b5bdb] text-white w-6 h-6 flex items-center justify-center rounded-lg shadow-sm' : isSelected ? 'text-[#3b5bdb]' : 'text-slate-400'}`}>
                        {date.getDate()}
                      </span>
                    </div>
                    <div className="flex flex-col gap-1 overflow-hidden">
                      {dayTasks.slice(0, 3).map(t => (
                        <div key={t.id} className={`px-2 py-1 rounded-md text-[8px] font-bold truncate flex items-center gap-1.5 ${SECTION_STYLES[t.section].bg} ${SECTION_STYLES[t.section].text} ${t.completed ? 'opacity-40' : ''}`}>
                          <span className="shrink-0 w-1 h-1 rounded-full bg-current opacity-50" />
                          <span className="truncate">{t.section}: {t.title}</span>
                        </div>
                      ))}
                      {dayTasks.length > 3 && (
                        <span className="text-[8px] font-black text-slate-300 ml-1">+{dayTasks.length - 3} more</span>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : view === 'weekly' ? (
          <div className="space-y-6 pb-8">
            {/* Weekdays Row: Mon-Fri (5 columns) */}
            <div className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-5 gap-4">
              {currentRangeDays.slice(0, 5).map((d, i) => (
                <DayColumn
                  key={i}
                  date={d}
                  tasks={tasks.filter(t => t.date === formatDateKey(d))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              ))}
            </div>
            {/* Weekend Row: Sat-Sun (centered or aligned) */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
              <div className="lg:col-start-2">
                <DayColumn
                  date={currentRangeDays[5]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[5]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              </div>
              <div className="lg:col-start-3">
                <DayColumn
                  date={currentRangeDays[6]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[6]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              </div>
            </div>
          </div>
        ) : (
          <div className="flex justify-center pb-8">
            <DayColumn
              date={currentRangeDays[0]}
              tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[0]))}
              onToggleTask={toggleTask}
              onDragStartTask={handleDragStartTask}
              onDropTask={moveTask}
              onAddTask={handleAddTask}
              onEditTask={handleEditTask}
              isFocused
            />
          </div>
        )}
      </main>

      {/* Progress Footer */}
      <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur-xl px-10 py-5 rounded-[40px] shadow-[0_20px_60px_rgba(0,0,0,0.1)] border border-white flex items-center gap-8 z-50">
        <div className="flex flex-col">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Mastery</span>
          <span className="text-xl font-black text-[#3b5bdb]">{progressPercent}%</span>
        </div>
        <div className="w-48 sm:w-64 h-3 bg-slate-100 rounded-full overflow-hidden">
          <div className="h-full bg-gradient-to-r from-blue-400 to-[#3b5bdb] transition-all duration-1000" style={{ width: `${progressPercent}%` }} />
        </div>
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-2xl bg-[#3b5bdb] flex items-center justify-center text-white font-black text-xs">{tasks.filter(t => t.completed).length}</div>
          <span className="hidden sm:inline text-xs font-bold text-slate-500">Done</span>
        </div>
      </div>

      <EditTaskModal isOpen={isModalOpen} task={currentTaskToEdit} onClose={() => setIsModalOpen(false)} onSave={saveTask} onDelete={deleteTask} />
    </div>
  );
};

export default App;

export type MCATSection = 
  | 'Biology' 
  | 'Biochemistry' 
  | 'General Chemistry' 
  | 'Organic Chemistry' 
  | 'Physics' 
  | 'Behavioral Sciences' 
  | 'CARS' 
  | 'Practice Exam';

export type RecurrenceType = 'None' | 'Daily';
export type ViewType = 'daily' | 'weekly' | 'monthly';

export interface StudyTask {
  id: string;
  groupId?: string; // Links recurring tasks together
  title: string;
  description: string;
  section: MCATSection;
  completed: boolean;
  date: string; // ISO format YYYY-MM-DD
  duration: string;
  recurrence?: RecurrenceType;
}

export interface AIResponse {
  suggestion: string;
  updatedTasks: StudyTask[];
}

import React, { useState, useEffect, useMemo } from 'react';
import DayColumn from './components/DayColumn';
import EditTaskModal from './components/EditTaskModal';
import { StudyTask, ViewType } from './types';
import { INITIAL_TASKS, formatDateKey, DAYS_SHORT, SECTION_STYLES } from './constants';
import { adaptSchedule } from './services/geminiService';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(INITIAL_TASKS);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');
  const [view, setView] = useState<ViewType>('weekly');
  const [baseDate, setBaseDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('mcat-schedule-v3');
    if (saved) {
      setTasks(JSON.parse(saved));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('mcat-schedule-v3', JSON.stringify(tasks));
  }, [tasks]);

  // Task Handlers
  const toggleTask = (id: string) => setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  const handleDragStartTask = (e: React.DragEvent, id: string) => e.dataTransfer.setData('taskId', id);
  const moveTask = (taskId: string, targetDate: string) => setTasks(prev => prev.map(t => t.id === taskId ? { ...t, date: targetDate } : t));
  const handleEditTask = (task: StudyTask) => { setCurrentTaskToEdit(task); setIsModalOpen(true); };
  const handleAddTask = (dateKey: string) => { setCurrentTaskToEdit({ date: dateKey, completed: false, description: '', section: 'Biology', duration: '1h', recurrence: 'None' }); setIsModalOpen(true); };
  const deleteTask = (id: string) => setTasks(prev => prev.filter(t => t.id !== id));

  const saveTask = (task: StudyTask, scope: 'single' | 'future' = 'single') => {
    if (task.id) {
      if (scope === 'future' && task.groupId) {
        // Update this and all future tasks in the same group
        setTasks(prev => prev.map(t => {
          if (t.groupId === task.groupId && t.date >= task.date) {
            return { ...t, title: task.title, section: task.section, duration: task.duration };
          }
          return t;
        }));
      } else {
        // Standard single update
        setTasks(prev => prev.map(t => t.id === task.id ? task : t));
      }
    } else {
      // New Task
      if (task.recurrence === 'Daily') {
        const groupId = Math.random().toString(36).substr(2, 9);
        const newTasks: StudyTask[] = Array.from({ length: 7 }).map((_, i) => {
          const d = new Date(task.date);
          d.setDate(d.getDate() + i);
          return { ...task, id: Math.random().toString(36).substr(2, 9), groupId, date: formatDateKey(d) };
        });
        setTasks(prev => [...prev, ...newTasks]);
      } else {
        setTasks(prev => [...prev, { ...task, id: Math.random().toString(36).substr(2, 9) }]);
      }
    }
  };

  // Date Logic
  const navigate = (amount: number) => {
    const newDate = new Date(baseDate);
    if (view === 'daily') newDate.setDate(newDate.getDate() + amount);
    if (view === 'weekly') newDate.setDate(newDate.getDate() + (amount * 7));
    if (view === 'monthly') newDate.setMonth(newDate.getMonth() + amount);
    setBaseDate(newDate);
  };

  const currentRangeDays = useMemo(() => {
    if (view === 'daily') return [new Date(baseDate)];
    if (view === 'weekly') {
      const start = new Date(baseDate);
      const day = start.getDay();
      const shift = day === 0 ? 6 : day - 1;
      start.setDate(start.getDate() - shift); 
      return Array.from({ length: 7 }).map((_, i) => {
        const d = new Date(start);
        d.setDate(d.getDate() + i);
        return d;
      });
    }
    return [];
  }, [view, baseDate]);

  const monthGrid = useMemo(() => {
    if (view !== 'monthly') return [];
    const start = new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
    const end = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0);
    const startDay = start.getDay();
    const padding = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < padding; i++) {
      const d = new Date(start);
      d.setDate(d.getDate() - (padding - i));
      days.push({ date: d, currentMonth: false });
    }
    for (let i = 1; i <= end.getDate(); i++) {
      days.push({ date: new Date(baseDate.getFullYear(), baseDate.getMonth(), i), currentMonth: true });
    }
    const totalSlots = days.length > 35 ? 42 : 35;
    const remaining = totalSlots - days.length;
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(end);
      d.setDate(d.getDate() + i);
      days.push({ date: d, currentMonth: false });
    }
    return days;
  }, [view, baseDate]);

  const handleAiUpdate = async () => {
    if (!userInput.trim() && tasks.every(t => !t.completed)) return;
    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput || "Adjust my schedule based on my progress.");
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      setAiMessage("Something went wrong with the AI coach.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const progressPercent = Math.round((tasks.filter(t => t.completed).length / (tasks.length || 1)) * 100);

  return (
    <div className="min-h-screen bg-[#f8faff] pb-40">
      <header className="px-10 pt-10 max-w-[1900px] mx-auto flex flex-col md:flex-row items-center justify-between gap-8">
        <div className="shrink-0">
          <h1 className="text-4xl font-black text-slate-900 tracking-tighter flex items-center gap-2">
            <span className="text-[#3b5bdb]">MCAT</span> PULSE
          </h1>
          <p className="text-slate-400 font-bold text-sm tracking-widest mt-1 uppercase">PRECISION TRACKER</p>
        </div>

        <div className="flex flex-wrap items-center justify-center gap-6 bg-white p-2.5 rounded-[32px] shadow-sm border border-slate-100">
           <div className="flex bg-slate-50 p-1 rounded-2xl">
             {(['daily', 'weekly', 'monthly'] as ViewType[]).map(v => (
               <button 
                 key={v}
                 onClick={() => setView(v)}
                 className={`px-8 py-2.5 rounded-xl text-xs font-black uppercase tracking-[0.1em] transition-all ${view === v ? 'bg-white text-[#3b5bdb] shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
               >
                 {v}
               </button>
             ))}
           </div>
           <div className="h-8 w-px bg-slate-200" />
           <div className="flex items-center gap-3">
             <button onClick={() => navigate(-1)} className="p-2.5 hover:bg-slate-50 rounded-2xl transition-colors"><svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M15 18l-6-6 6-6"/></svg></button>
             <button onClick={() => setBaseDate(new Date())} className="px-5 py-2.5 text-sm font-black text-[#3b5bdb] uppercase tracking-tighter hover:bg-slate-50 rounded-2xl">Today</button>
             <button onClick={() => navigate(1)} className="p-2.5 hover:bg-slate-50 rounded-2xl transition-colors"><svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M9 18l6-6-6-6"/></svg></button>
           </div>
        </div>

        <div className="w-full sm:w-auto max-w-lg bg-white rounded-[32px] p-2.5 shadow-sm border border-slate-100 flex items-center gap-3">
          <input
            type="text"
            value={userInput}
            onChange={(e) => setUserInput(e.target.value)}
            placeholder="Adaptive scheduling AI..."
            className="flex-1 bg-transparent border-none px-5 py-3 font-bold text-sm focus:ring-0 outline-none placeholder:text-slate-300"
          />
          <button
            onClick={handleAiUpdate}
            disabled={isAiLoading}
            className="bg-[#3b5bdb] text-white px-8 py-3 rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-[#2f49b1] transition-all disabled:opacity-50"
          >
            {isAiLoading ? '...' : 'SYNC'}
          </button>
        </div>
      </header>

      {aiMessage && (
        <div className="max-w-3xl mx-auto mt-10 px-8 animate-in slide-in-from-top-6">
           <div className="bg-[#3b5bdb] text-white rounded-[40px] p-8 shadow-2xl relative">
             <p className="font-bold text-lg leading-relaxed">{aiMessage}</p>
             <button onClick={() => setAiMessage(null)} className="absolute top-6 right-6 opacity-60 hover:opacity-100 transition-opacity"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
           </div>
        </div>
      )}

      <main className="mt-14 px-10 max-w-[1900px] mx-auto overflow-visible">
        {view === 'monthly' ? (
          <div className="bg-white rounded-[48px] shadow-sm border border-slate-100 overflow-hidden">
            <div className="grid grid-cols-7 border-b border-slate-50">
              {DAYS_SHORT.map(d => <div key={d} className="py-6 text-center text-xs font-black text-slate-400 uppercase tracking-[0.25em]">{d}</div>)}
            </div>
            <div className="grid grid-cols-7">
              {monthGrid.map(({ date, currentMonth }, i) => {
                const dateKey = formatDateKey(date);
                const dayTasks = tasks.filter(t => t.date === dateKey);
                const isSelected = dateKey === formatDateKey(baseDate);
                const isToday = dateKey === formatDateKey(new Date());
                return (
                  <div 
                    key={i} 
                    onClick={() => { setBaseDate(new Date(date)); setView('daily'); }}
                    className={`min-h-[160px] p-3 border-r border-b border-slate-50 cursor-pointer transition-all hover:bg-slate-50/80 group ${!currentMonth ? 'opacity-25' : ''} ${isSelected ? 'bg-blue-50/20' : ''}`}
                  >
                    <div className="flex justify-between items-center mb-2.5">
                      <span className={`text-xs font-black ${isToday ? 'bg-[#3b5bdb] text-white w-7 h-7 flex items-center justify-center rounded-xl shadow-md' : isSelected ? 'text-[#3b5bdb]' : 'text-slate-400'}`}>
                        {date.getDate()}
                      </span>
                    </div>
                    <div className="flex flex-col gap-1.5 overflow-hidden">
                      {dayTasks.slice(0, 4).map(t => (
                        <div key={t.id} className={`px-2.5 py-1.5 rounded-xl text-[9px] font-bold truncate flex items-center gap-2 ${SECTION_STYLES[t.section].bg} ${SECTION_STYLES[t.section].text} ${t.completed ? 'opacity-30' : ''}`}>
                          <span className="shrink-0 w-1.5 h-1.5 rounded-full bg-current opacity-40" />
                          <span className="truncate">{t.section}: {t.title}</span>
                        </div>
                      ))}
                      {dayTasks.length > 4 && (
                        <span className="text-[9px] font-black text-slate-300 ml-1.5">+{dayTasks.length - 4} more</span>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : view === 'weekly' ? (
          <div className="space-y-10 pb-12">
            {/* Weekdays Row: Mon-Fri (5 columns) */}
            <div className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-5 gap-8">
              {currentRangeDays.slice(0, 5).map((d, i) => (
                <DayColumn
                  key={i}
                  date={d}
                  tasks={tasks.filter(t => t.date === formatDateKey(d))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              ))}
            </div>
            {/* Weekend Row */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-8">
              <div className="lg:col-start-2">
                <DayColumn
                  date={currentRangeDays[5]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[5]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              </div>
              <div className="lg:col-start-3">
                <DayColumn
                  date={currentRangeDays[6]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[6]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              </div>
            </div>
          </div>
        ) : (
          <div className="flex justify-center pb-12">
            <DayColumn
              date={currentRangeDays[0]}
              tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[0]))}
              onToggleTask={toggleTask}
              onDragStartTask={handleDragStartTask}
              onDropTask={moveTask}
              onAddTask={handleAddTask}
              onEditTask={handleEditTask}
              isFocused
            />
          </div>
        )}
      </main>

      {/* Progress Footer */}
      <div className="fixed bottom-12 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur-2xl px-12 py-6 rounded-[48px] shadow-[0_30px_80px_rgba(0,0,0,0.12)] border border-white/50 flex items-center gap-10 z-[60]">
        <div className="flex flex-col">
          <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Daily Goal</span>
          <span className="text-2xl font-black text-[#3b5bdb] tracking-tighter">{progressPercent}%</span>
        </div>
        <div className="w-56 sm:w-80 h-4 bg-slate-100 rounded-full overflow-hidden p-1 shadow-inner">
          <div className="h-full bg-gradient-to-r from-blue-400 to-[#3b5bdb] rounded-full transition-all duration-1000 shadow-[0_0_15px_rgba(59,91,219,0.3)]" style={{ width: `${progressPercent}%` }} />
        </div>
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-2xl bg-[#3b5bdb] flex items-center justify-center text-white font-black text-sm shadow-lg shadow-blue-200">{tasks.filter(t => t.completed).length}</div>
          <span className="hidden sm:inline text-sm font-black text-slate-500 uppercase tracking-widest">Tasks Done</span>
        </div>
      </div>

      <EditTaskModal isOpen={isModalOpen} task={currentTaskToEdit} onClose={() => setIsModalOpen(false)} onSave={saveTask} onDelete={deleteTask} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { StudyTask } from '../types';
import TaskCard from './TaskCard';
import { formatDateKey } from '../constants';

interface DayColumnProps {
  date: Date;
  tasks: StudyTask[];
  onToggleTask: (id: string) => void;
  onDropTask: (taskId: string, targetDate: string) => void;
  onDragStartTask: (e: React.DragEvent, id: string) => void;
  onAddTask: (date: string) => void;
  onEditTask: (task: StudyTask) => void;
  isFocused?: boolean;
}

const DayColumn: React.FC<DayColumnProps> = ({
  date,
  tasks,
  onToggleTask,
  onDropTask,
  onDragStartTask,
  onAddTask,
  onEditTask,
  isFocused = false
}) => {
  const [isOver, setIsOver] = useState(false);
  const dateKey = formatDateKey(date);
  const isToday = dateKey === formatDateKey(new Date());

  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const dayName = dayNames[date.getDay()];
  const dayNum = date.getDate();

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(true);
  };

  const handleDragLeave = () => {
    setIsOver(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(false);
    const taskId = e.dataTransfer.getData('taskId');
    onDropTask(taskId, dateKey);
  };

  return (
    <div
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`flex flex-col rounded-[40px] border-2 p-8 transition-all h-full ${
        isFocused ? 'min-h-[700px] w-full max-w-[550px]' : 'min-h-[500px] w-full'
      } ${
        isOver 
          ? 'bg-blue-50/50 border-blue-400 border-dashed scale-[1.02]' 
          : isToday
            ? 'bg-white border-[#3b5bdb]/30 shadow-[0_20px_50px_rgba(59,91,219,0.12)] ring-1 ring-[#3b5bdb]/5'
            : 'bg-[#f5f8ff] border-transparent'
      }`}
    >
      <div className="flex justify-between items-center mb-10">
        <div>
          <h3 className={`text-2xl font-black tracking-tighter ${isToday ? 'text-[#3b5bdb]' : 'text-slate-800'}`}>
            {dayName} {dayNum} {isToday && <span className="text-[0.85em] font-bold ml-1.5 opacity-80">(Today)</span>}
          </h3>
          <p className="text-slate-400 font-bold text-sm mt-1 uppercase tracking-widest opacity-60">
            {tasks.length} {tasks.length === 1 ? 'task' : 'tasks'}
          </p>
        </div>

        <button 
          onClick={() => onAddTask(dateKey)}
          className="w-12 h-12 rounded-[20px] bg-white shadow-[0_10px_25px_rgba(0,0,0,0.06)] border border-slate-100 flex items-center justify-center text-slate-400 hover:text-[#3b5bdb] hover:border-[#3b5bdb]/30 transition-all active:scale-90"
        >
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
            <line x1="12" y1="5" x2="12" y2="19"></line>
            <line x1="5" y1="12" x2="19" y2="12"></line>
          </svg>
        </button>
      </div>

      <div className="flex-1 space-y-5">
        {tasks.map((task) => (
          <TaskCard
            key={task.id}
            task={task}
            onToggle={onToggleTask}
            onDragStart={onDragStartTask}
            onEdit={onEditTask}
          />
        ))}
        {tasks.length === 0 && (
          <div className="h-32 border-2 border-dashed border-slate-200/50 rounded-[32px] flex items-center justify-center text-slate-300 font-black text-xs italic p-6 text-center opacity-40">
            Rest & Recharge
          </div>
        )}
      </div>
    </div>
  );
};

export default DayColumn;

import React, { useState, useEffect } from 'react';
import { StudyTask, MCATSection, RecurrenceType } from '../types';
import { SECTION_STYLES } from '../constants';

interface EditTaskModalProps {
  task: Partial<StudyTask> | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: StudyTask, scope?: 'single' | 'future') => void;
  onDelete?: (id: string) => void;
}

const EditTaskModal: React.FC<EditTaskModalProps> = ({ task, isOpen, onClose, onSave, onDelete }) => {
  const [title, setTitle] = useState('');
  const [section, setSection] = useState<MCATSection>('Biology');
  const [duration, setDuration] = useState('');
  const [recurrence, setRecurrence] = useState<RecurrenceType>('None');
  const [date, setDate] = useState('');
  const [saveScope, setSaveScope] = useState<'single' | 'future'>('single');

  useEffect(() => {
    if (task) {
      setTitle(task.title || '');
      setSection(task.section || 'Biology');
      setDuration(task.duration || '');
      setRecurrence(task.recurrence || 'None');
      setDate(task.date || '');
      setSaveScope('single');
    }
  }, [task, isOpen]);

  if (!isOpen || !task) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      ...task,
      title,
      section,
      duration,
      recurrence,
      date,
    } as StudyTask, saveScope);
    onClose();
  };

  const isRecurring = !!task.groupId;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white w-full max-w-lg rounded-[48px] p-10 shadow-2xl animate-in zoom-in-95 duration-300">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">
            {task.id ? 'Edit Task' : 'New Task'}
          </h2>
          <button onClick={onClose} className="text-slate-300 hover:text-slate-600 transition-colors">
            <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-8">
          <div>
            <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-3 ml-1">Task Title</label>
            <input
              autoFocus
              required
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="w-full bg-slate-50 border-2 border-slate-100 rounded-[24px] px-6 py-4 font-bold text-slate-800 focus:border-[#3b5bdb] focus:bg-white focus:ring-0 outline-none transition-all"
              placeholder="e.g. Molecular Genetics"
            />
          </div>

          <div className="grid grid-cols-2 gap-6">
             <div>
              <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-3 ml-1">Date</label>
              <input
                required
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-[24px] px-6 py-4 font-bold text-slate-800 focus:border-[#3b5bdb] focus:bg-white focus:ring-0 outline-none transition-all"
              />
            </div>
            <div>
              <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-3 ml-1">Duration</label>
              <input
                required
                type="text"
                value={duration}
                onChange={(e) => setDuration(e.target.value)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-[24px] px-6 py-4 font-bold text-slate-800 focus:border-[#3b5bdb] focus:bg-white focus:ring-0 outline-none transition-all"
                placeholder="e.g. 2h"
              />
            </div>
          </div>

          <div>
             <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-3 ml-1">Subject</label>
              <select
                value={section}
                onChange={(e) => setSection(e.target.value as MCATSection)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-[24px] px-6 py-4 font-bold text-slate-800 focus:border-[#3b5bdb] focus:bg-white focus:ring-0 outline-none transition-all appearance-none cursor-pointer"
              >
                {Object.keys(SECTION_STYLES).map((s) => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
          </div>

          {task.id && isRecurring && (
            <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100">
              <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Edit Scope</label>
              <div className="flex gap-3">
                <button
                  type="button"
                  onClick={() => setSaveScope('single')}
                  className={`flex-1 py-3.5 rounded-2xl font-black text-[11px] uppercase tracking-widest transition-all border-2 ${
                    saveScope === 'single'
                      ? 'bg-white border-[#3b5bdb] text-[#3b5bdb] shadow-md'
                      : 'bg-transparent border-slate-100 text-slate-400 opacity-60'
                  }`}
                >
                  This day
                </button>
                <button
                  type="button"
                  onClick={() => setSaveScope('future')}
                  className={`flex-1 py-3.5 rounded-2xl font-black text-[11px] uppercase tracking-widest transition-all border-2 ${
                    saveScope === 'future'
                      ? 'bg-white border-[#3b5bdb] text-[#3b5bdb] shadow-md'
                      : 'bg-transparent border-slate-100 text-slate-400 opacity-60'
                  }`}
                >
                  This and Future
                </button>
              </div>
            </div>
          )}

          {!task.id && (
            <div>
              <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-3 ml-1">Frequency</label>
              <div className="flex gap-3">
                {(['None', 'Daily'] as RecurrenceType[]).map((type) => (
                  <button
                    key={type}
                    type="button"
                    onClick={() => setRecurrence(type)}
                    className={`flex-1 py-4 rounded-[20px] font-black text-xs uppercase tracking-widest transition-all border-2 ${
                      recurrence === type 
                        ? 'bg-slate-900 text-white border-slate-900 shadow-xl scale-[1.02]' 
                        : 'bg-white text-slate-400 border-slate-100 hover:border-slate-200'
                    }`}
                  >
                    {type === 'None' ? 'One-time' : 'Repeat Daily'}
                  </button>
                ))}
              </div>
            </div>
          )}

          <div className="pt-6 flex gap-4">
            <button
              type="submit"
              className="flex-1 bg-[#3b5bdb] text-white py-5 rounded-[24px] font-black uppercase tracking-[0.2em] text-xs hover:bg-[#2f49b1] shadow-xl shadow-blue-100 transition-all active:scale-[0.98]"
            >
              {task.id ? 'Update Schedule' : 'Create Task'}
            </button>
            {task.id && onDelete && (
              <button
                type="button"
                onClick={() => {
                  if (confirm('Delete this task?')) {
                    onDelete(task.id!);
                    onClose();
                  }
                }}
                className="w-16 bg-rose-50 text-rose-500 rounded-[24px] flex items-center justify-center hover:bg-rose-100 transition-all shadow-sm border border-rose-100"
              >
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default EditTaskModal;

export type MCATSection = 
  | 'Biology' 
  | 'Biochemistry' 
  | 'General Chemistry' 
  | 'Organic Chemistry' 
  | 'Physics' 
  | 'Behavioral Sciences' 
  | 'CARS' 
  | 'Practice Exam';

export type RecurrenceType = 'None' | 'Daily';
export type ViewType = 'daily' | 'weekly' | 'monthly';

export interface StudyTask {
  id: string;
  groupId?: string; // Links recurring tasks together
  title: string;
  description: string;
  section: MCATSection;
  completed: boolean;
  date: string; // ISO format YYYY-MM-DD
  duration: string;
  recurrence?: RecurrenceType;
}

export interface AIResponse {
  suggestion: string;
  updatedTasks: StudyTask[];
}

import React, { useState, useEffect, useMemo } from 'react';
import DayColumn from './components/DayColumn';
import EditTaskModal from './components/EditTaskModal';
import { StudyTask, ViewType } from './types';
import { INITIAL_TASKS, formatDateKey, DAYS_SHORT, SECTION_STYLES } from './constants';
import { adaptSchedule } from './services/geminiService';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(INITIAL_TASKS);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');
  const [view, setView] = useState<ViewType>('weekly');
  const [baseDate, setBaseDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('mcat-pulse-v3');
    if (saved) {
      setTasks(JSON.parse(saved));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('mcat-pulse-v3', JSON.stringify(tasks));
  }, [tasks]);

  // Task Handlers
  const toggleTask = (id: string) => setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  const handleDragStartTask = (e: React.DragEvent, id: string) => e.dataTransfer.setData('taskId', id);
  const moveTask = (taskId: string, targetDate: string) => setTasks(prev => prev.map(t => t.id === taskId ? { ...t, date: targetDate } : t));
  const handleEditTask = (task: StudyTask) => { setCurrentTaskToEdit(task); setIsModalOpen(true); };
  const handleAddTask = (dateKey: string) => { setCurrentTaskToEdit({ date: dateKey, completed: false, description: '', section: 'Biology', duration: '1h', recurrence: 'None' }); setIsModalOpen(true); };
  const deleteTask = (id: string) => setTasks(prev => prev.filter(t => t.id !== id));

  const saveTask = (task: StudyTask, scope: 'single' | 'future' = 'single') => {
    if (task.id) {
      if (scope === 'future' && task.groupId) {
        // Update this and all future tasks in the same group
        setTasks(prev => prev.map(t => {
          if (t.groupId === task.groupId && t.date >= task.date) {
            // We update title, section, duration but keep the specific date and completion status
            return { ...t, title: task.title, section: task.section, duration: task.duration };
          }
          return t;
        }));
      } else {
        // Standard single update
        setTasks(prev => prev.map(t => t.id === task.id ? task : t));
      }
    } else {
      // New Task creation
      if (task.recurrence === 'Daily') {
        const groupId = Math.random().toString(36).substr(2, 9);
        const newTasks: StudyTask[] = Array.from({ length: 7 }).map((_, i) => {
          const d = new Date(task.date);
          d.setDate(d.getDate() + i);
          return { 
            ...task, 
            id: Math.random().toString(36).substr(2, 9), 
            groupId, 
            date: formatDateKey(d) 
          };
        });
        setTasks(prev => [...prev, ...newTasks]);
      } else {
        setTasks(prev => [...prev, { ...task, id: Math.random().toString(36).substr(2, 9) }]);
      }
    }
  };

  // Date Logic
  const navigate = (amount: number) => {
    const newDate = new Date(baseDate);
    if (view === 'daily') newDate.setDate(newDate.getDate() + amount);
    if (view === 'weekly') newDate.setDate(newDate.getDate() + (amount * 7));
    if (view === 'monthly') newDate.setMonth(newDate.getMonth() + amount);
    setBaseDate(newDate);
  };

  const currentRangeDays = useMemo(() => {
    if (view === 'daily') return [new Date(baseDate)];
    if (view === 'weekly') {
      const start = new Date(baseDate);
      const day = start.getDay();
      const shift = day === 0 ? 6 : day - 1;
      start.setDate(start.getDate() - shift); 
      return Array.from({ length: 7 }).map((_, i) => {
        const d = new Date(start);
        d.setDate(d.getDate() + i);
        return d;
      });
    }
    return [];
  }, [view, baseDate]);

  const monthGrid = useMemo(() => {
    if (view !== 'monthly') return [];
    const start = new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
    const end = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0);
    const startDay = start.getDay();
    const padding = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < padding; i++) {
      const d = new Date(start);
      d.setDate(d.getDate() - (padding - i));
      days.push({ date: d, currentMonth: false });
    }
    for (let i = 1; i <= end.getDate(); i++) {
      days.push({ date: new Date(baseDate.getFullYear(), baseDate.getMonth(), i), currentMonth: true });
    }
    const totalSlots = days.length > 35 ? 42 : 35;
    const remaining = totalSlots - days.length;
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(end);
      d.setDate(d.getDate() + i);
      days.push({ date: d, currentMonth: false });
    }
    return days;
  }, [view, baseDate]);

  const handleAiUpdate = async () => {
    if (!userInput.trim() && tasks.every(t => !t.completed)) return;
    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput || "Optimize my flow based on recent progress.");
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      setAiMessage("Sync failed. Check your connection.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const progressPercent = Math.round((tasks.filter(t => t.completed).length / (tasks.length || 1)) * 100);

  return (
    <div className="min-h-screen bg-[#f8faff] pb-40">
      <header className="px-10 pt-10 max-w-[1900px] mx-auto flex flex-col md:flex-row items-center justify-between gap-10">
        <div className="shrink-0">
          <h1 className="text-4xl font-black text-slate-900 tracking-tight flex items-center gap-2">
            <span className="text-[#3b5bdb]">MCAT</span> PULSE
          </h1>
          <p className="text-slate-400 font-bold text-sm tracking-[0.2em] mt-1 uppercase">PRECISION PLANNER</p>
        </div>

        <div className="flex flex-wrap items-center justify-center gap-6 bg-white p-3 rounded-[32px] shadow-sm border border-slate-100">
           <div className="flex bg-slate-50 p-1 rounded-2xl">
             {(['daily', 'weekly', 'monthly'] as ViewType[]).map(v => (
               <button 
                 key={v}
                 onClick={() => setView(v)}
                 className={`px-8 py-2.5 rounded-xl text-xs font-black uppercase tracking-[0.1em] transition-all ${view === v ? 'bg-white text-[#3b5bdb] shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
               >
                 {v}
               </button>
             ))}
           </div>
           <div className="h-8 w-px bg-slate-200" />
           <div className="flex items-center gap-3">
             <button onClick={() => navigate(-1)} className="p-2.5 hover:bg-slate-50 rounded-2xl transition-colors"><svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M15 18l-6-6 6-6"/></svg></button>
             <button onClick={() => setBaseDate(new Date())} className="px-5 py-2.5 text-xs font-black text-[#3b5bdb] uppercase tracking-tighter hover:bg-slate-50 rounded-2xl">Today</button>
             <button onClick={() => navigate(1)} className="p-2.5 hover:bg-slate-50 rounded-2xl transition-colors"><svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M9 18l6-6-6-6"/></svg></button>
           </div>
        </div>

        <div className="w-full sm:w-auto max-w-lg bg-white rounded-[32px] p-2.5 shadow-sm border border-slate-100 flex items-center gap-3">
          <input
            type="text"
            value={userInput}
            onChange={(e) => setUserInput(e.target.value)}
            placeholder="AI Schedule Adaptation..."
            className="flex-1 bg-transparent border-none px-5 py-3 font-bold text-sm focus:ring-0 outline-none placeholder:text-slate-300"
          />
          <button
            onClick={handleAiUpdate}
            disabled={isAiLoading}
            className="bg-[#3b5bdb] text-white px-8 py-3 rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-[#2f49b1] transition-all disabled:opacity-50"
          >
            {isAiLoading ? '...' : 'SYNC'}
          </button>
        </div>
      </header>

      {aiMessage && (
        <div className="max-w-4xl mx-auto mt-12 px-10 animate-in slide-in-from-top-6">
           <div className="bg-[#3b5bdb] text-white rounded-[40px] p-8 shadow-2xl relative">
             <p className="font-bold text-lg leading-relaxed">{aiMessage}</p>
             <button onClick={() => setAiMessage(null)} className="absolute top-6 right-6 opacity-60 hover:opacity-100 transition-opacity"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
           </div>
        </div>
      )}

      <main className="mt-16 px-10 max-w-[1900px] mx-auto overflow-visible">
        {view === 'monthly' ? (
          <div className="bg-white rounded-[48px] shadow-sm border border-slate-100 overflow-hidden">
            <div className="grid grid-cols-7 border-b border-slate-50">
              {DAYS_SHORT.map(d => <div key={d} className="py-6 text-center text-xs font-black text-slate-400 uppercase tracking-[0.25em]">{d}</div>)}
            </div>
            <div className="grid grid-cols-7">
              {monthGrid.map(({ date, currentMonth }, i) => {
                const dateKey = formatDateKey(date);
                const dayTasks = tasks.filter(t => t.date === dateKey);
                const isSelected = dateKey === formatDateKey(baseDate);
                const isToday = dateKey === formatDateKey(new Date());
                return (
                  <div 
                    key={i} 
                    onClick={() => { setBaseDate(new Date(date)); setView('daily'); }}
                    className={`min-h-[160px] p-4 border-r border-b border-slate-50 cursor-pointer transition-all hover:bg-slate-50 group ${!currentMonth ? 'opacity-25' : ''} ${isSelected ? 'bg-blue-50/20' : ''}`}
                  >
                    <div className="flex justify-between items-center mb-3">
                      <span className={`text-xs font-black ${isToday ? 'bg-[#3b5bdb] text-white w-7 h-7 flex items-center justify-center rounded-xl shadow-md' : isSelected ? 'text-[#3b5bdb]' : 'text-slate-400'}`}>
                        {date.getDate()}
                      </span>
                    </div>
                    <div className="flex flex-col gap-2 overflow-hidden">
                      {dayTasks.slice(0, 4).map(t => (
                        <div key={t.id} className={`px-2.5 py-1.5 rounded-xl text-[9px] font-bold truncate flex items-center gap-2 ${SECTION_STYLES[t.section].bg} ${SECTION_STYLES[t.section].text} ${t.completed ? 'opacity-30' : ''}`}>
                          <span className="shrink-0 w-1.5 h-1.5 rounded-full bg-current opacity-40" />
                          <span className="truncate">{t.section}: {t.title}</span>
                        </div>
                      ))}
                      {dayTasks.length > 4 && (
                        <span className="text-[9px] font-black text-slate-300 ml-1.5">+{dayTasks.length - 4} more</span>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : view === 'weekly' ? (
          <div className="space-y-12 pb-16">
            {/* Weekdays Row: Mon-Fri (5 columns) */}
            <div className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-5 gap-10">
              {currentRangeDays.slice(0, 5).map((d, i) => (
                <DayColumn
                  key={i}
                  date={d}
                  tasks={tasks.filter(t => t.date === formatDateKey(d))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              ))}
            </div>
            {/* Weekend Row: Sat-Sun (centered) */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-10">
              <div className="lg:col-start-2">
                <DayColumn
                  date={currentRangeDays[5]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[5]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              </div>
              <div className="lg:col-start-3">
                <DayColumn
                  date={currentRangeDays[6]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[6]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              </div>
            </div>
          </div>
        ) : (
          <div className="flex justify-center pb-16">
            <DayColumn
              date={currentRangeDays[0]}
              tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[0]))}
              onToggleTask={toggleTask}
              onDragStartTask={handleDragStartTask}
              onDropTask={moveTask}
              onAddTask={handleAddTask}
              onEditTask={handleEditTask}
              isFocused
            />
          </div>
        )}
      </main>

      {/* Progress Footer */}
      <div className="fixed bottom-12 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur-2xl px-12 py-6 rounded-[48px] shadow-[0_30px_80px_rgba(0,0,0,0.12)] border border-white/50 flex items-center gap-12 z-[60]">
        <div className="flex flex-col">
          <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Efficiency</span>
          <span className="text-2xl font-black text-[#3b5bdb] tracking-tighter">{progressPercent}%</span>
        </div>
        <div className="w-64 sm:w-96 h-4 bg-slate-100 rounded-full overflow-hidden p-1 shadow-inner">
          <div className="h-full bg-gradient-to-r from-blue-400 to-[#3b5bdb] rounded-full transition-all duration-1000 shadow-[0_0_15px_rgba(59,91,219,0.3)]" style={{ width: `${progressPercent}%` }} />
        </div>
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-2xl bg-[#3b5bdb] flex items-center justify-center text-white font-black text-sm shadow-xl shadow-blue-200">{tasks.filter(t => t.completed).length}</div>
          <span className="hidden sm:inline text-sm font-black text-slate-500 uppercase tracking-widest">Tasks Done</span>
        </div>
      </div>

      <EditTaskModal isOpen={isModalOpen} task={currentTaskToEdit} onClose={() => setIsModalOpen(false)} onSave={saveTask} onDelete={deleteTask} />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { StudyTask, MCATSection, RecurrenceType } from '../types';
import { SECTION_STYLES } from '../constants';

interface EditTaskModalProps {
  task: Partial<StudyTask> | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: StudyTask, scope?: 'single' | 'future') => void;
  onDelete?: (id: string) => void;
}

const EditTaskModal: React.FC<EditTaskModalProps> = ({ task, isOpen, onClose, onSave, onDelete }) => {
  const [title, setTitle] = useState('');
  const [section, setSection] = useState<MCATSection>('Biology');
  const [duration, setDuration] = useState('');
  const [recurrence, setRecurrence] = useState<RecurrenceType>('None');
  const [date, setDate] = useState('');
  const [saveScope, setSaveScope] = useState<'single' | 'future'>('single');

  useEffect(() => {
    if (task) {
      setTitle(task.title || '');
      setSection(task.section || 'Biology');
      setDuration(task.duration || '');
      setRecurrence(task.recurrence || 'None');
      setDate(task.date || '');
      setSaveScope('single');
    }
  }, [task, isOpen]);

  if (!isOpen || !task) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      ...task,
      title,
      section,
      duration,
      recurrence,
      date,
    } as StudyTask, saveScope);
    onClose();
  };

  const isRecurringInstance = !!task.groupId;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white w-full max-w-lg rounded-[48px] p-10 shadow-2xl animate-in zoom-in-95 duration-300">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">
            {task.id ? 'Edit Task' : 'New Task'}
          </h2>
          <button onClick={onClose} className="text-slate-300 hover:text-slate-600 transition-colors">
            <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-8">
          <div>
            <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-3 ml-1">Task Title</label>
            <input
              autoFocus
              required
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="w-full bg-slate-50 border-2 border-slate-100 rounded-[24px] px-6 py-4 font-bold text-slate-800 focus:border-[#3b5bdb] focus:bg-white focus:ring-0 outline-none transition-all"
              placeholder="e.g. Molecular Genetics"
            />
          </div>

          <div className="grid grid-cols-2 gap-6">
             <div>
              <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-3 ml-1">Date</label>
              <input
                required
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-[24px] px-6 py-4 font-bold text-slate-800 focus:border-[#3b5bdb] focus:bg-white focus:ring-0 outline-none transition-all"
              />
            </div>
            <div>
              <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-3 ml-1">Duration</label>
              <input
                required
                type="text"
                value={duration}
                onChange={(e) => setDuration(e.target.value)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-[24px] px-6 py-4 font-bold text-slate-800 focus:border-[#3b5bdb] focus:bg-white focus:ring-0 outline-none transition-all"
                placeholder="e.g. 2h"
              />
            </div>
          </div>

          <div>
             <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-3 ml-1">Subject</label>
              <select
                value={section}
                onChange={(e) => setSection(e.target.value as MCATSection)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-[24px] px-6 py-4 font-bold text-slate-800 focus:border-[#3b5bdb] focus:bg-white focus:ring-0 outline-none transition-all appearance-none cursor-pointer"
              >
                {Object.keys(SECTION_STYLES).map((s) => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
          </div>

          {task.id && isRecurringInstance && (
            <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100 animate-in slide-in-from-bottom-2">
              <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4 text-center">Update recurring task group?</label>
              <div className="flex gap-3">
                <button
                  type="button"
                  onClick={() => setSaveScope('single')}
                  className={`flex-1 py-4 rounded-2xl font-black text-[11px] uppercase tracking-widest transition-all border-2 ${
                    saveScope === 'single'
                      ? 'bg-white border-[#3b5bdb] text-[#3b5bdb] shadow-md'
                      : 'bg-transparent border-slate-200 text-slate-400 opacity-60 hover:opacity-100 hover:border-slate-300'
                  }`}
                >
                  This day only
                </button>
                <button
                  type="button"
                  onClick={() => setSaveScope('future')}
                  className={`flex-1 py-4 rounded-2xl font-black text-[11px] uppercase tracking-widest transition-all border-2 ${
                    saveScope === 'future'
                      ? 'bg-white border-[#3b5bdb] text-[#3b5bdb] shadow-md'
                      : 'bg-transparent border-slate-200 text-slate-400 opacity-60 hover:opacity-100 hover:border-slate-300'
                  }`}
                >
                  All future days
                </button>
              </div>
            </div>
          )}

          {!task.id && (
            <div>
              <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-3 ml-1">Frequency</label>
              <div className="flex gap-3">
                {(['None', 'Daily'] as RecurrenceType[]).map((type) => (
                  <button
                    key={type}
                    type="button"
                    onClick={() => setRecurrence(type)}
                    className={`flex-1 py-4 rounded-[20px] font-black text-xs uppercase tracking-widest transition-all border-2 ${
                      recurrence === type 
                        ? 'bg-slate-900 text-white border-slate-900 shadow-xl' 
                        : 'bg-white text-slate-400 border-slate-100 hover:border-slate-200'
                    }`}
                  >
                    {type === 'None' ? 'One-time' : 'Repeat Daily'}
                  </button>
                ))}
              </div>
            </div>
          )}

          <div className="pt-6 flex gap-4">
            <button
              type="submit"
              className="flex-1 bg-[#3b5bdb] text-white py-5 rounded-[24px] font-black uppercase tracking-[0.2em] text-xs hover:bg-[#2f49b1] shadow-xl shadow-blue-100 transition-all active:scale-[0.98]"
            >
              {task.id ? 'Apply Changes' : 'Create Task'}
            </button>
            {task.id && onDelete && (
              <button
                type="button"
                onClick={() => {
                  if (confirm('Permanently delete this study task?')) {
                    onDelete(task.id!);
                    onClose();
                  }
                }}
                className="w-16 bg-rose-50 text-rose-500 rounded-[24px] flex items-center justify-center hover:bg-rose-100 transition-all shadow-sm border border-rose-100"
              >
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

