import React from 'react';
import { StudyTask } from '../types';
import { SECTION_STYLES } from '../constants';

interface TaskCardProps {
  task: StudyTask;
  onToggle: (id: string) => void;
  onDragStart: (e: React.DragEvent, id: string) => void;
  onEdit: (task: StudyTask) => void;
}

const TaskCard: React.FC<TaskCardProps> = ({ task, onToggle, onDragStart, onEdit }) => {
  const styles = SECTION_STYLES[task.section];

  return (
    <div
      draggable
      onDragStart={(e) => onDragStart(e, task.id)}
      onClick={() => onEdit(task)}
      className={`group relative p-5 mb-4 bg-white rounded-[28px] border border-slate-100 shadow-[0_6px_16px_rgba(0,0,0,0.04)] transition-all cursor-grab active:cursor-grabbing hover:shadow-[0_15px_35px_rgba(0,0,0,0.08)] hover:border-slate-200 active:scale-[0.98] ${
        task.completed ? 'opacity-60 grayscale-[0.3]' : ''
      }`}
    >
      {/* Visual Indicator Dot */}
      {!task.completed && (
        <div className="absolute top-4 right-4 w-2 h-2 bg-[#3b5bdb] rounded-full animate-pulse opacity-20" />
      )}

      <div className="flex gap-4 items-center">
        {/* Checkbox Section */}
        <div className="flex shrink-0" onClick={(e) => e.stopPropagation()}>
          <button
            onClick={() => onToggle(task.id)}
            className={`w-8 h-8 rounded-full border-[3px] flex items-center justify-center transition-all ${
              task.completed 
                ? 'bg-[#3b5bdb] border-[#3b5bdb] shadow-lg shadow-blue-100' 
                : 'bg-white border-slate-200 hover:border-[#3b5bdb]/50'
            }`}
          >
            {task.completed && (
              <svg width="14" height="10" viewBox="0 0 14 11" fill="none" xmlns="http://www.w3.org/2000/svg">
                <path d="M1 6L5 9.5L13 1" stroke="white" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
            )}
          </button>
        </div>

        {/* Text Content */}
        <div className="flex-1 min-w-0">
          <h4 className={`font-black text-[14px] leading-tight text-slate-800 transition-all truncate tracking-tight ${
            task.completed ? 'line-through text-slate-400' : ''
          }`}>
            {task.title}
          </h4>

          <div className="mt-2 flex items-center gap-3">
            <span className={`px-2 py-0.5 rounded-lg text-[9px] font-black tracking-[0.15em] uppercase ${styles.bg} ${styles.text} border border-transparent group-hover:border-current/10 transition-all`}>
              {styles.label}
            </span>

            <div className="flex items-center gap-1.5 text-slate-400 text-[10px] font-black tracking-tight opacity-70">
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="12" cy="12" r="10"></circle>
                <polyline points="12 6 12 12 16 14"></polyline>
              </svg>
              <span>{task.duration}</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TaskCard;

export type MCATSection = 
  | 'Biology' 
  | 'Biochemistry' 
  | 'General Chemistry' 
  | 'Organic Chemistry' 
  | 'Physics' 
  | 'Behavioral Sciences' 
  | 'CARS' 
  | 'Practice Exam';

export type RecurrenceType = 'None' | 'Daily';
export type ViewType = 'daily' | 'weekly' | 'monthly';

export interface StudyTask {
  id: string;
  groupId?: string; // Links recurring tasks together
  title: string;
  description: string;
  section: MCATSection;
  completed: boolean;
  date: string; // ISO format YYYY-MM-DD
  duration: string;
  recurrence?: RecurrenceType;
}

export interface AIResponse {
  suggestion: string;
  updatedTasks: StudyTask[];
}

import React, { useState, useEffect, useMemo } from 'react';
import DayColumn from './components/DayColumn';
import EditTaskModal from './components/EditTaskModal';
import { StudyTask, ViewType } from './types';
import { INITIAL_TASKS, formatDateKey, DAYS_SHORT, SECTION_STYLES } from './constants';
import { adaptSchedule } from './services/geminiService';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(INITIAL_TASKS);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');
  const [view, setView] = useState<ViewType>('weekly');
  const [baseDate, setBaseDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('mcat-pulse-v5');
    if (saved) {
      setTasks(JSON.parse(saved));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('mcat-pulse-v5', JSON.stringify(tasks));
  }, [tasks]);

  // Task Handlers
  const toggleTask = (id: string) => setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  const handleDragStartTask = (e: React.DragEvent, id: string) => e.dataTransfer.setData('taskId', id);
  const moveTask = (taskId: string, targetDate: string) => setTasks(prev => prev.map(t => t.id === taskId ? { ...t, date: targetDate } : t));
  const handleEditTask = (task: StudyTask) => { setCurrentTaskToEdit(task); setIsModalOpen(true); };
  const handleAddTask = (dateKey: string) => { setCurrentTaskToEdit({ date: dateKey, completed: false, description: '', section: 'Biology', duration: '1h', recurrence: 'None' }); setIsModalOpen(true); };
  const deleteTask = (id: string) => setTasks(prev => prev.filter(t => t.id !== id));

  const saveTask = (task: StudyTask, scope: 'single' | 'future' = 'single') => {
    if (task.id) {
      if (scope === 'future' && task.groupId) {
        setTasks(prev => prev.map(t => {
          if (t.groupId === task.groupId && t.date >= task.date) {
            return { ...t, title: task.title, section: task.section, duration: task.duration };
          }
          return t;
        }));
      } else {
        setTasks(prev => prev.map(t => t.id === task.id ? task : t));
      }
    } else {
      if (task.recurrence === 'Daily') {
        const groupId = Math.random().toString(36).substr(2, 9);
        const newTasks: StudyTask[] = Array.from({ length: 14 }).map((_, i) => {
          const d = new Date(task.date);
          d.setDate(d.getDate() + i);
          return { ...task, id: Math.random().toString(36).substr(2, 9), groupId, date: formatDateKey(d) };
        });
        setTasks(prev => [...prev, ...newTasks]);
      } else {
        setTasks(prev => [...prev, { ...task, id: Math.random().toString(36).substr(2, 9) }]);
      }
    }
  };

  const navigate = (amount: number) => {
    const newDate = new Date(baseDate);
    if (view === 'daily') newDate.setDate(newDate.getDate() + amount);
    if (view === 'weekly') newDate.setDate(newDate.getDate() + (amount * 7));
    if (view === 'monthly') newDate.setMonth(newDate.getMonth() + amount);
    setBaseDate(newDate);
  };

  const currentRangeDays = useMemo(() => {
    if (view === 'daily') return [new Date(baseDate)];
    if (view === 'weekly') {
      const start = new Date(baseDate);
      const day = start.getDay();
      const shift = day === 0 ? 6 : day - 1;
      start.setDate(start.getDate() - shift); 
      return Array.from({ length: 7 }).map((_, i) => {
        const d = new Date(start);
        d.setDate(d.getDate() + i);
        return d;
      });
    }
    return [];
  }, [view, baseDate]);

  const monthGrid = useMemo(() => {
    if (view !== 'monthly') return [];
    const start = new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
    const end = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0);
    const startDay = start.getDay();
    const padding = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < padding; i++) {
      const d = new Date(start);
      d.setDate(d.getDate() - (padding - i));
      days.push({ date: d, currentMonth: false });
    }
    for (let i = 1; i <= end.getDate(); i++) {
      days.push({ date: new Date(baseDate.getFullYear(), baseDate.getMonth(), i), currentMonth: true });
    }
    const totalSlots = days.length > 35 ? 42 : 35;
    const remaining = totalSlots - days.length;
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(end);
      d.setDate(d.getDate() + i);
      days.push({ date: d, currentMonth: false });
    }
    return days;
  }, [view, baseDate]);

  const handleAiUpdate = async () => {
    if (!userInput.trim() && tasks.every(t => !t.completed)) return;
    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput || "Adjust my flow based on my progress.");
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      setAiMessage("Sync failed. Check your connection.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const progressPercent = Math.round((tasks.filter(t => t.completed).length / (tasks.length || 1)) * 100);

  return (
    <div className="min-h-screen bg-[#f8faff] pb-56">
      <header className="px-12 pt-12 max-w-[2000px] mx-auto flex flex-col xl:flex-row items-center justify-between gap-12">
        <div className="shrink-0 text-center xl:text-left">
          <h1 className="text-5xl font-black text-slate-900 tracking-tighter flex items-center justify-center xl:justify-start gap-3">
            <span className="text-[#3b5bdb]">MCAT</span> PULSE
          </h1>
          <p className="text-slate-400 font-bold text-sm tracking-[0.3em] mt-2 uppercase opacity-80">PRECISION SCHEDULER</p>
        </div>

        <div className="flex flex-wrap items-center justify-center gap-6 bg-white p-3 rounded-[40px] shadow-sm border border-slate-100">
           <div className="flex bg-slate-50 p-1.5 rounded-[24px]">
             {(['daily', 'weekly', 'monthly'] as ViewType[]).map(v => (
               <button 
                 key={v}
                 onClick={() => setView(v)}
                 className={`px-10 py-3 rounded-2xl text-sm font-black uppercase tracking-widest transition-all ${view === v ? 'bg-white text-[#3b5bdb] shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
               >
                 {v}
               </button>
             ))}
           </div>
           <div className="h-10 w-px bg-slate-200" />
           <div className="flex items-center gap-4">
             <button onClick={() => navigate(-1)} className="p-3 hover:bg-slate-50 rounded-2xl transition-all active:scale-90"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M15 18l-6-6 6-6"/></svg></button>
             <button onClick={() => setBaseDate(new Date())} className="px-6 py-3 text-sm font-black text-[#3b5bdb] uppercase tracking-tighter hover:bg-slate-50 rounded-2xl">Today</button>
             <button onClick={() => navigate(1)} className="p-3 hover:bg-slate-50 rounded-2xl transition-all active:scale-90"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M9 18l6-6-6-6"/></svg></button>
           </div>
        </div>

        <div className="w-full sm:w-auto max-w-xl bg-white rounded-[40px] p-3 shadow-sm border border-slate-100 flex items-center gap-4">
          <input
            type="text"
            value={userInput}
            onChange={(e) => setUserInput(e.target.value)}
            placeholder="AI Schedule Optimization..."
            className="flex-1 bg-transparent border-none px-6 py-3.5 font-bold text-base focus:ring-0 outline-none placeholder:text-slate-300"
          />
          <button
            onClick={handleAiUpdate}
            disabled={isAiLoading}
            className="bg-[#3b5bdb] text-white px-10 py-4 rounded-3xl text-sm font-black uppercase tracking-widest hover:bg-[#2f49b1] transition-all disabled:opacity-50"
          >
            {isAiLoading ? '...' : 'SYNC'}
          </button>
        </div>
      </header>

      {aiMessage && (
        <div className="max-w-4xl mx-auto mt-14 px-12 animate-in slide-in-from-top-6">
           <div className="bg-[#3b5bdb] text-white rounded-[48px] p-10 shadow-3xl relative">
             <p className="font-bold text-xl leading-relaxed">{aiMessage}</p>
             <button onClick={() => setAiMessage(null)} className="absolute top-8 right-8 opacity-40 hover:opacity-100 transition-opacity"><svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
           </div>
        </div>
      )}

      <main className="mt-20 px-12 max-w-[2000px] mx-auto">
        {view === 'monthly' ? (
          <div className="bg-white rounded-[60px] shadow-sm border border-slate-100 overflow-hidden">
            <div className="grid grid-cols-7 border-b border-slate-50">
              {DAYS_SHORT.map(d => <div key={d} className="py-8 text-center text-sm font-black text-slate-400 uppercase tracking-[0.3em]">{d}</div>)}
            </div>
            <div className="grid grid-cols-7">
              {monthGrid.map(({ date, currentMonth }, i) => {
                const dateKey = formatDateKey(date);
                const dayTasks = tasks.filter(t => t.date === dateKey);
                const isSelected = dateKey === formatDateKey(baseDate);
                const isToday = dateKey === formatDateKey(new Date());
                return (
                  <div 
                    key={i} 
                    onClick={() => { setBaseDate(new Date(date)); setView('daily'); }}
                    className={`min-h-[180px] p-5 border-r border-b border-slate-50 cursor-pointer transition-all hover:bg-slate-50 group ${!currentMonth ? 'opacity-20' : ''} ${isSelected ? 'bg-blue-50/20' : ''}`}
                  >
                    <div className="flex justify-between items-center mb-4">
                      <span className={`text-sm font-black ${isToday ? 'bg-[#3b5bdb] text-white w-8 h-8 flex items-center justify-center rounded-xl shadow-lg' : isSelected ? 'text-[#3b5bdb]' : 'text-slate-400'}`}>
                        {date.getDate()}
                      </span>
                    </div>
                    <div className="flex flex-col gap-2.5">
                      {dayTasks.slice(0, 4).map(t => (
                        <div key={t.id} className={`px-3 py-2 rounded-xl text-[10px] font-bold truncate flex items-center gap-2.5 ${SECTION_STYLES[t.section].bg} ${SECTION_STYLES[t.section].text} ${t.completed ? 'opacity-30' : ''}`}>
                          <span className="shrink-0 w-2 h-2 rounded-full bg-current opacity-40" />
                          <span className="truncate">{t.section}: {t.title}</span>
                        </div>
                      ))}
                      {dayTasks.length > 4 && (
                        <span className="text-[10px] font-black text-slate-300 ml-2">+{dayTasks.length - 4} MORE</span>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : view === 'weekly' ? (
          <div className="space-y-16 pb-20">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-10">
              {currentRangeDays.slice(0, 5).map((d, i) => (
                <DayColumn
                  key={i}
                  date={d}
                  tasks={tasks.filter(t => t.date === formatDateKey(d))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              ))}
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-10">
              <div className="xl:col-start-2">
                <DayColumn
                  date={currentRangeDays[5]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[5]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              </div>
              <div className="xl:col-start-3">
                <DayColumn
                  date={currentRangeDays[6]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[6]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              </div>
            </div>
          </div>
        ) : (
          <div className="flex justify-center pb-20">
            <DayColumn
              date={currentRangeDays[0]}
              tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[0]))}
              onToggleTask={toggleTask}
              onDragStartTask={handleDragStartTask}
              onDropTask={moveTask}
              onAddTask={handleAddTask}
              onEditTask={handleEditTask}
              isFocused
            />
          </div>
        )}
      </main>

      <div className="fixed bottom-12 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur-3xl px-14 py-7 rounded-[56px] shadow-[0_40px_100px_rgba(0,0,0,0.15)] border border-white/60 flex items-center gap-14 z-[60]">
        <div className="flex flex-col">
          <span className="text-[12px] font-black text-slate-400 uppercase tracking-[0.25em]">Progress</span>
          <span className="text-3xl font-black text-[#3b5bdb] tracking-tighter leading-none mt-1">{progressPercent}%</span>
        </div>
        <div className="w-72 sm:w-[450px] h-5 bg-slate-100 rounded-full overflow-hidden p-1 shadow-inner">
          <div className="h-full bg-gradient-to-r from-blue-400 to-[#3b5bdb] rounded-full transition-all duration-1000 shadow-[0_0_20px_rgba(59,91,219,0.35)]" style={{ width: `${progressPercent}%` }} />
        </div>
        <div className="flex items-center gap-5">
          <div className="w-14 h-14 rounded-[24px] bg-[#3b5bdb] flex items-center justify-center text-white font-black text-lg shadow-2xl shadow-blue-200">{tasks.filter(t => t.completed).length}</div>
          <span className="hidden sm:inline text-sm font-black text-slate-500 uppercase tracking-[0.2em]">Tasks Done</span>
        </div>
      </div>

      <EditTaskModal isOpen={isModalOpen} task={currentTaskToEdit} onClose={() => setIsModalOpen(false)} onSave={saveTask} onDelete={deleteTask} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { StudyTask } from '../types';
import TaskCard from './TaskCard';
import { formatDateKey } from '../constants';

interface DayColumnProps {
  date: Date;
  tasks: StudyTask[];
  onToggleTask: (id: string) => void;
  onDropTask: (taskId: string, targetDate: string) => void;
  onDragStartTask: (e: React.DragEvent, id: string) => void;
  onAddTask: (date: string) => void;
  onEditTask: (task: StudyTask) => void;
  isFocused?: boolean;
}

const DayColumn: React.FC<DayColumnProps> = ({
  date,
  tasks,
  onToggleTask,
  onDropTask,
  onDragStartTask,
  onAddTask,
  onEditTask,
  isFocused = false
}) => {
  const [isOver, setIsOver] = useState(false);
  const dateKey = formatDateKey(date);
  const isToday = dateKey === formatDateKey(new Date());

  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const dayName = dayNames[date.getDay()];
  const dayNum = date.getDate();

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(true);
  };

  const handleDragLeave = () => {
    setIsOver(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(false);
    const taskId = e.dataTransfer.getData('taskId');
    onDropTask(taskId, dateKey);
  };

  return (
    <div
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`flex flex-col rounded-[48px] border-2 p-10 transition-all h-full ${
        isFocused ? 'min-h-[800px] w-full max-w-[600px]' : 'min-h-[550px] w-full'
      } ${
        isOver 
          ? 'bg-blue-50/50 border-blue-400 border-dashed scale-[1.03] shadow-2xl z-10' 
          : isToday
            ? 'bg-white border-[#3b5bdb]/40 shadow-[0_25px_60px_rgba(59,91,219,0.15)] ring-1 ring-[#3b5bdb]/10'
            : 'bg-[#f5f8ff] border-transparent shadow-[inset_0_4px_6px_rgba(0,0,0,0.02)]'
      }`}
    >
      <div className="flex justify-between items-center mb-10">
        <div>
          <h3 className={`text-3xl font-black tracking-tight ${isToday ? 'text-[#3b5bdb]' : 'text-slate-800'}`}>
            {dayName} {dayNum} {isToday && <span className="text-[0.8em] font-bold ml-2 opacity-60 uppercase">(Today)</span>}
          </h3>
          <p className="text-slate-400 font-bold text-sm mt-1 uppercase tracking-widest opacity-60">
            {tasks.length} {tasks.length === 1 ? 'task' : 'tasks'}
          </p>
        </div>

        <button 
          onClick={() => onAddTask(dateKey)}
          className="w-14 h-14 rounded-[24px] bg-white shadow-[0_12px_30px_rgba(0,0,0,0.08)] border border-slate-100 flex items-center justify-center text-slate-400 hover:text-[#3b5bdb] hover:border-[#3b5bdb]/40 transition-all active:scale-90"
        >
          <svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
            <line x1="12" y1="5" x2="12" y2="19"></line>
            <line x1="5" y1="12" x2="19" y2="12"></line>
          </svg>
        </button>
      </div>

      <div className="flex-1 space-y-6">
        {tasks.map((task) => (
          <TaskCard
            key={task.id}
            task={task}
            onToggle={onToggleTask}
            onDragStart={onDragStartTask}
            onEdit={onEditTask}
          />
        ))}
        {tasks.length === 0 && (
          <div className="h-40 border-2 border-dashed border-slate-200/50 rounded-[40px] flex items-center justify-center text-slate-300 font-black text-sm italic p-8 text-center opacity-60 leading-relaxed">
            Rest and reflect.<br/>You've earned it.
          </div>
        )}
      </div>
    </div>
  );
};

export default DayColumn;

import React from 'react';
import { StudyTask } from '../types';
import { SECTION_STYLES } from '../constants';

interface TaskCardProps {
  task: StudyTask;
  onToggle: (id: string) => void;
  onDragStart: (e: React.DragEvent, id: string) => void;
  onEdit: (task: StudyTask) => void;
}

const TaskCard: React.FC<TaskCardProps> = ({ task, onToggle, onDragStart, onEdit }) => {
  const styles = SECTION_STYLES[task.section];

  return (
    <div
      draggable
      onDragStart={(e) => onDragStart(e, task.id)}
      onClick={() => onEdit(task)}
      className={`group relative p-6 mb-4 bg-white rounded-[32px] border border-slate-100 shadow-[0_6px_16px_rgba(0,0,0,0.04)] transition-all cursor-grab active:cursor-grabbing hover:shadow-[0_15px_35px_rgba(0,0,0,0.08)] hover:border-slate-200 active:scale-[0.98] ${
        task.completed ? 'opacity-60 grayscale-[0.2]' : ''
      }`}
    >
      {/* Visual Indicator Dot */}
      {!task.completed && (
        <div className="absolute top-4 right-4 w-2 h-2 bg-[#3b5bdb] rounded-full animate-pulse opacity-20" />
      )}

      <div className="flex gap-5 items-start">
        {/* Checkbox Section */}
        <div className="flex shrink-0 pt-1" onClick={(e) => e.stopPropagation()}>
          <button
            onClick={() => onToggle(task.id)}
            className={`w-8 h-8 rounded-full border-[3px] flex items-center justify-center transition-all ${
              task.completed 
                ? 'bg-[#3b5bdb] border-[#3b5bdb] shadow-lg shadow-blue-100' 
                : 'bg-white border-slate-200 hover:border-[#3b5bdb]/50'
            }`}
          >
            {task.completed && (
              <svg width="14" height="10" viewBox="0 0 14 11" fill="none" xmlns="http://www.w3.org/2000/svg">
                <path d="M1 6L5 9.5L13 1" stroke="white" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
            )}
          </button>
        </div>

        {/* Text Content */}
        <div className="flex-1 min-w-0">
          <h4 className={`font-black text-[15px] leading-tight text-slate-800 transition-all tracking-tight ${
            task.completed ? 'line-through text-slate-400' : ''
          }`}>
            {task.title}
          </h4>

          <div className="mt-3 flex flex-wrap items-center gap-3">
            <span className={`px-2.5 py-0.5 rounded-lg text-[10px] font-black tracking-[0.15em] uppercase ${styles.bg} ${styles.text} border border-transparent group-hover:border-current/10 transition-all`}>
              {styles.label}
            </span>

            <div className="flex items-center gap-1.5 text-slate-400 text-[11px] font-black tracking-tight opacity-70">
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="12" cy="12" r="10"></circle>
                <polyline points="12 6 12 12 16 14"></polyline>
              </svg>
              <span>{task.duration}</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TaskCard;

import React, { useState, useEffect } from 'react';
import { StudyTask, MCATSection, RecurrenceType } from '../types';
import { SECTION_STYLES } from '../constants';

interface EditTaskModalProps {
  task: Partial<StudyTask> | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: StudyTask, scope?: 'single' | 'future') => void;
  onDelete?: (id: string) => void;
}

const EditTaskModal: React.FC<EditTaskModalProps> = ({ task, isOpen, onClose, onSave, onDelete }) => {
  const [title, setTitle] = useState('');
  const [section, setSection] = useState<MCATSection>('Biology');
  const [duration, setDuration] = useState('');
  const [recurrence, setRecurrence] = useState<RecurrenceType>('None');
  const [date, setDate] = useState('');
  const [saveScope, setSaveScope] = useState<'single' | 'future'>('single');

  useEffect(() => {
    if (task) {
      setTitle(task.title || '');
      setSection(task.section || 'Biology');
      setDuration(task.duration || '');
      setRecurrence(task.recurrence || 'None');
      setDate(task.date || '');
      setSaveScope('single');
    }
  }, [task, isOpen]);

  if (!isOpen || !task) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      ...task,
      title,
      section,
      duration,
      recurrence,
      date,
    } as StudyTask, saveScope);
    onClose();
  };

  const isRecurringInstance = !!task.groupId;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white w-full max-w-lg rounded-[56px] p-12 shadow-2xl animate-in zoom-in-95 duration-300">
        <div className="flex justify-between items-center mb-10">
          <h2 className="text-4xl font-black text-slate-900 tracking-tighter">
            {task.id ? 'Refine Task' : 'New Study Task'}
          </h2>
          <button onClick={onClose} className="text-slate-300 hover:text-slate-600 transition-colors">
            <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-10">
          <div>
            <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.25em] mb-4 ml-1">Title</label>
            <input
              autoFocus
              required
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="w-full bg-slate-50 border-2 border-slate-100 rounded-[28px] px-7 py-5 font-bold text-slate-800 text-lg focus:border-[#3b5bdb] focus:bg-white focus:ring-0 outline-none transition-all shadow-sm"
              placeholder="e.g. Fluids and Flow Kinetics"
            />
          </div>

          <div className="grid grid-cols-2 gap-8">
             <div>
              <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.25em] mb-4 ml-1">Date</label>
              <input
                required
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-[28px] px-7 py-5 font-bold text-slate-800 focus:border-[#3b5bdb] focus:bg-white focus:ring-0 outline-none transition-all shadow-sm"
              />
            </div>
            <div>
              <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.25em] mb-4 ml-1">Time</label>
              <input
                required
                type="text"
                value={duration}
                onChange={(e) => setDuration(e.target.value)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-[28px] px-7 py-5 font-bold text-slate-800 focus:border-[#3b5bdb] focus:bg-white focus:ring-0 outline-none transition-all shadow-sm"
                placeholder="e.g. 2.5h"
              />
            </div>
          </div>

          <div>
             <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.25em] mb-4 ml-1">Discipline</label>
              <select
                value={section}
                onChange={(e) => setSection(e.target.value as MCATSection)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-[28px] px-7 py-5 font-bold text-slate-800 focus:border-[#3b5bdb] focus:bg-white focus:ring-0 outline-none transition-all appearance-none cursor-pointer shadow-sm"
              >
                {Object.keys(SECTION_STYLES).map((s) => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
          </div>

          {task.id && isRecurringInstance && (
            <div className="bg-slate-50 p-8 rounded-[40px] border border-slate-100 animate-in slide-in-from-bottom-2">
              <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.25em] mb-5 text-center">Propagate changes?</label>
              <div className="flex gap-4">
                <button
                  type="button"
                  onClick={() => setSaveScope('single')}
                  className={`flex-1 py-4 rounded-2xl font-black text-[11px] uppercase tracking-widest transition-all border-2 ${
                    saveScope === 'single'
                      ? 'bg-white border-[#3b5bdb] text-[#3b5bdb] shadow-md'
                      : 'bg-transparent border-slate-200 text-slate-400 opacity-60 hover:opacity-100 hover:border-slate-300'
                  }`}
                >
                  Current Day
                </button>
                <button
                  type="button"
                  onClick={() => setSaveScope('future')}
                  className={`flex-1 py-4 rounded-2xl font-black text-[11px] uppercase tracking-widest transition-all border-2 ${
                    saveScope === 'future'
                      ? 'bg-white border-[#3b5bdb] text-[#3b5bdb] shadow-md'
                      : 'bg-transparent border-slate-200 text-slate-400 opacity-60 hover:opacity-100 hover:border-slate-300'
                  }`}
                >
                  And All Future
                </button>
              </div>
            </div>
          )}

          {!task.id && (
            <div>
              <label className="block text-xs font-black text-slate-400 uppercase tracking-[0.25em] mb-4 ml-1">Frequency</label>
              <div className="flex gap-4">
                {(['None', 'Daily'] as RecurrenceType[]).map((type) => (
                  <button
                    key={type}
                    type="button"
                    onClick={() => setRecurrence(type)}
                    className={`flex-1 py-5 rounded-[28px] font-black text-xs uppercase tracking-[0.2em] transition-all border-2 ${
                      recurrence === type 
                        ? 'bg-slate-900 text-white border-slate-900 shadow-xl' 
                        : 'bg-white text-slate-400 border-slate-100 hover:border-slate-200 shadow-sm'
                    }`}
                  >
                    {type === 'None' ? 'One-time' : 'Repeat Daily'}
                  </button>
                ))}
              </div>
            </div>
          )}

          <div className="pt-6 flex gap-5">
            <button
              type="submit"
              className="flex-1 bg-[#3b5bdb] text-white py-6 rounded-[32px] font-black uppercase tracking-[0.25em] text-sm hover:bg-[#2f49b1] shadow-2xl shadow-blue-200 transition-all active:scale-[0.98]"
            >
              {task.id ? 'Update Schedule' : 'Create Task'}
            </button>
            {task.id && onDelete && (
              <button
                type="button"
                onClick={() => {
                  if (confirm('Permanently remove this task?')) {
                    onDelete(task.id!);
                    onClose();
                  }
                }}
                className="w-20 bg-rose-50 text-rose-500 rounded-[32px] flex items-center justify-center hover:bg-rose-100 transition-all shadow-sm border border-rose-100"
              >
                <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default EditTaskModal;

import React, { useState, useEffect, useMemo } from 'react';
import DayColumn from './components/DayColumn';
import EditTaskModal from './components/EditTaskModal';
import { StudyTask, ViewType } from './types';
import { INITIAL_TASKS, formatDateKey, DAYS_SHORT, SECTION_STYLES } from './constants';
import { adaptSchedule } from './services/geminiService';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(INITIAL_TASKS);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');
  const [view, setView] = useState<ViewType>('weekly');
  const [baseDate, setBaseDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('mcat-pulse-v5');
    if (saved) {
      setTasks(JSON.parse(saved));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('mcat-pulse-v5', JSON.stringify(tasks));
  }, [tasks]);

  // Task Handlers
  const toggleTask = (id: string) => setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  const handleDragStartTask = (e: React.DragEvent, id: string) => e.dataTransfer.setData('taskId', id);
  const moveTask = (taskId: string, targetDate: string) => setTasks(prev => prev.map(t => t.id === taskId ? { ...t, date: targetDate } : t));
  const handleEditTask = (task: StudyTask) => { setCurrentTaskToEdit(task); setIsModalOpen(true); };
  const handleAddTask = (dateKey: string) => { setCurrentTaskToEdit({ date: dateKey, completed: false, description: '', section: 'Biology', duration: '1h', recurrence: 'None' }); setIsModalOpen(true); };
  const deleteTask = (id: string) => setTasks(prev => prev.filter(t => t.id !== id));

  const saveTask = (task: StudyTask, scope: 'single' | 'future' = 'single') => {
    if (task.id) {
      if (scope === 'future' && task.groupId) {
        setTasks(prev => prev.map(t => {
          if (t.groupId === task.groupId && t.date >= task.date) {
            return { ...t, title: task.title, section: task.section, duration: task.duration };
          }
          return t;
        }));
      } else {
        setTasks(prev => prev.map(t => t.id === task.id ? task : t));
      }
    } else {
      if (task.recurrence === 'Daily') {
        const groupId = Math.random().toString(36).substr(2, 9);
        const newTasks: StudyTask[] = Array.from({ length: 14 }).map((_, i) => {
          const d = new Date(task.date);
          d.setDate(d.getDate() + i);
          return { ...task, id: Math.random().toString(36).substr(2, 9), groupId, date: formatDateKey(d) };
        });
        setTasks(prev => [...prev, ...newTasks]);
      } else {
        setTasks(prev => [...prev, { ...task, id: Math.random().toString(36).substr(2, 9) }]);
      }
    }
  };

  const navigate = (amount: number) => {
    const newDate = new Date(baseDate);
    if (view === 'daily') newDate.setDate(newDate.getDate() + amount);
    if (view === 'weekly') newDate.setDate(newDate.getDate() + (amount * 7));
    if (view === 'monthly') newDate.setMonth(newDate.getMonth() + amount);
    setBaseDate(newDate);
  };

  const currentRangeDays = useMemo(() => {
    if (view === 'daily') return [new Date(baseDate)];
    if (view === 'weekly') {
      const start = new Date(baseDate);
      const day = start.getDay();
      const shift = day === 0 ? 6 : day - 1;
      start.setDate(start.getDate() - shift); 
      return Array.from({ length: 7 }).map((_, i) => {
        const d = new Date(start);
        d.setDate(d.getDate() + i);
        return d;
      });
    }
    return [];
  }, [view, baseDate]);

  const monthGrid = useMemo(() => {
    if (view !== 'monthly') return [];
    const start = new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
    const end = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0);
    const startDay = start.getDay();
    const padding = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < padding; i++) {
      const d = new Date(start);
      d.setDate(d.getDate() - (padding - i));
      days.push({ date: d, currentMonth: false });
    }
    for (let i = 1; i <= end.getDate(); i++) {
      days.push({ date: new Date(baseDate.getFullYear(), baseDate.getMonth(), i), currentMonth: true });
    }
    const totalSlots = days.length > 35 ? 42 : 35;
    const remaining = totalSlots - days.length;
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(end);
      d.setDate(d.getDate() + i);
      days.push({ date: d, currentMonth: false });
    }
    return days;
  }, [view, baseDate]);

  const handleAiUpdate = async () => {
    if (!userInput.trim() && tasks.every(t => !t.completed)) return;
    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput || "Adjust my flow based on my progress.");
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      setAiMessage("Sync failed. Check your connection.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const progressPercent = Math.round((tasks.filter(t => t.completed).length / (tasks.length || 1)) * 100);

  return (
    <div className="min-h-screen bg-[#f8faff] pb-56">
      <header className="px-12 pt-12 max-w-[2000px] mx-auto flex flex-col xl:flex-row items-center justify-between gap-12">
        <div className="shrink-0 text-center xl:text-left">
          <h1 className="text-5xl font-black text-slate-900 tracking-tighter flex items-center justify-center xl:justify-start gap-3">
            <span className="text-[#3b5bdb]">MCAT</span> PULSE
          </h1>
          <p className="text-slate-400 font-bold text-sm tracking-[0.3em] mt-2 uppercase opacity-80">PRECISION SCHEDULER</p>
        </div>

        <div className="flex flex-wrap items-center justify-center gap-6 bg-white p-3 rounded-[40px] shadow-sm border border-slate-100">
           <div className="flex bg-slate-50 p-1.5 rounded-[24px]">
             {(['daily', 'weekly', 'monthly'] as ViewType[]).map(v => (
               <button 
                 key={v}
                 onClick={() => setView(v)}
                 className={`px-10 py-3 rounded-2xl text-sm font-black uppercase tracking-widest transition-all ${view === v ? 'bg-white text-[#3b5bdb] shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
               >
                 {v}
               </button>
             ))}
           </div>
           <div className="h-10 w-px bg-slate-200" />
           <div className="flex items-center gap-4">
             <button onClick={() => navigate(-1)} className="p-3 hover:bg-slate-50 rounded-2xl transition-all active:scale-90"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M15 18l-6-6 6-6"/></svg></button>
             <button onClick={() => setBaseDate(new Date())} className="px-6 py-3 text-sm font-black text-[#3b5bdb] uppercase tracking-tighter hover:bg-slate-50 rounded-2xl">Today</button>
             <button onClick={() => navigate(1)} className="p-3 hover:bg-slate-50 rounded-2xl transition-all active:scale-90"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M9 18l6-6-6-6"/></svg></button>
           </div>
        </div>

        <div className="w-full sm:w-auto max-w-xl bg-white rounded-[40px] p-3 shadow-sm border border-slate-100 flex items-center gap-4">
          <input
            type="text"
            value={userInput}
            onChange={(e) => setUserInput(e.target.value)}
            placeholder="AI Schedule Optimization..."
            className="flex-1 bg-transparent border-none px-6 py-3.5 font-bold text-base focus:ring-0 outline-none placeholder:text-slate-300"
          />
          <button
            onClick={handleAiUpdate}
            disabled={isAiLoading}
            className="bg-[#3b5bdb] text-white px-10 py-4 rounded-3xl text-sm font-black uppercase tracking-widest hover:bg-[#2f49b1] transition-all disabled:opacity-50"
          >
            {isAiLoading ? '...' : 'SYNC'}
          </button>
        </div>
      </header>

      {aiMessage && (
        <div className="max-w-4xl mx-auto mt-14 px-12 animate-in slide-in-from-top-6">
           <div className="bg-[#3b5bdb] text-white rounded-[48px] p-10 shadow-3xl relative">
             <p className="font-bold text-xl leading-relaxed">{aiMessage}</p>
             <button onClick={() => setAiMessage(null)} className="absolute top-8 right-8 opacity-40 hover:opacity-100 transition-opacity"><svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
           </div>
        </div>
      )}

      <main className="mt-20 px-12 max-w-[2000px] mx-auto">
        {view === 'monthly' ? (
          <div className="bg-white rounded-[60px] shadow-sm border border-slate-100 overflow-hidden">
            <div className="grid grid-cols-7 border-b border-slate-50">
              {DAYS_SHORT.map(d => <div key={d} className="py-8 text-center text-sm font-black text-slate-400 uppercase tracking-[0.3em]">{d}</div>)}
            </div>
            <div className="grid grid-cols-7">
              {monthGrid.map(({ date, currentMonth }, i) => {
                const dateKey = formatDateKey(date);
                const dayTasks = tasks.filter(t => t.date === dateKey);
                const isSelected = dateKey === formatDateKey(baseDate);
                const isToday = dateKey === formatDateKey(new Date());
                return (
                  <div 
                    key={i} 
                    onClick={() => { setBaseDate(new Date(date)); setView('daily'); }}
                    className={`min-h-[180px] p-5 border-r border-b border-slate-50 cursor-pointer transition-all hover:bg-slate-50 group ${!currentMonth ? 'opacity-20' : ''} ${isSelected ? 'bg-blue-50/20' : ''}`}
                  >
                    <div className="flex justify-between items-center mb-4">
                      <span className={`text-sm font-black ${isToday ? 'bg-[#3b5bdb] text-white w-8 h-8 flex items-center justify-center rounded-xl shadow-lg' : isSelected ? 'text-[#3b5bdb]' : 'text-slate-400'}`}>
                        {date.getDate()}
                      </span>
                    </div>
                    <div className="flex flex-col gap-2.5">
                      {dayTasks.slice(0, 4).map(t => (
                        <div key={t.id} className={`px-3 py-2 rounded-xl text-[10px] font-bold flex items-center gap-2.5 ${SECTION_STYLES[t.section].bg} ${SECTION_STYLES[t.section].text} ${t.completed ? 'opacity-30' : ''}`}>
                          <span className="shrink-0 w-2 h-2 rounded-full bg-current opacity-40" />
                          <span className="break-words line-clamp-2">{t.section}: {t.title}</span>
                        </div>
                      ))}
                      {dayTasks.length > 4 && (
                        <span className="text-[10px] font-black text-slate-300 ml-2">+{dayTasks.length - 4} MORE</span>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : view === 'weekly' ? (
          <div className="space-y-16 pb-20">
            {/* Main Weekday Row - Forced to 5 columns on desktop sizes */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-10">
              {currentRangeDays.slice(0, 5).map((d, i) => (
                <DayColumn
                  key={i}
                  date={d}
                  tasks={tasks.filter(t => t.date === formatDateKey(d))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              ))}
            </div>
            {/* Weekend Row */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-10">
              <div className="lg:col-start-2">
                <DayColumn
                  date={currentRangeDays[5]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[5]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              </div>
              <div className="lg:col-start-3">
                <DayColumn
                  date={currentRangeDays[6]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[6]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              </div>
            </div>
          </div>
        ) : (
          <div className="flex justify-center pb-20">
            <DayColumn
              date={currentRangeDays[0]}
              tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[0]))}
              onToggleTask={toggleTask}
              onDragStartTask={handleDragStartTask}
              onDropTask={moveTask}
              onAddTask={handleAddTask}
              onEditTask={handleEditTask}
              isFocused
            />
          </div>
        )}
      </main>

      <div className="fixed bottom-12 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur-3xl px-14 py-7 rounded-[56px] shadow-[0_40px_100px_rgba(0,0,0,0.15)] border border-white/60 flex items-center gap-14 z-[60]">
        <div className="flex flex-col">
          <span className="text-[12px] font-black text-slate-400 uppercase tracking-[0.25em]">Progress</span>
          <span className="text-3xl font-black text-[#3b5bdb] tracking-tighter leading-none mt-1">{progressPercent}%</span>
        </div>
        <div className="w-72 sm:w-[450px] h-5 bg-slate-100 rounded-full overflow-hidden p-1 shadow-inner">
          <div className="h-full bg-gradient-to-r from-blue-400 to-[#3b5bdb] rounded-full transition-all duration-1000 shadow-[0_0_20px_rgba(59,91,219,0.35)]" style={{ width: `${progressPercent}%` }} />
        </div>
        <div className="flex items-center gap-5">
          <div className="w-14 h-14 rounded-[24px] bg-[#3b5bdb] flex items-center justify-center text-white font-black text-lg shadow-2xl shadow-blue-200">{tasks.filter(t => t.completed).length}</div>
          <span className="hidden sm:inline text-sm font-black text-slate-500 uppercase tracking-[0.2em]">Tasks Done</span>
        </div>
      </div>

      <EditTaskModal isOpen={isModalOpen} task={currentTaskToEdit} onClose={() => setIsModalOpen(false)} onSave={saveTask} onDelete={deleteTask} />
    </div>
  );
};

export default App;

