import React, { useState, useEffect } from 'react';
import { StudyTask, MCATSection, RecurrenceType } from '../types';
import { SECTION_STYLES } from '../constants';

interface EditTaskModalProps {
  task: Partial<StudyTask> | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: StudyTask, scope?: 'single' | 'future') => void;
  onDelete?: (id: string) => void;
}

const EditTaskModal: React.FC<EditTaskModalProps> = ({ task, isOpen, onClose, onSave, onDelete }) => {
  const [title, setTitle] = useState('');
  const [section, setSection] = useState<MCATSection>('Biology');
  const [duration, setDuration] = useState('');
  const [recurrence, setRecurrence] = useState<RecurrenceType>('None');
  const [date, setDate] = useState('');
  const [saveScope, setSaveScope] = useState<'single' | 'future'>('single');

  useEffect(() => {
    if (task) {
      setTitle(task.title || '');
      setSection(task.section || 'Biology');
      setDuration(task.duration || '');
      setRecurrence(task.recurrence || 'None');
      setDate(task.date || '');
      setSaveScope('single');
    }
  }, [task, isOpen]);

  if (!isOpen || !task) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      ...task,
      title,
      section,
      duration,
      recurrence,
      date,
    } as StudyTask, saveScope);
    onClose();
  };

  const isRecurringInstance = !!task.groupId;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white w-full max-w-md rounded-[40px] p-10 shadow-2xl animate-in zoom-in-95 duration-200">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">
            {task.id ? 'Edit Task' : 'New Task'}
          </h2>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 transition-colors">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-8">
          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Task Title</label>
            <input
              autoFocus
              required
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-5 py-3.5 font-bold text-slate-800 focus:border-[#3b5bdb] focus:ring-0 outline-none transition-all"
              placeholder="e.g. Enzyme Kinetics"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Date</label>
              <input
                required
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-5 py-3.5 font-bold text-slate-800 focus:border-[#3b5bdb] focus:ring-0 outline-none transition-all"
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Duration</label>
              <input
                required
                type="text"
                value={duration}
                onChange={(e) => setDuration(e.target.value)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-5 py-3.5 font-bold text-slate-800 focus:border-[#3b5bdb] focus:ring-0 outline-none transition-all"
                placeholder="e.g. 2h"
              />
            </div>
          </div>

          <div>
             <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Subject</label>
              <select
                value={section}
                onChange={(e) => setSection(e.target.value as MCATSection)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-5 py-3.5 font-bold text-slate-800 focus:border-[#3b5bdb] focus:ring-0 outline-none transition-all appearance-none cursor-pointer"
              >
                {Object.keys(SECTION_STYLES).map((s) => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
          </div>

          {task.id && isRecurringInstance && (
            <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100 animate-in slide-in-from-bottom-2">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 text-center">Recurring Update Scope</label>
              <div className="flex gap-2">
                <button
                  type="button"
                  onClick={() => setSaveScope('single')}
                  className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all border-2 ${
                    saveScope === 'single'
                      ? 'bg-white border-[#3b5bdb] text-[#3b5bdb] shadow-sm'
                      : 'bg-transparent border-slate-200 text-slate-400'
                  }`}
                >
                  This day
                </button>
                <button
                  type="button"
                  onClick={() => setSaveScope('future')}
                  className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all border-2 ${
                    saveScope === 'future'
                      ? 'bg-white border-[#3b5bdb] text-[#3b5bdb] shadow-sm'
                      : 'bg-transparent border-slate-200 text-slate-400'
                  }`}
                >
                  Future days
                </button>
              </div>
            </div>
          )}

          {!task.id && (
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Frequency</label>
              <div className="flex gap-2">
                {(['None', 'Daily'] as RecurrenceType[]).map((type) => (
                  <button
                    key={type}
                    type="button"
                    onClick={() => setRecurrence(type)}
                    className={`flex-1 py-3.5 rounded-2xl font-black text-xs uppercase tracking-widest transition-all border-2 ${
                      recurrence === type 
                        ? 'bg-slate-900 text-white border-slate-900 shadow-lg' 
                        : 'bg-white text-slate-500 border-slate-100 hover:border-slate-200'
                    }`}
                  >
                    {type === 'None' ? 'One-time' : 'Repeat Daily'}
                  </button>
                ))}
              </div>
            </div>
          )}

          <div className="pt-4 flex gap-3">
            <button
              type="submit"
              className="flex-1 bg-[#3b5bdb] text-white py-4.5 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-[#2f49b1] shadow-xl shadow-blue-200 transition-all active:scale-[0.98]"
            >
              {task.id ? 'Save Changes' : 'Create Task'}
            </button>
            {task.id && onDelete && (
              <button
                type="button"
                onClick={() => {
                  if (confirm('Permanently delete this task?')) {
                    onDelete(task.id!);
                    onClose();
                  }
                }}
                className="w-14 bg-rose-50 text-rose-500 rounded-2xl flex items-center justify-center hover:bg-rose-100 transition-all shadow-sm border border-rose-100"
              >
                <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default EditTaskModal;

export type MCATSection = 
  | 'Biology' 
  | 'Biochemistry' 
  | 'General Chemistry' 
  | 'Organic Chemistry' 
  | 'Physics' 
  | 'Behavioral Sciences' 
  | 'CARS' 
  | 'Practice Exam';

export type RecurrenceType = 'None' | 'Daily';
export type ViewType = 'daily' | 'weekly' | 'monthly';

export interface StudyTask {
  id: string;
  groupId?: string; // Links recurring tasks
  title: string;
  description: string;
  section: MCATSection;
  completed: boolean;
  date: string; // ISO format YYYY-MM-DD
  duration: string;
  recurrence?: RecurrenceType;
}

export interface AIResponse {
  suggestion: string;
  updatedTasks: StudyTask[];
}

import React from 'react';
import { StudyTask } from '../types';
import { SECTION_STYLES } from '../constants';

