import { INITIAL_TASKS, formatDateKey, DAYS_SHORT, SECTION_STYLES } from './constants';
import { adaptSchedule } from './services/geminiService';

const STORAGE_KEY = 'mcat-pulse-v9';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>([]);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');
  const [view, setView] = useState<ViewType>('weekly');
  const [baseDate, setBaseDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  // Initialize state from storage or defaults
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        setTasks(JSON.parse(saved));
      } catch (e) {
        setTasks(INITIAL_TASKS);
      }
    } else {
      setTasks(INITIAL_TASKS);
    }
  }, []);

  // Persist state changes
  useEffect(() => {
    if (tasks.length > 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(tasks));
    }
  }, [tasks]);

  // Task Handlers
  const toggleTask = (id: string) => setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  const handleDragStartTask = (e: React.DragEvent, id: string) => e.dataTransfer.setData('taskId', id);
  const moveTask = (taskId: string, targetDate: string) => setTasks(prev => prev.map(t => t.id === taskId ? { ...t, date: targetDate } : t));
  const handleEditTask = (task: StudyTask) => { setCurrentTaskToEdit(task); setIsModalOpen(true); };
  const handleAddTask = (dateKey: string) => { 
    setCurrentTaskToEdit({ 
      date: dateKey, 
      completed: false, 
      title: '', 
      description: '', 
      section: 'Biology', 
      duration: '1h', 
      recurrence: 'None' 
    }); 
    setIsModalOpen(true); 
  };

  const deleteTask = (task: Partial<StudyTask>, scope: 'single' | 'future' = 'single') => {
    const taskId = task.id;
    if (!taskId) return;

    setTasks(prev => {
      if (scope === 'future' && task.groupId && task.date) {
        return prev.filter(t => !(t.groupId === task.groupId && t.date >= task.date));
      }
      return prev.filter(t => t.id !== taskId);
    });
  };

  const saveTask = (task: StudyTask, scope: 'single' | 'future' = 'single') => {
    if (task.id) {
      if (scope === 'future' && task.groupId) {
        setTasks(prev => prev.map(t => {
          if (t.groupId === task.groupId && t.date >= task.date) {
            return { ...t, title: task.title, section: task.section, duration: task.duration };
          }
          return t;
        }));
      } else {
        setTasks(prev => prev.map(t => t.id === task.id ? task : t));
      }
    } else {
      if (task.recurrence && task.recurrence !== 'None') {
        const groupId = Math.random().toString(36).substr(2, 9);
        let occurrences = 12; 
        let interval = 1;

        if (task.recurrence === 'Weekly') interval = 7;
        if (task.recurrence === 'Custom' && task.customInterval) interval = task.customInterval;

        const newTasks: StudyTask[] = Array.from({ length: occurrences }).map((_, i) => {
          const d = new Date(task.date);
          d.setDate(d.getDate() + (i * interval));
          return { 
            ...task, 
            id: Math.random().toString(36).substr(2, 9), 
            groupId, 
            date: formatDateKey(d) 
          };
        });
        setTasks(prev => [...prev, ...newTasks]);
      } else {
        setTasks(prev => [...prev, { ...task, id: Math.random().toString(36).substr(2, 9) }]);
      }
    }
  };

  const navigate = (amount: number) => {
    const newDate = new Date(baseDate);
    if (view === 'daily') newDate.setDate(newDate.getDate() + amount);
    if (view === 'weekly') newDate.setDate(newDate.getDate() + (amount * 7));
    if (view === 'monthly') newDate.setMonth(newDate.getMonth() + amount);
    setBaseDate(newDate);
  };

  const currentRangeDays = useMemo(() => {
    if (view === 'daily') return [new Date(baseDate)];
    if (view === 'weekly') {
      const start = new Date(baseDate);
      const day = start.getDay();
      const shift = day === 0 ? 6 : day - 1;
      start.setDate(start.getDate() - shift); 
      return Array.from({ length: 7 }).map((_, i) => {
        const d = new Date(start);
        d.setDate(d.getDate() + i);
        return d;
      });
    }
    return [];
  }, [view, baseDate]);

  const monthGrid = useMemo(() => {
    if (view !== 'monthly') return [];
    const start = new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
    const end = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0);
    const startDay = start.getDay();
    const padding = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < padding; i++) {
      const d = new Date(start);
      d.setDate(d.getDate() - (padding - i));
      days.push({ date: d, currentMonth: false });
    }
    for (let i = 1; i <= end.getDate(); i++) {
      days.push({ date: new Date(baseDate.getFullYear(), baseDate.getMonth(), i), currentMonth: true });
    }
    const totalSlots = days.length > 35 ? 42 : 35;
    const remaining = totalSlots - days.length;
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(end);
      d.setDate(d.getDate() + i);
      days.push({ date: d, currentMonth: false });
    }
    return days;
  }, [view, baseDate]);

  const handleAiUpdate = async () => {
    if (!userInput.trim() && tasks.every(t => !t.completed)) return;
    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput || "Optimize my schedule.");
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      setAiMessage("Sync failed. Check your connection.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const progressPercent = tasks.length > 0 
    ? Math.round((tasks.filter(t => t.completed).length / tasks.length) * 100)
    : 0;

  return (
    <div className="min-h-screen bg-[#f8faff] pb-40">
      <header className="px-8 pt-8 max-w-[1800px] mx-auto flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="shrink-0">
          <h1 className="text-3xl font-black text-slate-900 tracking-tight flex items-center gap-2">
            <span className="text-[#3b5bdb]">MCAT</span> PULSE
          </h1>
          <p className="text-slate-400 font-bold text-sm tracking-wide mt-1 uppercase">PRECISION PLANNER</p>
        </div>

        <div className="flex flex-wrap items-center justify-center gap-4 bg-white p-2 rounded-[28px] shadow-sm border border-slate-100">
           <div className="flex bg-slate-50 p-1 rounded-2xl">
             {(['daily', 'weekly', 'monthly'] as ViewType[]).map(v => (
               <button 
                 key={v}
                 onClick={() => setView(v)}
                 className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${view === v ? 'bg-white text-[#3b5bdb] shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
               >
                 {v}
               </button>
             ))}
           </div>
           <div className="h-6 w-px bg-slate-200" />
           <div className="flex items-center gap-2">
             <button onClick={() => navigate(-1)} className="p-2 hover:bg-slate-50 rounded-xl transition-colors"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M15 18l-6-6 6-6"/></svg></button>
             <button onClick={() => setBaseDate(new Date())} className="px-4 py-2 text-xs font-black text-[#3b5bdb] uppercase tracking-tighter hover:bg-slate-50 rounded-xl">Today</button>
             <button onClick={() => navigate(1)} className="p-2 hover:bg-slate-50 rounded-xl transition-colors"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M9 18l6-6-6-6"/></svg></button>
           </div>
        </div>

        <div className="w-full sm:w-auto md:max-w-md bg-white rounded-3xl p-2 shadow-sm border border-slate-100 flex items-center gap-2">
          <input
            type="text"
            value={userInput}
            onChange={(e) => setUserInput(e.target.value)}
            placeholder="Describe your goals..."
            className="flex-1 bg-transparent border-none px-4 py-2 font-semibold text-sm focus:ring-0 outline-none placeholder:text-slate-300"
          />
          <button
            onClick={handleAiUpdate}
            disabled={isAiLoading}
            className="bg-[#3b5bdb] text-white px-6 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-[#2f49b1] transition-all disabled:opacity-50"
          >
            {isAiLoading ? '...' : 'SYNC'}
          </button>
        </div>
      </header>

      {aiMessage && (
        <div className="max-w-2xl mx-auto mt-8 px-6 animate-in slide-in-from-top-4">
           <div className="bg-[#3b5bdb] text-white rounded-3xl p-6 shadow-xl relative">
             <p className="font-bold leading-relaxed">{aiMessage}</p>
             <button onClick={() => setAiMessage(null)} className="absolute top-4 right-4 opacity-50 hover:opacity-100"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
           </div>
        </div>
      )}

      <main className="mt-12 px-8 max-w-[1800px] mx-auto overflow-visible">
        {view === 'monthly' ? (
          <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
            <div className="grid grid-cols-7 border-b border-slate-50">
              {DAYS_SHORT.map(d => <div key={d} className="py-4 text-center text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{d}</div>)}
            </div>
            <div className="grid grid-cols-7">
              {monthGrid.map(({ date, currentMonth }, i) => {
                const dateKey = formatDateKey(date);
                const dayTasks = tasks.filter(t => t.date === dateKey);
                const isSelected = dateKey === formatDateKey(baseDate);
                const isToday = dateKey === formatDateKey(new Date());
                return (
                  <div 
                    key={i} 
                    onClick={() => { setBaseDate(new Date(date)); setView('daily'); }}
                    className={`min-h-[140px] p-2 border-r border-b border-slate-50 cursor-pointer transition-all hover:bg-slate-50 group ${!currentMonth ? 'opacity-30' : ''} ${isSelected ? 'bg-blue-50/30' : ''}`}
                  >
                    <div className="flex justify-between items-center mb-1.5">
                      <span className={`text-[11px] font-black ${isToday ? 'bg-[#3b5bdb] text-white w-6 h-6 flex items-center justify-center rounded-lg shadow-sm' : isSelected ? 'text-[#3b5bdb]' : 'text-slate-400'}`}>
                        {date.getDate()}
                      </span>
                    </div>
                    <div className="flex flex-col gap-1 overflow-hidden">
                      {dayTasks.slice(0, 3).map(t => (
                        <div key={t.id} className={`px-2 py-1 rounded-md text-[8px] font-bold truncate flex items-center gap-1.5 ${SECTION_STYLES[t.section].bg} ${SECTION_STYLES[t.section].text} ${t.completed ? 'opacity-40' : ''}`}>
                          <span className="shrink-0 w-1 h-1 rounded-full bg-current opacity-50" />
                          <span className="truncate">{t.section}: {t.title}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : view === 'weekly' ? (
          <div className="space-y-12 pb-8">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-6">
              {currentRangeDays.slice(0, 5).map((d, i) => (
                <DayColumn
                  key={i}
                  date={d}
                  tasks={tasks.filter(t => t.date === formatDateKey(d))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              ))}
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-6">
              <div className="lg:col-start-2">
                <DayColumn
                  date={currentRangeDays[5]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[5]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              </div>
              <div className="lg:col-start-3">
                <DayColumn
                  date={currentRangeDays[6]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[6]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                />
              </div>
            </div>
          </div>
        ) : (
          <div className="flex justify-center pb-8">
            <DayColumn
              date={currentRangeDays[0]}
              tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[0]))}
              onToggleTask={toggleTask}
              onDragStartTask={handleDragStartTask}
              onDropTask={moveTask}
              onAddTask={handleAddTask}
              onEditTask={handleEditTask}
              isFocused
            />
          </div>
        )}
      </main>

      <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur-xl px-10 py-5 rounded-[40px] shadow-[0_20px_60px_rgba(0,0,0,0.1)] border border-white flex items-center gap-8 z-50">
        <div className="flex flex-col">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Mastery</span>
          <span className="text-xl font-black text-[#3b5bdb]">{progressPercent}%</span>
        </div>
        <div className="w-48 sm:w-64 h-3 bg-slate-100 rounded-full overflow-hidden">
          <div className="h-full bg-gradient-to-r from-blue-400 to-[#3b5bdb] transition-all duration-1000" style={{ width: `${progressPercent}%` }} />
        </div>
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-2xl bg-[#3b5bdb] flex items-center justify-center text-white font-black text-xs">{tasks.filter(t => t.completed).length}</div>
          <span className="hidden sm:inline text-xs font-bold text-slate-500">Done</span>
        </div>
      </div>

      <EditTaskModal isOpen={isModalOpen} task={currentTaskToEdit} onClose={() => setIsModalOpen(false)} onSave={saveTask} onDelete={deleteTask} />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { StudyTask, MCATSection, RecurrenceType } from '../types';
import { SECTION_STYLES } from '../constants';

interface EditTaskModalProps {
  task: Partial<StudyTask> | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: StudyTask, scope?: 'single' | 'future') => void;
  onDelete?: (task: Partial<StudyTask>, scope?: 'single' | 'future') => void;
}

const EditTaskModal: React.FC<EditTaskModalProps> = ({ task, isOpen, onClose, onSave, onDelete }) => {
  const [title, setTitle] = useState('');
  const [section, setSection] = useState<MCATSection>('Biology');
  const [duration, setDuration] = useState('');
  const [recurrence, setRecurrence] = useState<RecurrenceType>('None');
  const [customInterval, setCustomInterval] = useState(2);
  const [date, setDate] = useState('');
  const [saveScope, setSaveScope] = useState<'single' | 'future'>('single');

  useEffect(() => {
    if (task && isOpen) {
      setTitle(task.title || '');
      setSection(task.section || 'Biology');
      setDuration(task.duration || '');
      setRecurrence(task.recurrence || 'None');
      setCustomInterval(task.customInterval || 2);
      setDate(task.date || '');
      setSaveScope('single');
    }
  }, [task, isOpen]);

  if (!isOpen || !task) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      ...task,
      title,
      section,
      duration,
      recurrence,
      customInterval: recurrence === 'Custom' ? customInterval : undefined,
      date,
    } as StudyTask, saveScope);
    onClose();
  };

  const handleDelete = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (onDelete && task.id) {
      const confirmMsg = saveScope === 'future' && task.groupId
        ? 'Delete this and all future occurrences?'
        : 'Permanently delete this task?';

      if (window.confirm(confirmMsg)) {
        onDelete(task, saveScope);
        onClose();
      }
    }
  };

  const isRecurringInstance = !!task.groupId;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white w-full max-w-md rounded-[32px] p-8 shadow-2xl animate-in zoom-in-95 duration-200" onClick={e => e.stopPropagation()}>
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">
            {task.id ? 'Edit Task' : 'New Task'}
          </h2>
          <button onClick={onClose} type="button" className="text-slate-400 hover:text-slate-600 p-2 transition-colors">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Task Title</label>
            <input
              autoFocus
              required
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-4 py-3 font-bold text-slate-800 focus:border-[#3b5bdb] focus:ring-0 outline-none transition-all"
              placeholder="e.g. Enzyme Kinetics"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Date</label>
              <input
                required
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-4 py-3 font-bold text-slate-800 focus:border-[#3b5bdb] focus:ring-0 outline-none transition-all"
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Duration</label>
              <input
                required
                type="text"
                value={duration}
                onChange={(e) => setDuration(e.target.value)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-4 py-3 font-bold text-slate-800 focus:border-[#3b5bdb] focus:ring-0 outline-none transition-all"
                placeholder="e.g. 2h"
              />
            </div>
          </div>

          <div>
             <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Subject</label>
              <select
                value={section}
                onChange={(e) => setSection(e.target.value as MCATSection)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-4 py-3 font-bold text-slate-800 focus:border-[#3b5bdb] focus:ring-0 outline-none transition-all appearance-none cursor-pointer"
              >
                {Object.keys(SECTION_STYLES).map((s) => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
          </div>

          {!task.id ? (
            <div className="space-y-4">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Recurrence</label>
              <div className="grid grid-cols-2 gap-2">
                {(['None', 'Daily', 'Weekly', 'Custom'] as RecurrenceType[]).map((type) => (
                  <button
                    key={type}
                    type="button"
                    onClick={() => setRecurrence(type)}
                    className={`py-3 rounded-xl font-bold text-xs transition-all border-2 ${
                      recurrence === type 
                        ? 'bg-slate-900 text-white border-slate-900' 
                        : 'bg-white text-slate-500 border-slate-100 hover:border-slate-200'
                    }`}
                  >
                    {type}
                  </button>
                ))}
              </div>

              {recurrence === 'Custom' && (
                <div className="flex items-center gap-3 bg-slate-50 p-3 rounded-xl border border-slate-100 animate-in slide-in-from-top-2">
                  <span className="text-xs font-bold text-slate-500">Every</span>
                  <input 
                    type="number" 
                    min="1" 
                    value={customInterval} 
                    onChange={(e) => setCustomInterval(parseInt(e.target.value) || 1)}
                    className="w-16 bg-white border-2 border-slate-100 rounded-lg px-2 py-1 text-center font-bold text-slate-800 focus:border-[#3b5bdb] outline-none"
                  />
                  <span className="text-xs font-bold text-slate-500">days</span>
                </div>
              )}
            </div>
          ) : isRecurringInstance && (
            <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 animate-in slide-in-from-bottom-2">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 text-center">Recurring Scope</label>
              <div className="flex gap-2">
                <button
                  type="button"
                  onClick={() => setSaveScope('single')}
                  className={`flex-1 py-2.5 rounded-xl font-black text-[10px] uppercase transition-all border-2 ${
                    saveScope === 'single'
                      ? 'bg-white border-[#3b5bdb] text-[#3b5bdb] shadow-sm'
                      : 'bg-transparent border-slate-200 text-slate-400'
                  }`}
                >
                  Just this one
                </button>
                <button
                  type="button"
                  onClick={() => setSaveScope('future')}
                  className={`flex-1 py-2.5 rounded-xl font-black text-[10px] uppercase transition-all border-2 ${
                    saveScope === 'future'
                      ? 'bg-white border-[#3b5bdb] text-[#3b5bdb] shadow-sm'
                      : 'bg-transparent border-slate-200 text-slate-400'
                  }`}
                >
                  This and upcoming
                </button>
              </div>
            </div>
          )}

          <div className="pt-4 flex gap-3">
            <button
              type="submit"
              className="flex-1 bg-[#3b5bdb] text-white py-4 rounded-2xl font-black uppercase tracking-widest hover:bg-[#2f49b1] shadow-lg shadow-blue-200 transition-all active:scale-[0.98]"
            >
              {task.id ? 'Save Changes' : 'Create Task'}
            </button>
            {task.id && onDelete && (
              <button
                type="button"
                onClick={handleDelete}
                className="w-14 bg-rose-50 text-rose-500 rounded-2xl flex items-center justify-center hover:bg-rose-100 transition-all border border-rose-100 active:scale-95"
                title="Delete Task"
              >
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default EditTaskModal;

import React from 'react';
import { StudyTask } from '../types';
import { SECTION_STYLES } from '../constants';

interface TaskCardProps {
  task: StudyTask;
  onToggle: (id: string) => void;
  onDragStart: (e: React.DragEvent, id: string) => void;
  onEdit: (task: StudyTask) => void;
  onDelete: (task: StudyTask) => void;
}

const TaskCard: React.FC<TaskCardProps> = ({ task, onToggle, onDragStart, onEdit, onDelete }) => {
  const styles = SECTION_STYLES[task.section];

  const handleDelete = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm('Delete this task?')) {
      onDelete(task);
    }
  };

  return (
    <div
      draggable
      onDragStart={(e) => onDragStart(e, task.id)}
      onClick={() => onEdit(task)}
      className={`group relative p-3.5 mb-2.5 bg-white rounded-2xl border border-slate-100 shadow-[0_4px_12px_rgba(0,0,0,0.03)] transition-all cursor-grab active:cursor-grabbing hover:shadow-[0_10px_25px_rgba(0,0,0,0.06)] hover:border-slate-200 ${
        task.completed ? 'opacity-60' : ''
      }`}
    >
      {/* Top Right Status Dot / Delete Button */}
      <div className="absolute top-2.5 right-2.5">
        {!task.completed && (
          <div className="w-1.5 h-1.5 bg-[#ff6b81] rounded-full group-hover:hidden transition-all" />
        )}
        <button
          onClick={handleDelete}
          className="hidden group-hover:flex items-center justify-center w-6 h-6 -mt-1.5 -mr-1.5 bg-rose-50 text-rose-500 rounded-lg hover:bg-rose-100 transition-all border border-rose-100 shadow-sm"
          title="Delete Task"
        >
          <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
            <polyline points="3 6 5 6 21 6"></polyline>
            <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
          </svg>
        </button>
      </div>

      <div className="flex gap-3 items-start">
        {/* Checkbox Section */}
        <div className="flex shrink-0 pt-0.5" onClick={(e) => e.stopPropagation()}>
          <button
            onClick={() => onToggle(task.id)}
            className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${
              task.completed 
                ? 'bg-[#3b5bdb] border-[#3b5bdb]' 
                : 'bg-white border-slate-200 hover:border-[#3b5bdb]/50'
            }`}
          >
            {task.completed && (
              <svg width="12" height="9" viewBox="0 0 14 11" fill="none" xmlns="http://www.w3.org/2000/svg">
                <path d="M1 6L5 9.5L13 1" stroke="white" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
            )}
          </button>
        </div>

        {/* Content Section */}
        <div className="flex-1 min-w-0 pr-2">
          <h4 className={`font-black text-[13px] leading-tight text-slate-800 transition-all whitespace-normal break-words ${
            task.completed ? 'line-through text-slate-400 font-bold' : ''
          }`}>
            {task.title}
          </h4>

          <div className="mt-2.5 flex flex-col gap-2">
            <div>
               <span className={`inline-block px-1.5 py-0.5 rounded-lg text-[8px] font-black tracking-widest uppercase border border-transparent ${styles.bg} ${styles.text}`}>
                {styles.label}
              </span>
            </div>

            <div className="flex items-center gap-1 text-slate-400 text-[8.5px] font-black tracking-tighter">
              <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="12" cy="12" r="10"></circle>
                <polyline points="12 6 12 12 16 14"></polyline>
              </svg>
              <span>{task.duration}</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TaskCard;

import React, { useState } from 'react';
import { StudyTask } from '../types';
import TaskCard from './TaskCard';
import { formatDateKey } from '../constants';

interface DayColumnProps {
  date: Date;
  tasks: StudyTask[];
  onToggleTask: (id: string) => void;
  onDropTask: (taskId: string, targetDate: string) => void;
  onDragStartTask: (e: React.DragEvent, id: string) => void;
  onAddTask: (date: string) => void;
  onEditTask: (task: StudyTask) => void;
  onDeleteTask: (task: StudyTask) => void;
  isFocused?: boolean;
}

const DayColumn: React.FC<DayColumnProps> = ({
  date,
  tasks,
  onToggleTask,
  onDropTask,
  onDragStartTask,
  onAddTask,
  onEditTask,
  onDeleteTask,
  isFocused = false
}) => {
  const [isOver, setIsOver] = useState(false);
  const dateKey = formatDateKey(date);
  const isToday = dateKey === formatDateKey(new Date());

  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const dayName = dayNames[date.getDay()];
  const dayNum = date.getDate();

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(true);
  };

  const handleDragLeave = () => {
    setIsOver(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(false);
    const taskId = e.dataTransfer.getData('taskId');
    onDropTask(taskId, dateKey);
  };

  return (
    <div
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`flex flex-col rounded-[32px] border-2 p-7 transition-all h-full ${
        isFocused ? 'min-h-[600px] w-full max-w-[500px]' : 'min-h-[450px] w-full'
      } ${
        isOver 
          ? 'bg-blue-50/50 border-blue-400 border-dashed' 
          : isToday
            ? 'bg-white border-[#3b5bdb]/30 shadow-[0_15px_40px_rgba(59,91,219,0.08)] ring-1 ring-[#3b5bdb]/5'
            : 'bg-[#f5f8ff] border-transparent'
      }`}
    >
      <div className="flex justify-between items-center mb-8">
        <div>
          <h3 className={`text-2xl font-black tracking-tight ${isToday ? 'text-[#3b5bdb]' : 'text-slate-800'}`}>
            {dayName} {dayNum} {isToday && <span className="text-[0.9em] ml-1">(Today)</span>}
          </h3>
          <p className="text-slate-400 font-semibold text-sm mt-0.5">
            {tasks.length} {tasks.length === 1 ? 'task' : 'tasks'}
          </p>
        </div>

        <button 
          onClick={() => onAddTask(dateKey)}
          className="w-11 h-11 rounded-2xl bg-white shadow-[0_8px_20px_rgba(0,0,0,0.06)] border border-slate-100 flex items-center justify-center text-slate-400 hover:text-[#3b5bdb] hover:border-[#3b5bdb]/20 transition-all active:scale-90"
        >
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
            <line x1="12" y1="5" x2="12" y2="19"></line>
            <line x1="5" y1="12" x2="19" y2="12"></line>
          </svg>
        </button>
      </div>

      <div className="flex-1 space-y-4">
        {tasks.map((task) => (
          <TaskCard
            key={task.id}
            task={task}
            onToggle={onToggleTask}
            onDragStart={onDragStartTask}
            onEdit={onEditTask}
            onDelete={onDeleteTask}
          />
        ))}
        {tasks.length === 0 && (
          <div className="h-28 border-2 border-dashed border-slate-200/50 rounded-[28px] flex items-center justify-center text-slate-300 font-bold text-xs italic p-4 text-center">
            Rest day?
          </div>
        )}
      </div>
    </div>
  );
};

export default DayColumn;

import React, { useState, useEffect, useMemo } from 'react';
import DayColumn from './components/DayColumn';
import EditTaskModal from './components/EditTaskModal';
import { StudyTask, ViewType } from './types';
import { INITIAL_TASKS, formatDateKey, DAYS_SHORT, SECTION_STYLES } from './constants';
import { adaptSchedule } from './services/geminiService';

const STORAGE_KEY = 'mcat-pulse-v9';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>([]);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');
  const [view, setView] = useState<ViewType>('weekly');
  const [baseDate, setBaseDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  // Initialize state from storage or defaults
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        setTasks(JSON.parse(saved));
      } catch (e) {
        setTasks(INITIAL_TASKS);
      }
    } else {
      setTasks(INITIAL_TASKS);
    }
  }, []);

  // Persist state changes
  useEffect(() => {
    if (tasks.length > 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(tasks));
    }
  }, [tasks]);

  // Task Handlers
  const toggleTask = (id: string) => setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  const handleDragStartTask = (e: React.DragEvent, id: string) => e.dataTransfer.setData('taskId', id);
  const moveTask = (taskId: string, targetDate: string) => setTasks(prev => prev.map(t => t.id === taskId ? { ...t, date: targetDate } : t));
  const handleEditTask = (task: StudyTask) => { setCurrentTaskToEdit(task); setIsModalOpen(true); };
  const handleAddTask = (dateKey: string) => { 
    setCurrentTaskToEdit({ 
      date: dateKey, 
      completed: false, 
      title: '', 
      description: '', 
      section: 'Biology', 
      duration: '1h', 
      recurrence: 'None' 
    }); 
    setIsModalOpen(true); 
  };

  const deleteTask = (task: Partial<StudyTask>, scope: 'single' | 'future' = 'single') => {
    const taskId = task.id;
    if (!taskId) return;

    setTasks(prev => {
      if (scope === 'future' && task.groupId && task.date) {
        return prev.filter(t => !(t.groupId === task.groupId && t.date >= task.date));
      }
      return prev.filter(t => t.id !== taskId);
    });
  };

  const saveTask = (task: StudyTask, scope: 'single' | 'future' = 'single') => {
    if (task.id) {
      if (scope === 'future' && task.groupId) {
        setTasks(prev => prev.map(t => {
          if (t.groupId === task.groupId && t.date >= task.date) {
            return { ...t, title: task.title, section: task.section, duration: task.duration };
          }
          return t;
        }));
      } else {
        setTasks(prev => prev.map(t => t.id === task.id ? task : t));
      }
    } else {
      if (task.recurrence && task.recurrence !== 'None') {
        const groupId = Math.random().toString(36).substr(2, 9);
        let occurrences = 12; 
        let interval = 1;

        if (task.recurrence === 'Weekly') interval = 7;
        if (task.recurrence === 'Custom' && task.customInterval) interval = task.customInterval;

        const newTasks: StudyTask[] = Array.from({ length: occurrences }).map((_, i) => {
          const d = new Date(task.date);
          d.setDate(d.getDate() + (i * interval));
          return { 
            ...task, 
            id: Math.random().toString(36).substr(2, 9), 
            groupId, 
            date: formatDateKey(d) 
          };
        });
        setTasks(prev => [...prev, ...newTasks]);
      } else {
        setTasks(prev => [...prev, { ...task, id: Math.random().toString(36).substr(2, 9) }]);
      }
    }
  };

  const navigate = (amount: number) => {
    const newDate = new Date(baseDate);
    if (view === 'daily') newDate.setDate(newDate.getDate() + amount);
    if (view === 'weekly') newDate.setDate(newDate.getDate() + (amount * 7));
    if (view === 'monthly') newDate.setMonth(newDate.getMonth() + amount);
    setBaseDate(newDate);
  };

  const currentRangeDays = useMemo(() => {
    if (view === 'daily') return [new Date(baseDate)];
    if (view === 'weekly') {
      const start = new Date(baseDate);
      const day = start.getDay();
      const shift = day === 0 ? 6 : day - 1;
      start.setDate(start.getDate() - shift); 
      return Array.from({ length: 7 }).map((_, i) => {
        const d = new Date(start);
        d.setDate(d.getDate() + i);
        return d;
      });
    }
    return [];
  }, [view, baseDate]);

  const monthGrid = useMemo(() => {
    if (view !== 'monthly') return [];
    const start = new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
    const end = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0);
    const startDay = start.getDay();
    const padding = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < padding; i++) {
      const d = new Date(start);
      d.setDate(d.getDate() - (padding - i));
      days.push({ date: d, currentMonth: false });
    }
    for (let i = 1; i <= end.getDate(); i++) {
      days.push({ date: new Date(baseDate.getFullYear(), baseDate.getMonth(), i), currentMonth: true });
    }
    const totalSlots = days.length > 35 ? 42 : 35;
    const remaining = totalSlots - days.length;
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(end);
      d.setDate(d.getDate() + i);
      days.push({ date: d, currentMonth: false });
    }
    return days;
  }, [view, baseDate]);

  const handleAiUpdate = async () => {
    if (!userInput.trim() && tasks.every(t => !t.completed)) return;
    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput || "Optimize my schedule.");
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      setAiMessage("Sync failed. Check your connection.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const progressPercent = tasks.length > 0 
    ? Math.round((tasks.filter(t => t.completed).length / tasks.length) * 100)
    : 0;

  return (
    <div className="min-h-screen bg-[#f8faff] pb-40">
      <header className="px-8 pt-8 max-w-[1800px] mx-auto flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="shrink-0">
          <h1 className="text-3xl font-black text-slate-900 tracking-tight flex items-center gap-2">
            <span className="text-[#3b5bdb]">MCAT</span> PULSE
          </h1>
          <p className="text-slate-400 font-bold text-sm tracking-wide mt-1 uppercase">PRECISION PLANNER</p>
        </div>

        <div className="flex flex-wrap items-center justify-center gap-4 bg-white p-2 rounded-[28px] shadow-sm border border-slate-100">
           <div className="flex bg-slate-50 p-1 rounded-2xl">
             {(['daily', 'weekly', 'monthly'] as ViewType[]).map(v => (
               <button 
                 key={v}
                 onClick={() => setView(v)}
                 className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${view === v ? 'bg-white text-[#3b5bdb] shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
               >
                 {v}
               </button>
             ))}
           </div>
           <div className="h-6 w-px bg-slate-200" />
           <div className="flex items-center gap-2">
             <button onClick={() => navigate(-1)} className="p-2 hover:bg-slate-50 rounded-xl transition-colors"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M15 18l-6-6 6-6"/></svg></button>
             <button onClick={() => setBaseDate(new Date())} className="px-4 py-2 text-xs font-black text-[#3b5bdb] uppercase tracking-tighter hover:bg-slate-50 rounded-xl">Today</button>
             <button onClick={() => navigate(1)} className="p-2 hover:bg-slate-50 rounded-xl transition-colors"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M9 18l6-6-6-6"/></svg></button>
           </div>
        </div>

        <div className="w-full sm:w-auto md:max-w-md bg-white rounded-3xl p-2 shadow-sm border border-slate-100 flex items-center gap-2">
          <input
            type="text"
            value={userInput}
            onChange={(e) => setUserInput(e.target.value)}
            placeholder="Describe your goals..."
            className="flex-1 bg-transparent border-none px-4 py-2 font-semibold text-sm focus:ring-0 outline-none placeholder:text-slate-300"
          />
          <button
            onClick={handleAiUpdate}
            disabled={isAiLoading}
            className="bg-[#3b5bdb] text-white px-6 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-[#2f49b1] transition-all disabled:opacity-50"
          >
            {isAiLoading ? '...' : 'SYNC'}
          </button>
        </div>
      </header>

      {aiMessage && (
        <div className="max-w-2xl mx-auto mt-8 px-6 animate-in slide-in-from-top-4">
           <div className="bg-[#3b5bdb] text-white rounded-3xl p-6 shadow-xl relative">
             <p className="font-bold leading-relaxed">{aiMessage}</p>
             <button onClick={() => setAiMessage(null)} className="absolute top-4 right-4 opacity-50 hover:opacity-100"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
           </div>
        </div>
      )}

      <main className="mt-12 px-8 max-w-[1800px] mx-auto overflow-visible">
        {view === 'monthly' ? (
          <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
            <div className="grid grid-cols-7 border-b border-slate-50">
              {DAYS_SHORT.map(d => <div key={d} className="py-4 text-center text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{d}</div>)}
            </div>
            <div className="grid grid-cols-7">
              {monthGrid.map(({ date, currentMonth }, i) => {
                const dateKey = formatDateKey(date);
                const dayTasks = tasks.filter(t => t.date === dateKey);
                const isSelected = dateKey === formatDateKey(baseDate);
                const isToday = dateKey === formatDateKey(new Date());
                return (
                  <div 
                    key={i} 
                    onClick={() => { setBaseDate(new Date(date)); setView('daily'); }}
                    className={`min-h-[140px] p-2 border-r border-b border-slate-50 cursor-pointer transition-all hover:bg-slate-50 group ${!currentMonth ? 'opacity-30' : ''} ${isSelected ? 'bg-blue-50/30' : ''}`}
                  >
                    <div className="flex justify-between items-center mb-1.5">
                      <span className={`text-[11px] font-black ${isToday ? 'bg-[#3b5bdb] text-white w-6 h-6 flex items-center justify-center rounded-lg shadow-sm' : isSelected ? 'text-[#3b5bdb]' : 'text-slate-400'}`}>
                        {date.getDate()}
                      </span>
                    </div>
                    <div className="flex flex-col gap-1 overflow-hidden">
                      {dayTasks.slice(0, 3).map(t => (
                        <div key={t.id} className={`px-2 py-1 rounded-md text-[8px] font-bold truncate flex items-center gap-1.5 ${SECTION_STYLES[t.section].bg} ${SECTION_STYLES[t.section].text} ${t.completed ? 'opacity-40' : ''}`}>
                          <span className="shrink-0 w-1 h-1 rounded-full bg-current opacity-50" />
                          <span className="truncate">{t.section}: {t.title}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : view === 'weekly' ? (
          <div className="space-y-12 pb-8">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-6">
              {currentRangeDays.slice(0, 5).map((d, i) => (
                <DayColumn
                  key={i}
                  date={d}
                  tasks={tasks.filter(t => t.date === formatDateKey(d))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                  onDeleteTask={(task) => deleteTask(task, 'single')}
                />
              ))}
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-6">
              <div className="lg:col-start-2">
                <DayColumn
                  date={currentRangeDays[5]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[5]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                  onDeleteTask={(task) => deleteTask(task, 'single')}
                />
              </div>
              <div className="lg:col-start-3">
                <DayColumn
                  date={currentRangeDays[6]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[6]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                  onDeleteTask={(task) => deleteTask(task, 'single')}
                />
              </div>
            </div>
          </div>
        ) : (
          <div className="flex justify-center pb-8">
            <DayColumn
              date={currentRangeDays[0]}
              tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[0]))}
              onToggleTask={toggleTask}
              onDragStartTask={handleDragStartTask}
              onDropTask={moveTask}
              onAddTask={handleAddTask}
              onEditTask={handleEditTask}
              onDeleteTask={(task) => deleteTask(task, 'single')}
              isFocused
            />
          </div>
        )}
      </main>

      <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur-xl px-10 py-5 rounded-[40px] shadow-[0_20px_60px_rgba(0,0,0,0.1)] border border-white flex items-center gap-8 z-50">
        <div className="flex flex-col">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Mastery</span>
          <span className="text-xl font-black text-[#3b5bdb]">{progressPercent}%</span>
        </div>
        <div className="w-48 sm:w-64 h-3 bg-slate-100 rounded-full overflow-hidden">
          <div className="h-full bg-gradient-to-r from-blue-400 to-[#3b5bdb] transition-all duration-1000" style={{ width: `${progressPercent}%` }} />
        </div>
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-2xl bg-[#3b5bdb] flex items-center justify-center text-white font-black text-xs">{tasks.filter(t => t.completed).length}</div>
          <span className="hidden sm:inline text-xs font-bold text-slate-500">Done</span>
        </div>
      </div>

      <EditTaskModal isOpen={isModalOpen} task={currentTaskToEdit} onClose={() => setIsModalOpen(false)} onSave={saveTask} onDelete={deleteTask} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import DayColumn from './components/DayColumn';
import EditTaskModal from './components/EditTaskModal';
import { StudyTask, ViewType } from './types';
import { INITIAL_TASKS, formatDateKey, DAYS_SHORT, SECTION_STYLES } from './constants';
import { adaptSchedule } from './services/geminiService';

const STORAGE_KEY = 'mcat-pulse-v9';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>([]);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');
  const [view, setView] = useState<ViewType>('weekly');
  const [baseDate, setBaseDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  // 1. Initialize state from storage or defaults (runs once)
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed)) {
          setTasks(parsed);
          return;
        }
      } catch (e) {
        console.error("Storage parse error", e);
      }
    }
    setTasks(INITIAL_TASKS);
  }, []);

  // 2. Persist state changes (runs whenever tasks array updates)
  useEffect(() => {
    // We remove the length check so that empty arrays (deleting last task) are persisted.
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tasks));
  }, [tasks]);

  // Task Handlers
  const toggleTask = (id: string) => setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  const handleDragStartTask = (e: React.DragEvent, id: string) => e.dataTransfer.setData('taskId', id);
  const moveTask = (taskId: string, targetDate: string) => setTasks(prev => prev.map(t => t.id === taskId ? { ...t, date: targetDate } : t));
  const handleEditTask = (task: StudyTask) => { setCurrentTaskToEdit(task); setIsModalOpen(true); };
  const handleAddTask = (dateKey: string) => { 
    setCurrentTaskToEdit({ 
      date: dateKey, 
      completed: false, 
      title: '', 
      description: '', 
      section: 'Biology', 
      duration: '1h', 
      recurrence: 'None' 
    }); 
    setIsModalOpen(true); 
  };

  const deleteTask = (task: Partial<StudyTask>, scope: 'single' | 'future' = 'single') => {
    const taskId = task.id;
    if (!taskId) return;

    setTasks(prev => {
      if (scope === 'future' && task.groupId && task.date) {
        return prev.filter(t => !(t.groupId === task.groupId && t.date >= task.date));
      }
      return prev.filter(t => t.id !== taskId);
    });
  };

  const saveTask = (task: StudyTask, scope: 'single' | 'future' = 'single') => {
    if (task.id) {
      if (scope === 'future' && task.groupId) {
        setTasks(prev => prev.map(t => {
          if (t.groupId === task.groupId && t.date >= task.date) {
            return { ...t, title: task.title, section: task.section, duration: task.duration };
          }
          return t;
        }));
      } else {
        setTasks(prev => prev.map(t => t.id === task.id ? task : t));
      }
    } else {
      if (task.recurrence && task.recurrence !== 'None') {
        const groupId = Math.random().toString(36).substr(2, 9);
        let occurrences = 12; 
        let interval = 1;

        if (task.recurrence === 'Weekly') interval = 7;
        if (task.recurrence === 'Custom' && task.customInterval) interval = task.customInterval;

        const newTasks: StudyTask[] = Array.from({ length: occurrences }).map((_, i) => {
          const d = new Date(task.date);
          d.setDate(d.getDate() + (i * interval));
          return { 
            ...task, 
            id: Math.random().toString(36).substr(2, 9), 
            groupId, 
            date: formatDateKey(d) 
          };
        });
        setTasks(prev => [...prev, ...newTasks]);
      } else {
        setTasks(prev => [...prev, { ...task, id: Math.random().toString(36).substr(2, 9) }]);
      }
    }
  };

  const navigate = (amount: number) => {
    const newDate = new Date(baseDate);
    if (view === 'daily') newDate.setDate(newDate.getDate() + amount);
    if (view === 'weekly') newDate.setDate(newDate.getDate() + (amount * 7));
    if (view === 'monthly') newDate.setMonth(newDate.getMonth() + amount);
    setBaseDate(newDate);
  };

  const currentRangeDays = useMemo(() => {
    if (view === 'daily') return [new Date(baseDate)];
    if (view === 'weekly') {
      const start = new Date(baseDate);
      const day = start.getDay();
      const shift = day === 0 ? 6 : day - 1;
      start.setDate(start.getDate() - shift); 
      return Array.from({ length: 7 }).map((_, i) => {
        const d = new Date(start);
        d.setDate(d.getDate() + i);
        return d;
      });
    }
    return [];
  }, [view, baseDate]);

  const monthGrid = useMemo(() => {
    if (view !== 'monthly') return [];
    const start = new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
    const end = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0);
    const startDay = start.getDay();
    const padding = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < padding; i++) {
      const d = new Date(start);
      d.setDate(d.getDate() - (padding - i));
      days.push({ date: d, currentMonth: false });
    }
    for (let i = 1; i <= end.getDate(); i++) {
      days.push({ date: new Date(baseDate.getFullYear(), baseDate.getMonth(), i), currentMonth: true });
    }
    const totalSlots = days.length > 35 ? 42 : 35;
    const remaining = totalSlots - days.length;
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(end);
      d.setDate(d.getDate() + i);
      days.push({ date: d, currentMonth: false });
    }
    return days;
  }, [view, baseDate]);

  const handleAiUpdate = async () => {
    if (!userInput.trim() && tasks.every(t => !t.completed)) return;
    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput || "Optimize my schedule.");
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      setAiMessage("Sync failed. Check your connection.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const progressPercent = tasks.length > 0 
    ? Math.round((tasks.filter(t => t.completed).length / tasks.length) * 100)
    : 0;

  return (
    <div className="min-h-screen bg-[#f8faff] pb-40">
      <header className="px-8 pt-8 max-w-[1800px] mx-auto flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="shrink-0">
          <h1 className="text-3xl font-black text-slate-900 tracking-tight flex items-center gap-2">
            <span className="text-[#3b5bdb]">MCAT</span> PULSE
          </h1>
          <p className="text-slate-400 font-bold text-sm tracking-wide mt-1 uppercase">PRECISION PLANNER</p>
        </div>

        <div className="flex flex-wrap items-center justify-center gap-4 bg-white p-2 rounded-[28px] shadow-sm border border-slate-100">
           <div className="flex bg-slate-50 p-1 rounded-2xl">
             {(['daily', 'weekly', 'monthly'] as ViewType[]).map(v => (
               <button 
                 key={v}
                 onClick={() => setView(v)}
                 className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${view === v ? 'bg-white text-[#3b5bdb] shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
               >
                 {v}
               </button>
             ))}
           </div>
           <div className="h-6 w-px bg-slate-200" />
           <div className="flex items-center gap-2">
             <button onClick={() => navigate(-1)} className="p-2 hover:bg-slate-50 rounded-xl transition-colors"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M15 18l-6-6 6-6"/></svg></button>
             <button onClick={() => setBaseDate(new Date())} className="px-4 py-2 text-xs font-black text-[#3b5bdb] uppercase tracking-tighter hover:bg-slate-50 rounded-xl">Today</button>
             <button onClick={() => navigate(1)} className="p-2 hover:bg-slate-50 rounded-xl transition-colors"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M9 18l6-6-6-6"/></svg></button>
           </div>
        </div>

        <div className="w-full sm:w-auto md:max-w-md bg-white rounded-3xl p-2 shadow-sm border border-slate-100 flex items-center gap-2">
          <input
            type="text"
            value={userInput}
            onChange={(e) => setUserInput(e.target.value)}
            placeholder="Describe your goals..."
            className="flex-1 bg-transparent border-none px-4 py-2 font-semibold text-sm focus:ring-0 outline-none placeholder:text-slate-300"
          />
          <button
            onClick={handleAiUpdate}
            disabled={isAiLoading}
            className="bg-[#3b5bdb] text-white px-6 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-[#2f49b1] transition-all disabled:opacity-50"
          >
            {isAiLoading ? '...' : 'SYNC'}
          </button>
        </div>
      </header>

      {aiMessage && (
        <div className="max-w-2xl mx-auto mt-8 px-6 animate-in slide-in-from-top-4">
           <div className="bg-[#3b5bdb] text-white rounded-3xl p-6 shadow-xl relative">
             <p className="font-bold leading-relaxed">{aiMessage}</p>
             <button onClick={() => setAiMessage(null)} className="absolute top-4 right-4 opacity-50 hover:opacity-100"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
           </div>
        </div>
      )}

      <main className="mt-12 px-8 max-w-[1800px] mx-auto overflow-visible">
        {view === 'monthly' ? (
          <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
            <div className="grid grid-cols-7 border-b border-slate-50">
              {DAYS_SHORT.map(d => <div key={d} className="py-4 text-center text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{d}</div>)}
            </div>
            <div className="grid grid-cols-7">
              {monthGrid.map(({ date, currentMonth }, i) => {
                const dateKey = formatDateKey(date);
                const dayTasks = tasks.filter(t => t.date === dateKey);
                const isSelected = dateKey === formatDateKey(baseDate);
                const isToday = dateKey === formatDateKey(new Date());
                return (
                  <div 
                    key={i} 
                    onClick={() => { setBaseDate(new Date(date)); setView('daily'); }}
                    className={`min-h-[140px] p-2 border-r border-b border-slate-50 cursor-pointer transition-all hover:bg-slate-50 group ${!currentMonth ? 'opacity-30' : ''} ${isSelected ? 'bg-blue-50/30' : ''}`}
                  >
                    <div className="flex justify-between items-center mb-1.5">
                      <span className={`text-[11px] font-black ${isToday ? 'bg-[#3b5bdb] text-white w-6 h-6 flex items-center justify-center rounded-lg shadow-sm' : isSelected ? 'text-[#3b5bdb]' : 'text-slate-400'}`}>
                        {date.getDate()}
                      </span>
                    </div>
                    <div className="flex flex-col gap-1 overflow-hidden">
                      {dayTasks.slice(0, 3).map(t => (
                        <div key={t.id} className={`px-2 py-1 rounded-md text-[8px] font-bold truncate flex items-center gap-1.5 ${SECTION_STYLES[t.section].bg} ${SECTION_STYLES[t.section].text} ${t.completed ? 'opacity-40' : ''}`}>
                          <span className="shrink-0 w-1 h-1 rounded-full bg-current opacity-50" />
                          <span className="truncate">{t.section}: {t.title}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : view === 'weekly' ? (
          <div className="space-y-12 pb-8">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-6">
              {currentRangeDays.slice(0, 5).map((d, i) => (
                <DayColumn
                  key={i}
                  date={d}
                  tasks={tasks.filter(t => t.date === formatDateKey(d))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                  onDeleteTask={(task) => deleteTask(task, 'single')}
                />
              ))}
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-6">
              <div className="lg:col-start-2">
                <DayColumn
                  date={currentRangeDays[5]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[5]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                  onDeleteTask={(task) => deleteTask(task, 'single')}
                />
              </div>
              <div className="lg:col-start-3">
                <DayColumn
                  date={currentRangeDays[6]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[6]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                  onDeleteTask={(task) => deleteTask(task, 'single')}
                />
              </div>
            </div>
          </div>
        ) : (
          <div className="flex justify-center pb-8">
            <DayColumn
              date={currentRangeDays[0]}
              tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[0]))}
              onToggleTask={toggleTask}
              onDragStartTask={handleDragStartTask}
              onDropTask={moveTask}
              onAddTask={handleAddTask}
              onEditTask={handleEditTask}
              onDeleteTask={(task) => deleteTask(task, 'single')}
              isFocused
            />
          </div>
        )}
      </main>

      <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur-xl px-10 py-5 rounded-[40px] shadow-[0_20px_60px_rgba(0,0,0,0.1)] border border-white flex items-center gap-8 z-50">
        <div className="flex flex-col">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Mastery</span>
          <span className="text-xl font-black text-[#3b5bdb]">{progressPercent}%</span>
        </div>
        <div className="w-48 sm:w-64 h-3 bg-slate-100 rounded-full overflow-hidden">
          <div className="h-full bg-gradient-to-r from-blue-400 to-[#3b5bdb] transition-all duration-1000" style={{ width: `${progressPercent}%` }} />
        </div>
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-2xl bg-[#3b5bdb] flex items-center justify-center text-white font-black text-xs">{tasks.filter(t => t.completed).length}</div>
          <span className="hidden sm:inline text-xs font-bold text-slate-500">Done</span>
        </div>
      </div>

      <EditTaskModal isOpen={isModalOpen} task={currentTaskToEdit} onClose={() => setIsModalOpen(false)} onSave={saveTask} onDelete={deleteTask} />
    </div>
  );
};

export default App;

