            task.completed ? 'line-through text-slate-400 font-bold' : ''
          }`}>
            {task.title}
          </h4>

          <div className="mt-2.5 flex flex-col gap-2">
            <div>
               <span className={`inline-block px-1.5 py-0.5 rounded-lg text-[8px] font-black tracking-widest uppercase border border-transparent ${styles.bg} ${styles.text}`}>
