import { GoogleGenAI, Type } from "@google/genai";
import { StudyTask } from "../types";

export async function adaptSchedule(currentTasks: StudyTask[], userGoals: string): Promise<{ suggestion: string, updatedTasks: StudyTask[] }> {
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    return { 
      suggestion: "API Key not found. Please ensure your environment is configured correctly.", 
      updatedTasks: currentTasks 
    };
  }

  const ai = new GoogleGenAI({ apiKey });
  const model = 'gemini-3-flash-preview';

  const prompt = `
    You are an expert MCAT Study Coach. 
    Current Schedule: ${JSON.stringify(currentTasks)}
    User Input: ${userGoals}

    Tasks:
    - If the user is behind, move uncompleted tasks to future days.
    - If the user wants to focus on a specific subject, add new tasks for that subject.
    - Ensure a balanced workload (max 4-5 tasks per day).
    - Provide a supportive encouragement message.

    CRITICAL: The 'date' field must be in YYYY-MM-DD format.

    Return the response in JSON format.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suggestion: { type: Type.STRING, description: "A message to the student" },
            updatedTasks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  section: { type: Type.STRING },
                  completed: { type: Type.BOOLEAN },
                  date: { type: Type.STRING, description: "YYYY-MM-DD format" },
                  duration: { type: Type.STRING }
                },
                required: ["id", "title", "section", "completed", "date", "duration"]
              }
            }
          },
          required: ["suggestion", "updatedTasks"]
        }
      }
    });

    const data = JSON.parse(response.text);
    return data;
  } catch (e) {
    console.error("Failed to parse AI response or fetch content", e);
    return { 
      suggestion: "I had trouble updating the schedule. Please check your connection and try again!", 
      updatedTasks: currentTasks 
    };
  }
}

import React, { useState, useEffect, useMemo } from 'react';
import DayColumn from './components/DayColumn';
import EditTaskModal from './components/EditTaskModal';
import { StudyTask, ViewType } from './types';
import { INITIAL_TASKS, formatDateKey, DAYS_SHORT, SECTION_STYLES } from './constants';
import { adaptSchedule } from './services/geminiService';

const STORAGE_KEY = 'lock-tf-in-v1';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed)) return parsed;
      } catch (e) {
        console.error("Failed to load tasks from storage", e);
      }
    }
    return INITIAL_TASKS;
  });

  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');
  const [view, setView] = useState<ViewType>('weekly');
  const [baseDate, setBaseDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tasks));
  }, [tasks]);

  const toggleTask = (id: string) => setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  const handleDragStartTask = (e: React.DragEvent, id: string) => e.dataTransfer.setData('taskId', id);
  const moveTask = (taskId: string, targetDate: string) => setTasks(prev => prev.map(t => t.id === taskId ? { ...t, date: targetDate } : t));

  const handleEditTask = (task: StudyTask) => { 
    setCurrentTaskToEdit(task); 
    setIsModalOpen(true); 
  };

  const handleAddTask = (dateKey: string) => { 
    setCurrentTaskToEdit({ 
      date: dateKey, 
      completed: false, 
      title: '', 
      description: '', 
      section: 'Biology', 
      duration: '1h', 
      recurrence: 'None' 
    }); 
    setIsModalOpen(true); 
  };

  const deleteTask = (task: Partial<StudyTask>, scope: 'single' | 'future' = 'single') => {
    const taskId = task.id;
    if (!taskId) return;

    setTasks(prev => {
      if (scope === 'future' && task.groupId && task.date) {
        return prev.filter(t => !(t.groupId === task.groupId && t.date >= task.date));
      }
      return prev.filter(t => t.id !== taskId);
    });
  };

  const saveTask = (task: StudyTask, scope: 'single' | 'future' = 'single') => {
    if (task.id) {
      if (scope === 'future' && task.groupId) {
        setTasks(prev => prev.map(t => {
          if (t.groupId === task.groupId && t.date >= task.date) {
            return { ...t, title: task.title, section: task.section, duration: task.duration };
          }
          return t;
        }));
      } else {
        setTasks(prev => prev.map(t => t.id === task.id ? task : t));
      }
    } else {
      const newId = Math.random().toString(36).substr(2, 9);
      if (task.recurrence && task.recurrence !== 'None') {
        const groupId = Math.random().toString(36).substr(2, 9);
        let occurrences = 12; 
        let interval = 1;

        if (task.recurrence === 'Weekly') interval = 7;
        if (task.recurrence === 'Custom' && task.customInterval) interval = task.customInterval;

        const newTasks: StudyTask[] = Array.from({ length: occurrences }).map((_, i) => {
          const d = new Date(task.date);
          d.setDate(d.getDate() + (i * interval));
          return { 
            ...task, 
            id: Math.random().toString(36).substr(2, 9) + i, 
            groupId, 
            date: formatDateKey(d) 
          };
        });
        setTasks(prev => [...prev, ...newTasks]);
      } else {
        setTasks(prev => [...prev, { ...task, id: newId }]);
      }
    }
  };

  const navigate = (amount: number) => {
    const newDate = new Date(baseDate);
    if (view === 'daily') newDate.setDate(newDate.getDate() + amount);
    if (view === 'weekly') newDate.setDate(newDate.getDate() + (amount * 7));
    if (view === 'monthly') newDate.setMonth(newDate.getMonth() + amount);
    setBaseDate(newDate);
  };

  const currentRangeDays = useMemo(() => {
    if (view === 'daily') return [new Date(baseDate)];
    if (view === 'weekly') {
      const start = new Date(baseDate);
      const day = start.getDay();
      const shift = day === 0 ? 6 : day - 1;
      start.setDate(start.getDate() - shift); 
      return Array.from({ length: 7 }).map((_, i) => {
        const d = new Date(start);
        d.setDate(d.getDate() + i);
        return d;
      });
    }
    return [];
  }, [view, baseDate]);

  const monthGrid = useMemo(() => {
    if (view !== 'monthly') return [];
    const start = new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
    const end = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0);
    const startDay = start.getDay();
    const padding = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < padding; i++) {
      const d = new Date(start);
      d.setDate(d.getDate() - (padding - i));
      days.push({ date: d, currentMonth: false });
    }
    for (let i = 1; i <= end.getDate(); i++) {
      days.push({ date: new Date(baseDate.getFullYear(), baseDate.getMonth(), i), currentMonth: true });
    }
    const totalSlots = days.length > 35 ? 42 : 35;
    const remaining = totalSlots - days.length;
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(end);
      d.setDate(d.getDate() + i);
      days.push({ date: d, currentMonth: false });
    }
    return days;
  }, [view, baseDate]);

  const handleAiUpdate = async () => {
    if (!userInput.trim() && tasks.every(t => !t.completed)) return;
    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput || "Optimize my schedule.");
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      setAiMessage("Sync failed. Check your connection.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const progressPercent = tasks.length > 0 
    ? Math.round((tasks.filter(t => t.completed).length / tasks.length) * 100)
    : 0;

  return (
    <div className="min-h-screen bg-[#090712] text-slate-100 pb-40">
      <header className="px-8 pt-8 max-w-[1800px] mx-auto flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="shrink-0">
          <h1 className="text-4xl font-black tracking-tighter flex items-center gap-2 italic">
            <span className="text-[#8b5cf6] drop-shadow-[0_0_15px_rgba(139,92,246,0.5)]">LOCK</span> TF IN!
          </h1>
          <p className="text-slate-500 font-bold text-xs tracking-[0.3em] mt-1 uppercase">Mission Control</p>
        </div>

        <div className="flex flex-wrap items-center justify-center gap-4 bg-[#16122b] p-2 rounded-[28px] shadow-2xl border border-slate-800">
           <div className="flex bg-[#0d0b1a] p-1 rounded-2xl">
             {(['daily', 'weekly', 'monthly'] as ViewType[]).map(v => (
               <button 
                 key={v}
                 onClick={() => setView(v)}
                 className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${view === v ? 'bg-[#16122b] text-[#8b5cf6] shadow-lg border border-slate-700' : 'text-slate-500 hover:text-slate-300'}`}
               >
                 {v}
               </button>
             ))}
           </div>
           <div className="h-6 w-px bg-slate-800" />
           <div className="flex items-center gap-2">
             <button onClick={() => navigate(-1)} className="p-2 hover:bg-[#1a1630] rounded-xl transition-colors text-slate-400"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M15 18l-6-6 6-6"/></svg></button>
             <button onClick={() => setBaseDate(new Date())} className="px-4 py-2 text-xs font-black text-[#8b5cf6] uppercase tracking-tighter hover:bg-[#1a1630] rounded-xl">Today</button>
             <button onClick={() => navigate(1)} className="p-2 hover:bg-[#1a1630] rounded-xl transition-colors text-slate-400"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M9 18l6-6-6-6"/></svg></button>
           </div>
        </div>

        <div className="w-full sm:w-auto md:max-w-md bg-[#16122b] rounded-3xl p-2 shadow-2xl border border-slate-800 flex items-center gap-2">
          <input
            type="text"
            value={userInput}
            onChange={(e) => setUserInput(e.target.value)}
            placeholder="Adapt your mission..."
            className="flex-1 bg-transparent border-none px-4 py-2 font-semibold text-sm focus:ring-0 outline-none placeholder:text-slate-600 text-slate-100"
          />
          <button
            onClick={handleAiUpdate}
            disabled={isAiLoading}
            className="bg-[#8b5cf6] text-white px-6 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-[#7c3aed] transition-all disabled:opacity-50 shadow-[0_0_20px_rgba(139,92,246,0.3)]"
          >
            {isAiLoading ? '...' : 'SYNC'}
          </button>
        </div>
      </header>

      {aiMessage && (
        <div className="max-w-2xl mx-auto mt-8 px-6 animate-in slide-in-from-top-4">
           <div className="bg-[#1a1630] border border-[#8b5cf6]/30 text-slate-100 rounded-3xl p-6 shadow-2xl relative">
             <p className="font-bold leading-relaxed">{aiMessage}</p>
             <button onClick={() => setAiMessage(null)} className="absolute top-4 right-4 text-slate-500 hover:text-slate-300 transition-colors"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
           </div>
        </div>
      )}

      <main className="mt-12 px-8 max-w-[1800px] mx-auto overflow-visible">
        {view === 'monthly' ? (
          <div className="bg-[#16122b] rounded-[40px] shadow-2xl border border-slate-800 overflow-hidden">
            <div className="grid grid-cols-7 border-b border-slate-800 bg-[#0d0b1a]">
              {DAYS_SHORT.map(d => <div key={d} className="py-4 text-center text-[10px] font-black text-slate-600 uppercase tracking-[0.2em]">{d}</div>)}
            </div>
            <div className="grid grid-cols-7">
              {monthGrid.map(({ date, currentMonth }, i) => {
                const dateKey = formatDateKey(date);
                const dayTasks = tasks.filter(t => t.date === dateKey);
                const isSelected = dateKey === formatDateKey(baseDate);
                const isToday = dateKey === formatDateKey(new Date());
                return (
                  <div 
                    key={i} 
                    onClick={() => { setBaseDate(new Date(date)); setView('daily'); }}
                    className={`min-h-[140px] p-2 border-r border-b border-slate-800 cursor-pointer transition-all hover:bg-[#1a1630] group ${!currentMonth ? 'opacity-20' : ''} ${isSelected ? 'bg-violet-900/10' : ''}`}
                  >
                    <div className="flex justify-between items-center mb-1.5">
                      <span className={`text-[11px] font-black ${isToday ? 'bg-[#8b5cf6] text-white w-6 h-6 flex items-center justify-center rounded-lg shadow-[0_0_10px_rgba(139,92,246,0.4)]' : isSelected ? 'text-[#8b5cf6]' : 'text-slate-500'}`}>
                        {date.getDate()}
                      </span>
                    </div>
                    <div className="flex flex-col gap-1 overflow-hidden">
                      {dayTasks.slice(0, 3).map(t => (
                        <div key={t.id} className={`px-2 py-1 rounded-md text-[8px] font-bold truncate flex items-center gap-1.5 ${SECTION_STYLES[t.section].bg.replace('bg-', 'bg-opacity-20 bg-')} ${SECTION_STYLES[t.section].text} ${t.completed ? 'opacity-30' : ''}`}>
                          <span className="shrink-0 w-1 h-1 rounded-full bg-current" />
                          <span className="truncate">{t.section}: {t.title}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : view === 'weekly' ? (
          <div className="space-y-12 pb-8">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-6">
              {currentRangeDays.slice(0, 5).map((d, i) => (
                <DayColumn
                  key={i}
                  date={d}
                  tasks={tasks.filter(t => t.date === formatDateKey(d))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                  onDeleteTask={(task) => deleteTask(task, 'single')}
                />
              ))}
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-6">
              <div className="lg:col-start-2">
                <DayColumn
                  date={currentRangeDays[5]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[5]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                  onDeleteTask={(task) => deleteTask(task, 'single')}
                />
              </div>
              <div className="lg:col-start-3">
                <DayColumn
                  date={currentRangeDays[6]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[6]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                  onDeleteTask={(task) => deleteTask(task, 'single')}
                />
              </div>
            </div>
          </div>
        ) : (
          <div className="flex justify-center pb-8">
            <DayColumn
              date={currentRangeDays[0]}
              tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[0]))}
              onToggleTask={toggleTask}
              onDragStartTask={handleDragStartTask}
              onDropTask={moveTask}
              onAddTask={handleAddTask}
              onEditTask={handleEditTask}
              onDeleteTask={(task) => deleteTask(task, 'single')}
              isFocused
            />
          </div>
        )}
      </main>

      <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-[#16122b]/80 backdrop-blur-2xl px-10 py-5 rounded-[40px] shadow-[0_20px_60px_rgba(0,0,0,0.5)] border border-slate-800 flex items-center gap-8 z-50">
        <div className="flex flex-col">
          <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Mastery</span>
          <span className="text-xl font-black text-[#8b5cf6] drop-shadow-[0_0_10px_rgba(139,92,246,0.3)]">{progressPercent}%</span>
        </div>
        <div className="w-48 sm:w-64 h-3 bg-[#0d0b1a] rounded-full overflow-hidden border border-slate-800">
          <div className="h-full bg-gradient-to-r from-[#8b5cf6] to-[#d946ef] transition-all duration-1000" style={{ width: `${progressPercent}%` }} />
        </div>
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-2xl bg-[#1a1630] border border-[#8b5cf6]/30 flex items-center justify-center text-[#8b5cf6] font-black text-xs">{tasks.filter(t => t.completed).length}</div>
          <span className="hidden sm:inline text-xs font-bold text-slate-400">Locked In</span>
        </div>
      </div>

      <EditTaskModal isOpen={isModalOpen} task={currentTaskToEdit} onClose={() => setIsModalOpen(false)} onSave={saveTask} onDelete={deleteTask} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { StudyTask } from '../types';
import TaskCard from './TaskCard';
import { formatDateKey } from '../constants';

interface DayColumnProps {
  date: Date;
  tasks: StudyTask[];
  onToggleTask: (id: string) => void;
  onDropTask: (taskId: string, targetDate: string) => void;
  onDragStartTask: (e: React.DragEvent, id: string) => void;
  onAddTask: (date: string) => void;
  onEditTask: (task: StudyTask) => void;
  onDeleteTask: (task: StudyTask) => void;
  isFocused?: boolean;
}

const DayColumn: React.FC<DayColumnProps> = ({
  date,
  tasks,
  onToggleTask,
  onDropTask,
  onDragStartTask,
  onAddTask,
  onEditTask,
  onDeleteTask,
  isFocused = false
}) => {
  const [isOver, setIsOver] = useState(false);
  const dateKey = formatDateKey(date);
  const isToday = dateKey === formatDateKey(new Date());

  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const dayName = dayNames[date.getDay()];
  const dayNum = date.getDate();

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(true);
  };

  const handleDragLeave = () => {
    setIsOver(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(false);
    const taskId = e.dataTransfer.getData('taskId');
    onDropTask(taskId, dateKey);
  };

  return (
    <div
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`flex flex-col rounded-[32px] border-2 p-7 transition-all h-full ${
        isFocused ? 'min-h-[600px] w-full max-w-[500px]' : 'min-h-[450px] w-full'
      } ${
        isOver 
          ? 'bg-[#1a1630] border-[#8b5cf6] border-dashed shadow-[0_0_30px_rgba(139,92,246,0.2)]' 
          : isToday
            ? 'bg-[#16122b] border-[#8b5cf6]/30 shadow-[0_15px_40px_rgba(0,0,0,0.3)] ring-1 ring-[#8b5cf6]/10'
            : 'bg-[#16122b]/50 border-slate-800'
      }`}
    >
      <div className="flex justify-between items-center mb-8">
        <div>
          <h3 className={`text-2xl font-black tracking-tight ${isToday ? 'text-[#8b5cf6] drop-shadow-[0_0_10px_rgba(139,92,246,0.3)]' : 'text-slate-100'}`}>
            {dayName} {dayNum} {isToday && <span className="text-[0.9em] ml-1">(Today)</span>}
          </h3>
          <p className="text-slate-500 font-semibold text-sm mt-0.5">
            {tasks.length} {tasks.length === 1 ? 'task' : 'tasks'}
          </p>
        </div>

        <button 
          onClick={() => onAddTask(dateKey)}
          className="w-11 h-11 rounded-2xl bg-[#1a1630] shadow-xl border border-slate-800 flex items-center justify-center text-slate-500 hover:text-[#8b5cf6] hover:border-[#8b5cf6]/30 transition-all active:scale-90"
        >
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
            <line x1="12" y1="5" x2="12" y2="19"></line>
            <line x1="5" y1="12" x2="19" y2="12"></line>
          </svg>
        </button>
      </div>

      <div className="flex-1 space-y-4">
        {tasks.map((task) => (
          <TaskCard
            key={task.id}
            task={task}
            onToggle={onToggleTask}
            onDragStart={onDragStartTask}
            onEdit={onEditTask}
            onDelete={onDeleteTask}
          />
        ))}
        {tasks.length === 0 && (
          <div className="h-28 border-2 border-dashed border-slate-800 rounded-[28px] flex items-center justify-center text-slate-600 font-bold text-xs italic p-4 text-center">
            Rest day?
          </div>
        )}
      </div>
    </div>
  );
};

export default DayColumn;

import React, { useState } from 'react';
import { StudyTask } from '../types';
import { SECTION_STYLES } from '../constants';

interface TaskCardProps {
  task: StudyTask;
  onToggle: (id: string) => void;
  onDragStart: (e: React.DragEvent, id: string) => void;
  onEdit: (task: StudyTask) => void;
  onDelete: (task: StudyTask) => void;
}

const TaskCard: React.FC<TaskCardProps> = ({ task, onToggle, onDragStart, onEdit, onDelete }) => {
  const [confirmDelete, setConfirmDelete] = useState(false);
  const styles = SECTION_STYLES[task.section];

  const handleDelete = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (confirmDelete) {
      onDelete(task);
    } else {
      setConfirmDelete(true);
      setTimeout(() => setConfirmDelete(false), 3000);
    }
  };

  return (
    <div
      draggable
      onDragStart={(e) => onDragStart(e, task.id)}
      onClick={() => !confirmDelete && onEdit(task)}
      onMouseLeave={() => setConfirmDelete(false)}
      className={`group relative p-3.5 mb-2.5 bg-[#211b3d] rounded-2xl border border-slate-800 shadow-xl transition-all cursor-grab active:cursor-grabbing hover:shadow-[0_10px_30px_rgba(0,0,0,0.5)] hover:border-[#8b5cf6]/30 ${
        task.completed ? 'opacity-40' : ''
      }`}
    >
      <div className="absolute top-2.5 right-2.5 z-50 flex items-center gap-1.5 pointer-events-auto">
        {confirmDelete && (
          <span className="text-[9px] font-black text-rose-500 uppercase tracking-tighter animate-pulse">Confirm?</span>
        )}
        <button
          onClick={handleDelete}
          className={`flex items-center justify-center transition-all border shadow-lg rounded-lg ${
            confirmDelete 
              ? 'w-10 h-7 bg-rose-600 text-white border-rose-700 scale-110' 
              : 'w-7 h-7 bg-[#1a1630] text-rose-500 border-slate-800 md:opacity-0 md:group-hover:opacity-100'
          }`}
          title={confirmDelete ? "Click again to delete" : "Delete Task"}
        >
          {confirmDelete ? (
            <span className="text-[10px] font-black">YES</span>
          ) : (
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
              <polyline points="3 6 5 6 21 6"></polyline>
              <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
            </svg>
          )}
        </button>
      </div>

      <div className="flex gap-3 items-start pr-6">
        <div className="flex shrink-0 pt-0.5" onClick={(e) => e.stopPropagation()}>
          <button
            onClick={() => onToggle(task.id)}
            className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${
              task.completed 
