                : 'bg-[#1a1630] border-slate-700 hover:border-[#8b5cf6]/50'
            }`}
          >
            {task.completed && (
              <svg width="12" height="9" viewBox="0 0 14 11" fill="none" xmlns="http://www.w3.org/2000/svg">
                <path d="M1 6L5 9.5L13 1" stroke="white" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
            )}
          </button>
        </div>

        <div className="flex-1 min-w-0">
          <h4 className={`font-black text-[13px] leading-tight text-slate-100 transition-all whitespace-normal break-words ${
            task.completed ? 'line-through text-slate-500 font-bold' : ''
          }`}>
            {task.title}
          </h4>

          <div className="mt-2.5 flex flex-col gap-2">
            <div>
               <span className={`inline-block px-1.5 py-0.5 rounded-lg text-[8px] font-black tracking-widest uppercase border border-transparent bg-opacity-20 ${styles.bg} ${styles.text}`}>
                {styles.label}
              </span>
            </div>

            <div className="flex items-center gap-1 text-slate-500 text-[8.5px] font-black tracking-tighter">
              <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="12" cy="12" r="10"></circle>
                <polyline points="12 6 12 12 16 14"></polyline>
              </svg>
              <span>{task.duration}</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TaskCard;

import React, { useState, useEffect } from 'react';
import { StudyTask, MCATSection, RecurrenceType } from '../types';
import { SECTION_STYLES } from '../constants';

interface EditTaskModalProps {
  task: Partial<StudyTask> | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: StudyTask, scope?: 'single' | 'future') => void;
  onDelete?: (task: Partial<StudyTask>, scope?: 'single' | 'future') => void;
}

const EditTaskModal: React.FC<EditTaskModalProps> = ({ task, isOpen, onClose, onSave, onDelete }) => {
  const [title, setTitle] = useState('');
  const [section, setSection] = useState<MCATSection>('Biology');
  const [duration, setDuration] = useState('');
  const [recurrence, setRecurrence] = useState<RecurrenceType>('None');
  const [customInterval, setCustomInterval] = useState(2);
  const [date, setDate] = useState('');
  const [saveScope, setSaveScope] = useState<'single' | 'future'>('single');
  const [confirmDelete, setConfirmDelete] = useState(false);

  useEffect(() => {
    if (task && isOpen) {
      setTitle(task.title || '');
      setSection(task.section || 'Biology');
      setDuration(task.duration || '');
      setRecurrence(task.recurrence || 'None');
      setCustomInterval(task.customInterval || 2);
      setDate(task.date || '');
      setSaveScope('single');
      setConfirmDelete(false);
    }
  }, [task, isOpen]);

  if (!isOpen || !task) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      ...task,
      title,
      section,
      duration,
      recurrence,
      customInterval: recurrence === 'Custom' ? customInterval : undefined,
      date,
    } as StudyTask, saveScope);
    onClose();
  };

  const handleDelete = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (onDelete && task.id) {
      if (confirmDelete) {
        onDelete(task, saveScope);
        onClose();
      } else {
        setConfirmDelete(true);
      }
    }
  };

  const isRecurringInstance = !!task.groupId;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-[#090712]/80 backdrop-blur-md animate-in fade-in duration-200">
      <div className="bg-[#16122b] w-full max-w-md rounded-[32px] p-8 shadow-[0_0_50px_rgba(139,92,246,0.15)] border border-slate-800 animate-in zoom-in-95 duration-200" onClick={e => e.stopPropagation()}>
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-black text-slate-100 tracking-tight">
            {task.id ? 'Mission Control' : 'New Objective'}
          </h2>
          <button onClick={onClose} type="button" className="text-slate-500 hover:text-slate-300 p-2 transition-colors">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">Objective Title</label>
            <input
              autoFocus
              required
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="w-full bg-[#0d0b1a] border-2 border-slate-800 rounded-2xl px-4 py-3 font-bold text-slate-100 focus:border-[#8b5cf6] focus:ring-0 outline-none transition-all placeholder:text-slate-700"
              placeholder="e.g. Acid-Base Equilibrium"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">Launch Date</label>
              <input
                required
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full bg-[#0d0b1a] border-2 border-slate-800 rounded-2xl px-4 py-3 font-bold text-slate-100 focus:border-[#8b5cf6] focus:ring-0 outline-none transition-all"
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">Duration</label>
              <input
                required
                type="text"
                value={duration}
                onChange={(e) => setDuration(e.target.value)}
                className="w-full bg-[#0d0b1a] border-2 border-slate-800 rounded-2xl px-4 py-3 font-bold text-slate-100 focus:border-[#8b5cf6] focus:ring-0 outline-none transition-all placeholder:text-slate-700"
                placeholder="e.g. 2.5h"
              />
            </div>
          </div>

          <div>
             <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">Subject Sector</label>
              <select
                value={section}
                onChange={(e) => setSection(e.target.value as MCATSection)}
                className="w-full bg-[#0d0b1a] border-2 border-slate-800 rounded-2xl px-4 py-3 font-bold text-slate-100 focus:border-[#8b5cf6] focus:ring-0 outline-none transition-all appearance-none cursor-pointer"
              >
                {Object.keys(SECTION_STYLES).map((s) => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
          </div>

          {!task.id ? (
            <div className="space-y-4">
              <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest">Auto-Recurrence</label>
              <div className="grid grid-cols-2 gap-2">
                {(['None', 'Daily', 'Weekly', 'Custom'] as RecurrenceType[]).map((type) => (
                  <button
                    key={type}
                    type="button"
                    onClick={() => setRecurrence(type)}
                    className={`py-3 rounded-xl font-bold text-xs transition-all border-2 ${
                      recurrence === type 
                        ? 'bg-[#8b5cf6] text-white border-[#8b5cf6] shadow-[0_0_15px_rgba(139,92,246,0.4)]' 
                        : 'bg-[#0d0b1a] text-slate-500 border-slate-800 hover:border-slate-700'
                    }`}
                  >
                    {type}
                  </button>
                ))}
              </div>
            </div>
          ) : isRecurringInstance && (
            <div className="bg-[#0d0b1a] p-4 rounded-2xl border border-slate-800">
              <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3 text-center">Update Scope</label>
              <div className="flex gap-2">
                <button
                  type="button"
                  onClick={() => setSaveScope('single')}
                  className={`flex-1 py-2.5 rounded-xl font-black text-[10px] uppercase transition-all border-2 ${
                    saveScope === 'single'
                      ? 'bg-[#8b5cf6]/10 border-[#8b5cf6] text-[#8b5cf6]'
                      : 'bg-transparent border-slate-800 text-slate-600'
                  }`}
                >
                  Instance
                </button>
                <button
                  type="button"
                  onClick={() => setSaveScope('future')}
                  className={`flex-1 py-2.5 rounded-xl font-black text-[10px] uppercase transition-all border-2 ${
                    saveScope === 'future'
                      ? 'bg-[#8b5cf6]/10 border-[#8b5cf6] text-[#8b5cf6]'
                      : 'bg-transparent border-slate-800 text-slate-600'
                  }`}
                >
                  Sequence
                </button>
              </div>
            </div>
          )}

          <div className="pt-4 flex gap-3">
            <button
              type="submit"
              className="flex-1 bg-[#8b5cf6] text-white py-4 rounded-2xl font-black uppercase tracking-widest hover:bg-[#7c3aed] shadow-lg shadow-violet-900/50 transition-all active:scale-[0.98]"
            >
              {task.id ? 'Update Mission' : 'Launch Objective'}
            </button>
            {task.id && onDelete && (
              <button
                type="button"
                onClick={handleDelete}
                className={`w-auto min-w-[56px] px-3 transition-all rounded-2xl flex items-center justify-center border active:scale-95 ${
                  confirmDelete 
                    ? 'bg-rose-600 text-white border-rose-700 font-black text-[10px]' 
                    : 'bg-[#0d0b1a] text-rose-500 border-slate-800 hover:bg-rose-500/10'
                }`}
                title="Abort Objective"
              >
                {confirmDelete ? (
                  "ABORT?"
                ) : (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
                )}
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default EditTaskModal;

import React, { useState, useEffect, useMemo } from 'react';
import DayColumn from './components/DayColumn';
import EditTaskModal from './components/EditTaskModal';
import { StudyTask, ViewType } from './types';
import { INITIAL_TASKS, formatDateKey, DAYS_SHORT, SECTION_STYLES } from './constants';
import { adaptSchedule } from './services/geminiService';

const STORAGE_KEY = 'lock-tf-in-v2';
const THEME_KEY = 'lock-tf-in-theme';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed)) return parsed;
      } catch (e) {
        console.error("Failed to load tasks from storage", e);
      }
    }
    return INITIAL_TASKS;
  });

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    const saved = localStorage.getItem(THEME_KEY);
    return saved !== null ? saved === 'true' : true; // Default to dark mode
  });

  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');
  const [view, setView] = useState<ViewType>('weekly');
  const [baseDate, setBaseDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tasks));
  }, [tasks]);

  useEffect(() => {
    localStorage.setItem(THEME_KEY, String(isDarkMode));
    document.body.style.backgroundColor = isDarkMode ? '#090712' : '#f8fafc';
    document.body.style.color = isDarkMode ? '#f1f5f9' : '#1e293b';
  }, [isDarkMode]);

  const toggleTask = (id: string) => setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  const handleDragStartTask = (e: React.DragEvent, id: string) => e.dataTransfer.setData('taskId', id);
  const moveTask = (taskId: string, targetDate: string) => setTasks(prev => prev.map(t => t.id === taskId ? { ...t, date: targetDate } : t));

  const handleEditTask = (task: StudyTask) => { 
    setCurrentTaskToEdit(task); 
    setIsModalOpen(true); 
  };

  const handleAddTask = (dateKey: string) => { 
    setCurrentTaskToEdit({ 
      date: dateKey, 
      completed: false, 
      title: '', 
      description: '', 
      section: 'Biology', 
      duration: '1h', 
      recurrence: 'None' 
    }); 
    setIsModalOpen(true); 
  };

  const deleteTask = (task: Partial<StudyTask>, scope: 'single' | 'future' = 'single') => {
    const taskId = task.id;
    if (!taskId) return;

    setTasks(prev => {
      if (scope === 'future' && task.groupId && task.date) {
        return prev.filter(t => !(t.groupId === task.groupId && t.date >= task.date));
      }
      return prev.filter(t => t.id !== taskId);
    });
  };

  const saveTask = (task: StudyTask, scope: 'single' | 'future' = 'single') => {
    if (task.id) {
      if (scope === 'future' && task.groupId) {
        setTasks(prev => prev.map(t => {
          if (t.groupId === task.groupId && t.date >= task.date) {
            return { ...t, title: task.title, section: task.section, duration: task.duration };
          }
          return t;
        }));
      } else {
        setTasks(prev => prev.map(t => t.id === task.id ? task : t));
      }
    } else {
      const newId = Math.random().toString(36).substr(2, 9);
      if (task.recurrence && task.recurrence !== 'None') {
        const groupId = Math.random().toString(36).substr(2, 9);
        let occurrences = 12; 
        let interval = 1;

        if (task.recurrence === 'Weekly') interval = 7;
        if (task.recurrence === 'Custom' && task.customInterval) interval = task.customInterval;

        const newTasks: StudyTask[] = Array.from({ length: occurrences }).map((_, i) => {
          const d = new Date(task.date);
          d.setDate(d.getDate() + (i * interval));
          return { 
            ...task, 
            id: Math.random().toString(36).substr(2, 9) + i, 
            groupId, 
            date: formatDateKey(d) 
          };
        });
        setTasks(prev => [...prev, ...newTasks]);
      } else {
        setTasks(prev => [...prev, { ...task, id: newId }]);
      }
    }
  };

  const navigate = (amount: number) => {
    const newDate = new Date(baseDate);
    if (view === 'daily') newDate.setDate(newDate.getDate() + amount);
    if (view === 'weekly') newDate.setDate(newDate.getDate() + (amount * 7));
    if (view === 'monthly') newDate.setMonth(newDate.getMonth() + amount);
    setBaseDate(newDate);
  };

  const currentRangeDays = useMemo(() => {
    if (view === 'daily') return [new Date(baseDate)];
    if (view === 'weekly') {
      const start = new Date(baseDate);
      const day = start.getDay();
      const shift = day === 0 ? 6 : day - 1;
      start.setDate(start.getDate() - shift); 
      return Array.from({ length: 7 }).map((_, i) => {
        const d = new Date(start);
        d.setDate(d.getDate() + i);
        return d;
      });
    }
    return [];
  }, [view, baseDate]);

  const monthGrid = useMemo(() => {
    if (view !== 'monthly') return [];
    const start = new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
    const end = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0);
    const startDay = start.getDay();
    const padding = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < padding; i++) {
      const d = new Date(start);
      d.setDate(d.getDate() - (padding - i));
      days.push({ date: d, currentMonth: false });
    }
    for (let i = 1; i <= end.getDate(); i++) {
      days.push({ date: new Date(baseDate.getFullYear(), baseDate.getMonth(), i), currentMonth: true });
    }
    const totalSlots = days.length > 35 ? 42 : 35;
    const remaining = totalSlots - days.length;
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(end);
      d.setDate(d.getDate() + i);
      days.push({ date: d, currentMonth: false });
    }
    return days;
  }, [view, baseDate]);

  const handleAiUpdate = async () => {
    if (!userInput.trim() && tasks.every(t => !t.completed)) return;
    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput || "Optimize my schedule.");
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      setAiMessage("Sync failed. Check your connection.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const progressPercent = tasks.length > 0 
    ? Math.round((tasks.filter(t => t.completed).length / tasks.length) * 100)
    : 0;

  // Theme-specific colors
  const bgColor = isDarkMode ? 'bg-[#090712]' : 'bg-[#f8fafc]';
  const headerTextColor = isDarkMode ? 'text-slate-100' : 'text-slate-900';
  const subTextColor = isDarkMode ? 'text-slate-500' : 'text-slate-400';
  const accentColor = isDarkMode ? 'text-[#8b5cf6]' : 'text-[#3b5bdb]';
  const accentBg = isDarkMode ? 'bg-[#8b5cf6]' : 'bg-[#3b5bdb]';
  const surfaceBg = isDarkMode ? 'bg-[#16122b]' : 'bg-white';
  const borderCol = isDarkMode ? 'border-slate-800' : 'border-slate-100';

  return (
    <div className={`min-h-screen ${bgColor} ${isDarkMode ? 'text-slate-100' : 'text-slate-800'} pb-40 transition-colors duration-300`}>
      <header className="px-8 pt-8 max-w-[1800px] mx-auto flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="shrink-0">
          <h1 className={`text-4xl font-black tracking-tighter flex items-center gap-2 italic ${headerTextColor}`}>
            <span className={`${accentColor} ${isDarkMode ? 'drop-shadow-[0_0_15px_rgba(139,92,246,0.5)]' : ''}`}>LOCK</span> TF IN!
          </h1>
          <p className={`${subTextColor} font-bold text-xs tracking-[0.3em] mt-1 uppercase`}>Mission Control</p>
        </div>

        <div className={`flex flex-wrap items-center justify-center gap-4 ${surfaceBg} p-2 rounded-[28px] shadow-2xl border ${borderCol}`}>
           <div className={`flex ${isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-50'} p-1 rounded-2xl`}>
             {(['daily', 'weekly', 'monthly'] as ViewType[]).map(v => (
               <button 
                 key={v}
                 onClick={() => setView(v)}
                 className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${view === v ? `${isDarkMode ? 'bg-[#16122b]' : 'bg-white'} ${accentColor} shadow-lg border ${isDarkMode ? 'border-slate-700' : 'border-slate-100'}` : `${subTextColor} hover:${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}`}
               >
                 {v}
               </button>
             ))}
           </div>
           <div className={`h-6 w-px ${isDarkMode ? 'bg-slate-800' : 'bg-slate-200'}`} />
           <div className="flex items-center gap-2">
             <button onClick={() => navigate(-1)} className={`p-2 hover:${isDarkMode ? 'bg-[#1a1630]' : 'bg-slate-50'} rounded-xl transition-colors ${subTextColor}`}><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M15 18l-6-6 6-6"/></svg></button>
             <button onClick={() => setBaseDate(new Date())} className={`px-4 py-2 text-xs font-black ${accentColor} uppercase tracking-tighter hover:${isDarkMode ? 'bg-[#1a1630]' : 'bg-slate-50'} rounded-xl`}>Today</button>
             <button onClick={() => navigate(1)} className={`p-2 hover:${isDarkMode ? 'bg-[#1a1630]' : 'bg-slate-50'} rounded-xl transition-colors ${subTextColor}`}><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M9 18l6-6-6-6"/></svg></button>
           </div>
           <div className={`h-6 w-px ${isDarkMode ? 'bg-slate-800' : 'bg-slate-200'}`} />
           <button 
             onClick={() => setIsDarkMode(!isDarkMode)} 
             className={`p-2 rounded-xl transition-all ${isDarkMode ? 'bg-[#1a1630] text-yellow-400 hover:text-yellow-300' : 'bg-slate-50 text-indigo-600 hover:text-indigo-500'}`}
             title={isDarkMode ? "Switch to Light Mode" : "Switch to Dark Mode"}
           >
             {isDarkMode ? (
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="5"></circle><line x1="12" y1="1" x2="12" y2="3"></line><line x1="12" y1="21" x2="12" y2="23"></line><line x1="4.22" y1="4.22" x2="5.64" y2="5.64"></line><line x1="18.36" y1="18.36" x2="19.78" y2="19.78"></line><line x1="1" y1="12" x2="3" y2="12"></line><line x1="21" y1="12" x2="23" y2="12"></line><line x1="4.22" y1="19.78" x2="5.64" y2="18.36"></line><line x1="18.36" y1="5.64" x2="19.78" y2="4.22"></line></svg>
             ) : (
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"></path></svg>
             )}
           </button>
        </div>

        <div className={`w-full sm:w-auto md:max-w-md ${surfaceBg} rounded-3xl p-2 shadow-2xl border ${borderCol} flex items-center gap-2`}>
          <input
            type="text"
            value={userInput}
            onChange={(e) => setUserInput(e.target.value)}
            placeholder="Adapt your mission..."
            className={`flex-1 bg-transparent border-none px-4 py-2 font-semibold text-sm focus:ring-0 outline-none ${isDarkMode ? 'placeholder:text-slate-600 text-slate-100' : 'placeholder:text-slate-300 text-slate-800'}`}
          />
          <button
            onClick={handleAiUpdate}
            disabled={isAiLoading}
            className={`${accentBg} text-white px-6 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest hover:opacity-90 transition-all disabled:opacity-50 shadow-[0_0_20px_rgba(139,92,246,0.3)]`}
          >
            {isAiLoading ? '...' : 'SYNC'}
          </button>
        </div>
      </header>

      {aiMessage && (
        <div className="max-w-2xl mx-auto mt-8 px-6 animate-in slide-in-from-top-4">
           <div className={`${isDarkMode ? 'bg-[#1a1630] border border-[#8b5cf6]/30 text-slate-100' : 'bg-white border border-slate-200 text-slate-800'} rounded-3xl p-6 shadow-2xl relative`}>
             <p className="font-bold leading-relaxed">{aiMessage}</p>
             <button onClick={() => setAiMessage(null)} className={`absolute top-4 right-4 ${subTextColor} hover:${isDarkMode ? 'text-slate-300' : 'text-slate-600'} transition-colors`}><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
           </div>
        </div>
      )}

      <main className="mt-12 px-8 max-w-[1800px] mx-auto overflow-visible">
        {view === 'monthly' ? (
          <div className={`${surfaceBg} rounded-[40px] shadow-2xl border ${borderCol} overflow-hidden`}>
            <div className={`grid grid-cols-7 border-b ${borderCol} ${isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-50'}`}>
              {DAYS_SHORT.map(d => <div key={d} className={`py-4 text-center text-[10px] font-black ${subTextColor} uppercase tracking-[0.2em]`}>{d}</div>)}
            </div>
            <div className="grid grid-cols-7">
              {monthGrid.map(({ date, currentMonth }, i) => {
                const dateKey = formatDateKey(date);
                const dayTasks = tasks.filter(t => t.date === dateKey);
                const isSelected = dateKey === formatDateKey(baseDate);
                const isToday = dateKey === formatDateKey(new Date());
                return (
                  <div 
                    key={i} 
                    onClick={() => { setBaseDate(new Date(date)); setView('daily'); }}
                    className={`min-h-[140px] p-2 border-r border-b ${borderCol} cursor-pointer transition-all hover:${isDarkMode ? 'bg-[#1a1630]' : 'bg-slate-50'} group ${!currentMonth ? 'opacity-20' : ''} ${isSelected ? (isDarkMode ? 'bg-violet-900/10' : 'bg-blue-50/30') : ''}`}
                  >
                    <div className="flex justify-between items-center mb-1.5">
                      <span className={`text-[11px] font-black ${isToday ? `${accentBg} text-white w-6 h-6 flex items-center justify-center rounded-lg shadow-lg` : isSelected ? accentColor : subTextColor}`}>
                        {date.getDate()}
                      </span>
                    </div>
                    <div className="flex flex-col gap-1 overflow-hidden">
                      {dayTasks.slice(0, 3).map(t => (
                        <div key={t.id} className={`px-2 py-1 rounded-md text-[8px] font-bold truncate flex items-center gap-1.5 ${SECTION_STYLES[t.section].bg.replace('bg-', isDarkMode ? 'bg-opacity-20 bg-' : 'bg-')} ${SECTION_STYLES[t.section].text} ${t.completed ? 'opacity-30' : ''}`}>
                          <span className="shrink-0 w-1 h-1 rounded-full bg-current" />
                          <span className="truncate">{t.section}: {t.title}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : view === 'weekly' ? (
          <div className="space-y-12 pb-8">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-6">
              {currentRangeDays.slice(0, 5).map((d, i) => (
                <DayColumn
                  key={i}
                  isDarkMode={isDarkMode}
                  date={d}
                  tasks={tasks.filter(t => t.date === formatDateKey(d))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                  onDeleteTask={(task) => deleteTask(task, 'single')}
                />
              ))}
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-6">
              <div className="lg:col-start-2">
                <DayColumn
                  isDarkMode={isDarkMode}
                  date={currentRangeDays[5]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[5]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                  onDeleteTask={(task) => deleteTask(task, 'single')}
                />
              </div>
              <div className="lg:col-start-3">
                <DayColumn
                  isDarkMode={isDarkMode}
                  date={currentRangeDays[6]}
                  tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[6]))}
                  onToggleTask={toggleTask}
                  onDragStartTask={handleDragStartTask}
                  onDropTask={moveTask}
                  onAddTask={handleAddTask}
                  onEditTask={handleEditTask}
                  onDeleteTask={(task) => deleteTask(task, 'single')}
                />
              </div>
            </div>
          </div>
        ) : (
          <div className="flex justify-center pb-8">
            <DayColumn
              isDarkMode={isDarkMode}
              date={currentRangeDays[0]}
              tasks={tasks.filter(t => t.date === formatDateKey(currentRangeDays[0]))}
              onToggleTask={toggleTask}
              onDragStartTask={handleDragStartTask}
              onDropTask={moveTask}
              onAddTask={handleAddTask}
              onEditTask={handleEditTask}
              onDeleteTask={(task) => deleteTask(task, 'single')}
              isFocused
            />
          </div>
        )}
      </main>

      <div className={`fixed bottom-10 left-1/2 -translate-x-1/2 ${isDarkMode ? 'bg-[#16122b]/80' : 'bg-white/80'} backdrop-blur-2xl px-10 py-5 rounded-[40px] shadow-[0_20px_60px_rgba(0,0,0,0.3)] border ${borderCol} flex items-center gap-8 z-50`}>
        <div className="flex flex-col">
          <span className={`text-[10px] font-black ${subTextColor} uppercase tracking-widest`}>Mastery</span>
          <span className={`text-xl font-black ${accentColor}`}>{progressPercent}%</span>
        </div>
        <div className={`w-48 sm:w-64 h-3 ${isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-100'} rounded-full overflow-hidden border ${borderCol}`}>
          <div className={`h-full bg-gradient-to-r ${isDarkMode ? 'from-[#8b5cf6] to-[#d946ef]' : 'from-[#3b5bdb] to-[#5c7cff]'} transition-all duration-1000`} style={{ width: `${progressPercent}%` }} />
        </div>
        <div className="flex items-center gap-3">
          <div className={`w-10 h-10 rounded-2xl ${isDarkMode ? 'bg-[#1a1630] border-[#8b5cf6]/30 text-[#8b5cf6]' : 'bg-white border-slate-200 text-[#3b5bdb]'} border flex items-center justify-center font-black text-xs`}>{tasks.filter(t => t.completed).length}</div>
          <span className={`hidden sm:inline text-xs font-bold ${subTextColor}`}>Locked In</span>
        </div>
      </div>

      <EditTaskModal 
        isDarkMode={isDarkMode}
        isOpen={isModalOpen} 
        task={currentTaskToEdit} 
        onClose={() => setIsModalOpen(false)} 
        onSave={saveTask} 
        onDelete={deleteTask} 
      />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { StudyTask } from '../types';
import TaskCard from './TaskCard';
import { formatDateKey } from '../constants';

interface DayColumnProps {
  date: Date;
  tasks: StudyTask[];
  onToggleTask: (id: string) => void;
  onDropTask: (taskId: string, targetDate: string) => void;
  onDragStartTask: (e: React.DragEvent, id: string) => void;
  onAddTask: (date: string) => void;
  onEditTask: (task: StudyTask) => void;
  onDeleteTask: (task: StudyTask) => void;
  isFocused?: boolean;
  isDarkMode: boolean;
}

const DayColumn: React.FC<DayColumnProps> = ({
  date,
  tasks,
  onToggleTask,
  onDropTask,
  onDragStartTask,
  onAddTask,
  onEditTask,
  onDeleteTask,
  isFocused = false,
  isDarkMode
}) => {
  const [isOver, setIsOver] = useState(false);
  const dateKey = formatDateKey(date);
  const isToday = dateKey === formatDateKey(new Date());

  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const dayName = dayNames[date.getDay()];
  const dayNum = date.getDate();

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(true);
  };

  const handleDragLeave = () => {
    setIsOver(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(false);
    const taskId = e.dataTransfer.getData('taskId');
    onDropTask(taskId, dateKey);
  };

  const accentHex = isDarkMode ? '#8b5cf6' : '#3b5bdb';
  const surfaceBg = isDarkMode ? 'bg-[#16122b]' : 'bg-white';
  const borderCol = isDarkMode ? 'border-slate-800' : 'border-slate-100';
  const todayBorder = isDarkMode ? 'border-[#8b5cf6]/30' : 'border-[#3b5bdb]/30';

  return (
    <div
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`flex flex-col rounded-[32px] border-2 p-7 transition-all h-full ${
        isFocused ? 'min-h-[600px] w-full max-w-[500px]' : 'min-h-[450px] w-full'
      } ${
        isOver 
          ? `${isDarkMode ? 'bg-[#1a1630]' : 'bg-blue-50/30'} border-[${accentHex}] border-dashed shadow-2xl` 
          : isToday
            ? `${surfaceBg} ${todayBorder} shadow-2xl ring-1 ring-[#8b5cf6]/10`
            : `${isDarkMode ? 'bg-[#16122b]/50' : 'bg-white/50'} ${borderCol}`
      }`}
    >
      <div className="flex justify-between items-center mb-8">
        <div>
          <h3 className={`text-2xl font-black tracking-tight ${isToday ? (isDarkMode ? 'text-[#8b5cf6] drop-shadow-[0_0_10px_rgba(139,92,246,0.3)]' : 'text-[#3b5bdb]') : (isDarkMode ? 'text-slate-100' : 'text-slate-800')}`}>
            {dayName} {dayNum} {isToday && <span className="text-[0.9em] ml-1">(Today)</span>}
          </h3>
          <p className={`${isDarkMode ? 'text-slate-500' : 'text-slate-400'} font-semibold text-sm mt-0.5`}>
            {tasks.length} {tasks.length === 1 ? 'task' : 'tasks'}
          </p>
        </div>

        <button 
          onClick={() => onAddTask(dateKey)}
          className={`w-11 h-11 rounded-2xl ${isDarkMode ? 'bg-[#1a1630] border-slate-800 text-slate-500 hover:text-[#8b5cf6]' : 'bg-white border-slate-100 text-slate-400 hover:text-[#3b5bdb]'} shadow-xl border flex items-center justify-center transition-all active:scale-90`}
        >
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
            <line x1="12" y1="5" x2="12" y2="19"></line>
            <line x1="5" y1="12" x2="19" y2="12"></line>
          </svg>
        </button>
      </div>

      <div className="flex-1 space-y-4">
        {tasks.map((task) => (
          <TaskCard
            key={task.id}
            isDarkMode={isDarkMode}
            task={task}
            onToggle={onToggleTask}
            onDragStart={onDragStartTask}
            onEdit={onEditTask}
            onDelete={onDeleteTask}
          />
        ))}
        {tasks.length === 0 && (
          <div className={`h-28 border-2 border-dashed ${isDarkMode ? 'border-slate-800 text-slate-600' : 'border-slate-100 text-slate-300'} rounded-[28px] flex items-center justify-center font-bold text-xs italic p-4 text-center`}>
            Rest day?
          </div>
        )}
      </div>
    </div>
  );
};

export default DayColumn;

import React, { useState } from 'react';
import { StudyTask } from '../types';
import { SECTION_STYLES } from '../constants';

interface TaskCardProps {
  task: StudyTask;
  onToggle: (id: string) => void;
  onDragStart: (e: React.DragEvent, id: string) => void;
  onEdit: (task: StudyTask) => void;
  onDelete: (task: StudyTask) => void;
  isDarkMode: boolean;
}

const TaskCard: React.FC<TaskCardProps> = ({ task, onToggle, onDragStart, onEdit, onDelete, isDarkMode }) => {
  const [confirmDelete, setConfirmDelete] = useState(false);
  const styles = SECTION_STYLES[task.section];

  const handleDelete = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (confirmDelete) {
      onDelete(task);
    } else {
      setConfirmDelete(true);
      setTimeout(() => setConfirmDelete(false), 3000);
    }
  };

  const accentColor = isDarkMode ? '#8b5cf6' : '#3b5bdb';
  const cardBg = isDarkMode ? 'bg-[#211b3d]' : 'bg-white';
  const borderCol = isDarkMode ? 'border-slate-800' : 'border-slate-100';
  const textColor = isDarkMode ? 'text-slate-100' : 'text-slate-800';
  const subTextColor = isDarkMode ? 'text-slate-500' : 'text-slate-400';

  return (
    <div
      draggable
      onDragStart={(e) => onDragStart(e, task.id)}
      onClick={() => !confirmDelete && onEdit(task)}
      onMouseLeave={() => setConfirmDelete(false)}
      className={`group relative p-3.5 mb-2.5 ${cardBg} rounded-2xl border ${borderCol} shadow-xl transition-all cursor-grab active:cursor-grabbing hover:shadow-[0_10px_30px_rgba(0,0,0,0.15)] hover:border-[${accentColor}]/30 ${
        task.completed ? 'opacity-40' : ''
      }`}
    >
      <div className="absolute top-2.5 right-2.5 z-50 flex items-center gap-1.5 pointer-events-auto">
        {confirmDelete && (
          <span className="text-[9px] font-black text-rose-500 uppercase tracking-tighter animate-pulse">Confirm?</span>
        )}
        <button
          onClick={handleDelete}
          className={`flex items-center justify-center transition-all border shadow-lg rounded-lg ${
            confirmDelete 
              ? 'w-10 h-7 bg-rose-600 text-white border-rose-700 scale-110' 
              : `${isDarkMode ? 'bg-[#1a1630] border-slate-800' : 'bg-slate-50 border-slate-200'} text-rose-500 md:opacity-0 md:group-hover:opacity-100`
          }`}
          title={confirmDelete ? "Click again to delete" : "Delete Task"}
        >
          {confirmDelete ? (
            <span className="text-[10px] font-black">YES</span>
          ) : (
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
              <polyline points="3 6 5 6 21 6"></polyline>
              <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
            </svg>
          )}
        </button>
      </div>

      <div className="flex gap-3 items-start pr-6">
        <div className="flex shrink-0 pt-0.5" onClick={(e) => e.stopPropagation()}>
          <button
            onClick={() => onToggle(task.id)}
            className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${
              task.completed 
                ? `${isDarkMode ? 'bg-[#8b5cf6] border-[#8b5cf6] shadow-[0_0_10px_rgba(139,92,246,0.5)]' : 'bg-[#3b5bdb] border-[#3b5bdb]'}` 
                : `${isDarkMode ? 'bg-[#1a1630] border-slate-700' : 'bg-white border-slate-200'} hover:border-[${accentColor}]/50`
            }`}
          >
            {task.completed && (
              <svg width="12" height="9" viewBox="0 0 14 11" fill="none" xmlns="http://www.w3.org/2000/svg">
                <path d="M1 6L5 9.5L13 1" stroke="white" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
            )}
          </button>
        </div>

        <div className="flex-1 min-w-0">
          <h4 className={`font-black text-[13px] leading-tight ${textColor} transition-all whitespace-normal break-words ${
            task.completed ? 'line-through opacity-50 font-bold' : ''
          }`}>
            {task.title}
          </h4>

          <div className="mt-2.5 flex flex-col gap-2">
            <div>
               <span className={`inline-block px-1.5 py-0.5 rounded-lg text-[8px] font-black tracking-widest uppercase border border-transparent ${isDarkMode ? 'bg-opacity-20' : ''} ${styles.bg} ${styles.text}`}>
                {styles.label}
              </span>
            </div>

            <div className={`flex items-center gap-1 ${subTextColor} text-[8.5px] font-black tracking-tighter`}>
              <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="12" cy="12" r="10"></circle>
                <polyline points="12 6 12 12 16 14"></polyline>
              </svg>
              <span>{task.duration}</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TaskCard;

import React, { useState, useEffect } from 'react';
import { StudyTask, MCATSection, RecurrenceType } from '../types';
import { SECTION_STYLES } from '../constants';

interface EditTaskModalProps {
  task: Partial<StudyTask> | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: StudyTask, scope?: 'single' | 'future') => void;
  onDelete?: (task: Partial<StudyTask>, scope?: 'single' | 'future') => void;
  isDarkMode: boolean;
}

const EditTaskModal: React.FC<EditTaskModalProps> = ({ task, isOpen, onClose, onSave, onDelete, isDarkMode }) => {
  const [title, setTitle] = useState('');
  const [section, setSection] = useState<MCATSection>('Biology');
  const [duration, setDuration] = useState('');
  const [recurrence, setRecurrence] = useState<RecurrenceType>('None');
  const [customInterval, setCustomInterval] = useState(2);
  const [date, setDate] = useState('');
  const [saveScope, setSaveScope] = useState<'single' | 'future'>('single');
  const [confirmDelete, setConfirmDelete] = useState(false);

  useEffect(() => {
    if (task && isOpen) {
      setTitle(task.title || '');
      setSection(task.section || 'Biology');
      setDuration(task.duration || '');
      setRecurrence(task.recurrence || 'None');
      setCustomInterval(task.customInterval || 2);
      setDate(task.date || '');
      setSaveScope('single');
      setConfirmDelete(false);
    }
  }, [task, isOpen]);

  if (!isOpen || !task) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      ...task,
      title,
      section,
      duration,
      recurrence,
      customInterval: recurrence === 'Custom' ? customInterval : undefined,
      date,
    } as StudyTask, saveScope);
    onClose();
  };

  const handleDelete = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (onDelete && task.id) {
      if (confirmDelete) {
        onDelete(task, saveScope);
        onClose();
      } else {
        setConfirmDelete(true);
      }
    }
  };

  const isRecurringInstance = !!task.groupId;

  const accentColor = isDarkMode ? 'bg-[#8b5cf6]' : 'bg-[#3b5bdb]';
  const surfaceBg = isDarkMode ? 'bg-[#16122b]' : 'bg-white';
  const inputBg = isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-50';
  const borderCol = isDarkMode ? 'border-slate-800' : 'border-slate-100';
  const textColor = isDarkMode ? 'text-slate-100' : 'text-slate-800';
  const subTextColor = isDarkMode ? 'text-slate-500' : 'text-slate-400';

  return (
    <div className={`fixed inset-0 z-[100] flex items-center justify-center p-4 ${isDarkMode ? 'bg-[#090712]/80' : 'bg-slate-900/40'} backdrop-blur-md animate-in fade-in duration-200`}>
      <div className={`${surfaceBg} w-full max-w-md rounded-[32px] p-8 shadow-2xl border ${borderCol} animate-in zoom-in-95 duration-200`} onClick={e => e.stopPropagation()}>
        <div className="flex justify-between items-center mb-6">
          <h2 className={`text-2xl font-black ${textColor} tracking-tight`}>
            {task.id ? 'Mission Control' : 'New Objective'}
          </h2>
          <button onClick={onClose} type="button" className={`${subTextColor} hover:${isDarkMode ? 'text-slate-300' : 'text-slate-600'} p-2 transition-colors`}>
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest mb-2`}>Objective Title</label>
            <input
              autoFocus
              required
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className={`w-full ${inputBg} border-2 ${borderCol} rounded-2xl px-4 py-3 font-bold ${textColor} focus:border-${isDarkMode ? '[#8b5cf6]' : '[#3b5bdb]'} focus:ring-0 outline-none transition-all placeholder:text-slate-700`}
              placeholder="e.g. Acid-Base Equilibrium"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
              <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest mb-2`}>Launch Date</label>
              <input
                required
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className={`w-full ${inputBg} border-2 ${borderCol} rounded-2xl px-4 py-3 font-bold ${textColor} focus:border-${isDarkMode ? '[#8b5cf6]' : '[#3b5bdb]'} focus:ring-0 outline-none transition-all`}
              />
            </div>
            <div>
              <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest mb-2`}>Duration</label>
              <input
                required
                type="text"
                value={duration}
                onChange={(e) => setDuration(e.target.value)}
                className={`w-full ${inputBg} border-2 ${borderCol} rounded-2xl px-4 py-3 font-bold ${textColor} focus:border-${isDarkMode ? '[#8b5cf6]' : '[#3b5bdb]'} focus:ring-0 outline-none transition-all placeholder:text-slate-700`}
                placeholder="e.g. 2.5h"
              />
            </div>
          </div>

          <div>
             <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest mb-2`}>Subject Sector</label>
              <select
                value={section}
                onChange={(e) => setSection(e.target.value as MCATSection)}
                className={`w-full ${inputBg} border-2 ${borderCol} rounded-2xl px-4 py-3 font-bold ${textColor} focus:border-${isDarkMode ? '[#8b5cf6]' : '[#3b5bdb]'} focus:ring-0 outline-none transition-all appearance-none cursor-pointer`}
              >
                {Object.keys(SECTION_STYLES).map((s) => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
          </div>

          {!task.id ? (
            <div className="space-y-4">
              <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest`}>Auto-Recurrence</label>
              <div className="grid grid-cols-2 gap-2">
                {(['None', 'Daily', 'Weekly', 'Custom'] as RecurrenceType[]).map((type) => (
                  <button
                    key={type}
                    type="button"
                    onClick={() => setRecurrence(type)}
                    className={`py-3 rounded-xl font-bold text-xs transition-all border-2 ${
                      recurrence === type 
                        ? `${accentColor} text-white border-transparent shadow-lg` 
                        : `${inputBg} ${subTextColor} ${borderCol} hover:border-slate-300`
                    }`}
                  >
                    {type}
                  </button>
                ))}
              </div>
            </div>
          ) : isRecurringInstance && (
            <div className={`${inputBg} p-4 rounded-2xl border ${borderCol}`}>
              <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest mb-3 text-center`}>Update Scope</label>
              <div className="flex gap-2">
                <button
                  type="button"
                  onClick={() => setSaveScope('single')}
                  className={`flex-1 py-2.5 rounded-xl font-black text-[10px] uppercase transition-all border-2 ${
                    saveScope === 'single'
                      ? `${isDarkMode ? 'bg-[#8b5cf6]/10 border-[#8b5cf6] text-[#8b5cf6]' : 'bg-blue-50 border-[#3b5bdb] text-[#3b5bdb]'}`
                      : `bg-transparent ${borderCol} ${subTextColor}`
                  }`}
                >
                  Instance
                </button>
                <button
                  type="button"
                  onClick={() => setSaveScope('future')}
                  className={`flex-1 py-2.5 rounded-xl font-black text-[10px] uppercase transition-all border-2 ${
                    saveScope === 'future'
                      ? `${isDarkMode ? 'bg-[#8b5cf6]/10 border-[#8b5cf6] text-[#8b5cf6]' : 'bg-blue-50 border-[#3b5bdb] text-[#3b5bdb]'}`
                      : `bg-transparent ${borderCol} ${subTextColor}`
                  }`}
                >
                  Sequence
                </button>
              </div>
            </div>
          )}

          <div className="pt-4 flex gap-3">
            <button
              type="submit"
              className={`flex-1 ${accentColor} text-white py-4 rounded-2xl font-black uppercase tracking-widest hover:opacity-90 shadow-lg transition-all active:scale-[0.98]`}
            >
              {task.id ? 'Update Mission' : 'Launch Objective'}
            </button>
            {task.id && onDelete && (
              <button
                type="button"
                onClick={handleDelete}
                className={`w-auto min-w-[56px] px-3 transition-all rounded-2xl flex items-center justify-center border active:scale-95 ${
                  confirmDelete 
                    ? 'bg-rose-600 text-white border-rose-700 font-black text-[10px]' 
                    : `${inputBg} text-rose-500 ${borderCol} hover:bg-rose-500/10`
                }`}
                title="Abort Objective"
              >
                {confirmDelete ? (
                  "ABORT?"
                ) : (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
                )}
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default EditTaskModal;

export type MCATSection = 
  | 'Biology' 
  | 'Biochemistry' 
  | 'General Chemistry' 
  | 'Organic Chemistry' 
  | 'Physics' 
  | 'Behavioral Sciences' 
  | 'CARS' 
  | 'Practice Exam';

export type RecurrenceType = 'None' | 'Daily' | 'Weekly' | 'Custom' | 'SpacedRepetition';
export type ViewType = 'daily' | 'weekly' | 'monthly';
export type MasteryRating = 'Again' | 'Hard' | 'Good' | 'Easy';

export interface StudyTask {
  id: string;
  groupId?: string; // Links recurring tasks
  originalTaskId?: string; // Links Spaced Repetition reviews to the original chapter
  reviewIteration?: number; // 0 for original, 1-5 for SR reviews
  title: string;
  description: string;
  section: MCATSection;
  completed: boolean;
  date: string; // ISO format YYYY-MM-DD
  duration: string;
  recurrence?: RecurrenceType;
  customInterval?: number; // Days for custom recurrence
  masteryRating?: MasteryRating;
  isFSRSActive?: boolean; // Flagged for intensive review
}

export interface AIResponse {
  suggestion: string;
  updatedTasks: StudyTask[];
}

import React, { useState, useEffect, useMemo } from 'react';
import DayColumn from './components/DayColumn';
import EditTaskModal from './components/EditTaskModal';
import { StudyTask, ViewType, MasteryRating } from './types';
import { INITIAL_TASKS, formatDateKey, DAYS_SHORT, SECTION_STYLES } from './constants';
import { adaptSchedule } from './services/geminiService';

const STORAGE_KEY = 'lock-tf-in-v3-sr';
const THEME_KEY = 'lock-tf-in-theme';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed)) return parsed;
      } catch (e) {
        console.error("Failed to load tasks from storage", e);
      }
    }
    return INITIAL_TASKS;
  });

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    const saved = localStorage.getItem(THEME_KEY);
    return saved !== null ? saved === 'true' : true;
  });

  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');
  const [view, setView] = useState<ViewType>('weekly');
  const [baseDate, setBaseDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tasks));
  }, [tasks]);

  useEffect(() => {
    localStorage.setItem(THEME_KEY, String(isDarkMode));
    document.body.style.backgroundColor = isDarkMode ? '#090712' : '#f8fafc';
    document.body.style.color = isDarkMode ? '#f1f5f9' : '#1e293b';
  }, [isDarkMode]);

  const toggleTask = (id: string) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed, masteryRating: undefined } : t));
  };

  const handleRateTask = (id: string, rating: MasteryRating) => {
    setTasks(prev => {
      const task = prev.find(t => t.id === id);
      if (!task) return prev;

      let newTasks = prev.map(t => t.id === id ? { ...t, masteryRating: rating, completed: true } : t);

      // FSRS Logic
      if (rating === 'Again') {
        // Create an immediate "Blitz Review" for tomorrow
        const tomorrow = new Date(task.date);
        tomorrow.setDate(tomorrow.getDate() + 1);
        const blitzTask: StudyTask = {
          ...task,
          id: Math.random().toString(36).substr(2, 9),
          title: `Blitz: ${task.title}`,
          date: formatDateKey(tomorrow),
          completed: false,
          masteryRating: undefined,
          isFSRSActive: true
        };
        newTasks.push(blitzTask);
      } else if (rating === 'Hard') {
        // Create an extra review in 2 days
        const soon = new Date(task.date);
        soon.setDate(soon.getDate() + 2);
        const hardTask: StudyTask = {
          ...task,
          id: Math.random().toString(36).substr(2, 9),
          title: `Extra Review: ${task.title}`,
          date: formatDateKey(soon),
          completed: false,
          masteryRating: undefined,
          isFSRSActive: true
        };
        newTasks.push(hardTask);
      } else if (rating === 'Easy') {
        // Prune all future linked reviews
        if (task.originalTaskId || task.id) {
          const rootId = task.originalTaskId || task.id;
          newTasks = newTasks.filter(t => !(t.originalTaskId === rootId && !t.completed));
        }
      }

      return newTasks;
    });
  };

  const saveTask = (task: StudyTask, scope: 'single' | 'future' = 'single') => {
    const isChapter = task.title.toLowerCase().includes('chapter');

    if (task.id) {
      setTasks(prev => prev.map(t => t.id === task.id ? task : t));
    } else {
      const newId = Math.random().toString(36).substr(2, 9);
      const rootTask = { ...task, id: newId };
      let sequence: StudyTask[] = [rootTask];

      // Auto Spaced Repetition for "Chapter" tasks
      if (isChapter) {
        const intervals = [1, 3, 7, 12, 16];
        intervals.forEach((days, index) => {
          const reviewDate = new Date(task.date);
          reviewDate.setDate(reviewDate.getDate() + days);
          sequence.push({
            ...task,
            id: Math.random().toString(36).substr(2, 9),
            originalTaskId: newId,
            reviewIteration: index + 1,
            title: `Review #${index + 1}: ${task.title}`,
            date: formatDateKey(reviewDate),
            completed: false,
            recurrence: 'None' // Don't duplicate the duplication
          });
        });
      }

      setTasks(prev => [...prev, ...sequence]);
    }
  };

  // Helper for moving tasks via Drag and Drop
  const moveTask = (taskId: string, targetDate: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, date: targetDate } : t));
  };

  const handleDragStartTask = (e: React.DragEvent, id: string) => e.dataTransfer.setData('taskId', id);
  const handleEditTask = (task: StudyTask) => { setCurrentTaskToEdit(task); setIsModalOpen(true); };
  const handleAddTask = (dateKey: string) => { 
    setCurrentTaskToEdit({ date: dateKey, completed: false, title: '', description: '', section: 'Biology', duration: '1h' }); 
    setIsModalOpen(true); 
  };
  const deleteTask = (task: Partial<StudyTask>) => { if (task.id) setTasks(prev => prev.filter(t => t.id !== task.id)); };

  const navigate = (amount: number) => {
    const newDate = new Date(baseDate);
    if (view === 'daily') newDate.setDate(newDate.getDate() + amount);
    if (view === 'weekly') newDate.setDate(newDate.getDate() + (amount * 7));
    if (view === 'monthly') newDate.setMonth(newDate.getMonth() + amount);
    setBaseDate(newDate);
  };

  const currentRangeDays = useMemo(() => {
    if (view === 'daily') return [new Date(baseDate)];
    const start = new Date(baseDate);
    const day = start.getDay();
    const shift = day === 0 ? 6 : day - 1;
    start.setDate(start.getDate() - shift); 
    return Array.from({ length: 7 }).map((_, i) => {
      const d = new Date(start);
      d.setDate(d.getDate() + i);
      return d;
    });
  }, [view, baseDate]);

  const monthGrid = useMemo(() => {
    if (view !== 'monthly') return [];
    const start = new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
    const end = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0);
    const startDay = start.getDay();
    const padding = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < padding; i++) {
      const d = new Date(start);
      d.setDate(d.getDate() - (padding - i));
      days.push({ date: d, currentMonth: false });
    }
    for (let i = 1; i <= end.getDate(); i++) {
      days.push({ date: new Date(baseDate.getFullYear(), baseDate.getMonth(), i), currentMonth: true });
    }
    const totalSlots = days.length > 35 ? 42 : 35;
    const remaining = totalSlots - days.length;
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(end);
      d.setDate(d.getDate() + i);
      days.push({ date: d, currentMonth: false });
    }
    return days;
  }, [view, baseDate]);

  const handleAiUpdate = async () => {
    if (!userInput.trim()) return;
    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput);
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      setAiMessage("Sync failed.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const progressPercent = tasks.length > 0 ? Math.round((tasks.filter(t => t.completed).length / tasks.length) * 100) : 0;
  const bgColor = isDarkMode ? 'bg-[#090712]' : 'bg-[#f8fafc]';
  const headerTextColor = isDarkMode ? 'text-slate-100' : 'text-slate-900';
  const accentColor = isDarkMode ? 'text-[#8b5cf6]' : 'text-[#3b5bdb]';
  const accentBg = isDarkMode ? 'bg-[#8b5cf6]' : 'bg-[#3b5bdb]';
  const surfaceBg = isDarkMode ? 'bg-[#16122b]' : 'bg-white';
  const borderCol = isDarkMode ? 'border-slate-800' : 'border-slate-100';

  return (
    <div className={`min-h-screen ${bgColor} ${isDarkMode ? 'text-slate-100' : 'text-slate-800'} pb-40 transition-colors duration-300`}>
      <header className="px-8 pt-8 max-w-[1800px] mx-auto flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="shrink-0">
          <h1 className={`text-4xl font-black tracking-tighter flex items-center gap-2 italic ${headerTextColor}`}>
            <span className={`${accentColor} ${isDarkMode ? 'drop-shadow-[0_0_15px_rgba(139,92,246,0.5)]' : ''}`}>LOCK</span> TF IN!
          </h1>
          <p className={`${isDarkMode ? 'text-slate-500' : 'text-slate-400'} font-bold text-xs tracking-[0.3em] mt-1 uppercase`}>Spaced Repetition Active</p>
        </div>

        <div className={`flex flex-wrap items-center justify-center gap-4 ${surfaceBg} p-2 rounded-[28px] shadow-2xl border ${borderCol}`}>
           <div className={`flex ${isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-50'} p-1 rounded-2xl`}>
             {(['daily', 'weekly', 'monthly'] as ViewType[]).map(v => (
               <button key={v} onClick={() => setView(v)} className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${view === v ? `${isDarkMode ? 'bg-[#16122b]' : 'bg-white'} ${accentColor} shadow-lg border ${isDarkMode ? 'border-slate-700' : 'border-slate-100'}` : `text-slate-400 hover:${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}`}>
                 {v}
               </button>
             ))}
           </div>
           <div className="flex items-center gap-2 px-2">
             <button onClick={() => navigate(-1)} className="p-2 hover:opacity-50 transition-opacity"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M15 18l-6-6 6-6"/></svg></button>
             <button onClick={() => setBaseDate(new Date())} className={`px-3 py-1 text-xs font-black ${accentColor}`}>Today</button>
             <button onClick={() => navigate(1)} className="p-2 hover:opacity-50 transition-opacity"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M9 18l6-6-6-6"/></svg></button>
           </div>
           <button onClick={() => setIsDarkMode(!isDarkMode)} className={`p-2 rounded-xl transition-all ${isDarkMode ? 'bg-[#1a1630] text-yellow-400' : 'bg-slate-50 text-indigo-600'}`}>
             {isDarkMode ? <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="12" cy="12" r="5"></circle><line x1="12" y1="1" x2="12" y2="3"></line><line x1="12" y1="21" x2="12" y2="23"></line></svg> : <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"></path></svg>}
           </button>
        </div>

        <div className={`w-full sm:w-auto md:max-w-md ${surfaceBg} rounded-3xl p-2 shadow-2xl border ${borderCol} flex items-center gap-2`}>
          <input type="text" value={userInput} onChange={(e) => setUserInput(e.target.value)} placeholder="E.g. I need help with Biochemistry..." className={`flex-1 bg-transparent border-none px-4 py-2 font-semibold text-sm focus:ring-0 outline-none ${isDarkMode ? 'text-slate-100' : 'text-slate-800'}`} />
          <button onClick={handleAiUpdate} disabled={isAiLoading} className={`${accentBg} text-white px-6 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest hover:opacity-90 disabled:opacity-50`}>
            {isAiLoading ? '...' : 'SYNC'}
          </button>
        </div>
      </header>

      <main className="mt-12 px-8 max-w-[1800px] mx-auto overflow-visible">
        {view === 'monthly' ? (
          <div className={`${surfaceBg} rounded-[40px] shadow-2xl border ${borderCol} overflow-hidden`}>
            <div className={`grid grid-cols-7 border-b ${borderCol} ${isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-50'}`}>
              {DAYS_SHORT.map(d => <div key={d} className={`py-4 text-center text-[10px] font-black text-slate-500 uppercase tracking-widest`}>{d}</div>)}
            </div>
            <div className="grid grid-cols-7">
              {monthGrid.map(({ date, currentMonth }, i) => {
                const dateKey = formatDateKey(date);
                const dayTasks = tasks.filter(t => t.date === dateKey);
                const isSelected = dateKey === formatDateKey(baseDate);
                return (
                  <div key={i} onClick={() => { setBaseDate(new Date(date)); setView('daily'); }} className={`min-h-[140px] p-2 border-r border-b ${borderCol} cursor-pointer hover:${isDarkMode ? 'bg-[#1a1630]' : 'bg-slate-50'} ${!currentMonth ? 'opacity-20' : ''} ${isSelected ? (isDarkMode ? 'bg-violet-900/10' : 'bg-blue-50/30') : ''}`}>
                    <span className={`text-[11px] font-black ${isSelected ? accentColor : 'text-slate-500'}`}>{date.getDate()}</span>
                    <div className="flex flex-col gap-1 mt-1">
                      {dayTasks.slice(0, 3).map(t => (
                        <div key={t.id} className={`px-2 py-1 rounded-md text-[8px] font-bold truncate ${SECTION_STYLES[t.section].bg} ${SECTION_STYLES[t.section].text} ${t.completed ? 'opacity-30' : ''}`}>
                          {t.title}
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className={`grid ${view === 'daily' ? 'grid-cols-1 justify-items-center' : 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-6'}`}>
            {currentRangeDays.map((d, i) => (
              <DayColumn
                key={i}
                isDarkMode={isDarkMode}
                date={d}
                tasks={tasks.filter(t => t.date === formatDateKey(d))}
                onToggleTask={toggleTask}
                onRateTask={handleRateTask}
                onDropTask={moveTask}
                onDragStartTask={handleDragStartTask}
                onAddTask={handleAddTask}
                onEditTask={handleEditTask}
                onDeleteTask={deleteTask}
                isFocused={view === 'daily'}
              />
            ))}
          </div>
        )}
      </main>

      <div className={`fixed bottom-10 left-1/2 -translate-x-1/2 ${isDarkMode ? 'bg-[#16122b]/80' : 'bg-white/80'} backdrop-blur-2xl px-10 py-5 rounded-[40px] shadow-2xl border ${borderCol} flex items-center gap-8 z-50`}>
        <div className="flex flex-col">
          <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Mastery</span>
          <span className={`text-xl font-black ${accentColor}`}>{progressPercent}%</span>
        </div>
        <div className={`w-48 sm:w-64 h-3 ${isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-100'} rounded-full overflow-hidden border ${borderCol}`}>
          <div className={`h-full bg-gradient-to-r ${isDarkMode ? 'from-[#8b5cf6] to-[#d946ef]' : 'from-[#3b5bdb] to-[#5c7cff]'} transition-all duration-1000`} style={{ width: `${progressPercent}%` }} />
        </div>
      </div>

      <EditTaskModal isDarkMode={isDarkMode} isOpen={isModalOpen} task={currentTaskToEdit} onClose={() => setIsModalOpen(false)} onSave={saveTask} onDelete={deleteTask} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { StudyTask, MasteryRating } from '../types';
import TaskCard from './TaskCard';
import { formatDateKey } from '../constants';

interface DayColumnProps {
  date: Date;
  tasks: StudyTask[];
  onToggleTask: (id: string) => void;
  onRateTask: (id: string, rating: MasteryRating) => void;
  onDropTask: (taskId: string, targetDate: string) => void;
  onDragStartTask: (e: React.DragEvent, id: string) => void;
  onAddTask: (date: string) => void;
  onEditTask: (task: StudyTask) => void;
  onDeleteTask: (task: StudyTask) => void;
  isFocused?: boolean;
  isDarkMode: boolean;
}

const DayColumn: React.FC<DayColumnProps> = ({
  date,
  tasks,
  onToggleTask,
  onRateTask,
  onDropTask,
  onDragStartTask,
  onAddTask,
  onEditTask,
  onDeleteTask,
  isFocused = false,
  isDarkMode
}) => {
  const [isOver, setIsOver] = useState(false);
  const dateKey = formatDateKey(date);
  const isToday = dateKey === formatDateKey(new Date());

  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const dayName = dayNames[date.getDay()];
  const dayNum = date.getDate();

  const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); setIsOver(true); };
  const handleDragLeave = () => setIsOver(false);
  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(false);
    const taskId = e.dataTransfer.getData('taskId');
    onDropTask(taskId, dateKey);
  };

  const accentHex = isDarkMode ? '#8b5cf6' : '#3b5bdb';
  const surfaceBg = isDarkMode ? 'bg-[#16122b]' : 'bg-white';
  const borderCol = isDarkMode ? 'border-slate-800' : 'border-slate-100';
  const todayBorder = isDarkMode ? (isToday ? 'border-[#8b5cf6]' : 'border-slate-800') : (isToday ? 'border-[#3b5bdb]' : 'border-slate-100');

  return (
    <div
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`flex flex-col rounded-[32px] border-2 p-6 transition-all ${
        isFocused ? 'min-h-[600px] w-full max-w-[500px]' : 'min-h-[450px] w-full'
      } ${
        isOver ? `${isDarkMode ? 'bg-[#1a1630]' : 'bg-blue-50'} border-dashed border-[#8b5cf6]` : `${surfaceBg} ${todayBorder}`
      } ${isToday ? 'shadow-2xl' : ''}`}
    >
      <div className="flex justify-between items-center mb-6">
        <div>
          <h3 className={`text-xl font-black ${isToday ? (isDarkMode ? 'text-[#8b5cf6]' : 'text-[#3b5bdb]') : (isDarkMode ? 'text-slate-100' : 'text-slate-800')}`}>
            {dayName} {dayNum}
          </h3>
          <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">{tasks.length} Objectives</p>
        </div>
        <button onClick={() => onAddTask(dateKey)} className={`w-9 h-9 rounded-xl border ${borderCol} flex items-center justify-center hover:opacity-70 transition-opacity`}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
        </button>
      </div>

      <div className="flex-1 space-y-3">
        {tasks.map((task) => (
          <TaskCard
            key={task.id}
            isDarkMode={isDarkMode}
            task={task}
            onToggle={onToggleTask}
            onRate={onRateTask}
            onDragStart={onDragStartTask}
            onEdit={onEditTask}
            onDelete={onDeleteTask}
          />
        ))}
        {tasks.length === 0 && (
