import React, { useState, useEffect, useMemo } from 'react';
import DayColumn from './components/DayColumn';
import EditTaskModal from './components/EditTaskModal';
import { StudyTask, ViewType, MasteryRating } from './types';
import { INITIAL_TASKS, formatDateKey, DAYS_SHORT, SECTION_STYLES } from './constants';
import { adaptSchedule } from './services/geminiService';

const STORAGE_KEY = 'lock-tf-in-v3-sr';
const THEME_KEY = 'lock-tf-in-theme';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed)) return parsed;
      } catch (e) {
        console.error("Failed to load tasks from storage", e);
      }
    }
    return INITIAL_TASKS;
  });

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    const saved = localStorage.getItem(THEME_KEY);
    return saved !== null ? saved === 'true' : true;
  });

  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');
  const [view, setView] = useState<ViewType>('weekly');
  const [baseDate, setBaseDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tasks));
  }, [tasks]);

  useEffect(() => {
    localStorage.setItem(THEME_KEY, String(isDarkMode));
    document.body.style.backgroundColor = isDarkMode ? '#090712' : '#f8fafc';
    document.body.style.color = isDarkMode ? '#f1f5f9' : '#1e293b';
  }, [isDarkMode]);

  const toggleTask = (id: string) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed, masteryRating: undefined } : t));
  };

  const handleRateTask = (id: string, rating: MasteryRating) => {
    setTasks(prev => {
      const task = prev.find(t => t.id === id);
      if (!task || task.section === 'CARS') return prev;

      let newTasks = prev.map(t => t.id === id ? { ...t, masteryRating: rating, completed: true } : t);

      // FSRS Logic
      if (rating === 'Again') {
        const tomorrow = new Date(task.date);
        tomorrow.setDate(tomorrow.getDate() + 1);
        const blitzTask: StudyTask = {
          ...task,
          id: Math.random().toString(36).substr(2, 9),
          title: `Blitz: ${task.title}`,
          date: formatDateKey(tomorrow),
          completed: false,
          masteryRating: undefined,
          isFSRSActive: true
        };
        newTasks.push(blitzTask);
      } else if (rating === 'Hard') {
        const soon = new Date(task.date);
        soon.setDate(soon.getDate() + 2);
        const hardTask: StudyTask = {
          ...task,
          id: Math.random().toString(36).substr(2, 9),
          title: `Extra Review: ${task.title}`,
          date: formatDateKey(soon),
          completed: false,
          masteryRating: undefined,
          isFSRSActive: true
        };
        newTasks.push(hardTask);
      } else if (rating === 'Easy') {
        if (task.originalTaskId || task.id) {
          const rootId = task.originalTaskId || task.id;
          newTasks = newTasks.filter(t => !(t.originalTaskId === rootId && !t.completed));
        }
      }

      return newTasks;
    });
  };

  const saveTask = (task: StudyTask) => {
    const isChapter = task.title.toLowerCase().includes('chapter');

    if (task.id) {
      setTasks(prev => prev.map(t => t.id === task.id ? task : t));
    } else {
      const newId = Math.random().toString(36).substr(2, 9);
      const rootTask = { ...task, id: newId };
      let sequence: StudyTask[] = [rootTask];

      // Auto Spaced Repetition for "Chapter" tasks (excluding CARS if named Chapter by accident)
      if (isChapter && task.section !== 'CARS') {
        const intervals = [1, 3, 7, 12, 16];
        intervals.forEach((days, index) => {
          const reviewDate = new Date(task.date);
          reviewDate.setDate(reviewDate.getDate() + days);
          sequence.push({
            ...task,
            id: Math.random().toString(36).substr(2, 9),
            originalTaskId: newId,
            reviewIteration: index + 1,
            title: `Review #${index + 1}: ${task.title}`,
            date: formatDateKey(reviewDate),
            completed: false,
            recurrence: 'None'
          });
        });
      }

      setTasks(prev => [...prev, ...sequence]);
    }
  };

  const moveTask = (taskId: string, targetDate: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, date: targetDate } : t));
  };

  const handleDragStartTask = (e: React.DragEvent, id: string) => e.dataTransfer.setData('taskId', id);
  const handleEditTask = (task: StudyTask) => { setCurrentTaskToEdit(task); setIsModalOpen(true); };
  const handleAddTask = (dateKey: string) => { 
    setCurrentTaskToEdit({ date: dateKey, completed: false, title: '', description: '', section: 'Biology', duration: '1h' }); 
    setIsModalOpen(true); 
  };
  const deleteTask = (task: Partial<StudyTask>) => { 
    if (task.id) setTasks(prev => prev.filter(t => t.id !== task.id)); 
  };

  const navigate = (amount: number) => {
    const newDate = new Date(baseDate);
    if (view === 'daily') newDate.setDate(newDate.getDate() + amount);
    if (view === 'weekly') newDate.setDate(newDate.getDate() + (amount * 7));
    if (view === 'monthly') newDate.setMonth(newDate.getMonth() + amount);
    setBaseDate(newDate);
  };

  const currentRangeDays = useMemo(() => {
    if (view === 'daily') return [new Date(baseDate)];
    const start = new Date(baseDate);
    const day = start.getDay();
    const shift = day === 0 ? 6 : day - 1;
    start.setDate(start.getDate() - shift); 
    return Array.from({ length: 7 }).map((_, i) => {
      const d = new Date(start);
      d.setDate(d.getDate() + i);
      return d;
    });
  }, [view, baseDate]);

  const monthGrid = useMemo(() => {
    if (view !== 'monthly') return [];
    const start = new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
    const end = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0);
    const startDay = start.getDay();
    const padding = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < padding; i++) {
      const d = new Date(start);
      d.setDate(d.getDate() - (padding - i));
      days.push({ date: d, currentMonth: false });
    }
    for (let i = 1; i <= end.getDate(); i++) {
      days.push({ date: new Date(baseDate.getFullYear(), baseDate.getMonth(), i), currentMonth: true });
    }
    const totalSlots = days.length > 35 ? 42 : 35;
    const remaining = totalSlots - days.length;
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(end);
      d.setDate(d.getDate() + i);
      days.push({ date: d, currentMonth: false });
    }
    return days;
  }, [view, baseDate]);

  const handleAiUpdate = async () => {
    if (!userInput.trim()) return;
    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput);
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      setAiMessage("Sync failed.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const progressPercent = tasks.length > 0 ? Math.round((tasks.filter(t => t.completed).length / tasks.length) * 100) : 0;
  const bgColor = isDarkMode ? 'bg-[#090712]' : 'bg-[#f8fafc]';
  const headerTextColor = isDarkMode ? 'text-slate-100' : 'text-slate-900';
  const accentColor = isDarkMode ? 'text-[#8b5cf6]' : 'text-[#3b5bdb]';
  const accentBg = isDarkMode ? 'bg-[#8b5cf6]' : 'bg-[#3b5bdb]';
  const surfaceBg = isDarkMode ? 'bg-[#16122b]' : 'bg-white';
  const borderCol = isDarkMode ? 'border-slate-800' : 'border-slate-100';

  return (
    <div className={`min-h-screen ${bgColor} ${isDarkMode ? 'text-slate-100' : 'text-slate-800'} pb-40 transition-colors duration-300`}>
      <header className="px-8 pt-8 max-w-[1800px] mx-auto flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="shrink-0">
          <h1 className={`text-4xl font-black tracking-tighter flex items-center gap-2 italic ${headerTextColor}`}>
            <span className={`${accentColor} ${isDarkMode ? 'drop-shadow-[0_0_15px_rgba(139,92,246,0.5)]' : ''}`}>LOCK</span> TF IN!
          </h1>
          <p className={`${isDarkMode ? 'text-slate-500' : 'text-slate-400'} font-bold text-xs tracking-[0.3em] mt-1 uppercase`}>Mission Control Center</p>
        </div>

        <div className={`flex flex-wrap items-center justify-center gap-4 ${surfaceBg} p-2 rounded-[28px] shadow-2xl border ${borderCol}`}>
           <div className={`flex ${isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-50'} p-1 rounded-2xl`}>
             {(['daily', 'weekly', 'monthly'] as ViewType[]).map(v => (
               <button key={v} onClick={() => setView(v)} className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${view === v ? `${isDarkMode ? 'bg-[#16122b]' : 'bg-white'} ${accentColor} shadow-lg border ${isDarkMode ? 'border-slate-700' : 'border-slate-100'}` : `text-slate-400 hover:${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}`}>
                 {v}
               </button>
             ))}
           </div>
           <div className="flex items-center gap-2 px-2">
             <button onClick={() => navigate(-1)} className="p-2 hover:opacity-50 transition-opacity"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M15 18l-6-6 6-6"/></svg></button>
             <button onClick={() => setBaseDate(new Date())} className={`px-3 py-1 text-xs font-black ${accentColor}`}>Today</button>
             <button onClick={() => navigate(1)} className="p-2 hover:opacity-50 transition-opacity"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M9 18l6-6-6-6"/></svg></button>
           </div>
           <button onClick={() => setIsDarkMode(!isDarkMode)} className={`p-2 rounded-xl transition-all ${isDarkMode ? 'bg-[#1a1630] text-yellow-400' : 'bg-slate-50 text-indigo-600'}`}>
             {isDarkMode ? <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="12" cy="12" r="5"></circle><line x1="12" y1="1" x2="12" y2="3"></line><line x1="12" y1="21" x2="12" y2="23"></line></svg> : <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"></path></svg>}
           </button>
        </div>

        <div className={`w-full sm:w-auto md:max-w-md ${surfaceBg} rounded-3xl p-2 shadow-2xl border ${borderCol} flex items-center gap-2`}>
          <input type="text" value={userInput} onChange={(e) => setUserInput(e.target.value)} placeholder="Sync with AI Coach..." className={`flex-1 bg-transparent border-none px-4 py-2 font-semibold text-sm focus:ring-0 outline-none ${isDarkMode ? 'text-slate-100' : 'text-slate-800'}`} />
          <button onClick={handleAiUpdate} disabled={isAiLoading} className={`${accentBg} text-white px-6 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest hover:opacity-90 disabled:opacity-50 shadow-lg`}>
            {isAiLoading ? '...' : 'SYNC'}
          </button>
        </div>
      </header>

      <main className="mt-12 px-8 max-w-[1800px] mx-auto overflow-visible">
        {view === 'monthly' ? (
          <div className={`${surfaceBg} rounded-[40px] shadow-2xl border ${borderCol} overflow-hidden`}>
            <div className={`grid grid-cols-7 border-b ${borderCol} ${isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-50'}`}>
              {DAYS_SHORT.map(d => <div key={d} className={`py-4 text-center text-[10px] font-black text-slate-500 uppercase tracking-widest`}>{d}</div>)}
            </div>
            <div className="grid grid-cols-7">
              {monthGrid.map(({ date, currentMonth }, i) => {
                const dateKey = formatDateKey(date);
                const dayTasks = tasks.filter(t => t.date === dateKey);
                const isSelected = dateKey === formatDateKey(baseDate);
                return (
                  <div key={i} onClick={() => { setBaseDate(new Date(date)); setView('daily'); }} className={`min-h-[140px] p-2 border-r border-b ${borderCol} cursor-pointer hover:${isDarkMode ? 'bg-[#1a1630]' : 'bg-slate-50'} ${!currentMonth ? 'opacity-20' : ''} ${isSelected ? (isDarkMode ? 'bg-violet-900/10' : 'bg-blue-50/30') : ''}`}>
                    <span className={`text-[11px] font-black ${isSelected ? accentColor : 'text-slate-500'}`}>{date.getDate()}</span>
                    <div className="flex flex-col gap-1 mt-1">
                      {dayTasks.slice(0, 3).map(t => (
                        <div key={t.id} className={`px-2 py-1 rounded-md text-[8px] font-bold truncate ${SECTION_STYLES[t.section].bg} ${SECTION_STYLES[t.section].text} ${t.completed ? 'opacity-30' : ''}`}>
                          {t.title}
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className={`grid ${view === 'daily' ? 'grid-cols-1 justify-items-center' : 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-6'}`}>
            {currentRangeDays.map((d, i) => (
              <DayColumn
                key={i}
                isDarkMode={isDarkMode}
                date={d}
                tasks={tasks.filter(t => t.date === formatDateKey(d))}
                onToggleTask={toggleTask}
                onRateTask={handleRateTask}
                onDropTask={moveTask}
                onDragStartTask={handleDragStartTask}
                onAddTask={handleAddTask}
                onEditTask={handleEditTask}
                onDeleteTask={deleteTask}
                isFocused={view === 'daily'}
              />
            ))}
          </div>
        )}
      </main>

      <div className={`fixed bottom-10 left-1/2 -translate-x-1/2 ${isDarkMode ? 'bg-[#16122b]/80' : 'bg-white/80'} backdrop-blur-2xl px-10 py-5 rounded-[40px] shadow-2xl border ${borderCol} flex items-center gap-8 z-50`}>
        <div className="flex flex-col">
          <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Mastery</span>
          <span className={`text-xl font-black ${accentColor}`}>{progressPercent}%</span>
        </div>
        <div className={`w-48 sm:w-64 h-3 ${isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-100'} rounded-full overflow-hidden border ${borderCol}`}>
          <div className={`h-full bg-gradient-to-r ${isDarkMode ? 'from-[#8b5cf6] to-[#d946ef]' : 'from-[#3b5bdb] to-[#5c7cff]'} transition-all duration-1000`} style={{ width: `${progressPercent}%` }} />
        </div>
      </div>

      <EditTaskModal isDarkMode={isDarkMode} isOpen={isModalOpen} task={currentTaskToEdit} onClose={() => setIsModalOpen(false)} onSave={saveTask} onDelete={deleteTask} />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { StudyTask, MCATSection, RecurrenceType } from '../types';
import { SECTION_STYLES } from '../constants';

interface EditTaskModalProps {
  task: Partial<StudyTask> | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: StudyTask, scope?: 'single' | 'future') => void;
  onDelete?: (task: Partial<StudyTask>, scope?: 'single' | 'future') => void;
  isDarkMode: boolean;
}

const EditTaskModal: React.FC<EditTaskModalProps> = ({ task, isOpen, onClose, onSave, onDelete, isDarkMode }) => {
  const [title, setTitle] = useState('');
  const [section, setSection] = useState<MCATSection>('Biology');
  const [duration, setDuration] = useState('');
  const [date, setDate] = useState('');
  const [recurrence, setRecurrence] = useState<RecurrenceType>('None');
  const [customInterval, setCustomInterval] = useState(2);
  const [saveScope, setSaveScope] = useState<'single' | 'future'>('single');
  const [confirmDelete, setConfirmDelete] = useState(false);

  useEffect(() => {
    if (task && isOpen) {
      setTitle(task.title || '');
      setSection(task.section || 'Biology');
      setDuration(task.duration || '');
      setDate(task.date || '');
      setRecurrence(task.recurrence || 'None');
      setCustomInterval(task.customInterval || 2);
      setSaveScope('single');
      setConfirmDelete(false);
    }
  }, [task, isOpen]);

  if (!isOpen || !task) return null;

  const isChapter = title.toLowerCase().includes('chapter') && section !== 'CARS';
  const isRecurringInstance = !!task.groupId || !!task.originalTaskId;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({ 
      ...task, 
      title, 
      section, 
      duration, 
      date, 
      recurrence, 
      customInterval: recurrence === 'Custom' ? customInterval : undefined 
    } as StudyTask, saveScope);
    onClose();
  };

  const surfaceBg = isDarkMode ? 'bg-[#16122b]' : 'bg-white';
  const inputBg = isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-50';
  const borderCol = isDarkMode ? 'border-slate-800' : 'border-slate-100';
  const textColor = isDarkMode ? 'text-slate-100' : 'text-slate-800';
  const subTextColor = isDarkMode ? 'text-slate-500' : 'text-slate-400';

  return (
    <div className={`fixed inset-0 z-[100] flex items-center justify-center p-4 ${isDarkMode ? 'bg-black/80' : 'bg-slate-900/40'} backdrop-blur-md animate-in fade-in`}>
      <div className={`${surfaceBg} w-full max-w-md rounded-[32px] p-8 shadow-2xl border ${borderCol} max-h-[90vh] overflow-y-auto`} onClick={e => e.stopPropagation()}>
        <div className="flex justify-between items-center mb-6">
          <h2 className={`text-2xl font-black ${textColor}`}>Objective Details</h2>
          <button onClick={onClose} className={`${subTextColor} hover:text-white transition-colors`}><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest mb-2`}>Objective Title</label>
            <input
              autoFocus required type="text" value={title} onChange={(e) => setTitle(e.target.value)}
              className={`w-full ${inputBg} border-2 ${borderCol} rounded-2xl px-4 py-3 font-bold ${textColor} outline-none focus:border-[#8b5cf6]`}
              placeholder="e.g. Biology Chapter 4"
            />
            {isChapter && !task.id && (
              <p className="mt-2 text-[10px] font-black text-purple-400 uppercase tracking-tight flex items-center gap-1">
                <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4M4.93 19.07l2.83-2.83M16.24 7.76l2.83-2.83"/></svg>
                Spaced Repetition Auto-Sequence Detected
              </p>
            )}
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest mb-2`}>Launch Date</label>
              <input required type="date" value={date} onChange={(e) => setDate(e.target.value)} className={`w-full ${inputBg} border-2 ${borderCol} rounded-2xl px-4 py-3 font-bold ${textColor} outline-none focus:border-[#8b5cf6]`} />
            </div>
            <div>
              <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest mb-2`}>Duration</label>
              <input required type="text" value={duration} onChange={(e) => setDuration(e.target.value)} className={`w-full ${inputBg} border-2 ${borderCol} rounded-2xl px-4 py-3 font-bold ${textColor} outline-none focus:border-[#8b5cf6]`} placeholder="e.g. 2h" />
            </div>
          </div>

          <div>
            <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest mb-2`}>Sector</label>
            <select value={section} onChange={(e) => setSection(e.target.value as MCATSection)} className={`w-full ${inputBg} border-2 ${borderCol} rounded-2xl px-4 py-3 font-bold ${textColor} outline-none focus:border-[#8b5cf6]`}>
              {Object.keys(SECTION_STYLES).map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>

          {/* Recurrence Section - Restored */}
          {!task.id && !isChapter && (
            <div className="space-y-4">
              <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest`}>Auto-Recurrence</label>
              <div className="grid grid-cols-2 gap-2">
                {(['None', 'Daily', 'Weekly', 'Custom'] as RecurrenceType[]).map((type) => (
                  <button
                    key={type}
                    type="button"
                    onClick={() => setRecurrence(type)}
                    className={`py-3 rounded-xl font-bold text-xs transition-all border-2 ${
                      recurrence === type 
                        ? 'bg-[#8b5cf6] text-white border-transparent shadow-lg' 
                        : `${inputBg} ${subTextColor} ${borderCol} hover:border-slate-700`
                    }`}
                  >
                    {type}
                  </button>
                ))}
              </div>
              {recurrence === 'Custom' && (
                <div className="animate-in slide-in-from-top-2">
                  <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest mb-2`}>Repeat every X days</label>
                  <input
                    type="number"
                    min="1"
                    value={customInterval}
                    onChange={(e) => setCustomInterval(parseInt(e.target.value) || 1)}
                    className={`w-full ${inputBg} border-2 ${borderCol} rounded-2xl px-4 py-3 font-bold ${textColor} outline-none focus:border-[#8b5cf6]`}
                  />
                </div>
              )}
            </div>
          )}

          {/* Update Scope for existing recurring/SR tasks */}
          {task.id && isRecurringInstance && (
            <div className={`${inputBg} p-4 rounded-2xl border ${borderCol} space-y-3`}>
              <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest text-center`}>Update Scope</label>
              <div className="flex gap-2">
                <button
                  type="button"
                  onClick={() => setSaveScope('single')}
                  className={`flex-1 py-2.5 rounded-xl font-black text-[10px] uppercase transition-all border-2 ${
                    saveScope === 'single' ? 'bg-[#8b5cf6]/20 border-[#8b5cf6] text-[#8b5cf6]' : `bg-transparent ${borderCol} ${subTextColor}`
                  }`}
                >
                  Instance
                </button>
                <button
                  type="button"
                  onClick={() => setSaveScope('future')}
                  className={`flex-1 py-2.5 rounded-xl font-black text-[10px] uppercase transition-all border-2 ${
                    saveScope === 'future' ? 'bg-[#8b5cf6]/20 border-[#8b5cf6] text-[#8b5cf6]' : `bg-transparent ${borderCol} ${subTextColor}`
                  }`}
                >
                  Sequence
                </button>
              </div>
            </div>
          )}

          <div className="pt-4 flex gap-3">
            <button type="submit" className="flex-1 bg-[#8b5cf6] text-white py-4 rounded-2xl font-black uppercase tracking-widest hover:opacity-90 shadow-lg transition-all active:scale-95">
              {task.id ? 'Save Changes' : isChapter ? 'Launch Sequence' : 'Create Mission'}
            </button>
            {task.id && (
              <button 
                type="button" 
                onClick={() => { if(confirmDelete && onDelete) { onDelete(task, saveScope); onClose(); } else setConfirmDelete(true); }} 
                className={`w-14 transition-all rounded-2xl flex items-center justify-center border active:scale-95 ${confirmDelete ? 'bg-rose-600 border-rose-600 text-white' : `${inputBg} border-slate-800 text-rose-500`}`}
              >
                {confirmDelete ? <span className="text-[10px] font-black uppercase">Sure?</span> : <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>}
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default EditTaskModal;

import React, { useState, useEffect, useMemo } from 'react';
import DayColumn from './components/DayColumn';
import EditTaskModal from './components/EditTaskModal';
import { StudyTask, ViewType, MasteryRating } from './types';
import { INITIAL_TASKS, formatDateKey, DAYS_SHORT, SECTION_STYLES } from './constants';
import { adaptSchedule } from './services/geminiService';

const STORAGE_KEY = 'lock-tf-in-v3-sr';
const THEME_KEY = 'lock-tf-in-theme';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed)) return parsed;
      } catch (e) {
        console.error("Failed to load tasks from storage", e);
      }
    }
    return INITIAL_TASKS;
  });

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    const saved = localStorage.getItem(THEME_KEY);
    return saved !== null ? saved === 'true' : true;
  });

  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');
  const [view, setView] = useState<ViewType>('weekly');
  const [baseDate, setBaseDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tasks));
  }, [tasks]);

  useEffect(() => {
    localStorage.setItem(THEME_KEY, String(isDarkMode));
    document.body.style.backgroundColor = isDarkMode ? '#090712' : '#f8fafc';
    document.body.style.color = isDarkMode ? '#f1f5f9' : '#1e293b';
  }, [isDarkMode]);

  const toggleTask = (id: string) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed, masteryRating: undefined } : t));
  };

  const handleRateTask = (id: string, rating: MasteryRating) => {
    setTasks(prev => {
      const task = prev.find(t => t.id === id);
      if (!task || task.section === 'CARS') return prev;

      let newTasks = prev.map(t => t.id === id ? { ...t, masteryRating: rating, completed: true } : t);

      if (rating === 'Again') {
        const tomorrow = new Date(task.date);
        tomorrow.setDate(tomorrow.getDate() + 1);
        newTasks.push({
          ...task,
          id: Math.random().toString(36).substr(2, 9),
          title: `Blitz: ${task.title}`,
          date: formatDateKey(tomorrow),
          completed: false,
          masteryRating: undefined,
          isFSRSActive: true
        });
      } else if (rating === 'Hard') {
        const soon = new Date(task.date);
        soon.setDate(soon.getDate() + 2);
        newTasks.push({
          ...task,
          id: Math.random().toString(36).substr(2, 9),
          title: `Extra Review: ${task.title}`,
          date: formatDateKey(soon),
          completed: false,
          masteryRating: undefined,
          isFSRSActive: true
        });
      } else if (rating === 'Easy') {
        const rootId = task.originalTaskId || task.id;
        newTasks = newTasks.filter(t => !(t.originalTaskId === rootId && !t.completed));
      }

      return newTasks;
    });
  };

  const saveTask = (task: StudyTask, scope: 'single' | 'future' = 'single') => {
    const isChapter = task.title.toLowerCase().includes('chapter') && task.section !== 'CARS';

    if (task.id) {
      if (scope === 'future' && (task.groupId || task.originalTaskId)) {
        const linkId = task.groupId || task.originalTaskId;
        setTasks(prev => prev.map(t => {
          if ((t.groupId === linkId || t.originalTaskId === linkId) && t.date >= task.date) {
            return { ...t, title: task.title, section: task.section, duration: task.duration };
          }
          return t;
        }));
      } else {
        setTasks(prev => prev.map(t => t.id === task.id ? task : t));
      }
    } else {
      const newId = Math.random().toString(36).substr(2, 9);
      let sequence: StudyTask[] = [];

      if (isChapter) {
        const intervals = [0, 1, 3, 7, 12, 16];
        intervals.forEach((days, index) => {
          const d = new Date(task.date);
          d.setDate(d.getDate() + days);
          sequence.push({
            ...task,
            id: Math.random().toString(36).substr(2, 9),
            originalTaskId: newId,
            reviewIteration: index === 0 ? undefined : index,
            title: index === 0 ? task.title : `Review #${index}: ${task.title}`,
            date: formatDateKey(d),
            completed: false,
            recurrence: 'None'
          });
        });
      } else if (task.recurrence && task.recurrence !== 'None') {
        const groupId = Math.random().toString(36).substr(2, 9);
        let interval = 1;
        if (task.recurrence === 'Weekly') interval = 7;
        if (task.recurrence === 'Custom' && task.customInterval) interval = task.customInterval;

        for (let i = 0; i < 12; i++) {
          const d = new Date(task.date);
          d.setDate(d.getDate() + (i * interval));
          sequence.push({
            ...task,
            id: Math.random().toString(36).substr(2, 9),
            groupId,
            date: formatDateKey(d),
            completed: false
          });
        }
      } else {
        sequence.push({ ...task, id: newId });
      }

      setTasks(prev => [...prev, ...sequence]);
    }
  };

  const moveTask = (taskId: string, targetDate: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, date: targetDate } : t));
  };

  const deleteTask = (task: Partial<StudyTask>, scope: 'single' | 'future' = 'single') => {
    if (!task.id) return;
    setTasks(prev => {
      if (scope === 'future' && (task.groupId || task.originalTaskId)) {
        const linkId = task.groupId || task.originalTaskId;
        return prev.filter(t => !((t.groupId === linkId || t.originalTaskId === linkId) && t.date >= task.date));
      }
      return prev.filter(t => t.id !== task.id);
    });
  };

  const handleDragStartTask = (e: React.DragEvent, id: string) => e.dataTransfer.setData('taskId', id);
  const handleEditTask = (task: StudyTask) => { setCurrentTaskToEdit(task); setIsModalOpen(true); };
  const handleAddTask = (dateKey: string) => { 
    setCurrentTaskToEdit({ date: dateKey, completed: false, title: '', description: '', section: 'Biology', duration: '1h' }); 
    setIsModalOpen(true); 
  };

  const navigate = (amount: number) => {
    const newDate = new Date(baseDate);
    if (view === 'daily') newDate.setDate(newDate.getDate() + amount);
    if (view === 'weekly') newDate.setDate(newDate.getDate() + (amount * 7));
    if (view === 'monthly') newDate.setMonth(newDate.getMonth() + amount);
    setBaseDate(newDate);
  };

  const currentRangeDays = useMemo(() => {
    if (view === 'daily') return [new Date(baseDate)];
    const start = new Date(baseDate);
    const day = start.getDay();
    const shift = day === 0 ? 6 : day - 1;
    start.setDate(start.getDate() - shift); 
    return Array.from({ length: 7 }).map((_, i) => {
      const d = new Date(start);
      d.setDate(d.getDate() + i);
      return d;
    });
  }, [view, baseDate]);

  const monthGrid = useMemo(() => {
    if (view !== 'monthly') return [];
    const start = new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
    const end = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0);
    const startDay = start.getDay();
    const padding = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < padding; i++) {
      const d = new Date(start);
      d.setDate(d.getDate() - (padding - i));
      days.push({ date: d, currentMonth: false });
    }
    for (let i = 1; i <= end.getDate(); i++) {
      days.push({ date: new Date(baseDate.getFullYear(), baseDate.getMonth(), i), currentMonth: true });
    }
    const totalSlots = days.length > 35 ? 42 : 35;
    const remaining = totalSlots - days.length;
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(end);
      d.setDate(d.getDate() + i);
      days.push({ date: d, currentMonth: false });
    }
    return days;
  }, [view, baseDate]);

  const handleAiUpdate = async () => {
    if (!userInput.trim()) return;
    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput);
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      setAiMessage("Sync failed.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const progressPercent = tasks.length > 0 ? Math.round((tasks.filter(t => t.completed).length / tasks.length) * 100) : 0;
  const bgColor = isDarkMode ? 'bg-[#090712]' : 'bg-[#f8fafc]';
  const surfaceBg = isDarkMode ? 'bg-[#16122b]' : 'bg-white';
  const borderCol = isDarkMode ? 'border-slate-800' : 'border-slate-100';

  return (
    <div className={`min-h-screen ${bgColor} ${isDarkMode ? 'text-slate-100' : 'text-slate-800'} pb-40 transition-colors duration-300`}>
      <header className="px-8 pt-8 max-w-[1800px] mx-auto flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="shrink-0">
          <h1 className="text-4xl font-black tracking-tighter flex items-center gap-2 italic">
            <span className={`${isDarkMode ? 'text-[#8b5cf6] drop-shadow-[0_0_15px_rgba(139,92,246,0.5)]' : 'text-[#3b5bdb]'}`}>LOCK</span> TF IN!
          </h1>
          <p className={`${isDarkMode ? 'text-slate-500' : 'text-slate-400'} font-bold text-xs tracking-[0.3em] mt-1 uppercase`}>Adaptive Learning Active</p>
        </div>

        <div className={`flex flex-wrap items-center justify-center gap-4 ${surfaceBg} p-2 rounded-[28px] shadow-2xl border ${borderCol}`}>
           <div className={`flex ${isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-50'} p-1 rounded-2xl`}>
             {(['daily', 'weekly', 'monthly'] as ViewType[]).map(v => (
               <button key={v} onClick={() => setView(v)} className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${view === v ? `${isDarkMode ? 'bg-[#16122b]' : 'bg-white'} ${isDarkMode ? 'text-[#8b5cf6]' : 'text-[#3b5bdb]'} shadow-lg border ${isDarkMode ? 'border-slate-700' : 'border-slate-100'}` : `text-slate-400 hover:${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}`}>
                 {v}
               </button>
             ))}
           </div>
           <button onClick={() => setIsDarkMode(!isDarkMode)} className={`p-2 rounded-xl transition-all ${isDarkMode ? 'bg-[#1a1630] text-yellow-400' : 'bg-slate-50 text-indigo-600'}`}>
             {isDarkMode ? <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="12" cy="12" r="5"></circle><line x1="12" y1="1" x2="12" y2="3"></line><line x1="12" y1="21" x2="12" y2="23"></line></svg> : <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"></path></svg>}
           </button>
        </div>

        <div className={`w-full sm:w-auto md:max-w-md ${surfaceBg} rounded-3xl p-2 shadow-2xl border ${borderCol} flex items-center gap-2`}>
          <input type="text" value={userInput} onChange={(e) => setUserInput(e.target.value)} placeholder="Sync with AI Coach..." className={`flex-1 bg-transparent border-none px-4 py-2 font-semibold text-sm focus:ring-0 outline-none ${isDarkMode ? 'text-slate-100' : 'text-slate-800'}`} />
          <button onClick={handleAiUpdate} disabled={isAiLoading} className={`${isDarkMode ? 'bg-[#8b5cf6]' : 'bg-[#3b5bdb]'} text-white px-6 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest hover:opacity-90 disabled:opacity-50 shadow-lg`}>
            {isAiLoading ? '...' : 'SYNC'}
          </button>
        </div>
      </header>

      <main className="mt-12 px-8 max-w-[1800px] mx-auto overflow-visible">
        <div className={`grid ${view === 'daily' ? 'grid-cols-1 justify-items-center' : view === 'monthly' ? 'grid-cols-1' : 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-6'}`}>
          {view === 'monthly' ? (
            <div className={`${surfaceBg} rounded-[40px] shadow-2xl border ${borderCol} overflow-hidden w-full`}>
               <div className={`grid grid-cols-7 border-b ${borderCol} ${isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-50'}`}>
                {DAYS_SHORT.map(d => <div key={d} className="py-4 text-center text-[10px] font-black text-slate-500 uppercase tracking-widest">{d}</div>)}
              </div>
              <div className="grid grid-cols-7">
                {monthGrid.map(({ date, currentMonth }, i) => {
                  const dateKey = formatDateKey(date);
                  const dayTasks = tasks.filter(t => t.date === dateKey);
                  return (
                    <div key={i} onClick={() => { setBaseDate(new Date(date)); setView('daily'); }} className={`min-h-[120px] p-2 border-r border-b ${borderCol} cursor-pointer hover:${isDarkMode ? 'bg-[#1a1630]' : 'bg-slate-50'} ${!currentMonth ? 'opacity-20' : ''}`}>
                      <span className="text-[11px] font-black text-slate-500">{date.getDate()}</span>
                      <div className="flex flex-col gap-1 mt-1">
                        {dayTasks.slice(0, 2).map(t => <div key={t.id} className={`px-1.5 py-0.5 rounded text-[7px] font-bold truncate ${SECTION_STYLES[t.section].bg} ${SECTION_STYLES[t.section].text}`}>{t.title}</div>)}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          ) : (
            currentRangeDays.map((d, i) => (
              <DayColumn
                key={i}
                isDarkMode={isDarkMode}
                date={d}
                tasks={tasks.filter(t => t.date === formatDateKey(d))}
                onToggleTask={toggleTask}
                onRateTask={handleRateTask}
                onDropTask={moveTask}
                onDragStartTask={handleDragStartTask}
                onAddTask={handleAddTask}
                onEditTask={handleEditTask}
                onDeleteTask={deleteTask}
                isFocused={view === 'daily'}
              />
            ))
          )}
        </div>
      </main>

      <div className={`fixed bottom-10 left-1/2 -translate-x-1/2 ${isDarkMode ? 'bg-[#16122b]/80' : 'bg-white/80'} backdrop-blur-2xl px-10 py-5 rounded-[40px] shadow-2xl border ${borderCol} flex items-center gap-8 z-50`}>
        <div className="flex flex-col">
          <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Mastery</span>
          <span className={`text-xl font-black ${isDarkMode ? 'text-[#8b5cf6]' : 'text-[#3b5bdb]'}`}>{progressPercent}%</span>
        </div>
        <div className={`w-48 sm:w-64 h-3 ${isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-100'} rounded-full overflow-hidden border ${borderCol}`}>
          <div className={`h-full bg-gradient-to-r ${isDarkMode ? 'from-[#8b5cf6] to-[#d946ef]' : 'from-[#3b5bdb] to-[#5c7cff]'} transition-all duration-1000`} style={{ width: `${progressPercent}%` }} />
        </div>
      </div>

      <EditTaskModal isDarkMode={isDarkMode} isOpen={isModalOpen} task={currentTaskToEdit} onClose={() => setIsModalOpen(false)} onSave={saveTask} onDelete={deleteTask} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { StudyTask, MasteryRating } from '../types';
import { SECTION_STYLES } from '../constants';

interface TaskCardProps {
  task: StudyTask;
  onToggle: (id: string) => void;
  onRate: (id: string, rating: MasteryRating) => void;
  onDragStart: (e: React.DragEvent, id: string) => void;
  onEdit: (task: StudyTask) => void;
  onDelete: (task: StudyTask) => void;
  isDarkMode: boolean;
}

const TaskCard: React.FC<TaskCardProps> = ({ task, onToggle, onRate, onDragStart, onEdit, onDelete, isDarkMode }) => {
  const [confirmDelete, setConfirmDelete] = useState(false);
  const styles = SECTION_STYLES[task.section];
  const cardBg = isDarkMode ? 'bg-[#211b3d]' : 'bg-white';
  const borderCol = isDarkMode ? 'border-slate-800' : 'border-slate-100';

  const isReview = !!task.originalTaskId || task.reviewIteration !== undefined;
  const isHighPriority = task.isFSRSActive;
  const isCARS = task.section === 'CARS';

  const handleDelete = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (confirmDelete) {
      onDelete(task);
    } else {
      setConfirmDelete(true);
      setTimeout(() => setConfirmDelete(false), 3000);
    }
  };

  return (
    <div
      draggable
      onDragStart={(e) => onDragStart(e, task.id)}
      onClick={() => !confirmDelete && onEdit(task)}
      onMouseLeave={() => setConfirmDelete(false)}
      className={`group relative p-3.5 mb-2.5 ${cardBg} rounded-2xl border ${borderCol} shadow-xl transition-all cursor-grab active:cursor-grabbing hover:border-[#8b5cf6]/50 ${
        task.completed && !task.masteryRating && !isCARS ? 'ring-2 ring-yellow-400/30' : ''
      } ${isHighPriority ? 'ring-2 ring-rose-500/50 shadow-[0_0_20px_rgba(244,63,94,0.1)]' : ''}`}
    >
      {/* Restore Delete Icon with High Visibility */}
      <div className="absolute top-2.5 right-2.5 z-[60] flex items-center gap-1.5 pointer-events-auto">
        {confirmDelete && (
          <span className="text-[9px] font-black text-rose-500 uppercase tracking-tighter animate-pulse">Confirm?</span>
        )}
        <button
          onClick={handleDelete}
          className={`flex items-center justify-center transition-all border shadow-lg rounded-lg ${
            confirmDelete 
              ? 'w-10 h-7 bg-rose-600 text-white border-rose-700 scale-110' 
              : `${isDarkMode ? 'bg-[#1a1630] border-slate-800' : 'bg-slate-50 border-slate-200'} text-rose-500 md:opacity-0 md:group-hover:opacity-100`
          }`}
          title={confirmDelete ? "Click again to delete" : "Delete Task"}
        >
          {confirmDelete ? (
            <span className="text-[10px] font-black">YES</span>
          ) : (
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
              <polyline points="3 6 5 6 21 6"></polyline>
              <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
            </svg>
          )}
        </button>
      </div>

      <div className="flex gap-3 items-start pr-8">
        <button
          onClick={(e) => { e.stopPropagation(); onToggle(task.id); }}
          className={`shrink-0 w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${
            task.completed 
              ? `${isDarkMode ? 'bg-[#8b5cf6] border-[#8b5cf6]' : 'bg-[#3b5bdb] border-[#3b5bdb]'}` 
              : `${isDarkMode ? 'bg-[#1a1630] border-slate-700' : 'bg-white border-slate-200'}`
          }`}
        >
          {task.completed && <svg width="12" height="9" viewBox="0 0 14 11" fill="none"><path d="M1 6L5 9.5L13 1" stroke="white" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>}
        </button>

        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-1.5 mb-1 flex-wrap">
            {isReview && (
              <span className="px-1.5 py-0.5 rounded-md bg-purple-500/20 text-purple-400 text-[7px] font-black uppercase tracking-tighter flex items-center gap-1">
                {task.reviewIteration ? `Review #${task.reviewIteration}` : 'Spaced Rep'}
              </span>
            )}
            {isHighPriority && (
              <span className="px-1.5 py-0.5 rounded-md bg-rose-500/20 text-rose-400 text-[7px] font-black uppercase tracking-tighter">Intensive</span>
            )}
          </div>

          <h4 className={`font-black text-[13px] leading-tight ${task.completed ? 'line-through opacity-40' : ''}`}>
            {task.title}
          </h4>

          {!task.completed && (
            <div className="mt-2 flex items-center gap-2">
              <span className={`px-1.5 py-0.5 rounded-lg text-[8px] font-black tracking-widest uppercase ${styles.bg} ${styles.text}`}>
                {styles.label}
              </span>
              <span className="text-slate-500 text-[8px] font-bold">{task.duration}</span>
            </div>
          )}

          {task.completed && !task.masteryRating && !isCARS && (
            <div className="mt-3 flex flex-col gap-2 p-2 bg-black/10 rounded-xl" onClick={e => e.stopPropagation()}>
              <p className="text-[9px] font-black text-slate-400 uppercase text-center mb-1">Self-Assessment</p>
              <div className="grid grid-cols-4 gap-1">
                {(['Again', 'Hard', 'Good', 'Easy'] as MasteryRating[]).map(r => (
                  <button
                    key={r}
                    onClick={() => onRate(task.id, r)}
                    className={`py-1 rounded-lg text-[7px] font-black uppercase transition-all hover:scale-105 ${
                      r === 'Again' ? 'bg-rose-500 text-white' : 
                      r === 'Hard' ? 'bg-orange-500 text-white' : 
                      r === 'Good' ? 'bg-blue-500 text-white' : 
                      'bg-emerald-500 text-white'
                    }`}
                  >
                    {r}
                  </button>
                ))}
              </div>
            </div>
          )}

          {task.masteryRating && !isCARS && (
            <div className="mt-2">
               <span className={`text-[8px] font-black uppercase ${
                  task.masteryRating === 'Again' ? 'text-rose-400' : 
                  task.masteryRating === 'Hard' ? 'text-orange-400' : 
                  task.masteryRating === 'Good' ? 'text-blue-400' : 
                  'text-emerald-400'
                }`}>
                {task.masteryRating} Mastery
              </span>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default TaskCard;

import React, { useState, useEffect, useMemo } from 'react';
import DayColumn from './components/DayColumn';
import EditTaskModal from './components/EditTaskModal';
import { StudyTask, ViewType, MasteryRating } from './types';
import { INITIAL_TASKS, formatDateKey, DAYS_SHORT, SECTION_STYLES } from './constants';
import { adaptSchedule } from './services/geminiService';

const STORAGE_KEY = 'lock-tf-in-v3-sr';
const THEME_KEY = 'lock-tf-in-theme';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed)) return parsed;
      } catch (e) {
        console.error("Failed to load tasks from storage", e);
      }
    }
    return INITIAL_TASKS;
  });

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    const saved = localStorage.getItem(THEME_KEY);
    return saved !== null ? saved === 'true' : true;
  });

  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');
  const [view, setView] = useState<ViewType>('weekly');
  const [baseDate, setBaseDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tasks));
  }, [tasks]);

  useEffect(() => {
    localStorage.setItem(THEME_KEY, String(isDarkMode));
    document.body.style.backgroundColor = isDarkMode ? '#090712' : '#f8fafc';
    document.body.style.color = isDarkMode ? '#f1f5f9' : '#1e293b';
  }, [isDarkMode]);

  const toggleTask = (id: string) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed, masteryRating: undefined } : t));
  };

  const handleRateTask = (id: string, rating: MasteryRating) => {
    setTasks(prev => {
      const task = prev.find(t => t.id === id);
      if (!task || task.section === 'CARS') return prev;

      let newTasks = prev.map(t => t.id === id ? { ...t, masteryRating: rating, completed: true } : t);

      if (rating === 'Again') {
        const tomorrow = new Date(task.date);
        tomorrow.setDate(tomorrow.getDate() + 1);
        newTasks.push({
          ...task,
          id: Math.random().toString(36).substr(2, 9),
          title: `Blitz: ${task.title}`,
          date: formatDateKey(tomorrow),
          completed: false,
          masteryRating: undefined,
          isFSRSActive: true
        });
      } else if (rating === 'Hard') {
        const soon = new Date(task.date);
        soon.setDate(soon.getDate() + 2);
        newTasks.push({
          ...task,
          id: Math.random().toString(36).substr(2, 9),
          title: `Extra Review: ${task.title}`,
          date: formatDateKey(soon),
          completed: false,
          masteryRating: undefined,
          isFSRSActive: true
        });
      } else if (rating === 'Easy') {
        const rootId = task.originalTaskId || task.id;
        newTasks = newTasks.filter(t => !(t.originalTaskId === rootId && !t.completed));
      }

      return newTasks;
    });
  };

  const saveTask = (task: StudyTask, scope: 'single' | 'future' = 'single') => {
    const isChapter = task.title.toLowerCase().includes('chapter') && task.section !== 'CARS';

    if (task.id) {
      if (scope === 'future' && (task.groupId || task.originalTaskId)) {
        const linkId = task.groupId || task.originalTaskId;
        setTasks(prev => prev.map(t => {
          if ((t.groupId === linkId || t.originalTaskId === linkId) && t.date >= task.date) {
            return { ...t, title: task.title, section: task.section, duration: task.duration };
          }
          return t;
        }));
      } else {
        setTasks(prev => prev.map(t => t.id === task.id ? task : t));
      }
    } else {
      const newId = Math.random().toString(36).substr(2, 9);
      let sequence: StudyTask[] = [];

      if (isChapter) {
        const intervals = [0, 1, 3, 7, 12, 16];
        intervals.forEach((days, index) => {
          const d = new Date(task.date);
          d.setDate(d.getDate() + days);
          sequence.push({
            ...task,
            id: Math.random().toString(36).substr(2, 9),
            originalTaskId: newId,
            reviewIteration: index === 0 ? undefined : index,
            title: index === 0 ? task.title : `Review #${index}: ${task.title}`,
            date: formatDateKey(d),
            completed: false,
            recurrence: 'None'
          });
        });
      } else if (task.recurrence && task.recurrence !== 'None') {
        const groupId = Math.random().toString(36).substr(2, 9);
        let interval = 1;
        if (task.recurrence === 'Weekly') interval = 7;
        if (task.recurrence === 'Custom' && task.customInterval) interval = task.customInterval;

        for (let i = 0; i < 12; i++) {
          const d = new Date(task.date);
          d.setDate(d.getDate() + (i * interval));
          sequence.push({
            ...task,
            id: Math.random().toString(36).substr(2, 9),
            groupId,
            date: formatDateKey(d),
            completed: false
          });
        }
      } else {
        sequence.push({ ...task, id: newId });
      }

      setTasks(prev => [...prev, ...sequence]);
    }
  };

  const moveTask = (taskId: string, targetDate: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, date: targetDate } : t));
  };

  const deleteTask = (task: Partial<StudyTask>, scope: 'single' | 'future' = 'single') => {
    if (!task.id) return;
    setTasks(prev => {
      if (scope === 'future' && (task.groupId || task.originalTaskId)) {
        const linkId = task.groupId || task.originalTaskId;
        const taskDate = task.date || '';
        return prev.filter(t => !((t.groupId === linkId || t.originalTaskId === linkId) && t.date >= taskDate));
      }
      return prev.filter(t => t.id !== task.id);
    });
  };

  const handleDragStartTask = (e: React.DragEvent, id: string) => e.dataTransfer.setData('taskId', id);
  const handleEditTask = (task: StudyTask) => { setCurrentTaskToEdit(task); setIsModalOpen(true); };
  const handleAddTask = (dateKey: string) => { 
    setCurrentTaskToEdit({ date: dateKey, completed: false, title: '', description: '', section: 'Biology', duration: '1h' }); 
    setIsModalOpen(true); 
  };

  const navigate = (amount: number) => {
    const newDate = new Date(baseDate);
    if (view === 'daily') newDate.setDate(newDate.getDate() + amount);
    else if (view === 'weekly') newDate.setDate(newDate.getDate() + (amount * 7));
    else if (view === 'monthly') newDate.setMonth(newDate.getMonth() + amount);
    setBaseDate(newDate);
  };

  const currentRangeDays = useMemo(() => {
    if (view === 'daily') return [new Date(baseDate)];
    const start = new Date(baseDate);
    const day = start.getDay();
    const shift = day === 0 ? 6 : day - 1;
    start.setDate(start.getDate() - shift); 
    return Array.from({ length: 7 }).map((_, i) => {
      const d = new Date(start);
      d.setDate(d.getDate() + i);
      return d;
    });
  }, [view, baseDate]);

  const monthGrid = useMemo(() => {
    if (view !== 'monthly') return [];
    const start = new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
    const end = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0);
    const startDay = start.getDay();
    const padding = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < padding; i++) {
      const d = new Date(start);
      d.setDate(d.getDate() - (padding - i));
      days.push({ date: d, currentMonth: false });
    }
    for (let i = 1; i <= end.getDate(); i++) {
      days.push({ date: new Date(baseDate.getFullYear(), baseDate.getMonth(), i), currentMonth: true });
    }
    const totalSlots = days.length > 35 ? 42 : 35;
    const remaining = totalSlots - days.length;
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(end);
      d.setDate(d.getDate() + i);
      days.push({ date: d, currentMonth: false });
    }
    return days;
  }, [view, baseDate]);

  const handleAiUpdate = async () => {
    if (!userInput.trim()) return;
    setIsAiLoading(true);
    setAiMessage(null);
    try {
      const response = await adaptSchedule(tasks, userInput);
      setTasks(response.updatedTasks);
      setAiMessage(response.suggestion);
      setUserInput('');
    } catch (err) {
      setAiMessage("Sync failed.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const progressPercent = tasks.length > 0 ? Math.round((tasks.filter(t => t.completed).length / tasks.length) * 100) : 0;
  const bgColor = isDarkMode ? 'bg-[#090712]' : 'bg-[#f8fafc]';
  const surfaceBg = isDarkMode ? 'bg-[#16122b]' : 'bg-white';
  const borderCol = isDarkMode ? 'border-slate-800' : 'border-slate-100';

  return (
    <div className={`min-h-screen ${bgColor} ${isDarkMode ? 'text-slate-100' : 'text-slate-800'} pb-40 transition-colors duration-300`}>
      <header className="px-8 pt-8 max-w-[1800px] mx-auto flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="shrink-0">
          <h1 className="text-4xl font-black tracking-tighter flex items-center gap-2 italic">
            <span className={`${isDarkMode ? 'text-[#8b5cf6] drop-shadow-[0_0_15px_rgba(139,92,246,0.5)]' : 'text-[#3b5bdb]'}`}>LOCK</span> TF IN!
          </h1>
          <p className={`${isDarkMode ? 'text-slate-500' : 'text-slate-400'} font-bold text-xs tracking-[0.3em] mt-1 uppercase`}>Adaptive Learning Active</p>
        </div>

        <div className={`flex flex-wrap items-center justify-center gap-4 ${surfaceBg} p-2 rounded-[28px] shadow-2xl border ${borderCol}`}>
           <div className={`flex ${isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-50'} p-1 rounded-2xl`}>
             {(['daily', 'weekly', 'monthly'] as ViewType[]).map(v => (
               <button key={v} onClick={() => setView(v)} className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${view === v ? `${isDarkMode ? 'bg-[#16122b]' : 'bg-white'} ${isDarkMode ? 'text-[#8b5cf6]' : 'text-[#3b5bdb]'} shadow-lg border ${isDarkMode ? 'border-slate-700' : 'border-slate-100'}` : `text-slate-400 hover:${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}`}>
                 {v}
               </button>
             ))}
           </div>
           <div className="flex items-center gap-2 px-2">
             <button onClick={() => navigate(-1)} className="p-2 hover:opacity-50 transition-opacity">
               <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M15 18l-6-6 6-6"/></svg>
             </button>
             <button onClick={() => setBaseDate(new Date())} className={`px-3 py-1 text-xs font-black ${isDarkMode ? 'text-[#8b5cf6]' : 'text-[#3b5bdb]'}`}>Today</button>
             <button onClick={() => navigate(1)} className="p-2 hover:opacity-50 transition-opacity">
               <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M9 18l6-6-6-6"/></svg>
             </button>
           </div>
           <button onClick={() => setIsDarkMode(!isDarkMode)} className={`p-2 rounded-xl transition-all ${isDarkMode ? 'bg-[#1a1630] text-yellow-400' : 'bg-slate-50 text-indigo-600'}`}>
             {isDarkMode ? <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="12" cy="12" r="5"></circle><line x1="12" y1="1" x2="12" y2="3"></line><line x1="12" y1="21" x2="12" y2="23"></line></svg> : <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"></path></svg>}
           </button>
        </div>

        <div className={`w-full sm:w-auto md:max-w-md ${surfaceBg} rounded-3xl p-2 shadow-2xl border ${borderCol} flex items-center gap-2`}>
          <input type="text" value={userInput} onChange={(e) => setUserInput(e.target.value)} placeholder="Sync with AI Coach..." className={`flex-1 bg-transparent border-none px-4 py-2 font-semibold text-sm focus:ring-0 outline-none ${isDarkMode ? 'text-slate-100' : 'text-slate-800'}`} />
          <button onClick={handleAiUpdate} disabled={isAiLoading} className={`${isDarkMode ? 'bg-[#8b5cf6]' : 'bg-[#3b5bdb]'} text-white px-6 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest hover:opacity-90 disabled:opacity-50 shadow-lg`}>
            {isAiLoading ? '...' : 'SYNC'}
          </button>
        </div>
      </header>

      <main className="mt-12 px-8 max-w-[1800px] mx-auto overflow-visible">
        <div className={`grid ${view === 'daily' ? 'grid-cols-1 justify-items-center' : view === 'monthly' ? 'grid-cols-1' : 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-6'}`}>
          {view === 'monthly' ? (
            <div className={`${surfaceBg} rounded-[40px] shadow-2xl border ${borderCol} overflow-hidden w-full`}>
               <div className={`grid grid-cols-7 border-b ${borderCol} ${isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-50'}`}>
                {DAYS_SHORT.map(d => <div key={d} className="py-4 text-center text-[10px] font-black text-slate-500 uppercase tracking-widest">{d}</div>)}
              </div>
              <div className="grid grid-cols-7">
                {monthGrid.map(({ date, currentMonth }, i) => {
                  const dateKey = formatDateKey(date);
                  const dayTasks = tasks.filter(t => t.date === dateKey);
                  return (
                    <div key={i} onClick={() => { setBaseDate(new Date(date)); setView('daily'); }} className={`min-h-[120px] p-2 border-r border-b ${borderCol} cursor-pointer hover:${isDarkMode ? 'bg-[#1a1630]' : 'bg-slate-50'} ${!currentMonth ? 'opacity-20' : ''}`}>
                      <span className="text-[11px] font-black text-slate-500">{date.getDate()}</span>
                      <div className="flex flex-col gap-1 mt-1">
                        {dayTasks.slice(0, 2).map(t => <div key={t.id} className={`px-1.5 py-0.5 rounded text-[7px] font-bold truncate ${SECTION_STYLES[t.section].bg} ${SECTION_STYLES[t.section].text}`}>{t.title}</div>)}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          ) : (
            currentRangeDays.map((d, i) => (
              <DayColumn
                key={i}
                isDarkMode={isDarkMode}
                date={d}
                tasks={tasks.filter(t => t.date === formatDateKey(d))}
                onToggleTask={toggleTask}
                onRateTask={handleRateTask}
                onDropTask={moveTask}
                onDragStartTask={handleDragStartTask}
                onAddTask={handleAddTask}
                onEditTask={handleEditTask}
                onDeleteTask={deleteTask}
                isFocused={view === 'daily'}
              />
            ))
          )}
        </div>
      </main>

      <div className={`fixed bottom-10 left-1/2 -translate-x-1/2 ${isDarkMode ? 'bg-[#16122b]/80' : 'bg-white/80'} backdrop-blur-2xl px-10 py-5 rounded-[40px] shadow-2xl border ${borderCol} flex items-center gap-8 z-50`}>
        <div className="flex flex-col">
          <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Mastery</span>
          <span className={`text-xl font-black ${isDarkMode ? 'text-[#8b5cf6]' : 'text-[#3b5bdb]'}`}>{progressPercent}%</span>
        </div>
        <div className={`w-48 sm:w-64 h-3 ${isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-100'} rounded-full overflow-hidden border ${borderCol}`}>
          <div className={`h-full bg-gradient-to-r ${isDarkMode ? 'from-[#8b5cf6] to-[#d946ef]' : 'from-[#3b5bdb] to-[#5c7cff]'} transition-all duration-1000`} style={{ width: `${progressPercent}%` }} />
        </div>
      </div>

      <EditTaskModal isDarkMode={isDarkMode} isOpen={isModalOpen} task={currentTaskToEdit} onClose={() => setIsModalOpen(false)} onSave={saveTask} onDelete={deleteTask} />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { StudyTask, MCATSection, RecurrenceType } from '../types';
import { SECTION_STYLES } from '../constants';

interface EditTaskModalProps {
  task: Partial<StudyTask> | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: StudyTask, scope?: 'single' | 'future') => void;
  onDelete?: (task: Partial<StudyTask>, scope?: 'single' | 'future') => void;
  isDarkMode: boolean;
}

const EditTaskModal: React.FC<EditTaskModalProps> = ({ task, isOpen, onClose, onSave, onDelete, isDarkMode }) => {
  const [title, setTitle] = useState('');
  const [section, setSection] = useState<MCATSection>('Biology');
  const [duration, setDuration] = useState('');
  const [date, setDate] = useState('');
  const [recurrence, setRecurrence] = useState<RecurrenceType>('None');
  const [customInterval, setCustomInterval] = useState(2);
  const [saveScope, setSaveScope] = useState<'single' | 'future'>('single');
  const [confirmDelete, setConfirmDelete] = useState(false);

  useEffect(() => {
    if (task && isOpen) {
      setTitle(task.title || '');
      setSection(task.section || 'Biology');
      setDuration(task.duration || '');
      setDate(task.date || '');
      setRecurrence(task.recurrence || 'None');
      setCustomInterval(task.customInterval || 2);
      setSaveScope('single');
      setConfirmDelete(false);
    }
  }, [task, isOpen]);

  if (!isOpen || !task) return null;

  const isChapter = title.toLowerCase().includes('chapter') && section !== 'CARS';
  const isRecurringInstance = !!task.groupId || !!task.originalTaskId;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({ 
      ...task, 
      title, 
      section, 
      duration, 
      date, 
      recurrence, 
      customInterval: recurrence === 'Custom' ? customInterval : undefined 
    } as StudyTask, saveScope);
    onClose();
  };

  const surfaceBg = isDarkMode ? 'bg-[#16122b]' : 'bg-white';
  const inputBg = isDarkMode ? 'bg-[#0d0b1a]' : 'bg-slate-50';
  const borderCol = isDarkMode ? 'border-slate-800' : 'border-slate-100';
  const textColor = isDarkMode ? 'text-slate-100' : 'text-slate-800';
  const subTextColor = isDarkMode ? 'text-slate-500' : 'text-slate-400';

  return (
    <div className={`fixed inset-0 z-[100] flex items-center justify-center p-4 ${isDarkMode ? 'bg-black/80' : 'bg-slate-900/40'} backdrop-blur-md animate-in fade-in`}>
      <div className={`${surfaceBg} w-full max-w-md rounded-[32px] p-8 shadow-2xl border ${borderCol} max-h-[90vh] overflow-y-auto`} onClick={e => e.stopPropagation()}>
        <div className="flex justify-between items-center mb-6">
          <h2 className={`text-2xl font-black ${textColor}`}>Objective Details</h2>
          <button onClick={onClose} className={`${subTextColor} hover:text-white transition-colors`}><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest mb-2`}>Objective Title</label>
            <input
              autoFocus required type="text" value={title} onChange={(e) => setTitle(e.target.value)}
              className={`w-full ${inputBg} border-2 ${borderCol} rounded-2xl px-4 py-3 font-bold ${textColor} outline-none focus:border-[#8b5cf6]`}
              placeholder="e.g. Biology Chapter 4"
            />
            {isChapter && !task.id && (
              <p className="mt-2 text-[10px] font-black text-purple-400 uppercase tracking-tight flex items-center gap-1">
                <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4M4.93 19.07l2.83-2.83M16.24 7.76l2.83-2.83"/></svg>
                Spaced Repetition Auto-Sequence Enabled
              </p>
            )}
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest mb-2`}>Launch Date</label>
              <input required type="date" value={date} onChange={(e) => setDate(e.target.value)} className={`w-full ${inputBg} border-2 ${borderCol} rounded-2xl px-4 py-3 font-bold ${textColor} outline-none focus:border-[#8b5cf6]`} />
            </div>
            <div>
              <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest mb-2`}>Duration</label>
              <input required type="text" value={duration} onChange={(e) => setDuration(e.target.value)} className={`w-full ${inputBg} border-2 ${borderCol} rounded-2xl px-4 py-3 font-bold ${textColor} outline-none focus:border-[#8b5cf6]`} placeholder="e.g. 2h" />
            </div>
          </div>

          <div>
            <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest mb-2`}>Sector</label>
            <select value={section} onChange={(e) => setSection(e.target.value as MCATSection)} className={`w-full ${inputBg} border-2 ${borderCol} rounded-2xl px-4 py-3 font-bold ${textColor} outline-none focus:border-[#8b5cf6]`}>
              {Object.keys(SECTION_STYLES).map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>

          {/* Recurrence Section - Always show for new tasks to avoid confusion */}
          {!task.id && (
            <div className="space-y-4">
              <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest`}>Auto-Recurrence</label>
              <div className="grid grid-cols-2 gap-2">
                {(['None', 'Daily', 'Weekly', 'Custom'] as RecurrenceType[]).map((type) => (
                  <button
                    key={type}
                    type="button"
                    onClick={() => setRecurrence(type)}
                    className={`py-3 rounded-xl font-bold text-xs transition-all border-2 ${
                      recurrence === type 
                        ? 'bg-[#8b5cf6] text-white border-transparent shadow-lg' 
                        : `${inputBg} ${subTextColor} ${borderCol} hover:border-slate-700`
                    }`}
                  >
                    {type}
                  </button>
                ))}
              </div>
              {recurrence === 'Custom' && (
                <div className="animate-in slide-in-from-top-2">
                  <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest mb-2`}>Repeat every X days</label>
                  <input
                    type="number"
                    min="1"
                    value={customInterval}
                    onChange={(e) => setCustomInterval(parseInt(e.target.value) || 1)}
                    className={`w-full ${inputBg} border-2 ${borderCol} rounded-2xl px-4 py-3 font-bold ${textColor} outline-none focus:border-[#8b5cf6]`}
                  />
                </div>
              )}
            </div>
          )}

          {/* Update Scope for existing recurring/SR tasks */}
          {task.id && isRecurringInstance && (
            <div className={`${inputBg} p-4 rounded-2xl border ${borderCol} space-y-3`}>
              <label className={`block text-[10px] font-black ${subTextColor} uppercase tracking-widest text-center`}>Update Scope</label>
              <div className="flex gap-2">
                <button
                  type="button"
                  onClick={() => setSaveScope('single')}
                  className={`flex-1 py-2.5 rounded-xl font-black text-[10px] uppercase transition-all border-2 ${
                    saveScope === 'single' ? 'bg-[#8b5cf6]/20 border-[#8b5cf6] text-[#8b5cf6]' : `bg-transparent ${borderCol} ${subTextColor}`
                  }`}
                >
                  Instance
                </button>
                <button
                  type="button"
                  onClick={() => setSaveScope('future')}
                  className={`flex-1 py-2.5 rounded-xl font-black text-[10px] uppercase transition-all border-2 ${
                    saveScope === 'future' ? 'bg-[#8b5cf6]/20 border-[#8b5cf6] text-[#8b5cf6]' : `bg-transparent ${borderCol} ${subTextColor}`
                  }`}
                >
                  Sequence
                </button>
              </div>
            </div>
          )}

          <div className="pt-4 flex gap-3">
            <button type="submit" className="flex-1 bg-[#8b5cf6] text-white py-4 rounded-2xl font-black uppercase tracking-widest hover:opacity-90 shadow-lg transition-all active:scale-95">
              {task.id ? 'Save Changes' : isChapter ? 'Launch Sequence' : 'Create Mission'}
            </button>
            {task.id && (
              <button 
                type="button" 
                onClick={() => { if(confirmDelete && onDelete) { onDelete(task, saveScope); onClose(); } else setConfirmDelete(true); }} 
                className={`w-14 transition-all rounded-2xl flex items-center justify-center border active:scale-95 ${confirmDelete ? 'bg-rose-600 border-rose-600 text-white' : `${inputBg} border-slate-800 text-rose-500`}`}
              >
                {confirmDelete ? <span className="text-[10px] font-black uppercase">Sure?</span> : <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>}
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default EditTaskModal;

import React, { useState, useEffect, useMemo } from 'react';
import DayColumn from './components/DayColumn';
import EditTaskModal from './components/EditTaskModal';
import { StudyTask, ViewType, MasteryRating } from './types';
import { INITIAL_TASKS, formatDateKey, DAYS_SHORT, SECTION_STYLES } from './constants';
import { adaptSchedule } from './services/geminiService';

const STORAGE_KEY = 'lock-tf-in-v3-sr';
const THEME_KEY = 'lock-tf-in-theme';

// Helper to parse "YYYY-MM-DD" into a local Date object safely
const parseSafeDate = (dateStr: string) => {
  const [y, m, d] = dateStr.split('-').map(Number);
  return new Date(y, m - 1, d);
};

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed)) return parsed;
      } catch (e) {
        console.error("Failed to load tasks from storage", e);
      }
    }
    return INITIAL_TASKS;
  });

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    const saved = localStorage.getItem(THEME_KEY);
    return saved !== null ? saved === 'true' : true;
  });

  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');
  const [view, setView] = useState<ViewType>('weekly');
  const [baseDate, setBaseDate] = useState(new Date());

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentTaskToEdit, setCurrentTaskToEdit] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tasks));
  }, [tasks]);

  useEffect(() => {
    localStorage.setItem(THEME_KEY, String(isDarkMode));
    document.body.style.backgroundColor = isDarkMode ? '#090712' : '#f8fafc';
    document.body.style.color = isDarkMode ? '#f1f5f9' : '#1e293b';
  }, [isDarkMode]);

  const toggleTask = (id: string) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed, masteryRating: undefined } : t));
  };

  const handleRateTask = (id: string, rating: MasteryRating) => {
    setTasks(prev => {
      const task = prev.find(t => t.id === id);
      if (!task || task.section === 'CARS') return prev;

      let newTasks = prev.map(t => t.id === id ? { ...t, masteryRating: rating, completed: true } : t);

      if (rating === 'Again') {
        const dObj = parseSafeDate(task.date);
        dObj.setDate(dObj.getDate() + 1);
        newTasks.push({
          ...task,
          id: Math.random().toString(36).substr(2, 9),
          title: `Blitz: ${task.title}`,
          date: formatDateKey(dObj),
          completed: false,
          masteryRating: undefined,
          isFSRSActive: true
        });
      } else if (rating === 'Hard') {
        const dObj = parseSafeDate(task.date);
        dObj.setDate(dObj.getDate() + 2);
        newTasks.push({
          ...task,
          id: Math.random().toString(36).substr(2, 9),
          title: `Extra Review: ${task.title}`,
          date: formatDateKey(dObj),
          completed: false,
          masteryRating: undefined,
          isFSRSActive: true
        });
      } else if (rating === 'Easy') {
        const rootId = task.originalTaskId || task.id;
        newTasks = newTasks.filter(t => !(t.originalTaskId === rootId && !t.completed));
      }

      return newTasks;
    });
  };

  const saveTask = (task: StudyTask, scope: 'single' | 'future' = 'single') => {
    const isChapter = task.title.toLowerCase().includes('chapter') && task.section !== 'CARS';

    if (task.id) {
      if (scope === 'future' && (task.groupId || task.originalTaskId)) {
        const linkId = task.groupId || task.originalTaskId;
        setTasks(prev => prev.map(t => {
          if ((t.groupId === linkId || t.originalTaskId === linkId) && t.date >= task.date) {
            return { ...t, title: task.title, section: task.section, duration: task.duration };
          }
          return t;
        }));
      } else {
        setTasks(prev => prev.map(t => t.id === task.id ? task : t));
      }
    } else {
      const newId = Math.random().toString(36).substr(2, 9);
      let sequence: StudyTask[] = [];

      if (isChapter) {
        const intervals = [0, 1, 3, 7, 12, 16];
        intervals.forEach((days, index) => {
          const d = parseSafeDate(task.date);
          d.setDate(d.getDate() + days);
          sequence.push({
            ...task,
            id: Math.random().toString(36).substr(2, 9),
            originalTaskId: newId,
            reviewIteration: index === 0 ? undefined : index,
            title: index === 0 ? task.title : `Review #${index}: ${task.title}`,
            date: formatDateKey(d),
            completed: false,
            recurrence: 'None'
          });
        });
      } else if (task.recurrence && task.recurrence !== 'None') {
        const groupId = Math.random().toString(36).substr(2, 9);
        let interval = 1;
        if (task.recurrence === 'Weekly') interval = 7;
        if (task.recurrence === 'Custom' && task.customInterval) interval = task.customInterval;

        for (let i = 0; i < 12; i++) {
          const d = parseSafeDate(task.date);
          d.setDate(d.getDate() + (i * interval));
          sequence.push({
            ...task,
            id: Math.random().toString(36).substr(2, 9),
            groupId,
            date: formatDateKey(d),
            completed: false
          });
        }
      } else {
        sequence.push({ ...task, id: newId });
      }

      setTasks(prev => [...prev, ...sequence]);
    }
  };

  const moveTask = (taskId: string, targetDate: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, date: targetDate } : t));
  };

  const deleteTask = (task: Partial<StudyTask>, scope: 'single' | 'future' = 'single') => {
    if (!task.id) return;
    setTasks(prev => {
      if (scope === 'future' && (task.groupId || task.originalTaskId)) {
        const linkId = task.groupId || task.originalTaskId;
        return prev.filter(t => !((t.groupId === linkId || t.originalTaskId === linkId) && t.date >= (task.date || '')));
      }
      return prev.filter(t => t.id !== task.id);
    });
  };

  const handleDragStartTask = (e: React.DragEvent, id: string) => e.dataTransfer.setData('taskId', id);
  const handleEditTask = (task: StudyTask) => { setCurrentTaskToEdit(task); setIsModalOpen(true); };
  const handleAddTask = (dateKey: string) => { 
    setCurrentTaskToEdit({ date: dateKey, completed: false, title: '', description: '', section: 'Biology', duration: '1h' }); 
    setIsModalOpen(true); 
  };

  const navigate = (amount: number) => {
    const newDate = new Date(baseDate);
    if (view === 'daily') newDate.setDate(newDate.getDate() + amount);
    else if (view === 'weekly') newDate.setDate(newDate.getDate() + (amount * 7));
    else if (view === 'monthly') newDate.setMonth(newDate.getMonth() + amount);
    setBaseDate(newDate);
  };

  const currentRangeDays = useMemo(() => {
    if (view === 'daily') return [new Date(baseDate)];
    const start = new Date(baseDate);
    const day = start.getDay();
    const shift = day === 0 ? 6 : day - 1;
    start.setDate(start.getDate() - shift); 
    return Array.from({ length: 7 }).map((_, i) => {
      const d = new Date(start);
      d.setDate(d.getDate() + i);
      return d;
    });
  }, [view, baseDate]);

  const monthGrid = useMemo(() => {
    if (view !== 'monthly') return [];
    const start = new Date(baseDate.getFullYear(), baseDate.getMonth(), 1);
    const end = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0);
    const startDay = start.getDay();
    const padding = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < padding; i++) {
      const d = new Date(start);
      d.setDate(d.getDate() - (padding - i));
      days.push({ date: d, currentMonth: false });
    }
    for (let i = 1; i <= end.getDate(); i++) {
      days.push({ date: new Date(baseDate.getFullYear(), baseDate.getMonth(), i), currentMonth: true });
    }
    const totalSlots = days.length > 35 ? 42 : 35;
    const remaining = totalSlots - days.length;
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(end);
      d.setDate(d.getDate() + i);
      days.push({ date: d, currentMonth: false });
    }
    return days;
  }, [view, baseDate]);

