    setTasks(prev => {
      const task = prev.find(t => t.id === id);
      if (!task) return prev;

      let newTasks = prev.map(t => t.id === id ? { ...t, masteryRating: rating, completed: true } : t);

      if (rating === 'Again') {
        const dObj = parseSafeDate(task.date);
        dObj.setDate(dObj.getDate() + 1);
