      }
    } else {
      const isChapter = task.title.toLowerCase().includes('chapter') && task.section !== 'CARS';
      const newId = Math.random().toString(36).substring(2, 11);
      let sequence: StudyTask[] = [];

      if (isChapter) {
        const intervals = [0, 1, 3, 7, 12, 16];
        intervals.forEach((days, index) => {
          const d = parseSafeDate(task.date);
          d.setDate(d.getDate() + days);
          sequence.push({
            ...task,
            id: Math.random().toString(36).substring(2, 11),
            originalTaskId: newId,
            reviewIteration: index === 0 ? undefined : index,
            title: index === 0 ? task.title : `Review #${index}: ${task.title}`,
            date: formatDateKey(d),
            completed: false,
            recurrence: 'None'
          });
        });
      } else if (task.recurrence && task.recurrence !== 'None') {
        const groupId = Math.random().toString(36).substring(2, 11);
        let interval = task.recurrence === 'Weekly' ? 7 : (task.recurrence === 'Daily' ? 1 : (task.customInterval || 1));
        for (let i = 0; i < 10; i++) {
          const d = parseSafeDate(task.date);
          d.setDate(d.getDate() + (i * interval));
          sequence.push({ ...task, id: Math.random().toString(36).substring(2, 11), groupId, date: formatDateKey(d), completed: false });
        }
      } else {
        sequence.push({ ...task, id: newId });
      }
      setTasks(prev => [...prev, ...sequence]);
    }
  };

