              <DayColumn
                key={i}
                isDarkMode={isDarkMode}
                date={d}
                tasks={tasks.filter(t => t.date === formatDateKey(d))}
                onToggleTask={toggleTask}
                onRateTask={handleRateTask}
                onDropTask={moveTask}
                onDragStartTask={handleDragStartTask}
                onAddTask={(dk) => { setCurrentTaskToEdit({ date: dk, completed: false, section: 'Biology' }); setIsModalOpen(true); }}
                onEditTask={(t) => { setCurrentTaskToEdit(t); setIsModalOpen(true); }}
                onDeleteTask={deleteTask}
