      <div className={`fixed bottom-10 left-1/2 -translate-x-1/2 ${isDarkMode ? 'bg-[#16122b]/80' : 'bg-white/80'} backdrop-blur-2xl px-10 py-5 rounded-[40px] shadow-2xl border ${borderCol} flex items-center gap-8 z-50`}>
