import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { GoogleGenAI, Type } from "@google/genai";

// --- TYPES ---
export type MCATSection = 
  | 'Biology' | 'Biochemistry' | 'General Chemistry' | 'Organic Chemistry' 
  | 'Physics' | 'Behavioral Sciences' | 'CARS' | 'Practice Exam';

export type RecurrenceType = 'None' | 'Daily' | 'Weekly' | 'Custom' | 'SpacedRepetition';
export type ViewType = 'daily' | 'weekly' | 'monthly';
export type MasteryRating = 'Again' | 'Hard' | 'Good' | 'Easy';

export interface StudyTask {
  id: string;
  groupId?: string;
  originalTaskId?: string;
  reviewIteration?: number;
  title: string;
  description: string;
  section: MCATSection;
  completed: boolean;
  date: string;
  duration: string;
  recurrence?: RecurrenceType;
  customInterval?: number;
  masteryRating?: MasteryRating;
  isFSRSActive?: boolean;
}

// --- CONSTANTS ---
export const SECTION_STYLES: Record<MCATSection, { bg: string, text: string, label: string, dot: string }> = {
  'Biology': { bg: 'bg-emerald-100', text: 'text-emerald-700', label: 'BIOLOGY', dot: 'bg-emerald-500' },
  'Biochemistry': { bg: 'bg-teal-100', text: 'text-teal-700', label: 'BIOCHEMISTRY', dot: 'bg-teal-500' },
  'General Chemistry': { bg: 'bg-blue-100', text: 'text-blue-700', label: 'GEN CHEM', dot: 'bg-blue-500' },
  'Organic Chemistry': { bg: 'bg-indigo-100', text: 'text-indigo-700', label: 'ORG CHEM', dot: 'bg-indigo-500' },
  'Physics': { bg: 'bg-purple-100', text: 'text-purple-700', label: 'PHYSICS', dot: 'bg-purple-500' },
  'Behavioral Sciences': { bg: 'bg-rose-100', text: 'text-rose-700', label: 'BEHAVIORAL', dot: 'bg-rose-500' },
  'CARS': { bg: 'bg-orange-100', text: 'text-orange-700', label: 'CARS', dot: 'bg-orange-500' },
  'Practice Exam': { bg: 'bg-slate-800', text: 'text-white', label: 'PRACTICE', dot: 'bg-slate-800' },
};

export const DAYS_SHORT = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

export const formatDateKey = (date: Date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const INITIAL_TASKS: StudyTask[] = [
  { id: '1', title: 'Amino Acids Review', description: 'Side chains and pKa', section: 'Biochemistry', completed: false, date: formatDateKey(new Date()), duration: '2h' },
  { id: '2', title: 'Enzyme Kinetics', description: 'Michaelis-Menten plots', section: 'Biology', completed: false, date: formatDateKey(new Date()), duration: '1h' },
];

// --- AI SERVICE ---
async function adaptSchedule(currentTasks: StudyTask[], userGoals: string): Promise<{ suggestion: string, updatedTasks: StudyTask[] }> {
  const apiKey = (process.env as any).API_KEY;
  if (!apiKey) return { suggestion: "API Key missing.", updatedTasks: currentTasks };

  const ai = new GoogleGenAI({ apiKey });
  const model = 'gemini-3-flash-preview';

  const prompt = `Act as an MCAT Study Coach. 
  Schedule: ${JSON.stringify(currentTasks)}
  User Input: ${userGoals}
  Balanced workload, max 4-5 tasks/day. Format date: YYYY-MM-DD.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suggestion: { type: Type.STRING },
            updatedTasks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  section: { type: Type.STRING },
                  completed: { type: Type.BOOLEAN },
                  date: { type: Type.STRING },
                  duration: { type: Type.STRING }
                },
                required: ["id", "title", "section", "completed", "date", "duration"]
              }
            }
          },
          required: ["suggestion", "updatedTasks"]
        }
      }
    });
    return JSON.parse(response.text);
  } catch (e) {
    return { suggestion: "Sync failed.", updatedTasks: currentTasks };
  }
}

// --- COMPONENTS ---
const TaskCard: React.FC<{
  task: StudyTask;
  onToggle: (id: string) => void;
  onRate: (id: string, rating: MasteryRating) => void;
  onDragStart: (e: React.DragEvent, id: string) => void;
  onEdit: (task: StudyTask) => void;
  onDelete: (task: StudyTask) => void;
  isDarkMode: boolean;
}> = ({ task, onToggle, onRate, onDragStart, onEdit, onDelete, isDarkMode }) => {
  const [confirmDelete, setConfirmDelete] = useState(false);
  const styles = SECTION_STYLES[task.section];

  return (
    <div
      draggable
      onDragStart={(e) => onDragStart(e, task.id)}
      onClick={() => !confirmDelete && onEdit(task)}
      className={`group relative p-4 mb-3 rounded-2xl border transition-all cursor-grab active:cursor-grabbing ${
        isDarkMode ? 'bg-[#211b3d] border-slate-800' : 'bg-white border-slate-100 shadow-sm hover:shadow-md'
      } ${task.completed ? 'opacity-60' : ''}`}
    >
      <div className="flex gap-3 items-start">
