import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { GoogleGenAI, Type } from "@google/genai";

// --- TYPES ---
type MCATSection = 
  | 'Biology' | 'Biochemistry' | 'General Chemistry' | 'Organic Chemistry' 
  | 'Physics' | 'Behavioral Sciences' | 'CARS' | 'Practice Exam';

type RecurrenceType = 'None' | 'Daily' | 'Weekly' | 'Custom';
type ViewType = 'daily' | 'weekly' | 'monthly';
type MasteryRating = 'Again' | 'Hard' | 'Good' | 'Easy';

interface StudyTask {
  id: string;
  groupId?: string;
  originalTaskId?: string;
  reviewIteration?: number;
  title: string;
  description: string;
  section: MCATSection;
  completed: boolean;
  date: string; // YYYY-MM-DD
  duration: string;
  recurrence?: RecurrenceType;
  customInterval?: number;
  masteryRating?: MasteryRating;
}

// --- CONSTANTS ---
const SECTION_STYLES: Record<MCATSection, { bg: string, text: string, label: string }> = {
  'Biology': { bg: 'bg-emerald-100', text: 'text-emerald-700', label: 'BIO' },
  'Biochemistry': { bg: 'bg-teal-100', text: 'text-teal-700', label: 'BCM' },
  'General Chemistry': { bg: 'bg-blue-100', text: 'text-blue-700', label: 'CHM' },
  'Organic Chemistry': { bg: 'bg-indigo-100', text: 'text-indigo-700', label: 'ORG' },
  'Physics': { bg: 'bg-purple-100', text: 'text-purple-700', label: 'PHY' },
  'Behavioral Sciences': { bg: 'bg-rose-100', text: 'text-rose-700', label: 'BEH' },
  'CARS': { bg: 'bg-orange-100', text: 'text-orange-700', label: 'CARS' },
  'Practice Exam': { bg: 'bg-slate-800', text: 'text-white', label: 'EXAM' },
};

const formatDateKey = (date: Date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const INITIAL_TASKS: StudyTask[] = [
  { id: '1', title: 'Amino Acids: Structure & pKa', description: 'Review all 20 side chains', section: 'Biochemistry', completed: false, date: formatDateKey(new Date()), duration: '1.5h' },
  { id: '2', title: 'CARS Daily Practice', description: '3 passages from Jack Westin', section: 'CARS', completed: true, date: formatDateKey(new Date()), duration: '1h' },
];

// --- AI SERVICE ---
async function adaptSchedule(currentTasks: StudyTask[], userGoals: string): Promise<{ suggestion: string, updatedTasks: StudyTask[] }> {
  const apiKey = (process.env as any).API_KEY;
  if (!apiKey) return { suggestion: "API Key missing.", updatedTasks: currentTasks };

  const ai = new GoogleGenAI({ apiKey });
  const model = 'gemini-3-flash-preview';

  const prompt = `Act as an expert MCAT Study Coach. 
  Context: ${JSON.stringify(currentTasks)}
  User Query: ${userGoals}
  Rules:
  1. Move unfinished tasks to tomorrow if the user is behind.
  2. Add relevant high-yield topics if they ask for more work.
  3. Keep daily load under 5 tasks.
  4. Response MUST be valid JSON.
  5. Date format YYYY-MM-DD.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suggestion: { type: Type.STRING },
            updatedTasks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  section: { type: Type.STRING },
                  completed: { type: Type.BOOLEAN },
                  date: { type: Type.STRING },
                  duration: { type: Type.STRING }
                },
                required: ["id", "title", "section", "completed", "date", "duration"]
              }
            }
          },
          required: ["suggestion", "updatedTasks"]
        }
      }
    });
    return JSON.parse(response.text);
  } catch (e) {
    console.error(e);
    return { suggestion: "AI sync temporarily offline.", updatedTasks: currentTasks };
  }
}

