const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(() => {
    const saved = localStorage.getItem('mcat-planner-v3');
    return saved ? JSON.parse(saved) : INITIAL_TASKS;
  });
  const [userInput, setUserInput] = useState('');
  const [baseDate, setBaseDate] = useState(new Date());
  const [aiLoading, setAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editTask, setEditTask] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => { localStorage.setItem('mcat-planner-v3', JSON.stringify(tasks)); }, [tasks]);

  const currentRangeDays = useMemo(() => {
    const start = new Date(baseDate);
    const day = start.getDay();
    const shift = day === 0 ? 6 : day - 1;
    start.setDate(start.getDate() - shift);
    return Array.from({ length: 7 }).map((_, i) => {
      const d = new Date(start);
      d.setDate(d.getDate() + i);
      return d;
    });
  }, [baseDate]);

  const onSync = async () => {
    if (!userInput) return;
    setAiLoading(true);
    setAiMessage(null);
    const res = await adaptSchedule(tasks, userInput);
    setTasks(res.updatedTasks);
    setAiMessage(res.suggestion);
    setUserInput('');
    setAiLoading(false);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editTask) return;
    if (editTask.id) {
      setTasks(prev => prev.map(t => t.id === editTask.id ? { ...t, ...editTask } as StudyTask : t));
    } else {
      setTasks(prev => [...prev, { ...editTask, id: Math.random().toString(36).substr(2, 9), completed: false } as StudyTask]);
    }
    setIsModalOpen(false);
  };

  const progressPercent = tasks.length > 0 ? Math.round((tasks.filter(t => t.completed).length / tasks.length) * 100) : 0;

  return (
    <div className="min-h-screen bg-[#090712] text-white">
      {/* Header Section */}
      <header className="px-8 py-10 max-w-[1700px] mx-auto flex flex-col lg:flex-row items-center justify-between gap-10">
        <div>
          <h1 className="text-4xl md:text-5xl font-black italic tracking-tighter uppercase leading-none">
            LOCK <span className="text-indigo-500 drop-shadow-[0_0_15px_rgba(99,102,241,0.4)]">TF</span> IN!
          </h1>
          <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-3">MCAT Tactical Operating System</p>
        </div>

        {/* AI Control Center */}
        <div className="flex-1 max-w-2xl w-full flex items-center gap-3 bg-white/5 p-2 rounded-[32px] border border-white/10 shadow-2xl backdrop-blur-xl">
           <input 
             value={userInput} 
             onChange={e => setUserInput(e.target.value)}
             placeholder="Need to pivot? Ask your AI Strategic Coach..." 
             className="bg-transparent border-none outline-none px-6 py-3 text-sm font-semibold w-full placeholder:text-slate-600"
             onKeyDown={e => e.key === 'Enter' && onSync()}
           />
           <button 
             onClick={onSync} 
             disabled={aiLoading} 
             className="bg-indigo-500 text-white px-10 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-400 transition-all shadow-lg active:scale-95 disabled:opacity-50"
           >
             {aiLoading ? 'ANALYZING...' : 'SYNC'}
           </button>
        </div>

        {/* Status Hub */}
        <div className="flex items-center gap-6 bg-[#16122b] px-6 py-4 rounded-3xl border border-slate-800 shadow-xl">
           <div className="text-right">
             <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Mastery Level</p>
             <p className="text-xl font-black text-indigo-400">{progressPercent}%</p>
           </div>
           <div className="w-10 h-10 rounded-full border-4 border-indigo-500/20 flex items-center justify-center relative">
             <svg className="absolute inset-0 w-full h-full -rotate-90">
                <circle cx="50%" cy="50%" r="40%" stroke="currentColor" strokeWidth="4" fill="transparent" className="text-indigo-500" strokeDasharray="100" strokeDashoffset={100 - progressPercent} />
             </svg>
           </div>
        </div>
      </header>

      {/* AI Intelligence Briefing */}
      {aiMessage && (
        <div className="px-8 max-w-[1700px] mx-auto mb-8 animate-fade-in">
          <div className="bg-indigo-500/10 border-l-4 border-indigo-500 p-6 rounded-2xl flex items-center gap-4">
            <span className="text-2xl">🤖</span>
            <p className="text-sm font-bold italic text-indigo-100 opacity-90">{aiMessage}</p>
            <button onClick={() => setAiMessage(null)} className="ml-auto text-slate-500 hover:text-white"><svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
          </div>
        </div>
      )}

      {/* Strategic Grid */}
      <main className="px-8 pb-40 max-w-[1700px] mx-auto">
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-7 gap-6 animate-fade-in">
          {currentRangeDays.map((d, i) => (
            <DayColumn 
              key={i} 
              date={d} 
              tasks={tasks.filter(t => t.date === formatDateKey(d))} 
              onToggleTask={id => setTasks(prev => prev.map(t => t.id === id ? {...t, completed: !t.completed} : t))}
              onDropTask={(id, date) => setTasks(prev => prev.map(t => t.id === id ? {...t, date} : t))}
              onDragStartTask={(e, id) => e.dataTransfer.setData('taskId', id)}
              onAddTask={date => { setEditTask({ title: '', section: 'Biology', date, duration: '1.5h', description: '' }); setIsModalOpen(true); }}
              onEditTask={task => { setEditTask(task); setIsModalOpen(true); }}
            />
          ))}
        </div>
      </main>

      {/* Navigation Controller */}
      <nav className="fixed bottom-10 left-1/2 -translate-x-1/2 flex items-center gap-10 bg-[#16122b]/90 border-slate-800 backdrop-blur-2xl p-5 px-12 rounded-[50px] shadow-[0_25px_60px_rgba(0,0,0,0.5)] border z-[90]">
