        </div>
        <button onClick={() => { const d = new Date(baseDate); d.setDate(d.getDate() + 7); setBaseDate(d); }} className="p-3 hover:bg-indigo-500/20 rounded-full transition-all text-slate-400 hover:text-white">
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="M9 18l6-6-6-6"/></svg>
        </button>
      </nav>

      {/* Mission Detail Modal */}
      {isModalOpen && editTask && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/80 backdrop-blur-xl animate-fade-in">
          <div className="bg-[#16122b] border-slate-800 w-full max-w-md p-10 rounded-[40px] border shadow-2xl">
            <h2 className="text-3xl font-black mb-8 uppercase italic tracking-tighter">Mission <span className="text-indigo-500">Parameters</span></h2>
            <form onSubmit={handleSave} className="space-y-6">
              <div>
                <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Objective Title</label>
                <input 
                  className="w-full p-4 rounded-2xl border-2 bg-[#090712] border-slate-800 outline-none font-bold focus:border-indigo-500 transition-all"
                  placeholder="e.g. Chemical Bonding"
                  value={editTask.title}
                  onChange={e => setEditTask({...editTask, title: e.target.value})}
                  autoFocus
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Operation Date</label>
                  <input 
                    type="date"
                    className="w-full p-4 rounded-2xl border-2 bg-[#090712] border-slate-800 outline-none font-bold focus:border-indigo-500 transition-all text-white"
                    value={editTask.date}
                    onChange={e => setEditTask({...editTask, date: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Duration</label>
                  <input 
                    className="w-full p-4 rounded-2xl border-2 bg-[#090712] border-slate-800 outline-none font-bold focus:border-indigo-500 transition-all"
                    placeholder="2h"
                    value={editTask.duration}
                    onChange={e => setEditTask({...editTask, duration: e.target.value})}
                  />
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Combat Sector</label>
                <select 
                  className="w-full p-4 rounded-2xl border-2 bg-[#090712] border-slate-800 outline-none font-bold focus:border-indigo-500 transition-all text-white appearance-none"
                  value={editTask.section}
                  onChange={e => setEditTask({...editTask, section: e.target.value as MCATSection})}
                >
                  {Object.keys(SECTION_STYLES).map(s => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
              <div className="pt-6 flex gap-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-4 font-black uppercase tracking-widest text-xs text-slate-500 hover:text-white transition-colors">Abort</button>
                <button type="submit" className="flex-[2] bg-indigo-500 text-white py-5 rounded-2xl font-black uppercase tracking-widest text-xs shadow-lg hover:bg-indigo-400 active:scale-95 transition-all">Engage</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

