import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { GoogleGenAI, Type } from "@google/genai";

// --- TYPES ---
type MCATSection = 
  | 'Biology' | 'Biochemistry' | 'General Chemistry' | 'Organic Chemistry' 
  | 'Physics' | 'Behavioral Sciences' | 'CARS' | 'Practice Exam';

type MasteryRating = 'Again' | 'Hard' | 'Good' | 'Easy';
type ViewType = 'daily' | 'weekly' | 'monthly';

interface StudyTask {
  id: string;
  groupId?: string;
  originalTaskId?: string;
  reviewIteration?: number;
  title: string;
  description: string;
  section: MCATSection;
  completed: boolean;
  date: string; // YYYY-MM-DD
  duration: string;
  masteryRating?: MasteryRating;
  isFSRSActive?: boolean;
}

// --- CONSTANTS ---
const SECTION_STYLES: Record<MCATSection, { bg: string, text: string, label: string }> = {
  'Biology': { bg: 'bg-emerald-500/20', text: 'text-emerald-400', label: 'BIO' },
  'Biochemistry': { bg: 'bg-teal-500/20', text: 'text-teal-400', label: 'BCM' },
  'General Chemistry': { bg: 'bg-blue-500/20', text: 'text-blue-400', label: 'CHM' },
  'Organic Chemistry': { bg: 'bg-indigo-500/20', text: 'text-indigo-400', label: 'ORG' },
  'Physics': { bg: 'bg-purple-500/20', text: 'text-purple-400', label: 'PHY' },
  'Behavioral Sciences': { bg: 'bg-rose-500/20', text: 'text-rose-400', label: 'BEH' },
  'CARS': { bg: 'bg-orange-500/20', text: 'text-orange-400', label: 'CARS' },
  'Practice Exam': { bg: 'bg-slate-500/20', text: 'text-slate-300', label: 'EXAM' },
};

const formatDateKey = (date: Date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const INITIAL_TASKS: StudyTask[] = [
  { id: '1', title: 'Amino Acids Structure', description: 'Review all 20 side chains', section: 'Biochemistry', completed: false, date: formatDateKey(new Date()), duration: '1.5h' },
  { id: '2', title: 'Daily CARS Passage', description: 'Jack Westin / AAMC Practice', section: 'CARS', completed: true, date: formatDateKey(new Date()), duration: '1h' },
];

// --- AI SERVICE ---
async function adaptSchedule(currentTasks: StudyTask[], userGoals: string): Promise<{ suggestion: string, updatedTasks: StudyTask[] }> {
  const apiKey = (process.env as any).API_KEY;
  if (!apiKey) return { suggestion: "Connect API key to unlock AI.", updatedTasks: currentTasks };

  const ai = new GoogleGenAI({ apiKey });
  const model = 'gemini-3-flash-preview';

  const prompt = `Act as an expert MCAT Strategic Coach. 
  Current Schedule: ${JSON.stringify(currentTasks)}
  Input: ${userGoals}
  Rules:
  1. Move uncompleted tasks to next available slots if student is behind.
  2. Add high-yield focus areas if requested.
  3. Max 5 tasks/day.
  4. Response MUST be valid JSON.
  5. Format: YYYY-MM-DD.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suggestion: { type: Type.STRING },
            updatedTasks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  section: { type: Type.STRING },
                  completed: { type: Type.BOOLEAN },
                  date: { type: Type.STRING },
                  duration: { type: Type.STRING }
                },
                required: ["id", "title", "section", "completed", "date", "duration"]
              }
            }
          },
          required: ["suggestion", "updatedTasks"]
        }
      }
    });
    return JSON.parse(response.text);
  } catch (e) {
    return { suggestion: "Coach sync unavailable.", updatedTasks: currentTasks };
  }
}

