          <p className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">{tasks.length} Operations</p>
        </div>
        <button onClick={() => onAddTask(dateKey)} className="w-9 h-9 rounded-xl bg-white/5 text-slate-400 flex items-center justify-center hover:bg-indigo-500 hover:text-white transition-all shadow-xl">
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
        </button>
      </div>
      <div className="flex-1">
        {tasks.map(t => (
          <TaskCard key={t.id} task={t} onToggle={onToggleTask} onRate={onRateTask} onDragStart={onDragStartTask} onEdit={onEditTask} />
        ))}
        {tasks.length === 0 && (
          <div className="h-24 border-2 border-dashed border-slate-800/50 rounded-2xl flex items-center justify-center text-[10px] font-black text-slate-700 uppercase tracking-[0.2em] italic text-center px-4">Sector Clear</div>
        )}
      </div>
    </div>
  );
};

// --- MAIN APP ---
const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(() => {
    const saved = localStorage.getItem('lock-tf-in-v5');
    return saved ? JSON.parse(saved) : INITIAL_TASKS;
  });
  const [userInput, setUserInput] = useState('');
  const [baseDate, setBaseDate] = useState(new Date());
  const [aiLoading, setAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editTask, setEditTask] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => { localStorage.setItem('lock-tf-in-v5', JSON.stringify(tasks)); }, [tasks]);

  const currentRangeDays = useMemo(() => {
    const start = new Date(baseDate);
    const day = start.getDay();
    const shift = day === 0 ? 6 : day - 1;
    start.setDate(start.getDate() - shift);
    return Array.from({ length: 7 }).map((_, i) => {
      const d = new Date(start);
      d.setDate(d.getDate() + i);
      return d;
    });
  }, [baseDate]);

  const onSync = async () => {
    if (!userInput) return;
    setAiLoading(true);
    const res = await adaptSchedule(tasks, userInput);
    setTasks(res.updatedTasks);
    setAiMessage(res.suggestion);
    setUserInput('');
    setAiLoading(false);
  };

  const handleRateTask = (id: string, rating: MasteryRating) => {
    setTasks(prev => {
      const task = prev.find(t => t.id === id);
      if (!task) return prev;

      let updated = prev.map(t => t.id === id ? { ...t, masteryRating: rating, completed: true } : t);

      if (rating === 'Again' || rating === 'Hard') {
        const soon = new Date(task.date);
        soon.setDate(soon.getDate() + (rating === 'Again' ? 1 : 2));
        updated.push({
          ...task,
          id: Math.random().toString(36).substr(2, 9),
          title: `RE-TARGET: ${task.title}`,
          date: formatDateKey(soon),
          completed: false,
          masteryRating: undefined,
          isFSRSActive: true
        });
      }
      return updated;
    });
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editTask) return;
    if (editTask.id) {
