            LOCK <span className="text-indigo-500 drop-shadow-[0_0_15px_rgba(99,102,241,0.5)]">TF</span> IN!
          </h1>
          <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-3">Tactical Study Operating System</p>
        </div>

        <div className="flex-1 max-w-2xl w-full flex items-center gap-3 bg-white/5 p-2 rounded-[32px] border border-white/10 shadow-2xl backdrop-blur-xl">
