             onChange={e => setUserInput(e.target.value)}
             placeholder="Strategic Pivot? Inform AI Coach..." 
             className="bg-transparent border-none outline-none px-6 py-3 text-sm font-semibold w-full placeholder:text-slate-600 text-white"
             onKeyDown={e => e.key === 'Enter' && onSync()}
           />
           <button onClick={onSync} disabled={aiLoading} className="bg-indigo-500 text-white px-10 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-400 transition-all shadow-lg active:scale-95 disabled:opacity-50">
             {aiLoading ? 'SYNCING...' : 'SYNC'}
           </button>
        </div>

        <div className="flex items-center gap-6 bg-[#16122b] px-6 py-4 rounded-3xl border border-slate-800 shadow-xl">
           <div className="text-right">
             <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Efficiency</p>
             <p className="text-xl font-black text-indigo-400">{progressPercent}%</p>
           </div>
