import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { GoogleGenAI, Type } from "@google/genai";

// --- TYPES ---
type MCATSection = 
  | 'Biology' | 'Biochemistry' | 'General Chemistry' | 'Organic Chemistry' 
  | 'Physics' | 'Behavioral Sciences' | 'CARS' | 'Practice Exam';

type MasteryRating = 'Again' | 'Hard' | 'Good' | 'Easy';

interface StudyTask {
  id: string;
  title: string;
  description: string;
  section: MCATSection;
  completed: boolean;
  date: string; // YYYY-MM-DD
  duration: string;
  masteryRating?: MasteryRating;
  isFSRSActive?: boolean;
}

// --- CONSTANTS ---
const SECTION_STYLES: Record<MCATSection, { bg: string, text: string, label: string }> = {
  'Biology': { bg: 'bg-emerald-500/10', text: 'text-emerald-400', label: 'BIO' },
  'Biochemistry': { bg: 'bg-teal-500/10', text: 'text-teal-400', label: 'BCM' },
  'General Chemistry': { bg: 'bg-blue-500/10', text: 'text-blue-400', label: 'CHM' },
  'Organic Chemistry': { bg: 'bg-indigo-500/10', text: 'text-indigo-400', label: 'ORG' },
  'Physics': { bg: 'bg-purple-500/10', text: 'text-purple-400', label: 'PHY' },
  'Behavioral Sciences': { bg: 'bg-rose-500/10', text: 'text-rose-400', label: 'BEH' },
  'CARS': { bg: 'bg-orange-500/10', text: 'text-orange-400', label: 'CARS' },
  'Practice Exam': { bg: 'bg-slate-500/10', text: 'text-slate-300', label: 'EXAM' },
};

const formatDateKey = (date: Date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const INITIAL_TASKS: StudyTask[] = [
  { id: '1', title: 'Amino Acids: Fundamentals', description: 'Review all side chains and charge', section: 'Biochemistry', completed: false, date: formatDateKey(new Date()), duration: '1.5h' },
  { id: '2', title: 'Daily CARS Passage', description: '3 passages from official guide', section: 'CARS', completed: true, date: formatDateKey(new Date()), duration: '1h' },
];

// --- AI SERVICE ---
async function adaptSchedule(currentTasks: StudyTask[], userGoals: string): Promise<{ suggestion: string, updatedTasks: StudyTask[] }> {
  const apiKey = (process.env as any).API_KEY;
  if (!apiKey) return { suggestion: "Connect API key to sync.", updatedTasks: currentTasks };

  const ai = new GoogleGenAI({ apiKey });
  const model = 'gemini-3-flash-preview';

  const prompt = `Act as an expert MCAT Study Coach. 
  Current Schedule: ${JSON.stringify(currentTasks)}
  Student Input: ${userGoals}
  Rules:
  1. Move unfinished tasks to tomorrow.
  2. If the student is tired, reduce workload.
  3. If they want to focus on a subject, add 1-2 key high-yield topics.
  4. Response MUST be valid JSON.
  5. Date format YYYY-MM-DD.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suggestion: { type: Type.STRING },
            updatedTasks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  section: { type: Type.STRING },
                  completed: { type: Type.BOOLEAN },
                  date: { type: Type.STRING },
                  duration: { type: Type.STRING }
                },
                required: ["id", "title", "section", "completed", "date", "duration"]
              }
            }
          },
          required: ["suggestion", "updatedTasks"]
        }
      }
    });
    return JSON.parse(response.text);
  } catch (e) {
    return { suggestion: "Sync failed. Try again.", updatedTasks: currentTasks };
  }
}

// --- COMPONENTS ---
const TaskCard: React.FC<{
  task: StudyTask;
  onToggle: (id: string) => void;
  onDragStart: (e: React.DragEvent, id: string) => void;
  onEdit: (task: StudyTask) => void;
  onRate: (id: string, rating: MasteryRating) => void;
}> = ({ task, onToggle, onDragStart, onEdit, onRate }) => {
  const styles = SECTION_STYLES[task.section];

  return (
    <div
      draggable
      onDragStart={(e) => onDragStart(e, task.id)}
      onClick={() => onEdit(task)}
      className={`group relative p-4 mb-3 rounded-2xl border transition-all cursor-grab active:cursor-grabbing hover:scale-[1.02] bg-[#1a1630] border-slate-800 hover:border-indigo-500 shadow-lg ${task.completed ? 'opacity-40' : ''} ${task.isFSRSActive ? 'ring-2 ring-rose-500/50' : ''}`}
    >
      <div className="flex gap-3 items-start">
        <button
          onClick={(e) => { e.stopPropagation(); onToggle(task.id); }}
          className={`shrink-0 w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${
            task.completed ? 'bg-indigo-500 border-indigo-500' : 'border-slate-700 bg-[#0d0b1a]'
          }`}
        >
          {task.completed && <svg width="12" height="9" viewBox="0 0 14 11" fill="none"><path d="M1 6L5 9.5L13 1" stroke="white" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>}
        </button>
        <div className="flex-1 min-w-0">
          <h4 className={`font-bold text-[13px] leading-tight ${task.completed ? 'line-through text-slate-500' : 'text-slate-100'}`}>{task.title}</h4>
          <div className="mt-2.5 flex items-center gap-2">
            <span className={`px-2 py-0.5 rounded text-[8px] font-black uppercase tracking-widest ${styles.bg} ${styles.text}`}>{styles.label}</span>
            <span className="text-slate-500 text-[10px] font-bold uppercase tracking-tighter">{task.duration}</span>
            {task.isFSRSActive && <span className="text-rose-400 text-[8px] font-black uppercase">Blitz</span>}
          </div>

          {task.completed && !task.masteryRating && task.section !== 'CARS' && (
            <div className="mt-3 flex gap-1" onClick={e => e.stopPropagation()}>
              {(['Again', 'Hard', 'Good', 'Easy'] as MasteryRating[]).map(r => (
                <button
                  key={r}
                  onClick={() => onRate(task.id, r)}
                  className={`px-2 py-1 rounded text-[8px] font-black uppercase bg-slate-800 hover:bg-indigo-500 text-white transition-colors`}
                >
                  {r}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const DayColumn: React.FC<{
  date: Date;
  tasks: StudyTask[];
  onToggleTask: (id: string) => void;
  onDropTask: (taskId: string, targetDate: string) => void;
  onDragStartTask: (e: React.DragEvent, id: string) => void;
  onAddTask: (date: string) => void;
  onEditTask: (task: StudyTask) => void;
  onRateTask: (id: string, rating: MasteryRating) => void;
}> = ({ date, tasks, onToggleTask, onDropTask, onDragStartTask, onAddTask, onEditTask, onRateTask }) => {
  const [isOver, setIsOver] = useState(false);
  const dateKey = formatDateKey(date);
  const isToday = dateKey === formatDateKey(new Date());

  return (
    <div
      onDragOver={(e) => { e.preventDefault(); setIsOver(true); }}
      onDragLeave={() => setIsOver(false)}
      onDrop={(e) => { e.preventDefault(); setIsOver(false); onDropTask(e.dataTransfer.getData('taskId'), dateKey); }}
      className={`flex flex-col rounded-[32px] border-2 p-5 transition-all min-h-[450px] ${
        isOver ? 'border-dashed border-indigo-500 bg-indigo-500/5' : 
        isToday ? 'border-indigo-500 bg-indigo-500/5' : 'border-slate-800 bg-[#110e24]'
      }`}
    >
      <div className="flex justify-between items-center mb-6">
        <div>
          <h3 className={`font-black text-xl uppercase italic tracking-tighter ${isToday ? 'text-indigo-400' : 'text-slate-100'}`}>
            {date.toLocaleDateString('en-US', { weekday: 'short' })} <span className="text-slate-600 font-medium not-italic ml-1">{date.getDate()}</span>
          </h3>
        </div>
        <button onClick={() => onAddTask(dateKey)} className="w-9 h-9 rounded-xl bg-white/5 text-slate-400 flex items-center justify-center hover:bg-indigo-500 hover:text-white transition-all">
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
        </button>
      </div>
      <div className="flex-1">
        {tasks.map(t => (
          <TaskCard key={t.id} task={t} onToggle={onToggleTask} onDragStart={onDragStartTask} onEdit={onEditTask} onRate={onRateTask} />
        ))}
        {tasks.length === 0 && (
          <div className="h-24 border-2 border-dashed border-slate-800/50 rounded-2xl flex items-center justify-center text-[10px] font-black text-slate-700 uppercase tracking-[0.2em] italic text-center">No Missions</div>
        )}
      </div>
    </div>
  );
};

// --- MAIN APP ---
const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(() => {
    try {
      const saved = localStorage.getItem('lock-tf-in-v6');
      return saved ? JSON.parse(saved) : INITIAL_TASKS;
    } catch {
      return INITIAL_TASKS;
    }
  });
  const [userInput, setUserInput] = useState('');
  const [baseDate, setBaseDate] = useState(new Date());
  const [aiLoading, setAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editTask, setEditTask] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => { localStorage.setItem('lock-tf-in-v6', JSON.stringify(tasks)); }, [tasks]);

  const currentRangeDays = useMemo(() => {
    const start = new Date(baseDate);
    const day = start.getDay();
    const shift = day === 0 ? 6 : day - 1;
    start.setDate(start.getDate() - shift);
    return Array.from({ length: 7 }).map((_, i) => {
      const d = new Date(start);
      d.setDate(d.getDate() + i);
      return d;
    });
  }, [baseDate]);

  const onSync = async () => {
    if (!userInput) return;
    setAiLoading(true);
    const res = await adaptSchedule(tasks, userInput);
    if (res.updatedTasks) setTasks(res.updatedTasks);
    setAiMessage(res.suggestion);
    setUserInput('');
    setAiLoading(false);
  };

  const handleRateTask = (id: string, rating: MasteryRating) => {
    setTasks(prev => {
      const task = prev.find(t => t.id === id);
      if (!task) return prev;

      let updated = prev.map(t => t.id === id ? { ...t, masteryRating: rating, completed: true } : t);

      if (rating === 'Again' || rating === 'Hard') {
        const soon = new Date(task.date);
        soon.setDate(soon.getDate() + (rating === 'Again' ? 1 : 2));
        updated.push({
          ...task,
          id: Math.random().toString(36).substr(2, 9),
