      <div className={`${bgCol} w-full max-w-md p-10 rounded-[40px] shadow-2xl border ${isDarkMode ? 'border-slate-800' : 'border-slate-200'}`}>
        <h2 className={`text-3xl font-black mb-8 uppercase italic tracking-tighter ${textCol}`}>Mission <span className="text-indigo-500">Parameters</span></h2>
        <form onSubmit={(e) => { e.preventDefault(); onSave({ ...task, title, section, duration, date } as StudyTask); onClose(); }} className="space-y-6">
          <div>
            <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Objective</label>
            <input 
              className={`w-full p-4 rounded-2xl border-2 outline-none font-bold focus:border-indigo-500 transition-all ${inputBg} ${textCol}`}
              placeholder="e.g. Chemical Bonding"
              value={title}
              onChange={e => setTitle(e.target.value)}
              autoFocus
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Date</label>
              <input 
                type="date"
