                value={date}
                onChange={e => setDate(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Duration</label>
              <input 
                className={`w-full p-4 rounded-2xl border-2 outline-none font-bold focus:border-indigo-500 transition-all ${inputBg} ${textCol}`}
                placeholder="2h"
                value={duration}
                onChange={e => setDuration(e.target.value)}
              />
            </div>
          </div>
          <div>
            <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Sector</label>
            <select 
              className={`w-full p-4 rounded-2xl border-2 outline-none font-bold focus:border-indigo-500 transition-all appearance-none ${inputBg} ${textCol}`}
              value={section}
              onChange={e => setSection(e.target.value as MCATSection)}
            >
              {Object.keys(SECTION_STYLES).map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
          <div className="pt-6 flex gap-4">
            <button type="button" onClick={onClose} className="flex-1 py-4 font-black uppercase tracking-widest text-xs text-slate-500 hover:text-indigo-500 transition-colors">Abort</button>
            <button type="submit" className="flex-[2] bg-indigo-500 text-white py-5 rounded-2xl font-black uppercase tracking-widest text-xs shadow-lg hover:bg-indigo-400 active:scale-95 transition-all">Engage</button>
