      </div>
    </div>
  );
};

// ==========================================
// 5. MAIN APP
// ==========================================
const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(() => {
    try {
      const saved = localStorage.getItem('lock-tf-in-final');
      return saved ? JSON.parse(saved) : INITIAL_TASKS;
    } catch {
      return INITIAL_TASKS;
    }
  });

  // Default to true (Dark Mode) for immediate visibility
  const [isDarkMode, setIsDarkMode] = useState(true);
  const [userInput, setUserInput] = useState('');
  const [baseDate, setBaseDate] = useState(new Date());
  const [aiLoading, setAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editTask, setEditTask] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => { localStorage.setItem('lock-tf-in-final', JSON.stringify(tasks)); }, [tasks]);

  useEffect(() => {
    document.body.style.backgroundColor = isDarkMode ? '#090712' : '#f8fafc';
    document.body.style.color = isDarkMode ? '#f1f5f9' : '#1e293b';
  }, [isDarkMode]);

  const currentRangeDays = useMemo(() => {
    const start = new Date(baseDate);
    const day = start.getDay();
    const shift = day === 0 ? 6 : day - 1;
    start.setDate(start.getDate() - shift);
    return Array.from({ length: 7 }).map((_, i) => {
      const d = new Date(start);
      d.setDate(d.getDate() + i);
      return d;
    });
  }, [baseDate]);

  const onSync = async () => {
    if (!userInput) return;
    setAiLoading(true);
    const res = await adaptSchedule(tasks, userInput);
    if (res.updatedTasks) setTasks(res.updatedTasks);
    setAiMessage(res.suggestion);
    setUserInput('');
    setAiLoading(false);
  };

  const handleRateTask = (id: string, rating: MasteryRating) => {
    setTasks(prev => {
      const task = prev.find(t => t.id === id);
      if (!task) return prev;

      let updated = prev.map(t => t.id === id ? { ...t, masteryRating: rating, completed: true } : t);

      if (rating === 'Again' || rating === 'Hard') {
        const soon = new Date(task.date);
        soon.setDate(soon.getDate() + (rating === 'Again' ? 1 : 2));
        updated.push({
          ...task,
          id: Math.random().toString(36).substr(2, 9),
          title: `RE-TARGET: ${task.title}`,
          date: formatDateKey(soon),
          completed: false,
          masteryRating: undefined,
          isFSRSActive: true
        });
      }
      return updated;
    });
  };

  const handleSave = (task: StudyTask) => {
    if (task.id) {
      setTasks(prev => prev.map(t => t.id === task.id ? { ...t, ...task } : t));
    } else {
      setTasks(prev => [...prev, { ...task, id: Math.random().toString(36).substr(2, 9), completed: false }]);
    }
  };

  const handleDelete = (task: Partial<StudyTask>) => {
    if (task.id) setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const progressPercent = tasks.length > 0 ? Math.round((tasks.filter(t => t.completed).length / tasks.length) * 100) : 0;

  return (
    <div className={`min-h-screen ${isDarkMode ? 'bg-[#090712] text-white' : 'bg-[#f8fafc] text-slate-800'}`}>
      {/* Header */}
      <header className="px-8 py-10 max-w-[1700px] mx-auto flex flex-col lg:flex-row items-center justify-between gap-10">
        <div>
          <h1 className="text-4xl md:text-5xl font-black italic tracking-tighter uppercase leading-none">
            LOCK <span className={`drop-shadow-[0_0_15px_rgba(99,102,241,0.5)] ${isDarkMode ? 'text-indigo-500' : 'text-indigo-600'}`}>TF</span> IN!
          </h1>
          <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-3">Tactical MCAT Operating System</p>
        </div>

        {/* Controls */}
        <div className={`flex-1 max-w-2xl w-full flex items-center gap-3 p-2 rounded-[32px] border shadow-2xl backdrop-blur-xl ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-white border-slate-200'}`}>
           <input 
             value={userInput} 
             onChange={e => setUserInput(e.target.value)}
             placeholder="Need to pivot? Ask your AI Strategic Coach..." 
             className={`bg-transparent border-none outline-none px-6 py-3 text-sm font-semibold w-full ${isDarkMode ? 'placeholder:text-slate-600 text-white' : 'placeholder:text-slate-400 text-slate-800'}`}
             onKeyDown={e => e.key === 'Enter' && onSync()}
           />
           <button 
             onClick={onSync} 
             disabled={aiLoading} 
             className="bg-indigo-500 text-white px-8 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-400 transition-all shadow-lg active:scale-95 disabled:opacity-50 whitespace-nowrap"
           >
             {aiLoading ? 'ANALYZING...' : 'SYNC'}
           </button>
           <button onClick={() => setIsDarkMode(!isDarkMode)} className={`p-4 rounded-2xl transition-all ${isDarkMode ? 'bg-[#1a1630] text-yellow-400 hover:text-yellow-300' : 'bg-slate-100 text-indigo-600 hover:bg-slate-200'}`}>
             {isDarkMode ? '☀' : '☾'}
           </button>
        </div>

        {/* Status */}
        <div className={`flex items-center gap-6 px-6 py-4 rounded-3xl border shadow-xl ${isDarkMode ? 'bg-[#16122b] border-slate-800' : 'bg-white border-slate-100'}`}>
           <div className="text-right">
             <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Mastery Level</p>
             <p className={`text-xl font-black ${isDarkMode ? 'text-indigo-400' : 'text-indigo-600'}`}>{progressPercent}%</p>
           </div>
           <div className="w-10 h-10 rounded-full border-4 border-indigo-500/20 flex items-center justify-center relative">
             <div className="absolute inset-0 rounded-full border-4 border-indigo-500 border-t-transparent animate-spin-slow opacity-30"></div>
           </div>
        </div>
      </header>

      {/* AI Message */}
      {aiMessage && (
        <div className="px-8 max-w-[1700px] mx-auto mb-8 animate-fade-in">
          <div className={`border-l-4 border-indigo-500 p-6 rounded-2xl flex items-center gap-4 ${isDarkMode ? 'bg-indigo-500/10' : 'bg-indigo-50'}`}>
            <span className="text-2xl">🤖</span>
            <p className={`text-sm font-bold italic opacity-90 ${isDarkMode ? 'text-indigo-100' : 'text-indigo-900'}`}>{aiMessage}</p>
            <button onClick={() => setAiMessage(null)} className="ml-auto text-slate-500 hover:text-indigo-500">
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
            </button>
          </div>
        </div>
      )}

      {/* Main Grid */}
      <main className="px-8 pb-40 max-w-[1700px] mx-auto">
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-7 gap-6 animate-fade-in">
          {currentRangeDays.map((d, i) => (
            <DayColumn 
              key={i} 
              date={d} 
              isDarkMode={isDarkMode}
              tasks={tasks.filter(t => t.date === formatDateKey(d))} 
              onToggleTask={id => setTasks(prev => prev.map(t => t.id === id ? {...t, completed: !t.completed} : t))}
              onDropTask={(id, date) => setTasks(prev => prev.map(t => t.id === id ? {...t, date} : t))}
              onDragStartTask={(e, id) => e.dataTransfer.setData('taskId', id)}
              onAddTask={date => { setEditTask({ title: '', section: 'Biology', date, duration: '1.5h', description: '' }); setIsModalOpen(true); }}
              onEditTask={task => { setEditTask(task); setIsModalOpen(true); }}
              onDeleteTask={handleDelete}
              onRateTask={handleRateTask}
            />
          ))}
        </div>
      </main>

      {/* Navigation */}
      <nav className={`fixed bottom-10 left-1/2 -translate-x-1/2 flex items-center gap-10 backdrop-blur-2xl p-5 px-12 rounded-[50px] shadow-[0_25px_60px_rgba(0,0,0,0.5)] border z-[90] ${isDarkMode ? 'bg-[#16122b]/90 border-slate-800' : 'bg-white/90 border-slate-200'}`}>
        <button onClick={() => { const d = new Date(baseDate); d.setDate(d.getDate() - 7); setBaseDate(d); }} className="p-3 hover:bg-indigo-500/20 rounded-full transition-all text-slate-400 hover:text-indigo-500">
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="M15 18l-6-6 6-6"/></svg>
        </button>
        <div className="text-center min-w-[160px]">
          <span className="font-black text-xs uppercase tracking-[0.4em] text-indigo-500">{baseDate.toLocaleDateString('en-US', { month: 'short', year: 'numeric' })}</span>
        </div>
        <button onClick={() => { const d = new Date(baseDate); d.setDate(d.getDate() + 7); setBaseDate(d); }} className="p-3 hover:bg-indigo-500/20 rounded-full transition-all text-slate-400 hover:text-indigo-500">
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="M9 18l6-6-6-6"/></svg>
        </button>
      </nav>

      <EditTaskModal 
        isDarkMode={isDarkMode}
        isOpen={isModalOpen} 
        task={editTask} 
