import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { GoogleGenAI, Type } from "@google/genai";

// ==========================================
// 1. TYPES
// ==========================================
type MCATSection = 
  | 'Biology' | 'Biochemistry' | 'General Chemistry' | 'Organic Chemistry' 
  | 'Physics' | 'Behavioral Sciences' | 'CARS' | 'Practice Exam';

type RecurrenceType = 'None' | 'Daily' | 'Weekly' | 'Custom' | 'SpacedRepetition';
type MasteryRating = 'Again' | 'Hard' | 'Good' | 'Easy';

interface StudyTask {
  id: string;
  groupId?: string; 
  originalTaskId?: string; 
  reviewIteration?: number; 
  title: string;
  description: string;
  section: MCATSection;
  completed: boolean;
  date: string; // YYYY-MM-DD
  duration: string;
  recurrence?: RecurrenceType;
  customInterval?: number;
  masteryRating?: MasteryRating;
  isFSRSActive?: boolean;
}

// ==========================================
// 2. CONSTANTS
// ==========================================
const SECTION_STYLES: Record<MCATSection, { bg: string, text: string, label: string }> = {
  'Biology': { bg: 'bg-emerald-500/10', text: 'text-emerald-400', label: 'BIO' },
  'Biochemistry': { bg: 'bg-teal-500/10', text: 'text-teal-400', label: 'BCM' },
  'General Chemistry': { bg: 'bg-blue-500/10', text: 'text-blue-400', label: 'CHM' },
  'Organic Chemistry': { bg: 'bg-indigo-500/10', text: 'text-indigo-400', label: 'ORG' },
  'Physics': { bg: 'bg-purple-500/10', text: 'text-purple-400', label: 'PHY' },
  'Behavioral Sciences': { bg: 'bg-rose-500/10', text: 'text-rose-400', label: 'BEH' },
  'CARS': { bg: 'bg-orange-500/10', text: 'text-orange-400', label: 'CARS' },
  'Practice Exam': { bg: 'bg-slate-500/10', text: 'text-slate-300', label: 'EXAM' },
};

const formatDateKey = (date: Date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const INITIAL_TASKS: StudyTask[] = [
  { id: '1', title: 'Amino Acids Review', description: 'Side chains and pKa', section: 'Biochemistry', completed: false, date: formatDateKey(new Date()), duration: '2h' },
  { id: '2', title: 'Enzyme Kinetics', description: 'Michaelis-Menten plots', section: 'Biology', completed: false, date: formatDateKey(new Date()), duration: '1h' },
  { id: '3', title: 'CARS Practice', description: '3 passages', section: 'CARS', completed: true, date: formatDateKey(new Date()), duration: '1.5h' },
];

// ==========================================
// 3. SERVICE
// ==========================================
async function adaptSchedule(currentTasks: StudyTask[], userGoals: string): Promise<{ suggestion: string, updatedTasks: StudyTask[] }> {
  const apiKey = (process.env as any).API_KEY;
  if (!apiKey) return { suggestion: "Connect API key to sync.", updatedTasks: currentTasks };

  const ai = new GoogleGenAI({ apiKey });
  const model = 'gemini-3-flash-preview';

  const prompt = `Act as an expert MCAT Study Coach. 
  Current Schedule: ${JSON.stringify(currentTasks)}
  Student Input: ${userGoals}
  Rules:
  1. Move unfinished tasks to tomorrow.
  2. If the student is tired, reduce workload.
  3. If they want to focus on a subject, add 1-2 key high-yield topics.
  4. Response MUST be valid JSON.
  5. Date format YYYY-MM-DD.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suggestion: { type: Type.STRING },
            updatedTasks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  section: { type: Type.STRING },
                  completed: { type: Type.BOOLEAN },
                  date: { type: Type.STRING },
                  duration: { type: Type.STRING }
                },
                required: ["id", "title", "section", "completed", "date", "duration"]
              }
            }
          },
          required: ["suggestion", "updatedTasks"]
        }
      }
    });
    return JSON.parse(response.text);
  } catch (e) {
    console.error(e);
    return { suggestion: "Coach sync unavailable.", updatedTasks: currentTasks };
  }
}

// ==========================================
// 4. COMPONENTS
// ==========================================

// --- TaskCard ---
const TaskCard: React.FC<{
  task: StudyTask;
  onToggle: (id: string) => void;
  onRate: (id: string, rating: MasteryRating) => void;
  onDragStart: (e: React.DragEvent, id: string) => void;
  onEdit: (task: StudyTask) => void;
  onDelete: (task: StudyTask) => void;
  isDarkMode: boolean;
}> = ({ task, onToggle, onRate, onDragStart, onEdit, onDelete, isDarkMode }) => {
  const [confirmDelete, setConfirmDelete] = useState(false);
  const styles = SECTION_STYLES[task.section];

  const cardBg = isDarkMode ? 'bg-[#1a1630]' : 'bg-white';
  const borderCol = isDarkMode ? 'border-slate-800' : 'border-slate-200';
  const textColor = isDarkMode ? 'text-slate-100' : 'text-slate-800';

  const isReview = !!task.originalTaskId || task.reviewIteration !== undefined;
  const isHighPriority = task.isFSRSActive;
  const isCARS = task.section === 'CARS';

  return (
    <div
      draggable
      onDragStart={(e) => onDragStart(e, task.id)}
      onClick={() => !confirmDelete && onEdit(task)}
      onMouseLeave={() => setConfirmDelete(false)}
      className={`group relative p-4 mb-3 rounded-2xl border transition-all cursor-grab active:cursor-grabbing hover:scale-[1.02] ${cardBg} ${borderCol} shadow-lg ${task.completed && !task.masteryRating && !isCARS ? 'opacity-70' : ''} ${isHighPriority ? 'ring-2 ring-rose-500/50' : ''}`}
    >
      <div className="absolute top-3 right-3 z-20">
         {confirmDelete ? (
           <button onClick={(e) => { e.stopPropagation(); onDelete(task); }} className="bg-rose-500 text-white text-[10px] font-black uppercase px-2 py-1 rounded">Confirm</button>
         ) : (
           <button onClick={(e) => { e.stopPropagation(); setConfirmDelete(true); }} className="text-slate-500 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-opacity">
             <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M18 6L6 18M6 6l12 12"/></svg>
           </button>
         )}
      </div>

      <div className="flex gap-3 items-start">
        <button
          onClick={(e) => { e.stopPropagation(); onToggle(task.id); }}
          className={`shrink-0 w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${
            task.completed ? 'bg-indigo-500 border-indigo-500' : `border-slate-600 ${isDarkMode ? 'bg-transparent' : 'bg-slate-50'}`
          }`}
        >
          {task.completed && <svg width="12" height="9" viewBox="0 0 14 11" fill="none"><path d="M1 6L5 9.5L13 1" stroke="white" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>}
        </button>
        <div className="flex-1 min-w-0 pr-6">
          <div className="flex items-center gap-1.5 mb-1 flex-wrap">
            {isReview && <span className="px-1.5 py-0.5 rounded-md bg-purple-500/20 text-purple-400 text-[8px] font-black uppercase tracking-tighter">Review #{task.reviewIteration ?? 'SR'}</span>}
            {isHighPriority && <span className="px-1.5 py-0.5 rounded-md bg-rose-500/20 text-rose-400 text-[8px] font-black uppercase tracking-tighter">Blitz</span>}
          </div>

          <h4 className={`font-bold text-[13px] leading-tight ${textColor} ${task.completed ? 'line-through opacity-50' : ''}`}>{task.title}</h4>

          {!task.completed && (
            <div className="mt-2.5 flex items-center gap-2">
              <span className={`px-2 py-0.5 rounded text-[8px] font-black uppercase tracking-widest ${styles.bg} ${styles.text}`}>{styles.label}</span>
              <span className={`text-[10px] font-bold uppercase tracking-tighter ${isDarkMode ? 'text-slate-500' : 'text-slate-400'}`}>{task.duration}</span>
            </div>
          )}

          {task.completed && !task.masteryRating && !isCARS && (
            <div className="mt-3 flex gap-1" onClick={e => e.stopPropagation()}>
              {(['Again', 'Hard', 'Good', 'Easy'] as MasteryRating[]).map(r => (
                <button
                  key={r}
                  onClick={() => onRate(task.id, r)}
                  className={`px-2 py-1 rounded text-[8px] font-black uppercase transition-colors ${isDarkMode ? 'bg-slate-800 text-white hover:bg-indigo-500' : 'bg-slate-200 text-slate-700 hover:bg-indigo-500 hover:text-white'}`}
                >
                  {r}
                </button>
              ))}
            </div>
          )}

          {task.masteryRating && (
             <div className="mt-2">
               <span className={`text-[9px] font-black uppercase ${task.masteryRating === 'Again' ? 'text-rose-500' : task.masteryRating === 'Hard' ? 'text-orange-500' : 'text-emerald-500'}`}>
                 {task.masteryRating}
               </span>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

// --- DayColumn ---
const DayColumn: React.FC<{
  date: Date;
  tasks: StudyTask[];
  onToggleTask: (id: string) => void;
  onRateTask: (id: string, rating: MasteryRating) => void;
  onDropTask: (taskId: string, targetDate: string) => void;
  onDragStartTask: (e: React.DragEvent, id: string) => void;
  onAddTask: (date: string) => void;
  onEditTask: (task: StudyTask) => void;
  onDeleteTask: (task: StudyTask) => void;
  isDarkMode: boolean;
}> = ({ date, tasks, onToggleTask, onRateTask, onDropTask, onDragStartTask, onAddTask, onEditTask, onDeleteTask, isDarkMode }) => {
  const [isOver, setIsOver] = useState(false);
  const dateKey = formatDateKey(date);
  const isToday = dateKey === formatDateKey(new Date());

  const bgCol = isDarkMode ? 'bg-[#110e24]' : 'bg-slate-50';
  const borderCol = isDarkMode ? 'border-slate-800' : 'border-slate-200';
  const textCol = isDarkMode ? 'text-slate-100' : 'text-slate-800';

  return (
    <div
      onDragOver={(e) => { e.preventDefault(); setIsOver(true); }}
      onDragLeave={() => setIsOver(false)}
      onDrop={(e) => { e.preventDefault(); setIsOver(false); onDropTask(e.dataTransfer.getData('taskId'), dateKey); }}
      className={`flex flex-col rounded-[32px] border-2 p-5 transition-all min-h-[450px] ${
        isOver ? 'border-dashed border-indigo-500 bg-indigo-500/10' : 
        isToday ? 'border-indigo-500 bg-indigo-500/5' : `${borderCol} ${bgCol}`
      }`}
    >
      <div className="flex justify-between items-center mb-6">
        <div>
          <h3 className={`font-black text-xl uppercase italic tracking-tighter ${isToday ? 'text-indigo-500' : textCol}`}>
            {date.toLocaleDateString('en-US', { weekday: 'short' })} <span className="opacity-50 font-medium not-italic ml-1">{date.getDate()}</span>
          </h3>
          <p className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">{tasks.length} Operations</p>
        </div>
        <button onClick={() => onAddTask(dateKey)} className={`w-9 h-9 rounded-xl flex items-center justify-center transition-all ${isDarkMode ? 'bg-white/5 hover:bg-indigo-500 text-slate-400 hover:text-white' : 'bg-white border border-slate-200 text-slate-400 hover:border-indigo-500 hover:text-indigo-500'}`}>
