        </button>
      </div>
      <div className="flex-1">
        {tasks.map(t => (
          <TaskCard 
            key={t.id} 
            task={t} 
            isDarkMode={isDarkMode}
            onToggle={onToggleTask} 
            onRate={onRateTask} 
            onDragStart={onDragStartTask} 
            onEdit={onEditTask} 
            onDelete={onDeleteTask}
          />
