import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { GoogleGenAI, Type } from "@google/genai";

// ==========================================
// 1. TYPES & CONSTANTS
// ==========================================
type MCATSection = 
  | 'Biology' | 'Biochemistry' | 'General Chemistry' | 'Organic Chemistry' 
  | 'Physics' | 'Behavioral Sciences' | 'CARS' | 'Practice Exam';

type RecurrenceType = 'None' | 'Daily' | 'Weekly' | 'Custom';
type MasteryRating = 'Again' | 'Hard' | 'Good' | 'Easy';
type ViewType = 'daily' | 'weekly';

interface StudyTask {
  id: string;
  groupId?: string; 
  title: string;
  description: string;
  section: MCATSection;
  completed: boolean;
  date: string; // YYYY-MM-DD
  duration: string;
  recurrence?: RecurrenceType;
  masteryRating?: MasteryRating;
  isFSRSActive?: boolean;
}

const SECTION_STYLES: Record<MCATSection, { bg: string, text: string, label: string, accent: string }> = {
  'Biology': { bg: 'bg-emerald-500/10', text: 'text-emerald-400', label: 'BIO', accent: 'border-emerald-500' },
  'Biochemistry': { bg: 'bg-teal-500/10', text: 'text-teal-400', label: 'BCM', accent: 'border-teal-500' },
  'General Chemistry': { bg: 'bg-blue-500/10', text: 'text-blue-400', label: 'GEN', accent: 'border-blue-500' },
  'Organic Chemistry': { bg: 'bg-indigo-500/10', text: 'text-indigo-400', label: 'ORG', accent: 'border-indigo-500' },
  'Physics': { bg: 'bg-purple-500/10', text: 'text-purple-400', label: 'PHY', accent: 'border-purple-500' },
  'Behavioral Sciences': { bg: 'bg-rose-500/10', text: 'text-rose-400', label: 'PSY', accent: 'border-rose-500' },
  'CARS': { bg: 'bg-orange-500/10', text: 'text-orange-400', label: 'CAR', accent: 'border-orange-500' },
  'Practice Exam': { bg: 'bg-slate-500/10', text: 'text-slate-300', label: 'EXM', accent: 'border-slate-500' },
};

const formatDateKey = (date: Date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const INITIAL_TASKS: StudyTask[] = [
  { id: '1', title: 'Amino Acids Review', description: 'Side chains and pKa', section: 'Biochemistry', completed: false, date: formatDateKey(new Date()), duration: '2h' },
  { id: '2', title: 'Daily CARS Passage', description: '3 passages', section: 'CARS', completed: true, date: formatDateKey(new Date()), duration: '1.5h' },
];

// ==========================================
// 2. SERVICE (Gemini)
// ==========================================
async function adaptSchedule(currentTasks: StudyTask[], userGoals: string): Promise<{ suggestion: string, updatedTasks: StudyTask[] }> {
  const apiKey = (process.env as any).API_KEY;
  if (!apiKey) return { suggestion: "Sync failed: No API Key.", updatedTasks: currentTasks };

  const ai = new GoogleGenAI({ apiKey });
  const model = 'gemini-3-flash-preview';

  const prompt = `Act as an expert MCAT Study Coach. 
  Current Schedule: ${JSON.stringify(currentTasks)}
  Student Input: ${userGoals}
  Rules:
  1. Optimize the schedule based on the student's request.
  2. If they are burned out, reduce volume.
  3. If they need to focus on a weak area, add specific high-yield topics.
  4. Response MUST be valid JSON.
  5. Date format YYYY-MM-DD.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suggestion: { type: Type.STRING },
            updatedTasks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  section: { type: Type.STRING },
                  completed: { type: Type.BOOLEAN },
                  date: { type: Type.STRING },
                  duration: { type: Type.STRING }
                },
                required: ["id", "title", "section", "completed", "date", "duration"]
              }
            }
          },
          required: ["suggestion", "updatedTasks"]
        }
      }
    });
    return JSON.parse(response.text);
  } catch (e) {
    return { suggestion: "Connection unstable. Try again.", updatedTasks: currentTasks };
  }
}

// ==========================================
// 3. COMPONENTS
// ==========================================

const TaskCard: React.FC<{
  task: StudyTask;
  onToggle: (id: string) => void;
  onRate: (id: string, rating: MasteryRating) => void;
  onDragStart: (e: React.DragEvent, id: string) => void;
  onEdit: (task: StudyTask) => void;
  onDelete: (id: string) => void;
}> = ({ task, onToggle, onRate, onDragStart, onEdit, onDelete }) => {
  const styles = SECTION_STYLES[task.section];

  return (
    <div
      draggable
      onDragStart={(e) => onDragStart(e, task.id)}
      onClick={() => onEdit(task)}
      className={`relative group p-4 mb-3 rounded-2xl bg-[#1a1630] border border-slate-800 hover:border-indigo-500/50 shadow-lg transition-all cursor-grab active:cursor-grabbing hover:translate-y-[-2px] hover:shadow-indigo-500/10 ${task.completed ? 'opacity-60' : ''} ${task.isFSRSActive ? 'ring-1 ring-rose-500' : ''}`}
    >
      <div className="flex gap-4">
        <button
          onClick={(e) => { e.stopPropagation(); onToggle(task.id); }}
          className={`shrink-0 w-6 h-6 mt-1 rounded-full border-2 flex items-center justify-center transition-all ${
            task.completed ? 'bg-indigo-500 border-indigo-500' : 'border-slate-600 hover:border-indigo-400 bg-transparent'
          }`}
        >
          {task.completed && <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="4"><path d="M5 13l4 4L19 7" /></svg>}
        </button>

        <div className="flex-1 min-w-0">
          <h4 className={`text-sm font-bold leading-snug ${task.completed ? 'text-slate-500 line-through' : 'text-slate-100'}`}>
            {task.title}
          </h4>

          <div className="mt-2 flex items-center gap-2">
            <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-wider ${styles.bg} ${styles.text}`}>
              {styles.label}
            </span>
            <span className="text-slate-500 text-[10px] font-bold uppercase">{task.duration}</span>
            {task.isFSRSActive && <span className="text-rose-500 text-[10px] font-black uppercase tracking-wider">PRIORITY</span>}
          </div>

          {task.completed && !task.masteryRating && task.section !== 'CARS' && (
            <div className="mt-3 grid grid-cols-4 gap-1" onClick={e => e.stopPropagation()}>
              {(['Again', 'Hard', 'Good', 'Easy'] as MasteryRating[]).map(r => (
                <button
                  key={r}
                  onClick={() => onRate(task.id, r)}
                  className={`py-1.5 rounded-lg text-[9px] font-black uppercase transition-colors bg-slate-800 hover:bg-indigo-600 text-slate-300 hover:text-white`}
                >
                  {r}
                </button>
              ))}
            </div>
          )}

          {task.masteryRating && (
            <div className="mt-2">
              <span className={`text-[9px] font-black uppercase ${
                task.masteryRating === 'Again' ? 'text-rose-500' : 
                task.masteryRating === 'Hard' ? 'text-orange-500' : 
                'text-emerald-500'
              }`}>
                Recall: {task.masteryRating}
              </span>
            </div>
          )}
        </div>
      </div>

      <button 
        onClick={(e) => { e.stopPropagation(); onDelete(task.id); }}
        className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 p-2 text-slate-600 hover:text-rose-500 transition-all"
      >
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M18 6L6 18M6 6l12 12"/></svg>
      </button>
    </div>
  );
};

const DayColumn: React.FC<{
  date: Date;
  tasks: StudyTask[];
  onToggleTask: (id: string) => void;
  onRateTask: (id: string, rating: MasteryRating) => void;
  onDropTask: (taskId: string, targetDate: string) => void;
  onDragStartTask: (e: React.DragEvent, id: string) => void;
  onAddTask: (date: string) => void;
  onEditTask: (task: StudyTask) => void;
  onDeleteTask: (id: string) => void;
  isToday: boolean;
}> = ({ date, tasks, onToggleTask, onRateTask, onDropTask, onDragStartTask, onAddTask, onEditTask, onDeleteTask, isToday }) => {
  const [isOver, setIsOver] = useState(false);
  const dateKey = formatDateKey(date);

  return (
    <div
      onDragOver={(e) => { e.preventDefault(); setIsOver(true); }}
      onDragLeave={() => setIsOver(false)}
      onDrop={(e) => { e.preventDefault(); setIsOver(false); onDropTask(e.dataTransfer.getData('taskId'), dateKey); }}
      className={`flex flex-col rounded-[24px] p-4 transition-all min-h-[500px] border-2 ${
        isOver ? 'border-dashed border-indigo-500 bg-indigo-500/10' : 
        isToday ? 'border-indigo-500 bg-[#120f24]' : 'border-slate-800 bg-[#0d0b1a]'
      }`}
    >
      <div className="flex justify-between items-center mb-6 px-2">
        <div>
          <h3 className={`text-lg font-black uppercase tracking-tight ${isToday ? 'text-indigo-400' : 'text-slate-200'}`}>
            {date.toLocaleDateString('en-US', { weekday: 'short' })} <span className="text-slate-600 font-medium ml-1">{date.getDate()}</span>
          </h3>
          <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mt-1">{tasks.length} Missions</p>
        </div>
        <button onClick={() => onAddTask(dateKey)} className="w-8 h-8 rounded-lg bg-slate-800 hover:bg-indigo-600 text-slate-400 hover:text-white flex items-center justify-center transition-all">
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
        </button>
      </div>

      <div className="flex-1">
        {tasks.map(t => (
          <TaskCard 
            key={t.id} 
            task={t} 
            onToggle={onToggleTask} 
            onRate={onRateTask} 
            onDragStart={onDragStartTask} 
            onEdit={onEditTask} 
            onDelete={onDeleteTask}
          />
        ))}
        {tasks.length === 0 && (
          <div className="h-32 rounded-2xl border-2 border-dashed border-slate-800 flex items-center justify-center">
            <span className="text-[10px] font-black text-slate-700 uppercase tracking-widest">No Active Tasks</span>
          </div>
        )}
      </div>
    </div>
  );
};

