      {aiMessage && (
        <div className="max-w-[1800px] mx-auto px-6 mt-6 animate-fade-in">
          <div className="bg-indigo-500/10 border-l-4 border-indigo-500 p-4 rounded-r-xl flex items-center justify-between">
            <div className="flex items-center gap-3">
              <span className="text-xl">🤖</span>
