                 onRateTask={handleRate}
                 onDropTask={(id, date) => setTasks(prev => prev.map(t => t.id === id ? {...t, date} : t))}
                 onDragStartTask={(e, id) => e.dataTransfer.setData('taskId', id)}
                 onAddTask={(date) => { setEditingTask({ date, title: '', section: 'Biology', duration: '1h' }); setIsModalOpen(true); }}
                 onEditTask={(task) => { setEditingTask(task); setIsModalOpen(true); }}
                 onDeleteTask={(id) => setTasks(prev => prev.filter(t => t.id !== id))}
