import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { GoogleGenAI, Type } from "@google/genai";

// ==========================================
// 1. TYPES
// ==========================================
type MCATSection = 
  | 'Biology' | 'Biochemistry' | 'General Chemistry' | 'Organic Chemistry' 
  | 'Physics' | 'Behavioral Sciences' | 'CARS' | 'Practice Exam';

type RecurrenceType = 'None' | 'Daily' | 'Weekly' | 'Custom';
type MasteryRating = 'Again' | 'Hard' | 'Good' | 'Easy';
type ViewType = 'daily' | 'weekly';

interface StudyTask {
  id: string;
  groupId?: string; 
  title: string;
  description: string;
  section: MCATSection;
  completed: boolean;
  date: string; // YYYY-MM-DD
  duration: string;
  recurrence?: RecurrenceType;
  masteryRating?: MasteryRating;
  isFSRSActive?: boolean;
}

// ==========================================
// 2. CONSTANTS
// ==========================================
const SECTION_STYLES: Record<MCATSection, { bg: string, text: string, label: string, accent: string }> = {
  'Biology': { bg: 'bg-emerald-500/10', text: 'text-emerald-400', label: 'BIO', accent: 'border-emerald-500' },
  'Biochemistry': { bg: 'bg-teal-500/10', text: 'text-teal-400', label: 'BCM', accent: 'border-teal-500' },
  'General Chemistry': { bg: 'bg-blue-500/10', text: 'text-blue-400', label: 'GEN', accent: 'border-blue-500' },
  'Organic Chemistry': { bg: 'bg-indigo-500/10', text: 'text-indigo-400', label: 'ORG', accent: 'border-indigo-500' },
  'Physics': { bg: 'bg-purple-500/10', text: 'text-purple-400', label: 'PHY', accent: 'border-purple-500' },
  'Behavioral Sciences': { bg: 'bg-rose-500/10', text: 'text-rose-400', label: 'PSY', accent: 'border-rose-500' },
  'CARS': { bg: 'bg-orange-500/10', text: 'text-orange-400', label: 'CAR', accent: 'border-orange-500' },
  'Practice Exam': { bg: 'bg-slate-500/10', text: 'text-slate-300', label: 'EXM', accent: 'border-slate-500' },
};

const formatDateKey = (date: Date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const INITIAL_TASKS: StudyTask[] = [
  { id: '1', title: 'Amino Acids Review', description: 'Side chains and pKa', section: 'Biochemistry', completed: false, date: formatDateKey(new Date()), duration: '2h' },
  { id: '2', title: 'Daily CARS Passage', description: '3 passages', section: 'CARS', completed: true, date: formatDateKey(new Date()), duration: '1.5h' },
];

// ==========================================
// 3. SERVICE (Gemini)
// ==========================================
async function adaptSchedule(currentTasks: StudyTask[], userGoals: string): Promise<{ suggestion: string, updatedTasks: StudyTask[] }> {
  const apiKey = (process.env as any).API_KEY;
  if (!apiKey) return { suggestion: "Sync failed: No API Key.", updatedTasks: currentTasks };

  const ai = new GoogleGenAI({ apiKey });
  const model = 'gemini-3-flash-preview';

  const prompt = `Act as an expert MCAT Study Coach. 
  Current Schedule: ${JSON.stringify(currentTasks)}
  Student Input: ${userGoals}
  Rules:
  1. Optimize the schedule based on the student's request.
  2. If they are burned out, reduce volume.
  3. If they need to focus on a weak area, add specific high-yield topics.
  4. Response MUST be valid JSON.
  5. Date format YYYY-MM-DD.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suggestion: { type: Type.STRING },
            updatedTasks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  section: { type: Type.STRING },
                  completed: { type: Type.BOOLEAN },
                  date: { type: Type.STRING },
                  duration: { type: Type.STRING }
                },
                required: ["id", "title", "section", "completed", "date", "duration"]
              }
            }
          },
          required: ["suggestion", "updatedTasks"]
        }
      }
    });
    return JSON.parse(response.text);
  } catch (e) {
    return { suggestion: "Connection unstable. Try again.", updatedTasks: currentTasks };
  }
}

// ==========================================
// 4. COMPONENTS
// ==========================================

// --- TaskCard ---
