        </button>

        <div className="flex-1 min-w-0">
          <h4 className={`text-sm font-bold leading-snug ${task.completed ? 'text-slate-500 line-through' : 'text-slate-100'}`}>
            {task.title}
          </h4>

          <div className="mt-2 flex items-center gap-2">
            <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-wider ${styles.bg} ${styles.text}`}>
              {styles.label}
            </span>
            <span className="text-slate-500 text-[10px] font-bold uppercase">{task.duration}</span>
            {task.isFSRSActive && <span className="text-rose-500 text-[10px] font-black uppercase tracking-wider">PRIORITY</span>}
          </div>

