          {task.masteryRating && (
            <div className="mt-2">
              <span className={`text-[9px] font-black uppercase ${
                task.masteryRating === 'Again' ? 'text-rose-500' : 
                task.masteryRating === 'Hard' ? 'text-orange-500' : 
                'text-emerald-500'
              }`}>
                Recall: {task.masteryRating}
              </span>
            </div>
          )}
        </div>
      </div>

      <button 
        onClick={(e) => { e.stopPropagation(); onDelete(task.id); }}
        className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 p-2 text-slate-600 hover:text-rose-500 transition-all"
      >
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M18 6L6 18M6 6l12 12"/></svg>
      </button>
    </div>
  );
};

// --- DayColumn ---
const DayColumn: React.FC<{
  date: Date;
  tasks: StudyTask[];
  onToggleTask: (id: string) => void;
  onRateTask: (id: string, rating: MasteryRating) => void;
  onDropTask: (taskId: string, targetDate: string) => void;
  onDragStartTask: (e: React.DragEvent, id: string) => void;
  onAddTask: (date: string) => void;
  onEditTask: (task: StudyTask) => void;
  onDeleteTask: (id: string) => void;
  isToday: boolean;
}> = ({ date, tasks, onToggleTask, onRateTask, onDropTask, onDragStartTask, onAddTask, onEditTask, onDeleteTask, isToday }) => {
  const [isOver, setIsOver] = useState(false);
  const dateKey = formatDateKey(date);

  return (
    <div
      onDragOver={(e) => { e.preventDefault(); setIsOver(true); }}
      onDragLeave={() => setIsOver(false)}
      onDrop={(e) => { e.preventDefault(); setIsOver(false); onDropTask(e.dataTransfer.getData('taskId'), dateKey); }}
      className={`flex flex-col rounded-[24px] p-4 transition-all min-h-[500px] border-2 ${
        isOver ? 'border-dashed border-indigo-500 bg-indigo-500/10' : 
        isToday ? 'border-indigo-500 bg-[#120f24]' : 'border-slate-800 bg-[#0d0b1a]'
      }`}
    >
      <div className="flex justify-between items-center mb-6 px-2">
        <div>
          <h3 className={`text-lg font-black uppercase tracking-tight ${isToday ? 'text-indigo-400' : 'text-slate-200'}`}>
            {date.toLocaleDateString('en-US', { weekday: 'short' })} <span className="text-slate-600 font-medium ml-1">{date.getDate()}</span>
          </h3>
          <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mt-1">{tasks.length} Missions</p>
        </div>
        <button onClick={() => onAddTask(dateKey)} className="w-8 h-8 rounded-lg bg-slate-800 hover:bg-indigo-600 text-slate-400 hover:text-white flex items-center justify-center transition-all">
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
        </button>
      </div>

      <div className="flex-1">
        {tasks.map(t => (
          <TaskCard 
            key={t.id} 
            task={t} 
            onToggle={onToggleTask} 
            onRate={onRateTask} 
            onDragStart={onDragStartTask} 
            onEdit={onEditTask} 
            onDelete={onDeleteTask}
          />
        ))}
        {tasks.length === 0 && (
          <div className="h-32 rounded-2xl border-2 border-dashed border-slate-800 flex items-center justify-center">
            <span className="text-[10px] font-black text-slate-700 uppercase tracking-widest">No Active Tasks</span>
          </div>
        )}
      </div>
    </div>
  );
};

// ==========================================
// 5. MAIN APP
// ==========================================
const App: React.FC = () => {
  const [tasks, setTasks] = useState<StudyTask[]>(() => {
    try {
      const saved = localStorage.getItem('lock-tf-in-final');
      return saved ? JSON.parse(saved) : INITIAL_TASKS;
    } catch {
      return INITIAL_TASKS;
    }
  });

  const [userInput, setUserInput] = useState('');
  const [baseDate, setBaseDate] = useState(new Date());
  const [aiLoading, setAiLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTask, setEditingTask] = useState<Partial<StudyTask> | null>(null);

  useEffect(() => { localStorage.setItem('lock-tf-in-final', JSON.stringify(tasks)); }, [tasks]);

  const currentDays = useMemo(() => {
    const start = new Date(baseDate);
    // Align to Monday
    const day = start.getDay();
    const diff = start.getDate() - day + (day === 0 ? -6 : 1); 
    start.setDate(diff);

    return Array.from({ length: 7 }).map((_, i) => {
      const d = new Date(start);
      d.setDate(d.getDate() + i);
      return d;
    });
  }, [baseDate]);

  const handleSync = async () => {
    if (!userInput.trim()) return;
    setAiLoading(true);
    const result = await adaptSchedule(tasks, userInput);
    if (result.updatedTasks) setTasks(result.updatedTasks);
    setAiMessage(result.suggestion);
    setUserInput('');
    setAiLoading(false);
  };

  const handleRate = (id: string, rating: MasteryRating) => {
    setTasks(prev => {
      const task = prev.find(t => t.id === id);
      if (!task) return prev;

      let updated = prev.map(t => t.id === id ? { ...t, masteryRating: rating, completed: true } : t);

      if (rating === 'Again' || rating === 'Hard') {
        const nextDate = new Date(task.date);
        nextDate.setDate(nextDate.getDate() + (rating === 'Again' ? 1 : 2));

        updated.push({
          ...task,
          id: Math.random().toString(36).substr(2, 9),
          title: `RE-DRILL: ${task.title}`,
          date: formatDateKey(nextDate),
          completed: false,
          masteryRating: undefined,
          isFSRSActive: true
        });
      }
      return updated;
    });
  };

  const saveTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingTask) return;

    setTasks(prev => {
      if (editingTask.id) {
        return prev.map(t => t.id === editingTask.id ? { ...t, ...editingTask } as StudyTask : t);
      }
      return [...prev, { ...editingTask, id: Math.random().toString(36).substr(2, 9), completed: false } as StudyTask];
    });
    setIsModalOpen(false);
  };

  const progress = tasks.length ? Math.round((tasks.filter(t => t.completed).length / tasks.length) * 100) : 0;

  return (
    <div className="min-h-screen bg-[#090712] text-slate-100 pb-20 font-inter">
      {/* Header */}
      <header className="sticky top-0 z-40 bg-[#090712]/80 backdrop-blur-xl border-b border-slate-800">
        <div className="max-w-[1800px] mx-auto px-6 py-4 flex flex-col lg:flex-row items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/30">
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="3"><path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"/></svg>
            </div>
            <div>
              <h1 className="text-2xl font-black italic tracking-tighter uppercase leading-none">
                LOCK <span className="text-indigo-500">TF</span> IN!
              </h1>
              <p className="text-[9px] font-black uppercase tracking-[0.3em] text-slate-500">MCAT OS v3.0 (React 19)</p>
            </div>
          </div>

          <div className="flex-1 w-full max-w-xl flex gap-2">
            <div className="flex-1 relative group">
              <div className="absolute inset-0 bg-indigo-500/20 rounded-xl blur-md opacity-0 group-hover:opacity-100 transition-opacity"></div>
              <input 
                value={userInput}
                onChange={e => setUserInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSync()}
                placeholder="Ask Coach: 'I'm behind on Bio' or 'Focus on Chem today'"
                className="relative w-full bg-[#16122b] border border-slate-700 rounded-xl px-4 py-3 text-sm font-semibold text-white placeholder:text-slate-500 focus:outline-none focus:border-indigo-500 transition-all"
              />
            </div>
            <button 
              onClick={handleSync}
              disabled={aiLoading}
              className="px-6 rounded-xl bg-indigo-600 hover:bg-indigo-500 text-white font-black uppercase text-xs tracking-widest transition-all shadow-lg shadow-indigo-900/20 disabled:opacity-50"
            >
              {aiLoading ? 'Thinking...' : 'Sync'}
            </button>
          </div>

          <div className="flex items-center gap-4 bg-[#16122b] px-5 py-2 rounded-xl border border-slate-800">
            <div className="text-right">
              <p className="text-[9px] font-black text-slate-500 uppercase">Weekly Progress</p>
              <p className="text-lg font-black text-white">{progress}%</p>
            </div>
            <div className="w-10 h-10 rounded-full border-4 border-slate-800 flex items-center justify-center relative">
              <svg className="absolute inset-0 -rotate-90" width="40" height="40">
                <circle cx="20" cy="20" r="16" stroke="#312e81" strokeWidth="4" fill="none" />
                <circle cx="20" cy="20" r="16" stroke="#6366f1" strokeWidth="4" fill="none" strokeDasharray="100" strokeDashoffset={100 - progress} strokeLinecap="round" />
              </svg>
            </div>
          </div>
        </div>
      </header>

      {/* AI Message */}
      {aiMessage && (
        <div className="max-w-[1800px] mx-auto px-6 mt-6 animate-fade-in">
          <div className="bg-indigo-500/10 border-l-4 border-indigo-500 p-4 rounded-r-xl flex items-center justify-between">
            <div className="flex items-center gap-3">
              <span className="text-xl">🤖</span>
              <p className="text-sm font-bold text-indigo-200">{aiMessage}</p>
            </div>
            <button onClick={() => setAiMessage(null)} className="text-indigo-300 hover:text-white"><svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg></button>
          </div>
        </div>
      )}

      {/* Grid */}
      <main className="max-w-[1800px] mx-auto px-6 mt-8">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-7 gap-4">
          {currentDays.map((d, i) => {
             const dKey = formatDateKey(d);
             const isToday = dKey === formatDateKey(new Date());
             return (
               <DayColumn 
                 key={i} 
                 date={d} 
                 isToday={isToday}
                 tasks={tasks.filter(t => t.date === dKey)}
                 onToggleTask={(id) => setTasks(prev => prev.map(t => t.id === id ? {...t, completed: !t.completed} : t))}
                 onRateTask={handleRate}
                 onDropTask={(id, date) => setTasks(prev => prev.map(t => t.id === id ? {...t, date} : t))}
                 onDragStartTask={(e, id) => e.dataTransfer.setData('taskId', id)}
                 onAddTask={(date) => { setEditingTask({ date, title: '', section: 'Biology', duration: '1h' }); setIsModalOpen(true); }}
                 onEditTask={(task) => { setEditingTask(task); setIsModalOpen(true); }}
                 onDeleteTask={(id) => setTasks(prev => prev.filter(t => t.id !== id))}
               />
             );
          })}
        </div>
      </main>

      {/* Navigation */}
      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-[#16122b]/90 backdrop-blur-md px-6 py-3 rounded-2xl border border-slate-700 shadow-2xl flex items-center gap-6 z-50">
         <button onClick={() => { const d = new Date(baseDate); d.setDate(d.getDate() - 7); setBaseDate(d); }} className="text-slate-400 hover:text-white p-2 hover:bg-white/10 rounded-lg transition-all">
           <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M15 18l-6-6 6-6"/></svg>
         </button>
         <span className="text-sm font-black uppercase tracking-widest text-indigo-400 min-w-[140px] text-center">
           {baseDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
         </span>
         <button onClick={() => { const d = new Date(baseDate); d.setDate(d.getDate() + 7); setBaseDate(d); }} className="text-slate-400 hover:text-white p-2 hover:bg-white/10 rounded-lg transition-all">
           <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M9 18l6-6-6-6"/></svg>
         </button>
      </div>

      {/* Modal */}
      {isModalOpen && editingTask && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in">
          <div className="bg-[#16122b] border border-slate-700 w-full max-w-md p-8 rounded-3xl shadow-2xl">
            <h2 className="text-2xl font-black italic uppercase tracking-tighter mb-6">Mission <span className="text-indigo-500">Details</span></h2>
            <form onSubmit={saveTask} className="space-y-4">
              <div>
                <label className="block text-[10px] font-black uppercase text-slate-500 mb-2">Objective</label>
                <input 
                  autoFocus
                  className="w-full bg-[#090712] border border-slate-700 rounded-xl px-4 py-3 font-bold text-white focus:border-indigo-500 outline-none"
                  value={editingTask.title}
                  onChange={e => setEditingTask({...editingTask, title: e.target.value})}
                  placeholder="e.g. Physics Chapter 3"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black uppercase text-slate-500 mb-2">Date</label>
                  <input 
                    type="date"
                    className="w-full bg-[#090712] border border-slate-700 rounded-xl px-4 py-3 font-bold text-white focus:border-indigo-500 outline-none"
                    value={editingTask.date}
                    onChange={e => setEditingTask({...editingTask, date: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black uppercase text-slate-500 mb-2">Duration</label>
                  <input 
                    className="w-full bg-[#090712] border border-slate-700 rounded-xl px-4 py-3 font-bold text-white focus:border-indigo-500 outline-none"
                    value={editingTask.duration}
                    onChange={e => setEditingTask({...editingTask, duration: e.target.value})}
                    placeholder="2h"
                  />
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black uppercase text-slate-500 mb-2">Sector</label>
                <select 
                  className="w-full bg-[#090712] border border-slate-700 rounded-xl px-4 py-3 font-bold text-white focus:border-indigo-500 outline-none appearance-none"
                  value={editingTask.section}
                  onChange={e => setEditingTask({...editingTask, section: e.target.value as MCATSection})}
                >
                  {Object.keys(SECTION_STYLES).map(s => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>

              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-3 font-black uppercase text-xs text-slate-500 hover:text-white">Cancel</button>
                <button type="submit" className="flex-[2] py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl font-black uppercase text-xs tracking-widest shadow-lg shadow-indigo-900/20">
                  {editingTask.id ? 'Save Changes' : 'Initialize'}
                </button>
              </div>

              {editingTask.id && (
                <button 
                  type="button" 
                  onClick={() => { setTasks(prev => prev.filter(t => t.id !== editingTask.id)); setIsModalOpen(false); }}
                  className="w-full text-center py-2 text-[10px] font-black uppercase text-rose-500 hover:text-rose-400"
                >
                  Delete Mission
                </button>
              )}
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

